function normalizePathname(value) {
  const normalized = normalizeString(value);
  if (!normalized) {
    return "/";
  }
  return normalized.startsWith("/") ? normalized : `/${normalized}`;
}

function decodeRouteSegment(value) {
  const normalized = normalizeString(value);
  if (!normalized) {
    return "";
  }
  try {
    return decodeURIComponent(normalized);
  } catch {
    return normalized;
  }
}

function normalizeRouteParams(value) {
  if (!value || typeof value !== "object") {
    return {};
  }
  return Object.entries(value).reduce((params, [key, raw]) => {
    params[key] = normalizeString(raw);
    return params;
  }, {});
}

function parseRouteFromLocation(pathname = window.location.pathname) {
  const normalizedPath = normalizePathname(pathname);
  if (/^\/cta-invite(?:\/index\.html)?\/?$/u.test(normalizedPath)) {
    const params = readCurrentSearchParams();
    const token = normalizeString(params.get("token"));
    if (token) {
      return {
        routeKey: ROUTE_KEY_CTA_INVITE,
        routePath: `/cta-invite/${encodeURIComponent(token)}`,
        routeParams: { token },
      };
    }
  }
  if (normalizedPath === "/posts/view") {
    const params = readCurrentSearchParams();
    const postId = normalizeString(
      params.get("postId") || params.get("id") || params.get("post"),
    );
    if (postId) {
      return {
        routeKey: ROUTE_KEY_SHARE_POST,
        routePath: `/posts/${encodeURIComponent(postId)}`,
        routeParams: { postId },
      };
    }
    return {
      routeKey: ROUTE_KEY_FEED,
      routePath: "/feed",
      routeParams: {},
    };
  }
  const routePatterns = [
    [ROUTE_KEY_BOOTSTRAP, /^\/bootstrap$/u, []],
    [ROUTE_KEY_AUTH, /^\/auth$/u, []],
    [ROUTE_KEY_AUTH, /^\/auth\/signup\/email$/u, []],
    [ROUTE_KEY_AUTH, /^\/auth\/signup\/password$/u, []],
    [ROUTE_KEY_AUTH, /^\/auth\/confirm-code$/u, []],
    [ROUTE_KEY_AUTH, /^\/auth\/forgot-password$/u, []],
    [ROUTE_KEY_AUTH, /^\/auth\/forgot-password\/confirm$/u, []],
    [
      ROUTE_KEY_ACCOUNT_DELETION_REQUESTED,
      /^\/account-deletion-requested$/u,
      [],
    ],
    [ROUTE_KEY_POST_ANALYTICS, /^\/posts\/([^/]+)\/analytics$/u, ["postId"]],
    [ROUTE_KEY_SHARE_POST, /^\/posts\/([^/]+)$/u, ["postId"]],
    [ROUTE_KEY_FEED, /^\/feed$/u, []],
    [ROUTE_KEY_CREATE, /^\/create$/u, []],
    [ROUTE_KEY_CREATE, /^\/create-tab$/u, []],
    [ROUTE_KEY_DISCOVER, /^\/discover$/u, []],
    [ROUTE_KEY_ACHIEVEMENTS, /^\/achievements$/u, []],
    [ROUTE_KEY_SEARCH_RESULTS, /^\/search\/results$/u, []],
    [ROUTE_KEY_SEARCH, /^\/search$/u, []],
    [ROUTE_KEY_CTA_INVITE, /^\/cta-invite\/([^/]+)$/u, ["token"]],
    [ROUTE_KEY_CANDIDATES, /^\/candidates$/u, []],
    [ROUTE_KEY_ELECTION_DAY, /^\/election-day$/u, []],
    [
      ROUTE_KEY_CONGRESSIONAL_REPORT_CARD,
      /^\/officials\/congressional-report-card$/u,
      [],
    ],
    [
      ROUTE_KEY_OFFICIAL_REPORT_CARD,
      /^\/officials\/([^/]+)\/report-card$/u,
      ["officialId"],
    ],
    [ROUTE_KEY_OFFICIAL_DETAIL, /^\/officials\/([^/]+)$/u, ["officialId"]],
    [
      ROUTE_KEY_AUTO_CANDIDATE_DETAIL,
      /^\/auto-candidates\/([^/]+)$/u,
      ["entityId"],
    ],
    [
      ROUTE_KEY_CANDIDATE_EDIT,
      /^\/candidates\/([^/]+)\/edit$/u,
      ["candidateId"],
    ],
    [ROUTE_KEY_CANDIDATE_EDIT, /^\/settings\/candidate-edit$/u, []],
    [ROUTE_KEY_CANDIDATE_DETAIL, /^\/candidates\/([^/]+)$/u, ["candidateId"]],
    [
      ROUTE_KEY_CANDIDATE_DASHBOARD_SECTION,
      /^\/candidate-dashboard\/([^/]+)\/([^/]+)$/u,
      ["candidateId", "section"],
    ],
    [
      ROUTE_KEY_CANDIDATE_DASHBOARD_DETAIL,
      /^\/candidate-dashboard\/([^/]+)$/u,
      ["candidateId"],
    ],
    [ROUTE_KEY_CANDIDATE_DASHBOARD, /^\/candidate-dashboard$/u, []],
    [
      ROUTE_KEY_CANDIDATE_VOTER_MAP_SECTION,
      /^\/candidate\/voter-map\/(.+)$/u,
      ["voterMapSection"],
    ],
    [ROUTE_KEY_CANDIDATE_VOTER_MAP, /^\/candidate\/voter-map$/u, []],
    [ROUTE_KEY_COALITION_START, /^\/coalitions\/start$/u, []],
    [ROUTE_KEY_COALITION_JOIN, /^\/coalitions\/join$/u, []],
    [
      ROUTE_KEY_COALITION_SECTION,
      /^\/coalitions\/([^/]+)\/(.+)$/u,
      ["coalitionId", "section"],
    ],
    [
      ROUTE_KEY_COALITION_DETAIL,
      /^\/coalitions\/([^/]+)$/u,
      ["coalitionId"],
    ],
    [ROUTE_KEY_COALITIONS, /^\/coalitions$/u, []],
    [ROUTE_KEY_MISSION_DETAIL, /^\/missions\/([^/]+)$/u, ["missionId"]],
    [ROUTE_KEY_MISSIONS, /^\/missions$/u, []],
    [ROUTE_KEY_EVENTS, /^\/events$/u, []],
    [ROUTE_KEY_EVENT_DETAIL, /^\/events\/([^/]+)$/u, ["eventId"]],
    [ROUTE_KEY_EVENT_SIGNUP, /^\/events\/([^/]+)\/signup$/u, ["eventId"]],
    [ROUTE_KEY_EVENT_PAYMENT, /^\/events\/([^/]+)\/payment$/u, ["eventId"]],
    [ROUTE_KEY_MANAGE_EVENTS, /^\/manage-events$/u, []],
    [ROUTE_KEY_MANAGE_EVENTS_NEW, /^\/manage-events\/new$/u, []],
    [
      ROUTE_KEY_MANAGE_EVENTS_EDIT,
      /^\/manage-events\/([^/]+)\/edit$/u,
      ["eventId"],
    ],
    [ROUTE_KEY_PROFILE_SELF, /^\/profile$/u, []],
    [ROUTE_KEY_PROFILE_SELF, /^\/profile-tab$/u, []],
    [ROUTE_KEY_PROFILE_EDIT, /^\/profile\/edit$/u, []],
    [ROUTE_KEY_PROFILE_CONNECTIONS, /^\/profile\/connections$/u, []],
    [ROUTE_KEY_PROFILE_NOTIFICATIONS, /^\/profile\/notifications$/u, []],
    [ROUTE_KEY_PROFILE_USER, /^\/profile\/([^/]+)$/u, ["userId"]],
    [ROUTE_KEY_SETTINGS, /^\/settings$/u, []],
    [ROUTE_KEY_SETTINGS_SECTION, /^\/settings\/(.+)$/u, ["settingsPath"]],
    [ROUTE_KEY_ONBOARDING_PROFILE, /^\/onboarding\/profile$/u, []],
    [ROUTE_KEY_ONBOARDING_PHOTO, /^\/onboarding\/photo$/u, []],
    [ROUTE_KEY_ONBOARDING_LOCATION, /^\/onboarding\/location$/u, []],
    [ROUTE_KEY_ONBOARDING_ADDRESS, /^\/onboarding\/address$/u, []],
    [ROUTE_KEY_ONBOARDING_TOPICS, /^\/onboarding\/topics$/u, []],
    [ROUTE_KEY_TOPICS, /^\/topics$/u, []],
    [ROUTE_KEY_POLICY_QUESTION_DETAIL, /^\/questions\/([^/]+)$/u, ["questionId"]],
    [ROUTE_KEY_POLICY_QUESTIONS, /^\/questions$/u, []],
    [ROUTE_KEY_MESSAGES_ROOT, /^\/messages$/u, []],
    [ROUTE_KEY_MESSAGES_WILDCARD, /^\/messages\/(.+)$/u, ["messagePath"]],
    [ROUTE_KEY_ADMIN, /^\/admin$/u, []],
    [ROUTE_KEY_ADMIN_SECTION, /^\/admin\/(.+)$/u, ["adminPath"]],
  ];

  for (const [routeKey, pattern, paramKeys] of routePatterns) {
    const match = pattern.exec(normalizedPath);
    if (!match) {
      continue;
    }
    const routeParams = {};
    paramKeys.forEach((key, index) => {
      routeParams[key] = normalizeString(match[index + 1]);
    });
    return {
      routeKey,
      routePath: normalizedPath,
      routeParams,
    };
  }

  return {
    routeKey: ROUTE_KEY_SHARE_POST,
    routePath: normalizedPath,
    routeParams: normalizeRouteParams(runtimeConfig.routeParams),
  };
}

function getInitialRoute() {
  const runtimeRouteKey = normalizeString(runtimeConfig.routeKey);
  const parsedRoute = parseRouteFromLocation();
  if (runtimeRouteKey) {
    if (
      runtimeRouteKey === ROUTE_KEY_CTA_INVITE &&
      parsedRoute.routeKey === ROUTE_KEY_CTA_INVITE
    ) {
      return parsedRoute;
    }
    if (
      parsedRoute.routeKey !== ROUTE_KEY_SHARE_POST &&
      parsedRoute.routeKey !== runtimeRouteKey
    ) {
      return parsedRoute;
    }
    return {
      routeKey: runtimeRouteKey,
      routePath: normalizePathname(
        runtimeConfig.route || window.location.pathname,
      ),
      routeParams: normalizeRouteParams(runtimeConfig.routeParams),
    };
  }
  return parsedRoute;
}

