function readSettingsActivitySharingPreference() {
  try {
    const raw = window.localStorage?.getItem(FRIEND_ACTIVITY_SHARING_STORAGE_KEY);
    if (!normalizeString(raw)) {
      return true;
    }
    const normalized = normalizeString(raw).toLowerCase();
    return normalized !== "false" && normalized !== "0";
  } catch {
    return true;
  }
}

