    status: normalizeString(raw.status || "open"),
    channelId: normalizeString(raw.channelId || raw.conversationId),
    messageId: normalizeString(raw.messageId),
    sortKey: normalizeString(raw.sortKey),
    reportId: normalizeString(raw.reportId),
    ruleId: normalizeString(raw.ruleId),
    reason: normalizeString(raw.reason || raw.reasonCode),
    text: normalizeString(raw.text || raw.messageText || raw.previewText),
    actorId: normalizeString(raw.actorId || raw.targetUserId),
    createdBy: normalizeString(raw.createdBy || raw.reporterId),
    createdAt: Number(raw.createdAt) || null,
    reviewedBy: normalizeString(raw.reviewedBy),
