async function loadCandidateDashboardCampaigns({ refresh = false } = {}) {
  const campaigns = state.pages.candidateDashboard.campaigns;
  if (campaigns.loading) {
    return;
  }
  if (campaigns.loaded && !refresh) {
    return;
  }
  if (refresh) {
    campaigns.items = [];
    campaigns.nextCursor = null;
    campaigns.loaded = false;
  }
  campaigns.loading = true;
  campaigns.error = "";
  scheduleRender();

  try {
    const [accessResult, profileResult] = await Promise.allSettled([
      fetchJson("/api/candidateDashboard/candidates", { auth: true }),
      fetchJson("/api/profile/me", { auth: true }),
    ]);
    const accessItems =
      accessResult.status === "fulfilled"
        ? readArrayPayload(accessResult.value, [
            "items",
            "candidates",
            "campaigns",
            "access",
          ]).map(normalizeCandidateDashboardAccess)
        : [];
    const profile =
      profileResult.status === "fulfilled"
        ? normalizeProfile(profileResult.value.profile || profileResult.value)
        : state.pages.profile.me;
    if (profileResult.status === "fulfilled") {
      state.pages.profile.me = profile;
    }
    campaigns.items = mergeCandidateDashboardAccessItems(accessItems, profile);
    if (accessResult.status === "rejected" && !campaigns.items.length) {
      throw accessResult.reason;
    }
    campaigns.loaded = true;
  } catch (error) {
    campaigns.error =
      normalizeString(error?.message) || "Campaign access could not be loaded.";
  } finally {
    campaigns.loading = false;
    scheduleRender();
  }
}

function findCandidateDashboardAccess(candidateId) {
  const normalizedId = normalizeString(candidateId);
  if (!normalizedId) {
    return null;
  }
  return (
    state.pages.candidateDashboard.campaigns.items.find(
      (item) => normalizeString(item.candidateId) === normalizedId,
    ) || null
  );
}

async function loadCandidateDashboardDetail(candidateId, { refresh = false } = {}) {
  const normalizedCandidateId = decodeRouteSegment(candidateId);
  if (!normalizedCandidateId) {
    return;
  }
  const detail = state.pages.candidateDashboard.detail;
  if (detail.loading) {
    return;
  }
  if (
    refresh ||
    state.pages.candidateDashboard.selectedCandidateId !== normalizedCandidateId
  ) {
    resetCandidateDashboardDetail(normalizedCandidateId);
  }
  detail.loading = true;
  detail.error = "";
  detail.access = findCandidateDashboardAccess(normalizedCandidateId);
  scheduleRender();

  const now = new Date();
  const from = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const to = new Date(from.getTime() + 1000 * 60 * 60 * 24 * 30);
  const encodedId = encodeURIComponent(normalizedCandidateId);
  const requests = {
    candidate: fetchJson(`/api/candidates/${encodedId}`, { auth: true }),
    analytics: fetchJson(`/api/candidateDashboard/${encodedId}/analytics?days=30`, {
      auth: true,
    }),
    events: fetchJson(
      `/api/candidateDashboard/${encodedId}/events?status=active&limit=4`,
      { auth: true },
    ),
    staff: fetchJson(`/api/candidateDashboard/${encodedId}/staff`, {
      auth: true,
    }),
    calendar: fetchJson(
      `/api/candidateDashboard/${encodedId}/calendar/items?from=${encodeURIComponent(from.toISOString())}&to=${encodeURIComponent(to.toISOString())}&limit=6`,
      { auth: true },
    ),
    missions: fetchJson(
      `/api/missions?scopeType=candidate&scopeId=${encodedId}&view=mine&limit=5`,
      { auth: true },
    ),
  };

  const results = await Promise.allSettled(Object.values(requests));
  const [
    candidateResult,
    analyticsResult,
    eventsResult,
    staffResult,
    calendarResult,
    missionsResult,
  ] = results;

  if (candidateResult.status === "fulfilled") {
    detail.candidate = normalizeCandidate(
      candidateResult.value.candidate || candidateResult.value,
    );
  } else if (detail.access?.profile) {
    detail.candidate = normalizeCandidate({
      candidateId: normalizedCandidateId,
      userId: detail.access.profile.userId,
      displayName: detail.access.profile.displayName,
      username: detail.access.profile.username,
      avatarUrl: detail.access.profile.avatarUrl,
    });
  }
  if (analyticsResult.status === "fulfilled") {
    detail.analytics = normalizeCandidateDashboardAnalytics(
      analyticsResult.value,
    );
  }
  if (eventsResult.status === "fulfilled") {
    detail.events = readArrayPayload(eventsResult.value, ["items", "events"]).map(
      normalizeEvent,
    );
  }
  if (staffResult.status === "fulfilled") {
    detail.staff = readArrayPayload(staffResult.value, [
      "items",
      "staff",
      "members",
    ]).map(normalizeCandidateDashboardStaffMember);
  }
  if (calendarResult.status === "fulfilled") {
    detail.calendar = readArrayPayload(calendarResult.value, [
      "items",
      "calendar",
    ]).map(normalizeCandidateDashboardCalendarItem);
  }
  if (missionsResult.status === "fulfilled") {
    detail.missions = readArrayPayload(missionsResult.value, [
      "items",
      "missions",
    ]).map(normalizeCandidateDashboardMission);
  }

  const failed = results.filter((entry) => entry.status === "rejected");
  if (!detail.candidate && failed.length === results.length) {
    detail.error =
      normalizeString(failed[0]?.reason?.message) ||
      "Campaign dashboard could not be loaded.";
  }
  detail.loaded = true;
  detail.loading = false;
  scheduleRender();
}

async function loadCandidateDashboardAnalytics(
  candidateId,
  { refresh = false } = {},
) {
  const normalizedCandidateId = decodeRouteSegment(candidateId);
  if (!normalizedCandidateId) {
    return;
  }
  const detail = state.pages.candidateDashboard.detail;
  const resource = detail.analyticsWorkspace;
  if (resource.loading) {
    return;
  }
  if (resource.loaded && !refresh) {
    return;
  }
  resource.loading = true;
  resource.error = "";
  scheduleRender();

  const encodedId = encodeURIComponent(normalizedCandidateId);
  const days = Math.max(7, Math.min(90, Number(resource.days) || 30));
  const [analyticsResult, conversionsResult] = await Promise.allSettled([
    fetchJson(`/api/candidateDashboard/${encodedId}/analytics?days=${days}`, {
      auth: true,
    }),
    fetchJson(
      `/api/candidateDashboard/${encodedId}/event-conversions?days=${days}&includeDaily=true`,
      { auth: true },
    ),
  ]);

  if (analyticsResult.status === "fulfilled") {
    resource.snapshot = normalizeCandidateDashboardAnalytics(
      analyticsResult.value,
    );
    detail.analytics = resource.snapshot;
  }
  if (conversionsResult.status === "fulfilled") {
    resource.conversions = normalizeCandidateEventConversions(
      conversionsResult.value,
    );
  }
  if (analyticsResult.status === "rejected") {
    resource.error = settingsErrorMessage(
      analyticsResult.reason,
      "Campaign analytics could not be loaded.",
    );
  }
  resource.loaded = analyticsResult.status === "fulfilled";
  resource.loading = false;
  scheduleRender();
}

async function refreshCandidateDashboardAnalytics() {
  const candidateId = currentCandidateDashboardId();
  if (!candidateId) {
    return;
  }
  await loadCandidateDashboardAnalytics(candidateId, { refresh: true });
}

async function setCandidateAnalyticsRange(days) {
  const candidateId = currentCandidateDashboardId();
  if (!candidateId) {
    return;
  }
  const resource = state.pages.candidateDashboard.detail.analyticsWorkspace;
  const nextDays = Math.max(7, Math.min(90, Number(days) || 30));
  if (resource.days === nextDays && resource.loaded) {
    return;
  }
  resource.days = nextDays;
  resource.loaded = false;
  await loadCandidateDashboardAnalytics(candidateId, { refresh: true });
}

function normalizeCandidateDashboardEventsStatus(value) {
  const normalized = normalizeString(value).toLowerCase();
  return normalized === "previous" || normalized === "archived"
    ? "previous"
    : "active";
}

function candidateDashboardEventsStatusLabel(value) {
  return normalizeCandidateDashboardEventsStatus(value) === "previous"
    ? "Previous"
    : "Active";
}

function candidateDashboardEventsVisibleItems(resource) {
  return normalizeCandidateDashboardEventsStatus(resource.status) === "previous"
    ? resource.previousItems
    : resource.activeItems;
}

function candidateDashboardEventQueryString(status, resource) {
  return new URLSearchParams({
    status: normalizeCandidateDashboardEventsStatus(status),
    limit: "30",
    ...(resource.nextCursor ? { cursor: resource.nextCursor } : {}),
  }).toString();
}

function candidateDashboardEventsMapQueryString(resource) {
  const query = new URLSearchParams();
  if (resource.filters.tags) {
    query.set("tags", resource.filters.tags);
  }
  if (resource.filters.includePast) {
    query.set("includePast", "true");
  }
  return query.toString();
}

async function loadCandidateDashboardEvents(
  candidateId,
  { refresh = false } = {},
) {
  const normalizedCandidateId = decodeRouteSegment(candidateId);
  if (!normalizedCandidateId) {
    return;
  }
  const detail = state.pages.candidateDashboard.detail;
  const resource = detail.eventsWorkspace;
  if (resource.loading) {
    return;
  }
  if (resource.loaded && !refresh) {
    return;
  }
  if (refresh) {
    resource.activeItems = [];
    resource.previousItems = [];
    resource.mapItems = [];
    resource.route = null;
    resource.loaded = false;
  }
  resource.loading = true;
  resource.mapLoading = true;
  resource.error = "";
  resource.mapError = "";
  scheduleRender();

  const encodedId = encodeURIComponent(normalizedCandidateId);
  const mapQuery = candidateDashboardEventsMapQueryString(resource);
  const [activeResult, previousResult, mapResult] = await Promise.allSettled([
    fetchJson(
      `/api/candidateDashboard/${encodedId}/events?${candidateDashboardEventQueryString("active", resource)}`,
      { auth: true },
    ),
    fetchJson(
      `/api/candidateDashboard/${encodedId}/events?${candidateDashboardEventQueryString("previous", resource)}`,
      { auth: true },
    ),
    fetchJson(
      `/api/candidateDashboard/${encodedId}/events/map${mapQuery ? `?${mapQuery}` : ""}`,
      { auth: true },
    ),
  ]);

  if (activeResult.status === "fulfilled") {
    resource.activeItems = readArrayPayload(activeResult.value, [
      "items",
      "events",
    ]).map(normalizeEvent);
    detail.events = resource.activeItems;
  }
  if (previousResult.status === "fulfilled") {
    resource.previousItems = readArrayPayload(previousResult.value, [
      "items",
      "events",
    ]).map(normalizeEvent);
  }
  if (mapResult.status === "fulfilled") {
    resource.mapItems = readArrayPayload(mapResult.value, [
      "items",
      "events",
    ]).map(normalizeEvent);
  }
  if (activeResult.status === "rejected" && previousResult.status === "rejected") {
    resource.error = settingsErrorMessage(
      activeResult.reason,
      "Campaign events could not be loaded.",
    );
  }
  if (mapResult.status === "rejected") {
    resource.mapError = settingsErrorMessage(
      mapResult.reason,
      "Campaign event map could not be loaded.",
    );
  }
  resource.loaded =
    activeResult.status === "fulfilled" ||
    previousResult.status === "fulfilled";
  resource.loading = false;
  resource.mapLoading = false;
  scheduleRender();
}

async function refreshCandidateDashboardEvents() {
  const candidateId = currentCandidateDashboardId();
  if (!candidateId) {
    return;
  }
  await loadCandidateDashboardEvents(candidateId, { refresh: true });
}

