async function inviteCandidateDashboardStaff(formData) {
  const candidateId = currentCandidateDashboardId();
  const username = normalizeString(formData.get("username")).replace(/^@/u, "");
  const userId =
    normalizeString(formData.get("userId")) ||
    normalizeString(formData.get("directUserId"));
  const roleKey = normalizeCandidateStaffRoleKey(formData.get("roleKey"));
  const staffAdmin = state.pages.candidateDashboard.detail.staffAdmin;
  const catalog =
    staffAdmin.catalog || normalizeCandidateStaffAccessCatalog({});
  const permissions = formData.has("useRoleDefaults")
    ? candidateStaffRoleDefaultPermissions(catalog, roleKey)
    : candidateStaffSelectedPermissionsFromForm(formData);
  if (!candidateId || (!username && !userId)) {
    showToast("Enter a username or user id.");
    return false;
  }
  staffAdmin.actionPendingKey = "invite";
  staffAdmin.error = "";
  scheduleRender();
  try {
    await fetchJson(
      `/api/candidateDashboard/${encodeURIComponent(candidateId)}/staff/invitations`,
      {
        auth: true,
        method: "POST",
        body: {
          ...(userId ? { userId } : {}),
          ...(username ? { username } : {}),
          role: roleKey,
          roleKey,
          permissions,
        },
      },
    );
    showToast("Staff invitation sent.");
    staffAdmin.inviteSearch = createCandidateStaffInviteSearchState();
    await loadCandidateDashboardStaffAdmin(candidateId, { refresh: true });
    return true;
  } catch (error) {
    staffAdmin.error = settingsErrorMessage(
      error,
      "Staff invitation could not be sent.",
    );
    showToast(staffAdmin.error);
    return false;
  } finally {
    if (staffAdmin.actionPendingKey === "invite") {
      staffAdmin.actionPendingKey = "";
    }
    scheduleRender();
  }
}

