function currentCoalitionDetailId() {
  return decodeRouteSegment(getCurrentRoute().routeParams.coalitionId);
}

function canManageCoalitionProfile(membership) {
  return (
    membership?.isAdmin ||
    (membership?.permissions || []).includes("profile_manage")
  );
}

function coalitionSocialsFromForm(formData) {
  return ["facebook", "threads", "bluesky", "instagram", "tiktok"].reduce(
    (acc, key) => {
      const value = normalizeString(formData.get(`social:${key}`));
      if (value) {
        acc[key] = value;
      }
      return acc;
    },
    {},
  );
}

function coalitionProfilePayloadFromForm(formData) {
  const pacAssociated = formData.has("pacAssociated");
  const socials = coalitionSocialsFromForm(formData);
  return {
    name: normalizeString(formData.get("name")),
    description: normalizeString(formData.get("description")),
    imageUrl: normalizeUrl(formData.get("imageUrl")),
    primaryContactName: normalizeString(formData.get("primaryContactName")),
    phone: normalizeString(formData.get("phone")),
    email: normalizeString(formData.get("email")),
    website: normalizeUrl(formData.get("website")) || undefined,
    coalitionType:
      normalizeString(formData.get("coalitionType")).toLowerCase() || "simple",
    pacAssociated,
    fecNumber: pacAssociated ? normalizeString(formData.get("fecNumber")) : "",
    socials: Object.keys(socials).length ? socials : null,
  };
}

async function updateCoalitionProfile(formData) {
  const coalitionId = currentCoalitionDetailId();
  const detail = state.pages.coalitions.detail;
  const membership = detail.membership;
  if (!coalitionId || !canManageCoalitionProfile(membership)) {
    showToast("Coalition profile management is unavailable.");
    return false;
  }
  const body = coalitionProfilePayloadFromForm(formData);
  if (
    !body.name ||
    !body.description ||
    !body.imageUrl ||
    !body.primaryContactName ||
    !body.phone ||
    !body.email
  ) {
    showToast("Complete the required coalition profile fields.");
    return false;
  }
  if (body.pacAssociated && !body.fecNumber) {
    showToast("Add the FEC number for PAC-associated coalitions.");
    return false;
  }
  detail.actionPendingKey = "profile:update";
  detail.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/coalitions/${encodeURIComponent(coalitionId)}`,
      { auth: true, method: "PATCH", body },
    );
    const normalized = normalizeCoalitionDetail(payload);
    detail.coalition = normalized.coalition;
    detail.membership = normalized.membership;
    detail.imageUpload = createCoalitionImageUploadState();
    const listItem = findCoalitionListItem(coalitionId);
    if (listItem) {
      listItem.coalition = normalized.coalition;
      listItem.membership = normalized.membership || listItem.membership;
    }
    showToast("Coalition profile updated.");
    return true;
  } catch (error) {
    detail.error = settingsErrorMessage(
      error,
      "Coalition profile could not be updated.",
    );
    showToast(detail.error);
    return false;
  } finally {
    if (detail.actionPendingKey === "profile:update") {
      detail.actionPendingKey = "";
    }
    scheduleRender();
  }
}

function validateCoalitionProfilePayload(body) {
  if (
    !body.name ||
    !body.description ||
    !body.imageUrl ||
    !body.primaryContactName ||
    !body.phone ||
    !body.email
  ) {
    return "Complete the required coalition fields.";
  }
  if (!body.email.includes("@")) {
    return "Enter a valid coalition contact email.";
  }
  if (!["simple", "constitutional"].includes(body.coalitionType)) {
    return "Choose a coalition type.";
  }
  if (body.pacAssociated && !body.fecNumber) {
    return "Add the FEC number for PAC-associated coalitions.";
  }
  return "";
}

async function createCoalitionFromForm(formData) {
  const onboarding = state.pages.coalitions.onboarding;
  if (onboarding.actionPendingKey) {
    return false;
  }
  const body = coalitionProfilePayloadFromForm(formData);
  const validationError = validateCoalitionProfilePayload(body);
  if (validationError) {
    onboarding.error = validationError;
    showToast(validationError);
    return false;
  }

  onboarding.actionPendingKey = "create";
  onboarding.error = "";
  onboarding.createdCoalitionId = "";
  scheduleRender();
  try {
    const payload = await fetchJson("/api/coalitions", {
      auth: true,
      method: "POST",
      body,
    });
    const normalized = upsertCoalitionListItem(payload);
    const coalitionId = normalized.coalition.coalitionId;
    onboarding.createdCoalitionId = coalitionId;
    onboarding.imageUpload = createCoalitionImageUploadState();
    state.pages.coalitions.selectedCoalitionId = coalitionId;
    showToast("Coalition created.");
    navigateTo(coalitionSectionPath(coalitionId));
    return true;
  } catch (error) {
    onboarding.error = settingsErrorMessage(
      error,
      "Coalition could not be created.",
    );
    showToast(onboarding.error);
    return false;
  } finally {
    if (onboarding.actionPendingKey === "create") {
      onboarding.actionPendingKey = "";
    }
    scheduleRender();
  }
}

