async function useCoalitionVoterMapBrowserLocation() {
  const workspace = coalitionVoterMapWorkspace();
  workspace.locationError = "";
  if (!navigator.geolocation) {
    workspace.locationError = "Browser location is not available.";
    showToast(workspace.locationError);
    scheduleRender();
    return;
  }
  workspace.actionPendingKey = "location";
  scheduleRender();
  try {
    const position = await new Promise((resolve, reject) => {
      navigator.geolocation.getCurrentPosition(resolve, reject, {
        enableHighAccuracy: true,
        maximumAge: 5 * 60 * 1000,
        timeout: 10000,
      });
    });
    const coords = position?.coords || {};
    workspace.search = {
      ...workspace.search,
      lat: Number(coords.latitude).toFixed(6),
      lng: Number(coords.longitude).toFixed(6),
    };
    showToast("Location added to district search.");
  } catch (error) {
    workspace.locationError =
      normalizeString(error?.message) || "Location permission was not granted.";
    showToast(workspace.locationError);
  } finally {
    workspace.actionPendingKey = "";
    scheduleRender();
  }
}

function coalitionVoterMapDistrictSearchPayload(formData) {
  const lat = Number(normalizeString(formData.get("lat")));
  const lng = Number(normalizeString(formData.get("lng")));
  const radiusMiles = Number(normalizeString(formData.get("radiusMiles")));
  if (!Number.isFinite(lat) || lat < -90 || lat > 90) {
    throw new Error("Enter a valid latitude.");
  }
  if (!Number.isFinite(lng) || lng < -180 || lng > 180) {
    throw new Error("Enter a valid longitude.");
  }
  if (!Number.isFinite(radiusMiles) || radiusMiles <= 0 || radiusMiles > 500) {
    throw new Error("Enter a radius from 1 to 500 miles.");
  }
  return { lat, lng, radiusMiles };
}

