function coalitionSchedulePayloadFromForm(formData) {
  const debateHours = coalitionGovernanceNumberFromForm(formData, "debateHours", {
    fallback: 48,
    min: 0,
    max: 720,
  });
  const voteHours = coalitionGovernanceNumberFromForm(formData, "voteHours", {
    fallback: 24,
    min: 1,
    max: 720,
  });
  const voteStartValue = normalizeString(formData.get("voteStartAt"));
  const voteStartAtMs = voteStartValue ? Date.parse(voteStartValue) : null;
  if (voteStartValue && !Number.isFinite(voteStartAtMs)) {
    throw new Error("Vote start time is invalid.");
  }
  return {
    debateHours,
    voteHours,
    ...(voteStartAtMs ? { voteStartAtMs } : {}),
  };
}

