function splitCoalitionAmplifyTokens(value) {
  return normalizeString(value)
    .split(/[\s,]+/u)
    .map((entry) => entry.replace(/^#+/u, "").trim())
    .filter(Boolean);
}

function coalitionAmplifyLinksFromForm(formData) {
  return COALITION_AMPLIFY_PLATFORM_OPTIONS.reduce((acc, [key]) => {
    const value = normalizeUrl(formData.get(`link:${key}`));
    if (value) {
      acc[key] = value;
    }
    return acc;
  }, {});
}

