function buildCandidateVoterRegistryQuery(candidateId, resource, { cursor = "" } = {}) {
  const query = new URLSearchParams({
    candidateId,
    limit: "50",
  });
  const filters = resource.filters || {};
  [
    "q",
    "source",
    "city",
    "state",
    "party",
    "doorKnock",
    "mailPhysical",
    "mailEmail",
    "phoneCall",
    "textMessage",
    "yardSign",
  ].forEach((key) => {
    const value = normalizeString(filters[key]);
    if (value) {
      query.set(key, value);
    }
  });
  const normalizedCursor = normalizeString(cursor);
  if (normalizedCursor) {
    query.set("cursor", normalizedCursor);
  }
  return query;
}

async function loadCandidateDashboardVoterRegistry(
  candidateId,
  { refresh = false, append = false } = {},
) {
  const normalizedCandidateId = decodeRouteSegment(candidateId);
  if (!normalizedCandidateId) {
    return;
  }
  const registry = state.pages.candidateDashboard.detail.voterRegistry;
  if (append ? registry.loadingMore : registry.loading) {
    return;
  }
  if (!append && registry.loaded && !refresh) {
    return;
  }
  if (append && !registry.nextCursor) {
    return;
  }
  if (refresh && !append) {
    registry.items = [];
    registry.nextCursor = null;
    registry.loaded = false;
  }
  if (append) {
    registry.loadingMore = true;
  } else {
    registry.loading = true;
  }
  registry.error = "";
  scheduleRender();
  try {
    const query = buildCandidateVoterRegistryQuery(normalizedCandidateId, registry, {
      cursor: append ? registry.nextCursor : "",
    });
    const payload = await fetchJson(
      `/api/candidate-dashboard/voters?${query.toString()}`,
      { auth: true },
    );
    const page = normalizeCandidateVoterRegistryPage(payload);
    registry.items = append ? registry.items.concat(page.items) : page.items;
    registry.nextCursor = page.nextCursor;
    registry.loaded = true;
  } catch (error) {
    registry.error = settingsErrorMessage(
      error,
      "Voter registry could not be loaded.",
    );
  } finally {
    registry.loading = false;
    registry.loadingMore = false;
    scheduleRender();
  }
}

function candidateVoterRegistryFiltersFromForm(formData) {
  const filters = {};
  ["q", "source", "city", "state", "party"].forEach((key) => {
    const value = normalizeString(formData.get(key));
    if (value) filters[key] = value;
  });
  CANDIDATE_CONTACT_TYPE_CONFIG.forEach((type) => {
    const value = normalizeString(formData.get(type.key)).toLowerCase();
    if (["yes", "no", "unset"].includes(value)) {
      filters[type.key] = value;
    }
  });
  return filters;
}

async function applyCandidateVoterRegistryFilters(formData) {
  const candidateId = currentCandidateDashboardId();
  if (!candidateId) {
    return;
  }
  const registry = state.pages.candidateDashboard.detail.voterRegistry;
  registry.filters = candidateVoterRegistryFiltersFromForm(formData);
  await loadCandidateDashboardVoterRegistry(candidateId, { refresh: true });
}

function candidateVoterManualPayloadFromForm(formData, duplicateMode = "") {
  const payload = {
    name: normalizeString(formData.get("name")),
    addressLine1: normalizeString(formData.get("addressLine1")),
    addressLine2: normalizeString(formData.get("addressLine2")),
    city: normalizeString(formData.get("city")),
    state: normalizeString(formData.get("state")),
    postalCode: normalizeString(formData.get("postalCode")),
    phone: normalizeString(formData.get("phone")),
    email: normalizeString(formData.get("email")),
    party: normalizeString(formData.get("party")),
  };
  CANDIDATE_CONTACT_TYPE_CONFIG.forEach((type) => {
    const value = normalizeString(formData.get(type.key)).toLowerCase();
    if (value === "yes") {
      payload[type.key] = true;
    } else if (value === "no") {
      payload[type.key] = false;
    }
  });
  const mode = normalizeString(duplicateMode);
  if (mode) {
    payload.duplicateMode = mode;
  }
  return payload;
}

async function submitCandidateVoterManual(formData, duplicateMode = "") {
  const candidateId = currentCandidateDashboardId();
  if (!candidateId) {
    showToast("Campaign unavailable.");
    return false;
  }
  const registry = state.pages.candidateDashboard.detail.voterRegistry;
  const payload = candidateVoterManualPayloadFromForm(formData, duplicateMode);
  if (!payload.name && !payload.addressLine1 && !payload.email && !payload.phone) {
    showToast("Add a name, address, email, or phone.");
    return false;
  }
  registry.actionPendingKey = "manual";
  registry.error = "";
  registry.duplicate = null;
  scheduleRender();
  try {
    const query = new URLSearchParams({ candidateId });
    const response = await fetchJson(
      `/api/candidate-dashboard/voters/manual?${query.toString()}`,
      {
        auth: true,
        method: "POST",
        body: payload,
      },
    );
    const record = response.record
      ? normalizeCandidateVoterRecord(response.record)
      : null;
    showToast(response.skipped ? "Existing voter kept." : "Voter saved.");
    if (record?.recordId) {
      registry.items = [
        record,
        ...registry.items.filter((item) => item.recordId !== record.recordId),
      ];
    }
    await loadCandidateDashboardVoterRegistry(candidateId, { refresh: true });
    return true;
  } catch (error) {
    if (Number(error?.status) === 409) {
      registry.duplicate = {
        payload,
        existing: error?.payload?.existing
          ? normalizeCandidateVoterRecord(error.payload.existing)
          : null,
      };
      registry.error = "Duplicate voter found. Choose how to proceed.";
      showToast(registry.error);
      return false;
    }
    registry.error = settingsErrorMessage(error, "Voter could not be saved.");
    showToast(registry.error);
    return false;
  } finally {
    if (registry.actionPendingKey === "manual") {
      registry.actionPendingKey = "";
    }
    scheduleRender();
  }
}

async function resolveCandidateVoterDuplicate(mode) {
  const candidateId = currentCandidateDashboardId();
  const registry = state.pages.candidateDashboard.detail.voterRegistry;
  const duplicate = registry.duplicate;
  const normalizedMode = normalizeString(mode).toLowerCase();
  if (!candidateId || !duplicate || !["skip", "replace"].includes(normalizedMode)) {
    registry.duplicate = null;
    scheduleRender();
    return;
  }
  registry.actionPendingKey = `duplicate:${normalizedMode}`;
  registry.error = "";
  scheduleRender();
  try {
    const query = new URLSearchParams({ candidateId });
    const response = await fetchJson(
      `/api/candidate-dashboard/voters/manual?${query.toString()}`,
      {
        auth: true,
        method: "POST",
        body: { ...duplicate.payload, duplicateMode: normalizedMode },
      },
    );
    const record = response.record
      ? normalizeCandidateVoterRecord(response.record)
      : null;
    registry.duplicate = null;
    showToast(response.skipped ? "Existing voter kept." : "Voter replaced.");
    if (record?.recordId) {
      registry.items = [
        record,
        ...registry.items.filter((item) => item.recordId !== record.recordId),
      ];
    }
    await loadCandidateDashboardVoterRegistry(candidateId, { refresh: true });
  } catch (error) {
    registry.error = settingsErrorMessage(
      error,
      "Duplicate choice could not be saved.",
    );
    showToast(registry.error);
  } finally {
    registry.actionPendingKey = "";
    scheduleRender();
  }
}

async function previewCandidateVoterImport(formData) {
  const candidateId = currentCandidateDashboardId();
  const file = formData.get("csvFile");
  if (!candidateId || !(file instanceof File) || !file.name) {
    showToast("Choose a CSV file first.");
    return false;
  }
  const registryImport = state.pages.candidateDashboard.detail.voterRegistry.import;
  registryImport.actionPendingKey = "preview";
  registryImport.error = "";
  registryImport.preview = null;
  registryImport.status = null;
  scheduleRender();
  try {
    const query = new URLSearchParams({ candidateId });
    const uploadSession = await fetchJson(
      `/api/candidate-dashboard/voter-imports/upload?${query.toString()}`,
      {
        auth: true,
        method: "POST",
        body: {
          fileName: file.name,
          contentType: file.type || "text/csv",
        },
      },
    );
    const uploadId = normalizeString(uploadSession.uploadId);
    const upload = uploadSession.upload || {};
    const uploadUrl = normalizeString(upload.uploadUrl);
    if (!uploadId || !uploadUrl) {
      throw new Error("Import upload session was incomplete.");
    }
    const uploadHeaders = upload.headers && typeof upload.headers === "object"
      ? Object.fromEntries(
          Object.entries(upload.headers).map(([key, value]) => [
            key,
            normalizeString(value),
          ]),
        )
      : { "content-type": file.type || "text/csv" };
    const uploadResponse = await fetch(uploadUrl, {
      method: normalizeString(upload.method) || "PUT",
      headers: uploadHeaders,
      body: file,
    });
    if (!uploadResponse.ok) {
      throw new Error(`CSV upload failed: ${uploadResponse.status}`);
    }
    const preview = await fetchJson(
      `/api/candidate-dashboard/voter-imports/preview?${query.toString()}`,
      {
        auth: true,
        method: "POST",
        body: { uploadId },
      },
    );
    registryImport.uploadId = uploadId;
    registryImport.fileName = file.name;
    registryImport.preview = normalizeVoterImportPreview(preview);
    showToast("CSV preview ready.");
    return true;
  } catch (error) {
    registryImport.error = settingsErrorMessage(
      error,
      "CSV preview could not be created.",
    );
    showToast(registryImport.error);
    return false;
  } finally {
    if (registryImport.actionPendingKey === "preview") {
      registryImport.actionPendingKey = "";
    }
    scheduleRender();
  }
}

async function startCandidateVoterImport(duplicateMode = "") {
  const candidateId = currentCandidateDashboardId();
  const registry = state.pages.candidateDashboard.detail.voterRegistry;
  const registryImport = registry.import;
  const uploadId = normalizeString(registryImport.uploadId);
  if (!candidateId || !uploadId) {
    showToast("Run a CSV preview first.");
    return;
  }
  const mode =
    normalizeString(duplicateMode).toLowerCase() ||
    normalizeString(registryImport.duplicateMode).toLowerCase() ||
    "replace";
  registryImport.actionPendingKey = "start";
  registryImport.error = "";
  scheduleRender();
  try {
    const query = new URLSearchParams({ candidateId });
    const payload = await fetchJson(
      `/api/candidate-dashboard/voter-imports?${query.toString()}`,
      {
        auth: true,
        method: "POST",
        body: { uploadId, duplicateMode: mode },
      },
    );
    const importId = normalizeString(payload.importId);
    registryImport.status = normalizeVoterImportStatus({
      job: {
        importId,
        status: "queued",
      },
    });
    registryImport.duplicateMode = mode;
    showToast("Voter import started.");
    if (importId) {
      await loadCandidateVoterImportStatus(importId);
    }
  } catch (error) {
    registryImport.error = settingsErrorMessage(
      error,
      "Voter import could not be started.",
    );
    showToast(registryImport.error);
  } finally {
    if (registryImport.actionPendingKey === "start") {
      registryImport.actionPendingKey = "";
    }
    scheduleRender();
  }
}

async function loadCandidateVoterImportStatus(importId = "") {
  const candidateId = currentCandidateDashboardId();
  const registry = state.pages.candidateDashboard.detail.voterRegistry;
  const registryImport = registry.import;
  const normalizedImportId =
    normalizeString(importId) || normalizeString(registryImport.status?.importId);
  if (!candidateId || !normalizedImportId) {
    return;
  }
  registryImport.actionPendingKey = "status";
  registryImport.error = "";
  scheduleRender();
  try {
    const query = new URLSearchParams({ candidateId });
    const payload = await fetchJson(
      `/api/candidate-dashboard/voter-imports/${encodeURIComponent(normalizedImportId)}?${query.toString()}`,
      { auth: true },
    );
    registryImport.status = normalizeVoterImportStatus(payload);
    if (voterImportStatusIsTerminal(registryImport.status)) {
      await loadCandidateDashboardVoterRegistry(candidateId, { refresh: true });
    }
  } catch (error) {
    registryImport.error = settingsErrorMessage(
      error,
      "Import status could not be loaded.",
    );
    showToast(registryImport.error);
  } finally {
    registryImport.actionPendingKey = "";
    scheduleRender();
  }
}

