async function deleteCoalitionDirectoryMember(memberId) {
  const coalitionId = currentCoalitionDetailId();
  const normalizedMemberId = normalizeString(memberId);
  const directory = coalitionDirectoryWorkspace();
  const member = directory.members.find(
    (item) => item.memberId === normalizedMemberId,
  );
  if (!coalitionId || !normalizedMemberId) {
    return false;
  }
  const name = member?.fullName || "this coalition member";
  if (!window.confirm(`Archive ${name}?`)) {
    return false;
  }
  directory.actionPendingKey = `directory-delete:${normalizedMemberId}`;
  directory.error = "";
  scheduleRender();
  try {
    await fetchJson(
      `/api/coalitions/${encodeURIComponent(coalitionId)}/directory/members/${encodeURIComponent(normalizedMemberId)}`,
      {
        auth: true,
        method: "DELETE",
      },
    );
    directory.members = directory.members.filter(
      (item) => item.memberId !== normalizedMemberId,
    );
    showToast("Coalition member archived.");
    await loadCoalitionDirectory(coalitionId, { refresh: true });
    return true;
  } catch (error) {
    directory.error = settingsErrorMessage(
      error,
      "Coalition member could not be archived.",
    );
    showToast(directory.error);
    return false;
  } finally {
    directory.actionPendingKey = "";
    scheduleRender();
  }
}

async function loadCandidateDashboardCampaignQuest(
  candidateId,
  { refresh = false } = {},
) {
  const normalizedCandidateId = decodeRouteSegment(candidateId);
  if (!normalizedCandidateId) {
    return;
  }
  const quest = state.pages.candidateDashboard.detail.campaignQuest;
  if (quest.loading) {
    return;
  }
  if (quest.loaded && !refresh) {
    return;
  }
  quest.loading = true;
  quest.error = "";
  scheduleRender();
  try {
    const query = new URLSearchParams({ candidateId: normalizedCandidateId });
    const mapQuery = new URLSearchParams({
      candidateId: normalizedCandidateId,
      bbox: normalizeString(quest.bbox) || "-125,24,-66,50",
      zoom: String(Number(quest.zoom) || 5),
    });
    const [configResult, progressResult, mapResult] = await Promise.allSettled([
      fetchJson(
        `/api/candidate-dashboard/campaign-quest/config?${query.toString()}`,
        { auth: true },
      ),
      fetchJson(
        `/api/candidate-dashboard/campaign-quest/progress?${query.toString()}`,
        { auth: true },
      ),
      fetchJson(
        `/api/candidate-dashboard/campaign-quest/map?${mapQuery.toString()}`,
        { auth: true },
      ),
    ]);
    if (configResult.status === "fulfilled") {
      quest.config = normalizeCampaignQuestConfig(configResult.value);
    }
    if (progressResult.status === "fulfilled") {
      quest.progress = normalizeCampaignQuestProgress(progressResult.value);
    }
    if (mapResult.status === "fulfilled") {
      const page = normalizeCampaignQuestMapPage(mapResult.value);
      quest.targets = page.targets;
      quest.clusters = page.clusters;
      if (page.config.outcomeFields.length || page.config.questTemplates.length) {
        quest.config = page.config;
      }
      if (page.progress.level || page.progress.lifetimeXp) {
        quest.progress = page.progress;
      }
    }
    const failed = [configResult, progressResult, mapResult].filter(
      (entry) => entry.status === "rejected",
    );
    if (failed.length === 3) {
      throw failed[0].reason;
    }
    quest.loaded = true;
  } catch (error) {
    quest.error = settingsErrorMessage(
      error,
      "Campaign Quest could not be loaded.",
    );
  } finally {
    quest.loading = false;
    scheduleRender();
  }
}

