function normalizeCoalitionCtaEvent(raw = {}) {
  const source = readObjectPayload(raw.event || raw.item || raw);
  const destination = readObjectPayload(source.destination);
  const transportConfig = readObjectPayload(
    source.transportConfig || source.transport_config,
  );
  const transportState = readObjectPayload(
    source.transportState || source.transport_state,
  );
  const startAt = normalizeCandidateCalendarTimestamp(
    source.startAt ??
      source.startsAt ??
      source.startAtIso ??
      source.start_at ??
      source.start_at_iso,
  );
  const endAt = normalizeCandidateCalendarTimestamp(
    source.endAt ??
      source.endsAt ??
      source.endAtIso ??
      source.end_at ??
      source.end_at_iso,
  );
  return {
    eventId:
      normalizeString(
        source.eventId ||
          source.ctaEventId ||
          source.calendarItemId ||
          source.id ||
          raw.eventId,
      ) || "cta-event",
    coalitionId: normalizeString(source.coalitionId || source.coalition_id),
    title: normalizeString(source.title || source.name) || "CTA event",
    description: normalizeString(source.description || source.details),
    ctaType: normalizeString(source.ctaType || source.cta_type) || "cta",
    status: normalizeString(source.status || source.state) || "scheduled",
    visibility: normalizeString(source.visibility),
    startAt,
    endAt,
    locationName: normalizeString(
      source.locationName ||
        source.location ||
        destination.locationName ||
        destination.name,
    ),
    address: normalizeString(
      source.address ||
        source.locationAddress ||
        source.location_address ||
        destination.address,
    ),
    lat: Number.isFinite(Number(source.locationLat ?? destination.lat))
      ? Number(source.locationLat ?? destination.lat)
      : null,
    lng: Number.isFinite(Number(source.locationLng ?? destination.lng))
      ? Number(source.locationLng ?? destination.lng)
      : null,
    radiusMiles: Number(source.radiusMiles || source.radius_miles) || 0,
    bannerImageUrl: normalizeUrl(
      source.bannerImageUrl || source.banner_image_url || source.imageUrl,
    ),
    squareImageUrl: normalizeUrl(
      source.squareImageUrl || source.square_image_url,
    ),
    invitedCount: Number(source.invitedCount || source.invited_count) || 0,
    responseCount:
      Number(
        source.responseCount ||
          source.responses ||
          source.attendeeCount ||
          source.interestedCount,
      ) || 0,
    transportEnabled: parseBoolean(
      transportConfig.enabled ??
        source.transportationProvided ??
        source.transportation_provided,
      false,
    ),
    transportCount:
      Number(
        source.transportCount ||
          source.transport_count ||
          transportConfig.transportCount ||
          transportConfig.vehicleCount,
      ) || 0,
    seatsPerTransport:
      Number(
        source.seatsPerTransport ||
          source.seats_per_transport ||
          transportConfig.seatsPerTransport ||
          transportConfig.capacityPerVehicle,
      ) || 0,
    remainingSeats:
      Number(
        transportState.remainingSeats ||
          transportState.remaining_seats ||
          source.remainingSeats,
      ) || 0,
    assignedRiders:
      Number(
        transportState.assignedRiders ||
          transportState.assigned_riders ||
          source.assignedRiders,
      ) || 0,
    boardOutboundAt: normalizeString(
      source.boardOutboundAt ||
        source.board_outbound_at ||
        transportConfig.boardOutboundAt,
    ),
    boardReturnAt: normalizeString(
      source.boardReturnAt ||
        source.board_return_at ||
        transportConfig.boardReturnAt,
    ),
    transportConfig,
    transportState,
    raw: source,
  };
}

