function normalizeMessagingComposeCandidate(raw = {}, { isFriend = false } = {}) {
  const source = raw && typeof raw === "object" ? raw : {};
  const nestedUser =
    source.user && typeof source.user === "object"
      ? source.user
      : source.profile && typeof source.profile === "object"
        ? source.profile
        : {};
  const rawSearch = source.raw && typeof source.raw === "object" ? source.raw : {};
  const rawSearchUser =
    rawSearch.user && typeof rawSearch.user === "object"
      ? rawSearch.user
      : rawSearch.profile && typeof rawSearch.profile === "object"
        ? rawSearch.profile
        : {};
  const userId = normalizeString(
    source.userId ||
      source.user_id ||
      nestedUser.userId ||
      nestedUser.id ||
      rawSearch.userId ||
      rawSearch.user_id ||
      rawSearchUser.userId ||
      rawSearchUser.id ||
      source.id,
  );
  const username = normalizeString(
    source.username ||
      source.handle ||
      nestedUser.username ||
      nestedUser.handle ||
      rawSearch.username ||
      rawSearch.handle ||
      rawSearchUser.username ||
      rawSearchUser.handle,
  ).replace(/^@/u, "");
  const displayName =
    normalizeString(
      source.displayName ||
        source.name ||
        source.title ||
        nestedUser.displayName ||
        nestedUser.name ||
        rawSearch.displayName ||
        rawSearch.name ||
        rawSearch.title ||
        rawSearchUser.displayName ||
        rawSearchUser.name,
    ) ||
    username ||
    userId;
  const avatarUrl = normalizeUrl(
    source.avatarUrl ||
      source.imageUrl ||
      nestedUser.avatarUrl ||
      nestedUser.imageUrl ||
      rawSearch.avatarUrl ||
      rawSearch.imageUrl ||
      rawSearchUser.avatarUrl ||
      rawSearchUser.imageUrl,
  );
  if (!userId && !username) {
    return null;
  }
  const friend =
    isFriend ||
    source.isFriend === true ||
    source.friend === true ||
    rawSearch.isFriend === true;
  const blocked =
    source.blockedByPrivacy === true ||
    source.blocked === true ||
    rawSearch.blockedByPrivacy === true ||
    rawSearch.blocked === true;
  return {
    userId,
    username,
    displayName: displayName || "Polis user",
    avatarUrl,
    isFriend: friend,
    deliveryFolder:
      normalizeString(
        source.deliveryFolder ||
          source.delivery_folder ||
          rawSearch.deliveryFolder ||
          rawSearch.delivery_folder,
      ) || (friend ? "inbox" : "request"),
    blockedByPrivacy: blocked,
    reason:
      normalizeString(source.reason || source.subtitle || rawSearch.reason) ||
      (blocked ? "Unavailable due to privacy settings." : ""),
  };
}

function messagingComposeCandidateKey(candidate = {}) {
  const source = candidate && typeof candidate === "object" ? candidate : {};
  const userId = normalizeString(source.userId);
  if (userId) return `user:${userId}`;
  const username = normalizeString(source.username).replace(/^@/u, "");
  return username ? `username:${username.toLowerCase()}` : "";
}

function messagingComposeCandidates() {
  const compose = state.pages.messaging.compose;
  const selectedKeys = new Set(
    (compose.selected || []).map(messagingComposeCandidateKey).filter(Boolean),
  );
  const friendItems = (compose.friends.items || []).map((candidate) => ({
    ...candidate,
    selected: selectedKeys.has(messagingComposeCandidateKey(candidate)),
  }));
  const friendKeys = new Set(
    friendItems.map(messagingComposeCandidateKey).filter(Boolean),
  );
  const searchItems = (compose.search.items || [])
    .filter((candidate) => !friendKeys.has(messagingComposeCandidateKey(candidate)))
    .map((candidate) => ({
      ...candidate,
      selected: selectedKeys.has(messagingComposeCandidateKey(candidate)),
    }));
  return normalizeString(compose.query).length >= 3
    ? [...friendItems.filter((candidate) => {
        const query = normalizeString(compose.query).toLowerCase();
        return (
          normalizeString(candidate.displayName).toLowerCase().includes(query) ||
          normalizeString(candidate.username).toLowerCase().includes(query)
        );
      }), ...searchItems]
    : friendItems;
}

function findMessagingComposeCandidate(candidateKey) {
  const key = normalizeString(candidateKey);
  if (!key) return null;
  const compose = state.pages.messaging.compose;
  return [
    ...(compose.selected || []),
    ...(compose.friends.items || []),
    ...(compose.search.items || []),
  ].find((candidate) => messagingComposeCandidateKey(candidate) === key) || null;
}

function setMessagingComposeMode(mode) {
  const compose = state.pages.messaging.compose;
  compose.mode = mode === "group" ? "group" : "direct";
  compose.error = "";
  scheduleRender();
}

function toggleMessagingComposeCandidate(candidateKey) {
  const compose = state.pages.messaging.compose;
  const candidate = findMessagingComposeCandidate(candidateKey);
  if (!candidate) {
    compose.error = "Choose a person from the list first.";
    scheduleRender();
    return;
  }
  if (candidate.blockedByPrivacy) {
    compose.error = candidate.reason || "This person cannot be messaged right now.";
    showToast(compose.error);
    scheduleRender();
    return;
  }
  const key = messagingComposeCandidateKey(candidate);
  const selected = compose.selected || [];
  const exists = selected.some((item) => messagingComposeCandidateKey(item) === key);
  compose.selected = exists
    ? selected.filter((item) => messagingComposeCandidateKey(item) !== key)
    : [...selected, candidate];
  compose.error = "";
  scheduleRender();
}

async function loadMessagingComposeFriends({ refresh = false } = {}) {
  const compose = state.pages.messaging.compose;
  const friends = compose.friends;
  const currentUserId = currentMessagingUserId();
  if (!currentUserId) {
    friends.loaded = true;
    return;
  }
  if (friends.loading || (!refresh && friends.loaded)) {
    return;
  }
  if (refresh) {
    friends.items = [];
    friends.loaded = false;
  }
  friends.loading = true;
  friends.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/users/${encodeURIComponent(currentUserId)}/friends?limit=40`,
      { auth: true },
    );
    friends.items = readArrayPayload(payload, [
      "items",
      "friends",
      "connections",
      "users",
      "data",
    ])
      .map((item) => normalizeMessagingComposeCandidate(item, { isFriend: true }))
      .filter(Boolean);
    friends.loaded = true;
  } catch (error) {
    friends.error =
      normalizeString(error?.message) || "Friend suggestions could not load.";
    friends.loaded = true;
  } finally {
    friends.loading = false;
    scheduleRender();
  }
}

async function loadMessagingComposeSearch(query, { refresh = false } = {}) {
  const compose = state.pages.messaging.compose;
  const search = compose.search;
  const normalizedQuery = normalizeString(query);
  compose.query = normalizedQuery;
  if (normalizedQuery.length < 3) {
    compose.lastSearchQuery = "";
    search.items = [];
    search.error = "";
    search.loading = false;
    search.loaded = false;
    scheduleRender();
    return;
  }
  if (
    search.loading ||
    (!refresh && search.loaded && compose.lastSearchQuery === normalizedQuery)
  ) {
    return;
  }
  const token = compose.searchToken + 1;
  compose.searchToken = token;
  compose.lastSearchQuery = normalizedQuery;
  search.loading = true;
  search.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(messagingComposeSearchEndpoint(normalizedQuery), {
      auth: true,
    });
    if (compose.searchToken !== token) return;
    const friendsByKey = new Map(
      (compose.friends.items || []).map((candidate) => [
        messagingComposeCandidateKey(candidate),
        candidate,
      ]),
    );
    search.items = normalizeSearchResultsPayload(payload, "users").items
      .map((item) => {
        const candidate = normalizeMessagingComposeCandidate(item);
        if (!candidate) return null;
        const key = messagingComposeCandidateKey(candidate);
        return friendsByKey.has(key)
          ? { ...candidate, isFriend: true, deliveryFolder: "inbox" }
          : candidate;
      })
      .filter(Boolean);
    search.loaded = true;
  } catch (error) {
    if (compose.searchToken !== token) return;
    search.error = normalizeString(error?.message) || "People search failed.";
    search.loaded = true;
  } finally {
    if (compose.searchToken === token) {
      search.loading = false;
      scheduleRender();
    }
  }
}

function queueMessagingComposeSearch() {
  window.clearTimeout(messagingComposeSearchTimer);
  const query = normalizeString(state.pages.messaging.compose.query);
  if (query.length < 3) {
    loadMessagingComposeSearch(query).catch(() => {});
    return;
  }
  messagingComposeSearchTimer = window.setTimeout(() => {
    loadMessagingComposeSearch(query).catch(() => {});
  }, 300);
}

async function loadMessagingConversation(
  conversationId,
  { refresh = false } = {},
) {
  const conversation = state.pages.messaging.conversation;
  const normalizedConversationId = normalizeString(conversationId);
  if (!normalizedConversationId || conversation.loading) {
    return;
  }
  if (refresh) {
    conversation.messages = [];
    conversation.item = null;
    conversation.loaded = false;
    conversation.editingMessageId = "";
    conversation.editingOriginalText = "";
    conversation.pendingReply = null;
  }
  conversation.loading = true;
  conversation.error = "";
  scheduleRender();

  try {
    const [conversationPayload, historyPayload] = await Promise.all([
      fetchJson(
        `/api/messaging/conversations/${encodeURIComponent(normalizedConversationId)}`,
        {
          auth: true,
        },
      ),
      fetchJson(
        `/api/messaging/conversations/${encodeURIComponent(normalizedConversationId)}/history?limit=50`,
        { auth: true },
      ),
    ]);
    conversation.item = normalizeMessagingConversation(
      conversationPayload.conversation || conversationPayload,
    );
    conversation.messages = (historyPayload.messages || []).map(
      normalizeMessagingMessage,
    );
    conversation.nextCursor =
      normalizeString(historyPayload.nextCursor || historyPayload.cursor) ||
      null;
    conversation.loaded = true;
    messagingSocket.subscribeConversation(normalizedConversationId);
  } catch (error) {
    conversation.error =
      normalizeString(error?.message) || "Conversation unavailable.";
  } finally {
    conversation.loading = false;
    scheduleRender();
  }
}

