function normalizeMessagingChoice(value, options, fallback) {
  const normalized = normalizeString(value).toLowerCase();
  const resolved = normalized === "following" ? "followers" : normalized;
  return options.some(([key]) => key === resolved) ? resolved : fallback;
}

function messagingChoiceLabel(options, value, fallback = "Not set") {
  const normalized = normalizeString(value);
  const match = options.find(([key]) => key === normalized);
  return match?.[1] || fallback;
}

function normalizeMessagingAccountSettings(raw = {}) {
  const source = raw && typeof raw === "object" ? raw : {};
  const legacyReadReceiptsEnabled = parseBoolean(
    source.readReceiptsEnabled ?? source.read_receipts_enabled,
    true,
  );
  const readReceiptScope = normalizeMessagingChoice(
    source.readReceiptScope ?? source.read_receipt_scope,
    MESSAGING_READ_RECEIPT_SCOPE_OPTIONS,
    legacyReadReceiptsEnabled ? "all" : "none",
  );
  return {
    dmPrivacy: normalizeMessagingChoice(
      source.dmPrivacy ?? source.dm_privacy,
      MESSAGING_DM_PRIVACY_OPTIONS,
      "everyone",
    ),
    dmRequestsEnabled: parseBoolean(
      source.dmRequestsEnabled ?? source.dm_requests_enabled,
      true,
    ),
    presenceEnabled: parseBoolean(
      source.presenceEnabled ?? source.presence_enabled,
      false,
    ),
    presenceVisibility: normalizeMessagingChoice(
      source.presenceVisibility ?? source.presence_visibility,
      MESSAGING_PRESENCE_VISIBILITY_OPTIONS,
      "followers",
    ),
    presenceStatus: normalizeMessagingChoice(
      source.presenceStatus ?? source.presence_status,
      MESSAGING_PRESENCE_STATUS_OPTIONS,
      "online",
    ),
    readReceiptsEnabled: readReceiptScope !== "none",
    readReceiptScope,
    typingIndicatorsEnabled: parseBoolean(
      source.typingIndicatorsEnabled ?? source.typing_indicators_enabled,
      true,
    ),
    quietHoursEnabled: parseBoolean(
      source.quietHoursEnabled ?? source.quiet_hours_enabled,
      false,
    ),
    quietHoursStartMinutes: normalizeMinuteValue(
      source.quietHoursStartMinutes ?? source.quiet_hours_start_minutes,
      1320,
    ),
    quietHoursEndMinutes: normalizeMinuteValue(
      source.quietHoursEndMinutes ?? source.quiet_hours_end_minutes,
      420,
    ),
    dailyDigestEnabled: parseBoolean(
      source.dailyDigestEnabled ?? source.daily_digest_enabled,
      true,
    ),
    updatedAt: normalizeString(source.updatedAt ?? source.updated_at),
  };
}

async function saveMessagingAccountSettings(formData) {
  const messaging = state.pages.messaging;
  const current = normalizeMessagingAccountSettings(messaging.settings);
  const readReceiptScope = normalizeMessagingChoice(
    formData.get("readReceiptScope"),
    MESSAGING_READ_RECEIPT_SCOPE_OPTIONS,
    current.readReceiptScope,
  );
  const payload = {
    dmPrivacy: normalizeMessagingChoice(
      formData.get("dmPrivacy"),
      MESSAGING_DM_PRIVACY_OPTIONS,
      current.dmPrivacy,
    ),
    dmRequestsEnabled: formCheckboxValue(
      formData,
      "dmRequestsEnabled",
      current.dmRequestsEnabled,
    ),
    presenceEnabled: formCheckboxValue(
      formData,
      "presenceEnabled",
      current.presenceEnabled,
    ),
    presenceVisibility: normalizeMessagingChoice(
      formData.get("presenceVisibility"),
      MESSAGING_PRESENCE_VISIBILITY_OPTIONS,
      current.presenceVisibility,
    ),
    presenceStatus: normalizeMessagingChoice(
      formData.get("presenceStatus"),
      MESSAGING_PRESENCE_STATUS_OPTIONS,
      current.presenceStatus,
    ),
    readReceiptsEnabled: readReceiptScope !== "none",
    readReceiptScope,
    typingIndicatorsEnabled: formCheckboxValue(
      formData,
      "typingIndicatorsEnabled",
      current.typingIndicatorsEnabled,
    ),
    quietHoursEnabled: formCheckboxValue(
      formData,
      "quietHoursEnabled",
      current.quietHoursEnabled,
    ),
    quietHoursStartMinutes: timeInputToMinutes(
      formData.get("quietHoursStart"),
      current.quietHoursStartMinutes,
    ),
    quietHoursEndMinutes: timeInputToMinutes(
      formData.get("quietHoursEnd"),
      current.quietHoursEndMinutes,
    ),
    dailyDigestEnabled: formCheckboxValue(
      formData,
      "dailyDigestEnabled",
      current.dailyDigestEnabled,
    ),
  };

  messaging.settingsSaving = true;
  messaging.error = "";
  scheduleRender();
  try {
    const result = await fetchJson("/api/messaging/settings", {
      auth: true,
      method: "PUT",
      body: payload,
    });
    messaging.settings = normalizeMessagingAccountSettings(
      result.settings || result,
    );
    showToast("Messaging settings updated.");
  } catch (error) {
    messaging.error =
      normalizeString(error?.message) || "Messaging settings unavailable.";
    showToast(messaging.error);
  } finally {
    messaging.settingsSaving = false;
    scheduleRender();
  }
}

