async function loadMessagingServerAssets(
  scopeType,
  scopeId,
  type,
  { refresh = false } = {},
) {
  const assetState = state.pages.messaging.serverAssets;
  const normalizedScopeType = normalizeString(scopeType);
  const normalizedScopeId = normalizeString(scopeId);
  const normalizedType = normalizeString(type).toLowerCase();
  const scopeChanged =
    assetState.scopeType !== normalizedScopeType ||
    assetState.scopeId !== normalizedScopeId ||
    assetState.type !== normalizedType;
  if (
    !normalizedScopeType ||
    !normalizedScopeId ||
    !normalizedType ||
    assetState.loading
  ) {
    return;
  }
  if (refresh || scopeChanged) {
    assetState.items = [];
    assetState.loaded = false;
    assetState.scopeType = normalizedScopeType;
    assetState.scopeId = normalizedScopeId;
    assetState.type = normalizedType;
  }
  assetState.loading = true;
  assetState.error = "";
  scheduleRender();

  try {
    const query = buildMessagingScopeQuery(normalizedScopeType, normalizedScopeId, {
      type: normalizedType,
    });
    const payload = await fetchJson(`/api/messaging/server-assets?${query}`, {
      auth: true,
    });
    assetState.items = readArrayPayload(payload, ["assets", "items"])
      .map(normalizeMessagingServerAsset)
      .filter((asset) => asset.name || asset.assetId);
    assetState.loaded = true;
  } catch (error) {
    assetState.error =
      normalizeString(error?.message) || "Server assets unavailable.";
  } finally {
    assetState.loading = false;
    scheduleRender();
  }
}

function upsertMessagingServerAsset(asset) {
  const normalizedAsset = normalizeMessagingServerAsset(asset);
  const assetState = state.pages.messaging.serverAssets;
  const key =
    normalizedAsset.assetId ||
    `${normalizedAsset.type}:${normalizedAsset.name}:${normalizedAsset.imageUrl}`;
  if (!key) {
    return null;
  }
  const existingIndex = assetState.items.findIndex((item) => {
    const itemKey =
      item.assetId || `${item.type}:${item.name}:${item.imageUrl}`;
    return itemKey === key;
  });
  if (existingIndex >= 0) {
    assetState.items = assetState.items.map((item, index) =>
      index === existingIndex ? normalizedAsset : item,
    );
  } else {
    assetState.items = [normalizedAsset, ...assetState.items];
  }
  assetState.loaded = true;
  return normalizedAsset;
}

function removeMessagingServerAsset(assetId) {
  const normalizedAssetId = normalizeString(assetId);
  if (!normalizedAssetId) {
    return false;
  }
  const assetState = state.pages.messaging.serverAssets;
  const previousLength = assetState.items.length;
  assetState.items = assetState.items.filter(
    (item) => normalizeString(item.assetId) !== normalizedAssetId,
  );
  return assetState.items.length !== previousLength;
}

async function createMessagingServerAsset(formData) {
  const scopeType = normalizeString(formData.get("scopeType"));
  const scopeId = normalizeString(formData.get("scopeId"));
  const type = normalizeString(formData.get("type")).toLowerCase();
  const name = normalizeString(formData.get("name"));
  const imageUrl = normalizeUrl(formData.get("imageUrl"));
  const assetState = state.pages.messaging.serverAssets;
  if (!scopeType || !scopeId || !type) {
    showToast("Asset server unavailable.");
    return false;
  }
  if (!name || !imageUrl) {
    showToast("Add an asset name and image URL.");
    return false;
  }
  if (assetState.creating || assetState.actionPendingKey) {
    return false;
  }
  assetState.creating = true;
  assetState.error = "";
  scheduleRender();

  try {
    const payload = await fetchJson("/api/messaging/server-assets", {
      auth: true,
      method: "POST",
      body: {
        scopeType,
        scopeId,
        type,
        name,
        imageUrl,
      },
    });
    upsertMessagingServerAsset(payload.asset || payload);
    showToast("Server asset added.");
    return true;
  } catch (error) {
    assetState.error =
      normalizeString(error?.message) || "Server asset could not be added.";
    showToast(assetState.error);
    return false;
  } finally {
    assetState.creating = false;
    scheduleRender();
  }
}

async function updateMessagingServerAsset(formData) {
  const scopeType = normalizeString(formData.get("scopeType"));
  const scopeId = normalizeString(formData.get("scopeId"));
  const assetId = normalizeString(formData.get("assetId"));
  const type = normalizeString(formData.get("type")).toLowerCase();
  const name = normalizeString(formData.get("name"));
  const imageUrl = normalizeUrl(formData.get("imageUrl"));
  const assetState = state.pages.messaging.serverAssets;
  if (!scopeType || !scopeId || !assetId) {
    showToast("Asset unavailable.");
    return false;
  }
  if (!name || !imageUrl) {
    showToast("Keep the asset name and image URL filled in.");
    return false;
  }
  const pendingKey = `${assetId}:update`;
  if (assetState.actionPendingKey) {
    return false;
  }
  assetState.actionPendingKey = pendingKey;
  assetState.error = "";
  scheduleRender();

  try {
    const query = buildMessagingScopeQuery(scopeType, scopeId);
    const payload = await fetchJson(
      `/api/messaging/server-assets/${encodeURIComponent(assetId)}?${query}`,
      {
        auth: true,
        method: "PATCH",
        body: {
          scopeType,
          scopeId,
          type,
          name,
          imageUrl,
        },
      },
    );
    upsertMessagingServerAsset(payload.asset || payload);
    showToast("Server asset updated.");
    return true;
  } catch (error) {
    assetState.error =
      normalizeString(error?.message) || "Server asset could not be updated.";
    showToast(assetState.error);
    return false;
  } finally {
    if (assetState.actionPendingKey === pendingKey) {
      assetState.actionPendingKey = "";
    }
    scheduleRender();
  }
}

async function deleteMessagingServerAsset(scopeType, scopeId, assetId) {
  const normalizedScopeType = normalizeString(scopeType);
  const normalizedScopeId = normalizeString(scopeId);
  const normalizedAssetId = normalizeString(assetId);
  const assetState = state.pages.messaging.serverAssets;
  if (!normalizedScopeType || !normalizedScopeId || !normalizedAssetId) {
    showToast("Asset unavailable.");
    return false;
  }
  const pendingKey = `${normalizedAssetId}:delete`;
  if (assetState.actionPendingKey) {
    return false;
  }
  assetState.actionPendingKey = pendingKey;
  assetState.error = "";
  scheduleRender();

  try {
    const query = buildMessagingScopeQuery(normalizedScopeType, normalizedScopeId);
    await fetchJson(
      `/api/messaging/server-assets/${encodeURIComponent(normalizedAssetId)}?${query}`,
      {
        auth: true,
        method: "DELETE",
      },
    );
    removeMessagingServerAsset(normalizedAssetId);
    showToast("Server asset deleted.");
    return true;
  } catch (error) {
    assetState.error =
      normalizeString(error?.message) || "Server asset could not be deleted.";
    showToast(assetState.error);
    return false;
  } finally {
    if (assetState.actionPendingKey === pendingKey) {
      assetState.actionPendingKey = "";
    }
    scheduleRender();
  }
}

function normalizeMessagingServerSecurityPolicy(raw = {}) {
  const source =
    raw?.policy && typeof raw.policy === "object" && !Array.isArray(raw.policy)
      ? raw.policy
      : raw && typeof raw === "object" && !Array.isArray(raw)
        ? raw
        : {};
  return {
    requireMfaForAdminActions: parseBoolean(
      source.requireMfaForAdminActions,
      false,
    ),
    requireMfaForSensitiveChannels: parseBoolean(
      source.requireMfaForSensitiveChannels,
      false,
    ),
    requireTrustedDeviceForAdminActions: parseBoolean(
      source.requireTrustedDeviceForAdminActions,
      false,
    ),
    requireTrustedDeviceForSensitiveChannels: parseBoolean(
      source.requireTrustedDeviceForSensitiveChannels,
      false,
    ),
    requireE2eeForSensitiveChannels: parseBoolean(
      source.requireE2eeForSensitiveChannels,
      false,
    ),
    mfaSignalAvailable: parseBoolean(source.mfaSignalAvailable, false),
    updatedBy: normalizeString(source.updatedBy),
    updatedAt:
      Number(source.updatedAt) || Date.parse(source.updatedAtIso || "") || null,
    raw: source,
  };
}

function readMessagingServerSecurityPolicyFromSources(sources = []) {
  const policyKeys = [
    "requireMfaForAdminActions",
    "requireMfaForSensitiveChannels",
    "requireTrustedDeviceForAdminActions",
    "requireTrustedDeviceForSensitiveChannels",
    "requireE2eeForSensitiveChannels",
  ];
  for (const source of sources) {
    if (!source || typeof source !== "object" || Array.isArray(source)) {
      continue;
    }
    const candidates = [
      source.policy,
      source.securityPolicy,
      source.security,
      source.policies,
      source,
    ].filter(
      (candidate) =>
        candidate && typeof candidate === "object" && !Array.isArray(candidate),
    );
    const match = candidates.find((candidate) =>
      policyKeys.some((key) =>
        Object.prototype.hasOwnProperty.call(candidate, key),
      ),
    );
    if (match) {
      return normalizeMessagingServerSecurityPolicy(match);
    }
  }
  return normalizeMessagingServerSecurityPolicy({});
}

async function loadMessagingServerSecurityPolicy(
  scopeType,
  scopeId,
  { refresh = false } = {},
) {
  const policyState = state.pages.messaging.serverSecurityPolicy;
  const normalizedScopeType = normalizeString(scopeType);
  const normalizedScopeId = normalizeString(scopeId);
  const scopeChanged =
    policyState.scopeType !== normalizedScopeType ||
    policyState.scopeId !== normalizedScopeId;
  if (!normalizedScopeType || !normalizedScopeId || policyState.loading) {
    return;
  }
  if (refresh || scopeChanged) {
    policyState.item = null;
    policyState.loaded = false;
    policyState.scopeType = normalizedScopeType;
    policyState.scopeId = normalizedScopeId;
  }
  policyState.loading = true;
  policyState.error = "";
  scheduleRender();

  try {
    const query = buildMessagingScopeQuery(normalizedScopeType, normalizedScopeId);
    const payload = await fetchJson(
      `/api/messaging/server-security-policy?${query}`,
      { auth: true },
    );
    policyState.item = normalizeMessagingServerSecurityPolicy(payload);
    policyState.loaded = true;
  } catch (error) {
    policyState.error =
      normalizeString(error?.message) || "Server security policy unavailable.";
  } finally {
    policyState.loading = false;
    scheduleRender();
  }
}

async function updateMessagingServerSecurityPolicy(formData) {
  const scopeType = normalizeString(formData.get("scopeType"));
  const scopeId = normalizeString(formData.get("scopeId"));
  const policyState = state.pages.messaging.serverSecurityPolicy;
  const pendingKey = "security:policy";
  if (!scopeType || !scopeId) {
    showToast("Security policy server unavailable.");
    return false;
  }
  if (policyState.saving || policyState.actionPendingKey) {
    return false;
  }
  const current = normalizeMessagingServerSecurityPolicy(policyState.item || {});
  const body = {
    scopeType,
    scopeId,
    requireTrustedDeviceForAdminActions: formCheckboxValue(
      formData,
      "requireTrustedDeviceForAdminActions",
      current.requireTrustedDeviceForAdminActions,
    ),
    requireTrustedDeviceForSensitiveChannels: formCheckboxValue(
      formData,
      "requireTrustedDeviceForSensitiveChannels",
      current.requireTrustedDeviceForSensitiveChannels,
    ),
    requireE2eeForSensitiveChannels: formCheckboxValue(
      formData,
      "requireE2eeForSensitiveChannels",
      current.requireE2eeForSensitiveChannels,
    ),
    requireMfaForAdminActions: formCheckboxValue(
      formData,
      "requireMfaForAdminActions",
      current.requireMfaForAdminActions,
    ),
    requireMfaForSensitiveChannels: formCheckboxValue(
      formData,
      "requireMfaForSensitiveChannels",
      current.requireMfaForSensitiveChannels,
    ),
  };
  policyState.saving = true;
  policyState.actionPendingKey = pendingKey;
  policyState.error = "";
  scheduleRender();
  try {
    const query = buildMessagingScopeQuery(scopeType, scopeId);
    const payload = await fetchJson(
      `/api/messaging/server-security-policy?${query}`,
      {
        auth: true,
        method: "PATCH",
        body,
      },
    );
    policyState.item = normalizeMessagingServerSecurityPolicy(payload);
    policyState.loaded = true;
    showToast("Security policy updated.");
    return true;
  } catch (error) {
    policyState.error =
      normalizeString(error?.message) ||
      "Security policy could not be updated.";
    showToast(policyState.error);
    return false;
  } finally {
    policyState.saving = false;
    if (policyState.actionPendingKey === pendingKey) {
      policyState.actionPendingKey = "";
    }
    scheduleRender();
  }
}

