function messagingWorkflowActionFromForm(formData) {
  const actionType = normalizeMessagingWorkflowActionType(
    formData.get("actionType"),
  );
  const webhookUrl = normalizeUrl(formData.get("webhookUrl"));
  const channelId = normalizeString(formData.get("channelId"));
  const message = normalizeString(formData.get("message"));
  const reason = normalizeString(formData.get("reason"));
  const action = { type: actionType };
  if (actionType === "call_webhook" && webhookUrl) {
    action.webhookUrl = webhookUrl;
  }
  if (actionType === "send_message") {
    if (channelId) action.channelId = channelId;
    if (message) action.message = message;
  }
  if (actionType === "create_moderation_task" && reason) {
    action.reason = reason;
  }
  return action;
}

async function createMessagingWorkflow(formData) {
  const scopeType = normalizeString(formData.get("scopeType"));
  const scopeId = normalizeString(formData.get("scopeId"));
  const trigger = normalizeMessagingWorkflowTrigger(formData.get("trigger"));
  const keyword = normalizeString(formData.get("keyword"));
  const schedule = normalizeMessagingWorkflowSchedule(formData.get("schedule"));
  const name =
    normalizeString(formData.get("name")) ||
    (trigger === "schedule" ? "Scheduled workflow" : "Keyword workflow");
  const action = messagingWorkflowActionFromForm(formData);
  const workflowState = state.pages.messaging.serverWorkflows;
  if (!scopeType || !scopeId) {
    showToast("Workflow server unavailable.");
    return false;
  }
  if (trigger === "message_keyword" && !keyword) {
    showToast("Add a keyword for this workflow.");
    return false;
  }
  if (trigger === "schedule" && !schedule) {
    showToast("Choose a schedule for this workflow.");
    return false;
  }
  if (action.type === "call_webhook" && !normalizeUrl(action.webhookUrl)) {
    showToast("Add a webhook URL or choose another action.");
    return false;
  }
  if (action.type === "send_message" && !action.message) {
    showToast("Add a message for this workflow.");
    return false;
  }
  if (workflowState.creating) {
    return false;
  }
  workflowState.creating = true;
  workflowState.error = "";
  scheduleRender();

  try {
    const payload = await fetchJson("/api/messaging/server-workflows", {
      auth: true,
      method: "POST",
      body: {
        scopeType,
        scopeId,
        name,
        trigger,
        ...(trigger === "message_keyword" ? { keyword } : {}),
        ...(trigger === "schedule" ? { schedule } : {}),
        enabled: true,
        actions: [action],
      },
    });
    upsertMessagingWorkflow(payload.workflow || {});
    showToast("Workflow created.");
    return true;
  } catch (error) {
    workflowState.error =
      normalizeString(error?.message) || "Workflow create failed.";
    showToast(workflowState.error);
    return false;
  } finally {
    workflowState.creating = false;
    scheduleRender();
  }
}

