  const linksState = state.pages.messaging.roomInviteLinks;
  linksState.items = [
    normalizedLink,
    ...(linksState.items || []).filter((item) => {
      const itemKey = normalizeString(item.inviteId || item.token);
      return itemKey !== linkKey;
    }),
  ];
