async function updateMessagingRoomSettings(formData) {
  const conversationId = normalizeString(formData.get("conversationId"));
  const scopeType = normalizeString(formData.get("scopeType"));
  const scopeId = normalizeString(formData.get("scopeId"));
  const title = normalizeString(formData.get("title"));
  const topic = normalizeString(formData.get("topic"));
  const categoryId = normalizeString(formData.get("categoryId"));
  const currentRoomType =
    normalizeString(formData.get("currentRoomType")).toLowerCase() ||
    "public_within_scope";
  const advancedRoomType = messagingRoomIsAdvancedRoomType(currentRoomType);
  const announcementOnly =
    !advancedRoomType && formData.get("announcementOnly") === "on";
  const roomType = advancedRoomType
    ? currentRoomType
    : announcementOnly
      ? "announcement_only"
      : "public_within_scope";
  const slowmodeSeconds = normalizeMessagingRoomSlowmode(
    Number(formData.get("slowmodeSeconds")),
  );
  const hideAfterInactivityHours = normalizeMessagingRoomHideAfterHours(
    Number(formData.get("hideAfterInactivityHours")),
  );
  if (!conversationId || !title) {
    showToast("Room name is required.");
    return false;
  }
  if (topic.length > 1024) {
    showToast("Room topics are limited to 1024 characters.");
    return false;
  }
  const conversation = state.pages.messaging.conversation;
  if (conversation.settingsPending) {
    return false;
  }
  conversation.settingsPending = true;
  conversation.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/messaging/conversations/${encodeURIComponent(conversationId)}/settings`,
      {
        auth: true,
        method: "PATCH",
        body: {
          title,
          topic,
          roomType,
          announcementOnly,
          slowmodeSeconds,
          hideAfterInactivityHours,
          categoryId: categoryId || null,
        },
      },
    );
    if (payload.conversation) {
      conversation.item = normalizeMessagingConversation(payload.conversation);
    }
    await Promise.all([
      loadMessagingConversation(conversationId, { refresh: true }).catch(() => {}),
      scopeType && scopeId
        ? loadMessagingServerDirectory(scopeType, scopeId, { refresh: true }).catch(
            () => {},
          )
        : Promise.resolve(),
    ]);
    showToast("Room settings updated.");
    return true;
  } catch (error) {
    conversation.error =
      normalizeString(error?.message) || "Room settings could not be updated.";
    showToast(conversation.error);
    return false;
  } finally {
    conversation.settingsPending = false;
    scheduleRender();
  }
}

