async function createMessagingChannelInviteLink(formData) {
  const conversationId = normalizeString(formData.get("conversationId"));
  const expiresIn = normalizeString(formData.get("expiresIn")) || "7d";
  const maxUsesValue = Number(formData.get("maxUses"));
  const maxUses =
    Number.isFinite(maxUsesValue) && maxUsesValue > 0
      ? Math.trunc(maxUsesValue)
      : null;
  if (!conversationId) {
    showToast("Room invite links unavailable.");
    return false;
  }
  const linksState = state.pages.messaging.roomInviteLinks;
  if (linksState.actionPendingKey) {
    return false;
  }
  linksState.actionPendingKey = "create";
  linksState.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/messaging/conversations/${encodeURIComponent(conversationId)}/invite-links`,
      {
        auth: true,
        method: "POST",
        body: {
          expiresIn,
          ...(maxUses ? { maxUses } : {}),
        },
      },
    );
    const link = payload.link || payload;
    upsertMessagingChannelInviteLink(link);
    const token = normalizeString(link?.token);
    if (token) {
      linksState.latestToken = token;
    }
    await loadMessagingChannelInviteLinks(conversationId, {
      refresh: true,
    }).catch(() => {});
    showToast("Invite link created.");
    return true;
  } catch (error) {
    linksState.error =
      normalizeString(error?.message) || "Invite link could not be created.";
    showToast(linksState.error);
    return false;
  } finally {
    if (linksState.actionPendingKey === "create") {
      linksState.actionPendingKey = "";
    }
    scheduleRender();
  }
}

