function currentMessagingPermissionBundle() {
  return state.pages.messaging.permissionTarget.bundle || {};
}

function currentMessagingPermissionTarget() {
  const bundle = currentMessagingPermissionBundle();
  return bundle.target && typeof bundle.target === "object"
    ? bundle.target
    : state.pages.messaging.permissionTarget.item || {};
}

function currentMessagingPermissionRoles() {
  return messagingPermissionRolesFromBundle(
    currentMessagingPermissionBundle(),
    state.pages.messaging.serverRoles.items,
  );
}

function setMessagingPermissionTargetFromPayload(payload = {}) {
  const permissionState = state.pages.messaging.permissionTarget;
  const existingBundle = permissionState.bundle || {};
  const target =
    payload.target && typeof payload.target === "object"
      ? payload.target
      : payload && typeof payload === "object"
        ? payload
        : {};
  permissionState.bundle = {
    ...existingBundle,
    ...payload,
    target,
    roles: Array.isArray(payload.roles)
      ? payload.roles
      : Array.isArray(existingBundle.roles)
        ? existingBundle.roles
        : [],
  };
  permissionState.item = target;
  permissionState.loaded = true;
}

function buildMessagingPermissionTargetPayload(overrides = []) {
  return overrides
    .map((entry) => ({
      subjectId: normalizeString(entry.subjectId),
      permissions: normalizeMessagingPermissionSet(entry.permissions),
    }))
    .filter((entry) => entry.subjectId);
}

async function saveMessagingPermissionTarget({
  targetType,
  targetId,
  overrides,
  syncState,
  pendingKey = "permission-save",
  successMessage = "Permissions updated.",
} = {}) {
  const normalizedTargetType = normalizeString(targetType).toLowerCase();
  const normalizedTargetId = normalizeString(targetId);
  const permissionState = state.pages.messaging.permissionTarget;
  if (!normalizedTargetType || !normalizedTargetId) {
    showToast("Permission target unavailable.");
    return false;
  }
  permissionState.actionPendingKey = pendingKey;
  permissionState.saving = true;
  permissionState.error = "";
  scheduleRender();
  try {
    const body = {
      overrides: buildMessagingPermissionTargetPayload(overrides),
    };
    if (normalizeString(syncState)) {
      body.syncState = normalizeString(syncState);
    }
    const payload = await fetchJson(
      `/api/messaging/permission-targets/${encodeURIComponent(normalizedTargetType)}/${encodeURIComponent(normalizedTargetId)}`,
      {
        auth: true,
        method: "PUT",
        body,
      },
    );
    setMessagingPermissionTargetFromPayload(payload);
    showToast(successMessage);
    return true;
  } catch (error) {
    permissionState.error =
      normalizeString(error?.message) || "Permission update failed.";
    showToast(permissionState.error);
    return false;
  } finally {
    if (permissionState.actionPendingKey === pendingKey) {
      permissionState.actionPendingKey = "";
    }
    permissionState.saving = false;
    scheduleRender();
  }
}

function messagingPermissionTargetFromForm(formData) {
  return {
    targetType: normalizeString(formData.get("targetType")).toLowerCase(),
    targetId: normalizeString(formData.get("targetId")),
  };
}

function messagingPermissionRoleFromId(roleId) {
  const normalizedRoleId = normalizeString(roleId);
  return (
    currentMessagingPermissionRoles().find(
      (role) => role.roleId === normalizedRoleId,
    ) || null
  );
}

function messagingPermissionOverridesForEdit() {
  return messagingPermissionOverridesFromTarget(
    currentMessagingPermissionTarget(),
    currentMessagingPermissionRoles(),
  );
}

function readMessagingPermissionFormValues(formData) {
  return Object.fromEntries(
    MESSAGING_PERMISSION_KEYS.map((key) => [
      key,
      normalizeMessagingPermissionValue(formData.get(`permission:${key}`)),
    ]),
  );
}

async function saveMessagingPermissionRoleOverride(formData) {
  const { targetType, targetId } = messagingPermissionTargetFromForm(formData);
  const roleId = normalizeString(formData.get("roleId"));
  const role = messagingPermissionRoleFromId(roleId);
  if (!role) {
    showToast("Role unavailable.");
    return false;
  }
  const permissions = readMessagingPermissionFormValues(formData);
  const nextOverrides = messagingPermissionOverridesForEdit().filter(
    (entry) => entry.subjectId !== role.roleId,
  );
  if (!messagingPermissionAllInherited(permissions) || role.isEveryone) {
    nextOverrides.push({
      subjectId: role.roleId,
      permissions,
    });
  }
  return saveMessagingPermissionTarget({
    targetType,
    targetId,
    overrides: nextOverrides,
    pendingKey: `${targetType}:${targetId}:${role.roleId}:save`,
    successMessage: "Role permissions saved.",
  });
}

async function addMessagingPermissionRoleOverride(formData) {
  const { targetType, targetId } = messagingPermissionTargetFromForm(formData);
  const roleId = normalizeString(formData.get("roleId"));
  const role = messagingPermissionRoleFromId(roleId);
  if (!role) {
    showToast("Choose a role to add.");
    return false;
  }
  const currentOverrides = messagingPermissionOverridesForEdit();
  const roleRouteTemplate = normalizeString(formData.get("roleRouteTemplate"));
  const roleRoute = roleRouteTemplate
    ? roleRouteTemplate.replace("__ROLE_ID__", encodeURIComponent(role.roleId))
    : normalizeString(formData.get("roleRoute"));
  if (currentOverrides.some((entry) => entry.subjectId === role.roleId)) {
    if (roleRoute) navigateTo(roleRoute);
    return true;
  }
  const isPrivate =
    currentOverrides.find((entry) => entry.isEveryone)?.permissions
      ?.viewChannel === "deny";
  const permissions = normalizeMessagingPermissionSet({
    viewChannel: isPrivate ? "allow" : "inherit",
  });
  const saved = await saveMessagingPermissionTarget({
    targetType,
    targetId,
    overrides: [
      ...currentOverrides,
      {
        subjectId: role.roleId,
        permissions,
      },
    ],
    pendingKey: `${targetType}:${targetId}:${role.roleId}:add`,
    successMessage: "Role override added.",
  });
  if (saved) {
    if (roleRoute) {
      navigateTo(roleRoute);
    }
  }
  return saved;
}

async function removeMessagingPermissionRoleOverride({
  targetType,
  targetId,
  roleId,
  returnRoute = "",
} = {}) {
  const normalizedRoleId = normalizeString(roleId);
  if (!normalizedRoleId) {
    showToast("Role override unavailable.");
    return false;
  }
  const nextOverrides = messagingPermissionOverridesForEdit().filter(
    (entry) => entry.subjectId !== normalizedRoleId,
  );
  const saved = await saveMessagingPermissionTarget({
    targetType,
    targetId,
    overrides: nextOverrides,
    pendingKey: `${targetType}:${targetId}:${normalizedRoleId}:remove`,
    successMessage: "Role override removed.",
  });
  if (saved && normalizeString(returnRoute)) {
    navigateTo(returnRoute);
  }
  return saved;
}

async function toggleMessagingPermissionPrivate({
  targetType,
  targetId,
  privateMode,
} = {}) {
  const roles = currentMessagingPermissionRoles();
  const everyoneRole = roles.find((role) => role.isEveryone);
  if (!everyoneRole) {
    showToast("Default role unavailable.");
    return false;
  }
  const currentOverrides = messagingPermissionOverridesForEdit();
  const existingEveryone = currentOverrides.find((entry) => entry.isEveryone);
  const nextEveryonePermissions = normalizeMessagingPermissionSet({
    ...(existingEveryone?.permissions || {}),
    viewChannel: privateMode ? "deny" : "inherit",
  });
  const nextOverrides = currentOverrides.filter((entry) => !entry.isEveryone);
  if (!messagingPermissionAllInherited(nextEveryonePermissions)) {
    nextOverrides.unshift({
      subjectId: everyoneRole.roleId,
      permissions: nextEveryonePermissions,
    });
  }
  return saveMessagingPermissionTarget({
    targetType,
    targetId,
    overrides: nextOverrides,
    pendingKey: `${targetType}:${targetId}:private`,
    successMessage: privateMode
      ? "Private access enabled."
      : "Default access restored.",
  });
}

