async function createMessagingDmFromTarget({ recipientId = "", username = "" } = {}) {
  const compose = state.pages.messaging.compose;
  const normalizedRecipientId = normalizeString(recipientId);
  const normalizedUsername = normalizeString(username).replace(/^@/u, "");
  compose.recipientId = normalizedRecipientId;
  compose.username = normalizedUsername;
  if (!normalizedRecipientId && !normalizedUsername) {
    compose.error = "Choose a person or enter a username.";
    scheduleRender();
    return;
  }
  compose.pending = true;
  compose.error = "";
  scheduleRender();

  try {
    const payload = await fetchJson("/api/messaging/dm", {
      auth: true,
      method: "POST",
      body: {
        ...(normalizedRecipientId ? { targetUserId: normalizedRecipientId } : {}),
        ...(normalizedUsername ? { username: normalizedUsername } : {}),
      },
    });
    const conversationId = normalizeString(
      payload.conversation?.conversationId || payload.conversationId,
    );
    if (conversationId) {
      state.pages.messaging.compose = {
        ...createMessagingComposeState(),
        friends: compose.friends,
      };
      navigateTo(
        `/messages/conversations/${encodeURIComponent(conversationId)}`,
      );
    }
  } catch (error) {
    compose.error =
      normalizeString(error?.message) || "Unable to start direct message.";
    scheduleRender();
  } finally {
    compose.pending = false;
    scheduleRender();
  }
}

async function createMessagingDm(formData) {
  const selectedKey = normalizeString(formData.get("selectedKey"));
  const selected = selectedKey ? findMessagingComposeCandidate(selectedKey) : null;
  await createMessagingDmFromTarget({
    recipientId:
      normalizeString(selected?.userId) || normalizeString(formData.get("recipientId")),
    username:
      normalizeString(selected?.username) || normalizeString(formData.get("username")),
  });
}

async function createMessagingGroup(formData) {
  const compose = state.pages.messaging.compose;
  const selected = compose.selected || [];
  const title = normalizeString(formData.get("groupTitle") || compose.groupTitle);
  if (!selected.length) {
    compose.error = "Select at least one person for the group.";
    scheduleRender();
    return;
  }
  const blocked = selected.find((candidate) => candidate.blockedByPrivacy);
  if (blocked) {
    compose.error = blocked.reason || "Remove blocked selections before creating the group.";
    showToast(compose.error);
    scheduleRender();
    return;
  }
  const members = selected
    .map((candidate) => {
      const userId = normalizeString(candidate.userId);
      const username = normalizeString(candidate.username).replace(/^@/u, "");
      return userId ? { userId } : username ? { username } : null;
    })
    .filter(Boolean);
  if (!members.length) {
    compose.error = "Selected people need a user id or username.";
    scheduleRender();
    return;
  }
  compose.pending = true;
  compose.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson("/api/messaging/groups", {
      auth: true,
      method: "POST",
      body: {
        ...(title ? { title } : {}),
        members,
      },
    });
    const conversationId = normalizeString(
      payload.conversation?.conversationId || payload.conversationId,
    );
    if (conversationId) {
      state.pages.messaging.compose = {
        ...createMessagingComposeState(),
        friends: compose.friends,
      };
      navigateTo(
        `/messages/conversations/${encodeURIComponent(conversationId)}`,
      );
    }
  } catch (error) {
    compose.error =
      normalizeString(error?.message) || "Unable to create group.";
    showToast(compose.error);
  } finally {
    compose.pending = false;
    scheduleRender();
  }
}

async function submitMessagingCompose(formData) {
  const mode = normalizeString(formData.get("mode") || state.pages.messaging.compose.mode);
  if (mode === "group") {
    await createMessagingGroup(formData);
    return;
  }
  await createMessagingDm(formData);
}

function buildMessagingClientMessageId() {
  const randomId =
    typeof window.crypto?.randomUUID === "function"
      ? window.crypto.randomUUID()
      : `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
  return `web-${randomId}`;
}

function normalizeMessagingAttachmentHttpUrl(value) {
  const normalized = normalizeString(value);
  if (!normalized) {
    return "";
  }
  try {
    const url = new URL(normalized);
    if (!["http:", "https:"].includes(url.protocol)) {
      return "";
    }
    return url.toString();
  } catch {
    return "";
  }
}

function inferMessagingAttachmentMimeType(value, urlValue = "") {
  const normalized = normalizeString(value).toLowerCase();
  if (normalized) {
    return normalized;
  }
  const url = normalizeMessagingAttachmentHttpUrl(urlValue);
  if (!url) {
    return "";
  }
  let pathname = "";
  try {
    pathname = new URL(url).pathname.toLowerCase();
  } catch {
    pathname = url.toLowerCase();
  }
  const extension = pathname.split(".").pop() || "";
  const types = {
    jpg: "image/jpeg",
    jpeg: "image/jpeg",
    png: "image/png",
    webp: "image/webp",
    gif: "image/gif",
    mp4: "video/mp4",
    mov: "video/quicktime",
    webm: "video/webm",
  };
  return types[extension] || "";
}

function messagingAttachmentFileNameFromUrl(urlValue) {
  const url = normalizeMessagingAttachmentHttpUrl(urlValue);
  if (!url) {
    return "";
  }
  try {
    const name = new URL(url).pathname.split("/").filter(Boolean).pop() || "";
    return decodeURIComponent(name).slice(0, 120);
  } catch {
    return "";
  }
}

function isMessagingAttachmentFile(value) {
  return Boolean(
    value &&
      typeof value === "object" &&
      Number(value.size) > 0 &&
      normalizeString(value.name),
  );
}

function isAllowedMessagingAttachmentMimeType(value) {
  const mimeType = normalizeString(value).toLowerCase();
  return Boolean(
    mimeType &&
      mimeType !== "image/svg+xml" &&
      (mimeType.startsWith("image/") || mimeType.startsWith("video/")),
  );
}

function messagingAttachmentMaxBytes(mimeType) {
  return normalizeString(mimeType).toLowerCase().startsWith("video/")
    ? MESSAGING_ATTACHMENT_VIDEO_MAX_BYTES
    : MESSAGING_ATTACHMENT_IMAGE_MAX_BYTES;
}

function validateMessagingAttachmentFile(file, mimeType) {
  if (!isMessagingAttachmentFile(file)) {
    return "Choose an image or video file.";
  }
  if (!isAllowedMessagingAttachmentMimeType(mimeType)) {
    return "Choose an image or video file for the attachment.";
  }
  const maxBytes = messagingAttachmentMaxBytes(mimeType);
  if (Number(file.size) > maxBytes) {
    return `${normalizeString(mimeType).startsWith("video/") ? "Video" : "Image"} attachments must be ${formatComposerFileSize(maxBytes)} or smaller.`;
  }
  return "";
}

function readMessagingAttachmentDraft(formData) {
  const stateDraft =
    state.pages.messaging.conversation.attachmentDraft ||
    createMessagingAttachmentDraft();
  const formFile = formData?.get("attachmentFile");
  const file = isMessagingAttachmentFile(stateDraft.file)
    ? stateDraft.file
    : isMessagingAttachmentFile(formFile)
      ? formFile
      : null;
  return {
    url:
      normalizeString(formData?.get("attachmentUrl")) ||
      normalizeString(stateDraft.url),
    fileName:
      normalizeString(formData?.get("attachmentFileName")) ||
      normalizeString(stateDraft.fileName) ||
      normalizeString(file?.name),
    mimeType:
      normalizeString(formData?.get("attachmentMimeType")) ||
      normalizeString(stateDraft.mimeType) ||
      normalizeString(file?.type),
    file,
  };
}

function updateMessagingAttachmentPreview(form) {
  if (!form) {
    return;
  }
  const formData = new FormData(form);
  const draft = readMessagingAttachmentDraft(formData);
  const inferredType = inferMessagingAttachmentMimeType(
    draft.mimeType,
    draft.file?.name || draft.url,
  );
  const label =
    draft.fileName ||
    messagingAttachmentFileNameFromUrl(draft.url) ||
    "Media attachment";
  const detail =
    [inferredType, draft.file ? formatComposerFileSize(draft.file.size) : ""]
      .filter(Boolean)
      .join(" / ") ||
    (draft.url ? "Choose type before sending" : "Image or video URL");
  const labelEl = form.querySelector(
    "[data-messaging-attachment-preview-label]",
  );
  const detailEl = form.querySelector(
    "[data-messaging-attachment-preview-detail]",
  );
  if (labelEl) {
    labelEl.textContent = label;
  }
  if (detailEl) {
    detailEl.textContent = detail;
  }
}

function normalizeMessagingAttachmentForSend(raw = {}, fallback = {}) {
  const source = raw && typeof raw === "object" ? raw : {};
  const mimeType =
    normalizeString(source.mimeType || source.contentType) ||
    normalizeString(fallback.mimeType);
  return {
    attachmentId: normalizeString(source.attachmentId || source.id),
    url: normalizeUrl(source.url || source.downloadUrl || fallback.url),
    bucket: normalizeString(source.bucket || fallback.bucket),
    key: normalizeString(source.key || fallback.key),
    fileName:
      normalizeString(source.fileName || source.name || fallback.fileName) ||
      "Attachment",
    mimeType,
    contentType: mimeType,
    size: Number(source.size || fallback.size) || null,
    width: Number(source.width || fallback.width) || null,
    height: Number(source.height || fallback.height) || null,
    durationMs: Number(source.durationMs || fallback.durationMs) || null,
    thumbnailUrl: normalizeUrl(source.thumbnailUrl || fallback.thumbnailUrl),
  };
}

async function uploadMessagingAttachmentFile(conversationId, draft) {
  const file = draft.file;
  const fileName = normalizeString(draft.fileName || file?.name) || "attachment";
  const mimeType = inferMessagingAttachmentMimeType(
    draft.mimeType || file?.type,
    fileName,
  );
  const validationError = validateMessagingAttachmentFile(file, mimeType);
  if (validationError) {
    return { attachments: [], error: validationError };
  }
  const payload = await fetchJson("/api/messaging/uploads/create", {
    auth: true,
    method: "POST",
    body: {
      conversationId,
      fileName,
      mimeType,
      size: Number(file.size),
    },
  });
  const uploadRef = normalizeString(payload.uploadRef);
  const upload = payload.upload && typeof payload.upload === "object"
    ? payload.upload
    : {};
  const uploadUrl = normalizeUrl(upload.uploadUrl || upload.url);
  if (!uploadRef || !uploadUrl) {
    throw new Error("Messaging upload session was incomplete.");
  }
  const response = await fetch(uploadUrl, {
    method: normalizeString(upload.method).toUpperCase() || "PUT",
    headers:
      upload.headers && typeof upload.headers === "object"
        ? upload.headers
        : { "Content-Type": mimeType },
    body: file,
  });
  if (!response.ok) {
    throw new Error(`Attachment upload failed: ${response.status}`);
  }
  const finalized = await fetchJson("/api/messaging/uploads/finalize", {
    auth: true,
    method: "POST",
    body: {
      conversationId,
      uploadRef,
    },
  });
  const attachment = normalizeMessagingAttachmentForSend(
    finalized.attachment || payload.attachment || {},
    { fileName, mimeType, size: file.size },
  );
  if (
    !attachment.attachmentId &&
    !attachment.url &&
    !(attachment.bucket && attachment.key)
  ) {
    throw new Error("Messaging upload did not return an attachment.");
  }
  return { attachments: [attachment], error: "" };
}

async function buildMessagingAttachmentPayload(formData, conversationId) {
  const draft = readMessagingAttachmentDraft(formData);
  const hasDraft = Boolean(
    draft.file || draft.url || draft.fileName || draft.mimeType,
  );
  if (!hasDraft) {
    return { attachments: [], error: "" };
  }
  if (draft.file) {
    const conversationState = state.pages.messaging.conversation;
    conversationState.uploadingAttachment = true;
    conversationState.error = "";
    scheduleRender();
    try {
      return await uploadMessagingAttachmentFile(conversationId, draft);
    } finally {
      conversationState.uploadingAttachment = false;
      scheduleRender();
    }
  }
  const url = normalizeMessagingAttachmentHttpUrl(draft.url);
  if (!url) {
    return {
      attachments: [],
      error: "Use a valid http or https media URL, or clear the attachment.",
    };
  }
  const mimeType = inferMessagingAttachmentMimeType(draft.mimeType, url);
  if (!isAllowedMessagingAttachmentMimeType(mimeType)) {
    return {
      attachments: [],
      error: "Choose an image or video type for the media attachment.",
    };
  }
  const fileName =
    draft.fileName || messagingAttachmentFileNameFromUrl(url) || "Attachment";
  const randomId =
    typeof window.crypto?.randomUUID === "function"
      ? window.crypto.randomUUID()
      : `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
  return {
    attachments: [
      normalizeMessagingAttachmentForSend({
        attachmentId: `web-url-${randomId}`,
        url,
        fileName,
        mimeType,
        contentType: mimeType,
      }),
    ],
    error: "",
  };
}

async function sendMessagingDraft(
  conversationId,
  text,
  attachments = [],
  { replyTo = null } = {},
) {
  const normalizedConversationId = normalizeString(conversationId);
  const normalizedText = normalizeString(text);
  const normalizedAttachments = Array.isArray(attachments)
    ? attachments.filter((attachment) => normalizeString(attachment?.url))
    : [];
  const replyPreview = normalizeMessagingReplyPreview(replyTo);
  const conversation = state.pages.messaging.conversation.item;
  if (!normalizedConversationId || (!normalizedText && !normalizedAttachments.length)) {
    return false;
  }
  if (conversation?.isEncrypted) {
    state.pages.messaging.conversation.error =
      "Encrypted replies require mobile app message keys. Use the secure options below.";
    showToast("Open the app or restore a trusted device to reply.");
    scheduleRender();
    return false;
  }
  state.pages.messaging.conversation.sending = true;
  state.pages.messaging.conversation.error = "";
  scheduleRender();

  try {
    const clientMessageId = buildMessagingClientMessageId();
    const payload = await fetchJson(
      `/api/messaging/conversations/${encodeURIComponent(normalizedConversationId)}/messages`,
      {
        auth: true,
        method: "POST",
        body: {
          clientMessageId,
          type: normalizedText ? "text" : "media",
          ...(normalizedText ? { text: normalizedText } : {}),
          ...(normalizedAttachments.length
            ? { attachments: normalizedAttachments }
            : {}),
          ...(replyPreview
            ? {
                replyToMessageId: replyPreview.messageId,
                replyTo: replyPreview,
              }
            : {}),
        },
      },
    );
    const message = normalizeMessagingMessage(payload.message || payload);
    state.pages.messaging.conversation.messages = [
      ...state.pages.messaging.conversation.messages,
      message,
    ];
    state.pages.messaging.conversation.draft = "";
    state.pages.messaging.conversation.attachmentDraft =
      createMessagingAttachmentDraft();
    state.pages.messaging.conversation.attachmentEditorOpen = false;
    state.pages.messaging.conversation.pendingReply = null;
    state.pages.messaging.conversation.error = "";
    return true;
  } catch (error) {
    const message = normalizeString(error?.message) || "Message send failed.";
    state.pages.messaging.conversation.error = message;
    showToast(message);
    return false;
  } finally {
    state.pages.messaging.conversation.sending = false;
    scheduleRender();
  }
}

function currentMessagingUserId() {
  return normalizeString(state.auth.user?.userId);
}

function canEditMessagingMessageInWeb(message, currentUserId = "") {
  if (!message || message.isDeleted || message.isEncrypted) {
    return false;
  }
  if (normalizeString(message.type || "text") !== "text") {
    return false;
  }
  if (normalizeString(message.senderUserId) !== normalizeString(currentUserId)) {
    return false;
  }
  const canEditUntil =
    Number(message.canEditUntil) ||
    (Number(message.createdAt)
      ? Number(message.createdAt) + MESSAGING_MESSAGE_EDIT_WINDOW_MS
      : 0);
  return Boolean(canEditUntil && Date.now() <= canEditUntil);
}

function canDeleteMessagingMessageInWeb(message, currentUserId = "") {
  return Boolean(
    message &&
      !message.isDeleted &&
      !message.isEncrypted &&
      normalizeString(message.senderUserId) === normalizeString(currentUserId),
  );
}

function canReplyMessagingMessageInWeb(message) {
  const conversation = state.pages.messaging.conversation.item;
  return Boolean(
    message?.messageId &&
      !message.isDeleted &&
      !message.isEncrypted &&
      conversation &&
      !conversation.isEncrypted,
  );
}

function canReportMessagingMessageInWeb(message, currentUserId = "") {
  return Boolean(
    message?.messageId &&
      !message.isDeleted &&
      !message.isEncrypted &&
      normalizeString(message.senderUserId) !== normalizeString(currentUserId),
  );
}

function replaceMessagingMessage(nextMessage) {
  const normalized = normalizeMessagingMessage(nextMessage);
  if (!normalized.messageId) {
    return;
  }
  updateMessagingMessage(normalized.messageId, (message) => ({
    ...message,
    ...normalized,
  }));
}

function focusMessagingComposerSoon() {
  window.setTimeout(() => {
    try {
      root
        ?.querySelector('[data-route-form="messaging-send"] textarea[name="text"]')
        ?.focus();
    } catch {
      // Focus is best effort after rerender.
    }
  }, 0);
}

function startEditingMessagingMessage(messageId) {
  const normalizedMessageId = normalizeString(messageId);
  const conversation = state.pages.messaging.conversation;
  const message = conversation.messages.find(
    (item) => item.messageId === normalizedMessageId,
  );
  if (
    !message ||
    !canEditMessagingMessageInWeb(message, currentMessagingUserId())
  ) {
    showToast("This message can no longer be edited.");
    return;
  }
  conversation.editingMessageId = message.messageId;
  conversation.editingOriginalText = normalizeString(message.text);
  conversation.pendingReply = null;
  conversation.draft = normalizeString(message.text);
  conversation.attachmentDraft = createMessagingAttachmentDraft();
  conversation.attachmentEditorOpen = false;
  conversation.error = "";
  scheduleRender();
  focusMessagingComposerSoon();
}

function cancelEditingMessagingMessage() {
  const conversation = state.pages.messaging.conversation;
  conversation.editingMessageId = "";
  conversation.editingOriginalText = "";
  conversation.draft = "";
  conversation.error = "";
  scheduleRender();
}

function startReplyingToMessagingMessage(messageId) {
  const normalizedMessageId = normalizeString(messageId);
  const conversation = state.pages.messaging.conversation;
  const message = conversation.messages.find(
    (item) => item.messageId === normalizedMessageId,
  );
  if (!message || !canReplyMessagingMessageInWeb(message)) {
    showToast("This message cannot be replied to from the browser.");
    return;
  }
  conversation.editingMessageId = "";
  conversation.editingOriginalText = "";
  conversation.pendingReply = messagingReplyPreviewFromMessage(message);
  conversation.error = "";
  scheduleRender();
  focusMessagingComposerSoon();
}

function cancelReplyingToMessagingMessage() {
  const conversation = state.pages.messaging.conversation;
  conversation.pendingReply = null;
  conversation.error = "";
  scheduleRender();
}

function jumpToMessagingReplyTarget(messageId) {
  const normalizedMessageId = normalizeString(messageId);
  if (!normalizedMessageId) {
    return;
  }
  const target = Array.from(root?.querySelectorAll("[data-message-id]") || []).find(
    (item) => item.getAttribute("data-message-id") === normalizedMessageId,
  );
  if (!target) {
    showToast("Original message is not loaded.");
    return;
  }
  target.scrollIntoView({ behavior: "smooth", block: "center" });
  target.classList.add("is-highlighted");
  window.setTimeout(() => {
    target.classList.remove("is-highlighted");
  }, 1600);
}

function messagingReportEvidenceFromMessage(message) {
  if (!message || message.isEncrypted) {
    return null;
  }
  return {
    messageText: normalizeString(message.text),
    contentKind: normalizeString(message.type || "text"),
    senderUserId: normalizeString(message.senderUserId),
    senderDisplayName: normalizeString(message.senderDisplayName),
    createdAt: Number(message.createdAt) || null,
    attachments: (message.attachments || []).map((attachment) => ({
      fileName: normalizeString(attachment.fileName),
      contentType: normalizeString(attachment.contentType),
      url: normalizeUrl(attachment.url),
    })),
  };
}

function openMessagingMessageReport(messageId) {
  const normalizedMessageId = normalizeString(messageId);
  const conversation = state.pages.messaging.conversation;
  const message = conversation.messages.find(
    (item) => item.messageId === normalizedMessageId,
  );
  if (!message || !canReportMessagingMessageInWeb(message, currentMessagingUserId())) {
    showToast("This message cannot be reported from the browser.");
    return;
  }
  conversation.reportingMessageId = message.messageId;
  conversation.error = "";
  scheduleRender();
  window.setTimeout(() => {
    try {
      root
        ?.querySelector('[data-route-form="messaging-message-report"]')
        ?.focus();
    } catch {
      // Focus is best effort after rerender.
    }
  }, 0);
}

function cancelMessagingMessageReport() {
  const conversation = state.pages.messaging.conversation;
  conversation.reportingMessageId = "";
  conversation.error = "";
  scheduleRender();
}

async function submitMessagingMessageReport(formData) {
  const conversation = state.pages.messaging.conversation;
  const conversationItem = conversation.item || {};
  const conversationId =
    normalizeString(formData.get("conversationId")) ||
    normalizeString(conversationItem.conversationId);
  const messageId = normalizeString(formData.get("messageId"));
  const message = conversation.messages.find(
    (item) => item.messageId === messageId,
  );
  if (!message || !canReportMessagingMessageInWeb(message, currentMessagingUserId())) {
    conversation.error = "This message cannot be reported from the browser.";
    showToast(conversation.error);
    scheduleRender();
    return false;
  }
  const requestedReason = normalizeString(formData.get("reasonCode"));
  const reasonCode = MESSAGING_REPORT_REASON_OPTIONS.some(
    ([key]) => key === requestedReason,
  )
    ? requestedReason
    : "user_report";
  const details = normalizeString(formData.get("details"));
  const pendingKey = `report:${messageId}`;
  conversation.messageActionPendingKey = pendingKey;
  conversation.error = "";
  scheduleRender();
  try {
    await fetchJson("/api/messaging/report", {
      auth: true,
      method: "POST",
      body: {
        targetType: "message",
        targetId: messageId,
        reasonCode,
        ...(details ? { details } : {}),
        ...(conversationId ? { conversationId } : {}),
        ...(conversationItem.scopeType ? { scopeType: conversationItem.scopeType } : {}),
        ...(conversationItem.scopeId ? { scopeId: conversationItem.scopeId } : {}),
        decryptedEvidence: messagingReportEvidenceFromMessage(message),
      },
    });
    conversation.reportingMessageId = "";
    conversation.error = "";
    showToast("Message reported.");
    return true;
  } catch (error) {
    const messageText =
      normalizeString(error?.message) || "Message report failed.";
    conversation.error = messageText;
    showToast(messageText);
    return false;
  } finally {
    if (conversation.messageActionPendingKey === pendingKey) {
      conversation.messageActionPendingKey = "";
    }
    scheduleRender();
  }
}

async function editMessagingDraft(conversationId, text) {
  const normalizedConversationId = normalizeString(conversationId);
  const normalizedText = normalizeString(text);
  const conversation = state.pages.messaging.conversation;
  const messageId = normalizeString(conversation.editingMessageId);
  if (!normalizedConversationId || !messageId) {
    return false;
  }
  if (!normalizedText) {
    conversation.error = "Enter message text before saving.";
    scheduleRender();
    return false;
  }
  const originalMessage = conversation.messages.find(
    (message) => message.messageId === messageId,
  );
  if (
    !originalMessage ||
    !canEditMessagingMessageInWeb(originalMessage, currentMessagingUserId())
  ) {
    conversation.error = "This message can no longer be edited.";
    showToast(conversation.error);
    scheduleRender();
    return false;
  }
  conversation.sending = true;
  conversation.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/messaging/conversations/${encodeURIComponent(normalizedConversationId)}/messages/${encodeURIComponent(messageId)}`,
      {
        auth: true,
        method: "PUT",
        body: { text: normalizedText },
      },
    );
    replaceMessagingMessage(payload.message || payload);
    conversation.editingMessageId = "";
    conversation.editingOriginalText = "";
    conversation.draft = "";
    conversation.error = "";
    showToast("Message updated.");
    return true;
  } catch (error) {
    const message = normalizeString(error?.message) || "Message edit failed.";
    conversation.error = message;
    showToast(message);
    return false;
  } finally {
    conversation.sending = false;
    scheduleRender();
  }
}

async function deleteMessagingMessage(conversationId, messageId) {
  const normalizedConversationId = normalizeString(conversationId);
  const normalizedMessageId = normalizeString(messageId);
  const conversation = state.pages.messaging.conversation;
  const message = conversation.messages.find(
    (item) => item.messageId === normalizedMessageId,
  );
  if (
    !normalizedConversationId ||
    !normalizedMessageId ||
    !canDeleteMessagingMessageInWeb(message, currentMessagingUserId())
  ) {
    showToast("This message cannot be deleted from the browser.");
    return false;
  }
  if (
    !window.confirm(
      "Delete this message for everyone in the conversation?",
    )
  ) {
    return false;
  }
  const pendingKey = `delete:${normalizedMessageId}`;
  conversation.messageActionPendingKey = pendingKey;
  conversation.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/messaging/conversations/${encodeURIComponent(normalizedConversationId)}/messages/${encodeURIComponent(normalizedMessageId)}`,
      {
        auth: true,
        method: "DELETE",
        body: { deleteForEveryone: true },
      },
    );
    replaceMessagingMessage(payload.message || payload);
    if (conversation.editingMessageId === normalizedMessageId) {
      conversation.editingMessageId = "";
      conversation.editingOriginalText = "";
      conversation.draft = "";
    }
    if (conversation.pendingReply?.messageId === normalizedMessageId) {
      conversation.pendingReply = null;
    }
    showToast("Message deleted.");
    return true;
  } catch (error) {
    const messageText =
      normalizeString(error?.message) || "Message delete failed.";
    conversation.error = messageText;
    showToast(messageText);
    return false;
  } finally {
    if (conversation.messageActionPendingKey === pendingKey) {
      conversation.messageActionPendingKey = "";
    }
    scheduleRender();
  }
}

function messagingReactionPendingKey(messageId, emoji) {
  const normalizedMessageId = normalizeString(messageId);
  const normalizedEmoji = normalizeString(emoji);
  return normalizedMessageId && normalizedEmoji
    ? `${normalizedMessageId}:${normalizedEmoji}`
    : "";
}

function updateMessagingMessage(messageId, updater) {
  const normalizedMessageId = normalizeString(messageId);
  if (!normalizedMessageId || typeof updater !== "function") {
    return;
  }
  const conversation = state.pages.messaging.conversation;
  conversation.messages = conversation.messages.map((message) =>
    message.messageId === normalizedMessageId ? updater(message) : message,
  );
}

function applyMessagingReactionState(message, emoji, reactedByMe) {
  const normalizedEmoji = normalizeString(emoji);
  if (!normalizedEmoji) {
    return message;
  }
  const reactions = Array.isArray(message.reactions)
    ? message.reactions.slice()
    : [];
  const index = reactions.findIndex(
    (reaction) => normalizeString(reaction.emoji) === normalizedEmoji,
  );
  const current =
    index >= 0
      ? reactions[index]
      : { emoji: normalizedEmoji, count: 0, reactedByMe: false };
  const nextCount = Math.max(
    0,
    Number(current.count) +
      (reactedByMe && !current.reactedByMe
        ? 1
        : !reactedByMe && current.reactedByMe
          ? -1
          : 0),
  );
  const nextReaction = {
    ...current,
    emoji: normalizedEmoji,
    count: nextCount,
    reactedByMe,
  };
  if (index >= 0) {
    if (nextCount > 0) {
      reactions[index] = nextReaction;
    } else {
      reactions.splice(index, 1);
    }
  } else if (nextCount > 0) {
    reactions.push(nextReaction);
  }
  reactions.sort((left, right) =>
    normalizeString(left.emoji).localeCompare(normalizeString(right.emoji)),
  );
  return {
    ...message,
    reactions,
  };
}

async function toggleMessagingMessageReaction({
  conversationId,
  messageId,
  emoji,
  reactedByMe = false,
} = {}) {
  const normalizedConversationId = normalizeString(conversationId);
  const normalizedMessageId = normalizeString(messageId);
  const normalizedEmoji = normalizeString(emoji);
  const pendingKey = messagingReactionPendingKey(
    normalizedMessageId,
    normalizedEmoji,
  );
  if (!normalizedConversationId || !normalizedMessageId || !normalizedEmoji) {
    return false;
  }
  const conversation = state.pages.messaging.conversation;
  if (conversation.reactionPendingKey === pendingKey) {
    return false;
  }
  const nextReacted = reactedByMe !== true;
  conversation.reactionPendingKey = pendingKey;
  conversation.error = "";
  updateMessagingMessage(normalizedMessageId, (message) =>
    applyMessagingReactionState(message, normalizedEmoji, nextReacted),
  );
  scheduleRender();

  try {
    const encodedConversationId = encodeURIComponent(normalizedConversationId);
    const encodedMessageId = encodeURIComponent(normalizedMessageId);
    const path = `/api/messaging/conversations/${encodedConversationId}/messages/${encodedMessageId}/reactions`;
    if (nextReacted) {
      await fetchJson(path, {
        auth: true,
        method: "POST",
        body: { emoji: normalizedEmoji },
      });
    } else {
      await fetchJson(`${path}?emoji=${encodeURIComponent(normalizedEmoji)}`, {
        auth: true,
        method: "DELETE",
      });
    }
    return true;
  } catch (error) {
    updateMessagingMessage(normalizedMessageId, (message) =>
      applyMessagingReactionState(message, normalizedEmoji, reactedByMe === true),
    );
    const message =
      normalizeString(error?.message) || "Reaction could not be updated.";
    conversation.error = message;
    showToast(message);
    return false;
  } finally {
    if (conversation.reactionPendingKey === pendingKey) {
      conversation.reactionPendingKey = "";
    }
    scheduleRender();
  }
}

async function startMessagingRecovery({ rotate = false } = {}) {
  const recovery = state.pages.messaging.recovery;
  recovery.actionPending = true;
  recovery.error = "";
  scheduleRender();

  try {
    const currentBackupVersion = Number(recovery.status?.backupVersion) || 0;
    const pkg = await messagingDevice.createRecoveryEnrollment({
      backupVersion: currentBackupVersion + 1,
      deviceVersion: recovery.status?.deviceVersion || null,
      trustVersion: recovery.status?.trustVersion || null,
      rotate,
    });
    const endpoint = rotate
      ? "/api/messaging/recovery/rotate"
      : "/api/messaging/recovery/enroll";
    await fetchJson(endpoint, {
      auth: true,
      method: "POST",
      body: pkg.uploadPayload,
      headers: await messagingDevice.buildDeviceHeaders(),
    });
    recovery.localCode = pkg.recoveryCode;
    await loadMessagingRecovery();
    showToast(rotate ? "Recovery rotated." : "Recovery enrolled.");
  } catch (error) {
    recovery.error =
      normalizeString(error?.message) || "Recovery action failed.";
  } finally {
    recovery.actionPending = false;
    scheduleRender();
  }
}

async function verifyMessagingRecovery() {
  const recovery = state.pages.messaging.recovery;
  recovery.actionPending = true;
  recovery.error = "";
  scheduleRender();

  try {
    const restoreProof = await messagingDevice.currentRecoveryRestoreProof();
    await fetchJson("/api/messaging/recovery/verify", {
      auth: true,
      method: "POST",
      body: {
        backupVersion: recovery.status?.backupVersion,
        restoreProof,
      },
      headers: await messagingDevice.buildDeviceHeaders(),
    });
    await messagingDevice.markRecoveryVerified();
    await loadMessagingRecovery();
    showToast("Recovery verified.");
  } catch (error) {
    recovery.error =
      normalizeString(error?.message) || "Recovery verification failed.";
  } finally {
    recovery.actionPending = false;
    scheduleRender();
  }
}

function parseMessagingRecoveryKit(rawKit) {
  const normalized = normalizeString(rawKit);
  if (!normalized) {
    return null;
  }
  try {
    const decoded = JSON.parse(normalized);
    if (!decoded || typeof decoded !== "object" || Array.isArray(decoded)) {
      throw new Error("Recovery kit must be a JSON object.");
    }
    return decoded;
  } catch (error) {
    const message = normalizeString(error?.message) || "Invalid JSON.";
    throw new Error(`Recovery kit is invalid JSON: ${message}`);
  }
}

async function exportMessagingRecoveryKit() {
  const recovery = state.pages.messaging.recovery;
  recovery.actionPending = true;
  recovery.error = "";
  scheduleRender();

  try {
    const recoveryKit = await messagingDevice.buildRecoveryKit(recovery.bundle);
    if (!recoveryKit || typeof recoveryKit !== "object") {
      throw new Error("No recovery kit is available in this browser.");
    }
    const blob = new Blob([JSON.stringify(recoveryKit, null, 2)], {
      type: "application/json",
    });
    const url = window.URL?.createObjectURL(blob);
    if (!url) {
      throw new Error("File downloads are unavailable in this browser.");
    }
    const link = document.createElement("a");
    link.href = url;
    link.download = `polis-recovery-kit-${Date.now()}.json`;
    document.body.appendChild(link);
    link.click();
    link.remove();
    window.setTimeout(() => {
      try {
        window.URL?.revokeObjectURL(url);
      } catch {
        // Object URL cleanup is best effort.
      }
    }, 0);
    showToast("Recovery kit downloaded.");
  } catch (error) {
    recovery.error =
      normalizeString(error?.message) || "Recovery kit export failed.";
  } finally {
    recovery.actionPending = false;
    scheduleRender();
  }
}

async function restoreMessagingRecovery(formData) {
  const recovery = state.pages.messaging.recovery;
  const recoveryCode = normalizeString(formData.get("recoveryCode"));
  let recoveryBundle = recovery.bundle;
  if (!recoveryCode) {
    recovery.error = "Enter your recovery key first.";
    scheduleRender();
    return;
  }
  try {
    const pastedKit = parseMessagingRecoveryKit(formData.get("recoveryKit"));
    if (pastedKit) {
      recoveryBundle = pastedKit;
    }
  } catch (error) {
    recovery.error = normalizeString(error?.message) || "Recovery kit is invalid.";
    scheduleRender();
    return;
  }
  if (!recoveryBundle) {
    recovery.error =
      "Recovery bundle unavailable. Paste a recovery kit JSON file as a fallback.";
    scheduleRender();
    return;
  }
  recovery.actionPending = true;
  recovery.error = "";
  scheduleRender();

  try {
    const restoreProof = await messagingDevice.restoreFromRecoveryBundle({
      recoveryCode,
      recoveryBundle,
    });
    await fetchJson("/api/messaging/recovery/restore", {
      auth: true,
      method: "POST",
      body: {
        backupVersion:
          recoveryBundle.backupVersion || recovery.status?.backupVersion,
        restoreProof,
      },
      headers: await messagingDevice.buildDeviceHeaders(),
    });
    await loadMessagingRecovery();
    showToast("Recovery restored.");
  } catch (error) {
    recovery.error =
      normalizeString(error?.message) || "Recovery restore failed.";
  } finally {
    recovery.actionPending = false;
    scheduleRender();
  }
}

function handleMessagingSocketEvent(event) {
  const type = normalizeString(event?.type).toUpperCase();
  if (!type) {
    return;
  }
  if (type === "MESSAGE_NEW") {
    const message = normalizeMessagingMessage(
      event.payload?.message || event.payload,
    );
    if (
      message.conversationId &&
      message.conversationId ===
        state.pages.messaging.conversation.item?.conversationId
    ) {
      state.pages.messaging.conversation.messages = [
        ...state.pages.messaging.conversation.messages,
        message,
      ];
    }
    loadMessagingInbox({ refresh: true }).catch(() => {});
    scheduleRender();
    return;
  }
  if (type === "TYPING_EVENT") {
    const payload = event.payload || {};
    const conversationId = normalizeString(payload.conversationId);
    if (
      conversationId !== state.pages.messaging.conversation.item?.conversationId
    ) {
      return;
    }
    const userId = normalizeString(payload.userId);
    const label = normalizeString(
      payload.displayName || payload.username || userId,
    );
    const isTyping = payload.isTyping !== false;
    const existing =
      state.pages.messaging.conversation.typingParticipants.filter(
        (entry) => entry.userId !== userId,
      );
    state.pages.messaging.conversation.typingParticipants = isTyping
      ? existing.concat({ userId, label })
      : existing;
    scheduleRender();
    return;
  }
  if (
    type === "MESSAGE_EDITED" ||
    type === "MESSAGE_UPDATED" ||
    type === "MESSAGE_DELETED" ||
    type === "MESSAGE_REACTION_DIFF"
  ) {
    const conversationId = normalizeString(
      event.payload?.conversationId || event.payload?.message?.conversationId,
    );
    if (
      conversationId &&
      conversationId === state.pages.messaging.conversation.item?.conversationId
    ) {
      loadMessagingConversation(conversationId, { refresh: true }).catch(
        () => {},
      );
    }
    loadMessagingInbox({ refresh: true }).catch(() => {});
  }
}

async function requireAuthForRoute(route = state.route) {
  if (!isProtectedRoute(route)) {
    return true;
  }
  if (state.auth.session) {
    return true;
  }
  const capabilities = getSharedFeedAuthCapabilities(state.auth.config);
  if (!capabilities.direct && !capabilities.hosted) {
    state.renderError = "Web sign-in is not configured for this environment.";
    scheduleRender();
    return false;
  }
  promptForProtectedRoute(`${route.routePath}${window.location.search}`);
  return false;
}

