function getSettingsRoutePath(route = getCurrentRoute()) {
  const pathname =
    typeof window !== "undefined" ? normalizePathname(window.location.pathname) : "";
  if (pathname === "/settings") {
    return "";
  }
  if (pathname.startsWith("/settings/")) {
    return pathname.replace(/^\/settings\//u, "");
  }
  return normalizeString(route?.routeParams?.settingsPath);
}

function decodeSettingsPathSegment(value) {
  const normalized = normalizeString(value);
  if (!normalized) {
    return "";
  }
  try {
    return decodeURIComponent(normalized);
  } catch {
    return normalized;
  }
}

function getSettingsPathSegments(route = getCurrentRoute()) {
  return getSettingsRoutePath(route)
    .split("/")
    .map(decodeSettingsPathSegment)
    .map((segment) => normalizeString(segment).toLowerCase())
    .filter(Boolean);
}

function getSettingsSection(route = getCurrentRoute()) {
  const segments = getSettingsPathSegments(route);
  if (!segments.length) {
    return "overview";
  }
  const [firstSegment, secondSegment] = segments;
  if (firstSegment === "preferences" && secondSegment === "my-districts") {
    return "my-districts";
  }
  if (firstSegment === "preferences" && secondSegment === "home-location") {
    return "voter-profile";
  }
  return firstSegment || "overview";
}

function getSettingsSubpath(route = getCurrentRoute()) {
  return getSettingsPathSegments(route).slice(1).join("/");
}

function getSettingsSecuritySubpath(route = getCurrentRoute()) {
  const segments = getSettingsPathSegments(route);
  return segments[0] === "security" ? segments.slice(1).join("/") : "";
}

function isSettingsSecurityDeviceLinkRoute(route = getCurrentRoute()) {
  return getSettingsSecuritySubpath(route).split("/")[0] === "device-link";
}

function getSettingsSectionConfig(sectionKey = getSettingsSection()) {
  return (
    SETTINGS_CHILD_SECTION_CONFIGS[sectionKey] ||
    getSettingsSections().find((section) => section.key === sectionKey) ||
    getSettingsSections().find((section) => section.key === "overview")
  );
}

function getSettingsNavSectionKey(sectionKey = getSettingsSection()) {
  return SETTINGS_SECTION_PARENT_BY_KEY[sectionKey] || sectionKey;
}

