async function saveSettingsHomeLocation(formData) {
  const voterProfile = state.pages.settings.voterProfile;
  const redirectTo = normalizeString(formData.get("redirectTo"));
  const addressLine1 = normalizeString(formData.get("addressLine1"));
  const city = normalizeString(formData.get("city"));
  const stateId = normalizeString(formData.get("state")).toUpperCase();
  if (!addressLine1 || !city || !stateId) {
    voterProfile.profile.error = "Address, city, and state are required.";
    showToast(voterProfile.profile.error);
    scheduleRender();
    return;
  }
  voterProfile.homeLocationSaving = true;
  voterProfile.profile.error = "";
  voterProfile.districts.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson("/api/me/home-location/address", {
      auth: true,
      method: "PUT",
      body: {
        addressLine1,
        addressLine2: normalizeString(formData.get("addressLine2")),
        city,
        state: stateId,
        postalCode: normalizeString(formData.get("postalCode")),
      },
    });
    const nextProfile = payload.profile ? normalizeMyProfile(payload) : null;
    if (nextProfile?.userId) {
      voterProfile.profile.item = nextProfile;
      voterProfile.profile.loaded = true;
    }
    showToast(
      payload.requested === true
        ? "Home location review requested."
        : "Home location saved.",
    );
    await Promise.all([
      loadSettingsMyProfile({ refresh: true }),
      loadSettingsMyDistricts({ refresh: true }),
    ]);
    if (redirectTo) {
      navigateTo(redirectTo, { replace: true });
    }
  } catch (error) {
    voterProfile.profile.error = settingsErrorMessage(
      error,
      "Home location could not be saved.",
    );
    showToast(voterProfile.profile.error);
  } finally {
    voterProfile.homeLocationSaving = false;
    scheduleRender();
  }
}

function settingsAddressChangeRequestState() {
  if (!state.pages.settings.voterProfile.addressChange) {
    state.pages.settings.voterProfile.addressChange =
      createSettingsAddressChangeRequestState();
  }
  return state.pages.settings.voterProfile.addressChange;
}

async function loadSettingsAddressChangeRequests({
  refresh = false,
  append = false,
} = {}) {
  const resource = settingsAddressChangeRequestState();
  if (append ? resource.loadingMore : resource.loading) {
    return;
  }
  if (!append && resource.loaded && !refresh) {
    scheduleRender();
    return;
  }
  if (append && !resource.nextCursor) {
    return;
  }
  if (append) {
    resource.loadingMore = true;
  } else {
    resource.loading = true;
    resource.error = "";
    if (refresh) {
      resource.nextCursor = null;
    }
  }
  scheduleRender();
  try {
    const query = new URLSearchParams({ limit: "10" });
    if (append && resource.nextCursor) {
      query.set("cursor", resource.nextCursor);
    }
    const payload = await fetchJson(
      `/api/address-change-requests/mine?${query.toString()}`,
      { auth: true },
    );
    const items = readArrayPayload(payload, ["requests", "items"])
      .map(normalizeAddressChangeRequest)
      .filter((item) => item.requestId || formatAddressChangeAddress(item.requestedAddress));
    resource.items = append ? resource.items.concat(items) : items;
    resource.nextCursor = normalizeString(payload.nextCursor);
    resource.loaded = true;
    resource.error = "";
  } catch (error) {
    resource.error = settingsErrorMessage(
      error,
      "Address change requests could not be loaded.",
    );
  } finally {
    resource.loading = false;
    resource.loadingMore = false;
    scheduleRender();
  }
}

function inferAddressChangeAttachmentType(file) {
  const contentType = normalizeString(file?.type).toLowerCase();
  const fileName = normalizeString(file?.name).toLowerCase();
  if (contentType === "application/pdf" || fileName.endsWith(".pdf")) {
    return "pdf";
  }
  if (contentType.startsWith("image/") || /\.(?:png|jpe?g|webp)$/iu.test(fileName)) {
    return "image";
  }
  return "";
}

function normalizeAddressChangeUploadPayload(payload = {}) {
  const upload =
    payload?.upload && typeof payload.upload === "object" ? payload.upload : {};
  return {
    uploadUrl: normalizeUrl(upload.uploadUrl || payload.uploadUrl),
    method: normalizeString(upload.method || payload.method).toUpperCase() || "PUT",
    requiresMultipart:
      upload.requiresMultipart === true || payload.requiresMultipart === true,
    headers:
      upload.headers && typeof upload.headers === "object"
        ? upload.headers
        : payload.headers && typeof payload.headers === "object"
          ? payload.headers
          : {},
    fields:
      upload.fields && typeof upload.fields === "object"
        ? upload.fields
        : payload.fields && typeof payload.fields === "object"
          ? payload.fields
          : {},
    fileFieldName:
      normalizeString(upload.fileFieldName || payload.fileFieldName) || "file",
  };
}

async function addSettingsAddressChangeAttachmentFile(file) {
  const resource = settingsAddressChangeRequestState();
  if (!file) {
    return;
  }
  if (resource.attachments.length >= 3) {
    resource.attachmentError = "You can attach up to 3 files.";
    showToast(resource.attachmentError);
    scheduleRender();
    return;
  }
  if (Number(file.size) <= 0) {
    resource.attachmentError = "Selected file is empty.";
    showToast(resource.attachmentError);
    scheduleRender();
    return;
  }
  const attachmentType = inferAddressChangeAttachmentType(file);
  if (!attachmentType) {
    resource.attachmentError = "Attach a PNG, JPG, WEBP, or PDF file.";
    showToast(resource.attachmentError);
    scheduleRender();
    return;
  }
  resource.actionPendingKey = "attachment-upload";
  resource.attachmentError = "";
  scheduleRender();
  try {
    const fileName =
      normalizeString(file.name) ||
      `home-location-evidence.${attachmentType === "pdf" ? "pdf" : "jpg"}`;
    const contentType =
      attachmentType === "pdf"
        ? "application/pdf"
        : normalizeString(file.type) || "image/jpeg";
    let attachment;
    if (attachmentType === "pdf") {
      const uploadPayload = await fetchJson(
        "/api/address-change-requests/attachments/create",
        {
          auth: true,
          method: "POST",
          body: {
            fileName,
            fileSize: Number(file.size) || 0,
            contentType,
          },
        },
      );
      const upload = normalizeAddressChangeUploadPayload(uploadPayload);
      await uploadPostComposerFile(upload, file);
      attachment = normalizeAddressChangeAttachment({
        ...(uploadPayload.attachment || {}),
        type: "pdf",
        fileName,
        contentType,
        sizeBytes: Number(file.size) || 0,
      });
    } else {
      const uploadPayload = await fetchJson("/api/uploads/create", {
        auth: true,
        method: "POST",
        body: {
          type: "image",
          fileName,
          fileSize: Number(file.size) || 0,
          contentType,
        },
      });
      const upload = normalizeCreateUploadPayload(uploadPayload);
      await uploadPostComposerFile(upload, file);
      const remoteUrl = upload.deliveryUrl || upload.publicUrl;
      if (!remoteUrl) {
        throw new Error("Image upload finished without a public URL.");
      }
      attachment = normalizeAddressChangeAttachment({
        type: "image",
        fileName,
        contentType,
        sizeBytes: Number(file.size) || 0,
        url: remoteUrl,
      });
    }
    resource.attachments = resource.attachments.concat(attachment).slice(0, 3);
    showToast("Evidence attached.");
  } catch (error) {
    resource.attachmentError = settingsErrorMessage(
      error,
      "Evidence upload failed.",
    );
    showToast(resource.attachmentError);
  } finally {
    if (resource.actionPendingKey === "attachment-upload") {
      resource.actionPendingKey = "";
    }
    scheduleRender();
  }
}

