async function submitSettingsHomeLocationRequest(formData) {
  const resource = settingsAddressChangeRequestState();
  if (resource.actionPendingKey) {
    return false;
  }
  const addressLine1 = normalizeString(formData.get("addressLine1"));
  const city = normalizeString(formData.get("city"));
  const stateId = normalizeString(formData.get("state")).toUpperCase();
  const postalCode = normalizeString(formData.get("postalCode"));
  const message = normalizeString(formData.get("message"));
  if (!addressLine1 || !city || !stateId || !postalCode || !message) {
    resource.error =
      "Address, city, state, ZIP, and request note are required.";
    showToast(resource.error);
    scheduleRender();
    return false;
  }
  const requestedAddress = {
    addressLine1,
    city,
    state: stateId,
    postalCode,
    country: "US",
  };
  const addressLine2 = normalizeString(formData.get("addressLine2"));
  const county = normalizeString(formData.get("county"));
  const district = normalizeString(formData.get("district"));
  if (addressLine2) requestedAddress.addressLine2 = addressLine2;
  if (county) requestedAddress.county = county;
  if (district) requestedAddress.district = district;
  resource.actionPendingKey = "submit";
  resource.error = "";
  scheduleRender();
  try {
    const body = {
      message,
      requestedAddress,
      justification: message,
      addressLine1,
      city,
      state: stateId,
      postalCode,
      country: "US",
      ...(addressLine2 ? { addressLine2 } : {}),
      ...(county ? { county } : {}),
      ...(district ? { district } : {}),
      ...(resource.attachments.length
        ? { attachments: resource.attachments }
        : {}),
    };
    const payload = await fetchJson("/api/address-change-requests", {
      auth: true,
      method: "POST",
      body,
    });
    const created = normalizeAddressChangeRequest(
      payload.request || payload.addressChangeRequest || {
        ...body,
        status: "pending",
      },
    );
    resource.submittedRequest = created;
    resource.attachments = [];
    resource.items = [
      created,
      ...resource.items.filter((item) => item.requestId !== created.requestId),
    ];
    resource.loaded = true;
    showToast("Home location change request submitted.");
    return true;
  } catch (error) {
    resource.error = settingsErrorMessage(
      error,
      "Home location request could not be submitted.",
    );
    showToast(resource.error);
    return false;
  } finally {
    if (resource.actionPendingKey === "submit") {
      resource.actionPendingKey = "";
    }
    scheduleRender();
  }
}

