async function loadVoterIntelPolicyQuestions({ refresh = false } = {}) {
  const questions = state.pages.settings.voterIntel.questions;
  if (questions.loaded && !refresh) {
    return;
  }
  questions.loading = true;
  questions.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson("/api/policy-questions?limit=8", {
      auth: true,
    });
    const summaries = readArrayPayload(payload, ["items"])
      .map(normalizePolicyQuestion)
      .filter((question) => question.questionId);
    const details = await Promise.allSettled(
      summaries.map((question) =>
        fetchJson(
          `/api/policy-questions/${encodeURIComponent(question.questionId)}`,
          { auth: true },
        ),
      ),
    );
    questions.items = summaries.map((summary, index) => {
      const result = details[index];
      if (result?.status !== "fulfilled") {
        return summary;
      }
      const detail =
        result.value?.question && typeof result.value.question === "object"
          ? result.value.question
          : result.value;
      return normalizePolicyQuestion({ ...summary, ...detail });
    });
    questions.nextCursor =
      normalizeString(payload.cursor || payload.nextCursor) || null;
    questions.loaded = true;
  } catch (error) {
    questions.error = settingsErrorMessage(
      error,
      "Policy questions could not be loaded.",
    );
  } finally {
    questions.loading = false;
    scheduleRender();
  }
}

async function answerVoterIntelPolicyQuestion(questionId, optionId) {
  const questions = state.pages.settings.voterIntel.questions;
  const normalizedQuestionId = normalizeString(questionId);
  const normalizedOptionId = normalizeString(optionId);
  if (!normalizedQuestionId || !normalizedOptionId) {
    return;
  }
  questions.actionPendingKey = `${normalizedQuestionId}:${normalizedOptionId}`;
  questions.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/policy-questions/${encodeURIComponent(normalizedQuestionId)}/answer`,
      {
        auth: true,
        method: "PUT",
        body: { optionId: normalizedOptionId },
      },
    );
    const selectedAnswer = payload.answer
      ? {
          optionId: normalizeString(payload.answer.optionId),
          answerText: normalizeString(payload.answer.answerText),
          updatedAtIso: normalizeString(payload.answer.updatedAtIso),
        }
      : { optionId: normalizedOptionId, answerText: "", updatedAtIso: "" };
    questions.items = questions.items.map((question) =>
      question.questionId === normalizedQuestionId
        ? {
            ...question,
            selectedAnswer,
            aggregate: payload.aggregate
              ? {
                  total: Number(payload.aggregate.total) || 0,
                  options: readArrayPayload(payload.aggregate, ["options"]),
                }
              : question.aggregate,
          }
        : question,
    );
    if (payload.profile) {
      const snapshot = state.pages.settings.voterIntel.snapshot;
      snapshot.item = normalizeVoterIntelSnapshot({
        ...(snapshot.item || {}),
        profile: payload.profile,
        shares: snapshot.item?.shares || [],
        identityLinks: snapshot.item?.identityLinks || [],
        capability: snapshot.item?.capability || {},
      });
      snapshot.loaded = true;
    }
    showToast("Answer saved.");
  } catch (error) {
    questions.error = settingsErrorMessage(error, "Answer could not be saved.");
    showToast(questions.error);
  } finally {
    questions.actionPendingKey = "";
    scheduleRender();
  }
}

