async function saveSettingsAudienceGroup(formData) {
  const audienceGroups = state.pages.settings.audienceGroups;
  const groupId = normalizeString(formData.get("groupId"));
  const name = normalizeString(formData.get("name"));
  const memberUserIds = normalizeAudienceGroupMemberIds(
    formData.get("memberUserIds"),
  );
  if (!name) {
    audienceGroups.error = "Audience group name is required.";
    scheduleRender();
    return false;
  }
  const isUpdate = Boolean(groupId);
  audienceGroups.savingKey = isUpdate ? `save:${groupId}` : "create";
  audienceGroups.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      isUpdate
        ? `/api/me/audience-groups/${encodeURIComponent(groupId)}`
        : "/api/me/audience-groups",
      {
        auth: true,
        method: isUpdate ? "PUT" : "POST",
        body: {
          ...(isUpdate ? { groupId } : {}),
          name,
          memberUserIds,
        },
      },
    );
    audienceGroups.items = readArrayPayload(payload, [
      "groups",
      "audienceGroups",
    ]).map(normalizeAudienceGroup);
    audienceGroups.loaded = true;
    showToast(isUpdate ? "Audience group saved." : "Audience group created.");
    return true;
  } catch (error) {
    audienceGroups.error = settingsErrorMessage(
      error,
      "Audience group save failed.",
    );
    showToast(audienceGroups.error);
    return false;
  } finally {
    audienceGroups.savingKey = "";
    scheduleRender();
  }
}

