function findSettingsConnection(provider) {
  const normalizedProvider = normalizeSettingsProvider(provider);
  return (
    state.pages.settings.social.connections.find(
      (connection) => connection.provider === normalizedProvider,
    ) || null
  );
}

async function startSettingsSocialConnection(provider, options = {}) {
  const normalizedProvider = normalizeSettingsProvider(provider);
  if (!normalizedProvider) {
    showToast("Choose a provider to connect.");
    return;
  }
  const social = state.pages.settings.social;
  const allowCrosspostMentions =
    typeof options.allowCrosspostMentions === "boolean"
      ? options.allowCrosspostMentions
      : true;
  if (normalizedProvider === "bluesky" && !options.forceOAuth) {
    social.manualProvider = "bluesky";
    scheduleRender();
    return;
  }
  social.actionPendingKey = `connect:${normalizedProvider}`;
  social.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/social/connections/${encodeURIComponent(normalizedProvider)}/start`,
      {
        auth: true,
        method: "POST",
        body: { allowCrosspostMentions },
      },
    );
    const connectMode = normalizeString(payload.connectMode);
    const authorizationUrl = normalizeUrl(payload.authorizationUrl);
    if (connectMode === "manual_credentials_required") {
      social.manualProvider = normalizedProvider;
      return;
    }
    if (!authorizationUrl) {
      throw new Error("Authorization URL missing.");
    }
    window.location.assign(authorizationUrl);
  } catch (error) {
    social.error = settingsErrorMessage(error, "Connection start failed.");
    showToast(social.error);
  } finally {
    social.actionPendingKey = "";
    scheduleRender();
  }
}

