function formatAbsoluteDateTime(value) {
  const timestamp = Number(value);
  if (!Number.isFinite(timestamp) || timestamp <= 0) {
    return "";
  }
  return new Date(timestamp).toLocaleString(undefined, {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  });
}

function formatDateTimeInputValue(value) {
  const timestamp = Number(value);
  if (!Number.isFinite(timestamp) || timestamp <= 0) {
    return "";
  }
  const date = new Date(timestamp);
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  const hours = String(date.getHours()).padStart(2, "0");
  const minutes = String(date.getMinutes()).padStart(2, "0");
  return `${year}-${month}-${day}T${hours}:${minutes}`;
}

function formatDateInputValue(value) {
  const timestamp = Number(value);
  if (!Number.isFinite(timestamp) || timestamp <= 0) {
    return "";
  }
  const date = new Date(timestamp);
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function renderMediaThumbnailGrid(
  items = [],
  {
    emptyMessage = "Nothing here yet.",
    gridClassName = "",
    getRoute,
    getMediaUrl,
    getAltText,
    getOverlayText,
    getPlaceholderLabel,
    overlayBare = false,
    isOverlayBare,
  } = {},
) {
  if (!items.length) {
    return `<div class="shared-page__empty">${escapeHtml(emptyMessage)}</div>`;
  }

  const normalizedGridClassName = normalizeString(gridClassName);

  return `<div class="shared-media-grid${normalizedGridClassName ? ` ${escapeHtml(normalizedGridClassName)}` : ""}">${items
    .map((item) => {
      const route = normalizeString(getRoute?.(item));
      const mediaUrl = normalizeUrl(getMediaUrl?.(item));
      const overlayText = normalizeString(getOverlayText?.(item));
      const altText = normalizeString(getAltText?.(item)) || "Media item";
      const overlayIsBare =
        typeof isOverlayBare === "function" ? isOverlayBare(item) : overlayBare;
      const placeholderLabel =
        normalizeString(getPlaceholderLabel?.(item))
          .slice(0, 1)
          .toUpperCase() ||
        altText.slice(0, 1).toUpperCase() ||
        "M";

      return `<button class="shared-media-tile" type="button" data-action="navigate" data-route="${escapeHtml(route)}" aria-label="${escapeHtml(altText)}">
        ${
          mediaUrl
            ? `<img class="shared-media-tile__image" src="${escapeHtml(mediaUrl)}" alt="${escapeHtml(altText)}" loading="lazy" />`
            : `<div class="shared-media-tile__placeholder" aria-hidden="true">${escapeHtml(placeholderLabel)}</div>`
        }
        ${
          overlayText
            ? `<span class="shared-media-tile__overlay${overlayIsBare ? " shared-media-tile__overlay--bare" : ""}">${escapeHtml(overlayText)}</span>`
            : ""
        }
      </button>`;
    })
    .join("")}</div>`;
}

function getFeedGridItems(items = []) {
  return items.filter(
    (item) => item?.kind === "post" || item?.kind === "event",
  );
}

function getFeedPromptItems(items = []) {
  return items.filter((item) => item?.kind === "prompt");
}

function renderFeedPromptCards(items = []) {
  if (!items.length) {
    return "";
  }

  return `<div>
    <h2>More from Polis</h2>
    <div class="shared-card-grid shared-card-grid--detail">
      ${items
        .map(
          (item) => `<article class="shared-card">
            <div class="shared-card__body">
              <p class="shared-page__eyebrow">Prompt</p>
              <h3>${escapeHtml(item.title || "Continue in Polis")}</h3>
              <p class="shared-card__summary">${escapeHtml(item.description || "Open the app to continue this feed step.")}</p>
              <div class="shared-card__actions">
                <button class="shared-feed-chip shared-feed-chip--primary" data-action="open-app-shell">Open app</button>
              </div>
            </div>
          </article>`,
        )
        .join("")}
    </div>
  </div>`;
}

function renderFeedOverviewPage() {
  const feed = getCurrentFeedState();
  const items = getCurrentItems();
  const mediaItems = getFeedGridItems(items);
  const promptItems = getFeedPromptItems(items);
  const modeLabel =
    state.mode === FEED_MODE_FOLLOWING ? "Following" : "For You";

  return `<section class="shared-page">
    ${renderTopChrome()}
    <div class="shared-page__content">
      <div class="shared-page__header">
        <div>
          <p class="shared-page__eyebrow">Feed</p>
          <h1>${escapeHtml(modeLabel)}</h1>
          <p>Browse the latest Polis posts and events in a compact web grid.</p>
        </div>
        <div class="shared-card__actions">
          ${
            feed.nextCursor
              ? `<button class="shared-feed-chip" data-action="load-more-feed-grid"${feed.loadingMore ? " disabled" : ""}>${feed.loadingMore ? "Loading…" : "Load more"}</button>`
              : ""
          }
          <button class="shared-feed-chip shared-feed-chip--primary" data-action="refresh-feed-grid"${feed.loading ? " disabled" : ""}>${feed.loading ? "Refreshing…" : "Refresh"}</button>
        </div>
      </div>
      ${
        feed.loading && !items.length
          ? '<div class="shared-page__loading">Loading feed…</div>'
          : ""
      }
      ${feed.error ? `<div class="shared-page__error">${escapeHtml(feed.error)}</div>` : ""}
      ${renderMediaThumbnailGrid(mediaItems, {
        emptyMessage: "No feed items yet.",
        gridClassName: "shared-media-grid--five-wide",
        getRoute: (item) => {
          if (item.kind === "event" && item.eventId) {
            return `/events/${encodeURIComponent(item.eventId)}`;
          }
          return item.postId ? `/posts/${encodeURIComponent(item.postId)}` : "";
        },
        getMediaUrl: (item) =>
          item.kind === "event"
            ? item.imageUrl
            : item.posterUrl || item.imageUrl,
        getAltText: (item) =>
          item.kind === "event"
            ? item.title || "Event"
            : item.previewTitle ||
              item.caption ||
              item.authorDisplayName ||
              "Post",
        getOverlayText: (item) => {
          if (item.kind === "event") {
            if (Number(item.attendeeCount) > 0) {
              return `${formatCount(item.attendeeCount)} going`;
            }
            return item.startAt
              ? formatAbsoluteDateTime(item.startAt)
              : item.hostDisplayName || "Event";
          }
          return `${formatCount(item.likesCount)} like${Number(item.likesCount) === 1 ? "" : "s"}`;
        },
        getPlaceholderLabel: (item) => (item.kind === "event" ? "E" : "P"),
        isOverlayBare: (item) => item.kind === "post",
      })}
      ${
        feed.loadingMore
          ? '<div class="shared-page__hint">Loading more feed items…</div>'
          : ""
      }
      ${renderFeedPromptCards(promptItems)}
    </div>
  </section>`;
}

function electionStatusLabel(snapshot = null, option = null) {
  if (option?.future && option.clickable !== true) return "Upcoming";
  if (snapshot?.isActive || option?.active) return "Live";
  if (snapshot?.isFinalized || option?.finalized) return "Final";
  return "Election";
}

function electionReportingLine(snapshot = null) {
  if (!snapshot) return "Select a state to view federal race results.";
  const reporting = snapshot.reporting || {};
  const precinctsReported = Number(reporting.precinctsReported);
  const precinctsTotal = Number(reporting.precinctsTotal);
  const percent = Number(reporting.percent);
  const parts = [];
  if (
    Number.isFinite(precinctsReported) &&
    Number.isFinite(precinctsTotal) &&
    precinctsTotal > 0
  ) {
    parts.push(
      `${formatElectionVotes(precinctsReported)} of ${formatElectionVotes(precinctsTotal)} precincts`,
    );
  }
  if (Number.isFinite(percent) && percent > 0) {
    parts.push(`${formatElectionPercent(percent)} reporting`);
  }
  if (snapshot.updatedAt) {
    parts.push(`Updated ${formatCalendarDate(snapshot.updatedAt)}`);
  }
  return parts.join(" · ") || "Results update as vote totals are reported.";
}

function electionPreviousCandidateMap(snapshot = null) {
  const map = new Map();
  for (const race of snapshot?.races || []) {
    for (const candidate of race.candidates || []) {
      map.set(`${race.raceId}:${candidate.id}`, candidate);
    }
  }
  return map;
}

function electionMapDistrictOptions(election = state.pages.elections) {
  const features = Array.isArray(election.map.geometry?.districts?.features)
    ? election.map.geometry.districts.features
    : [];
  return features
    .map((feature) => {
      const properties =
        feature?.properties && typeof feature.properties === "object"
          ? feature.properties
          : {};
      const districtId = normalizeString(
        properties.districtId || properties.id || feature?.id,
      );
      if (!districtId) return null;
      return {
        districtId,
        label:
          normalizeString(properties.name || properties.districtName) ||
          districtId.replace(/^([A-Z]{2})-(HD|SD)-(\d+)$/u, "$2 $3"),
      };
    })
    .filter(Boolean)
    .sort((left, right) => {
      const leftNumber = Number(left.districtId.match(/-(\d+)$/u)?.[1]);
      const rightNumber = Number(right.districtId.match(/-(\d+)$/u)?.[1]);
      if (Number.isFinite(leftNumber) && Number.isFinite(rightNumber)) {
        return leftNumber - rightNumber;
      }
      return left.label.localeCompare(right.label);
    });
}

function selectedElectionDistrictLabel(election = state.pages.elections) {
  const selectedDistrict = normalizeString(election.selectedDistrictId);
  if (!selectedDistrict) {
    return `${election.selectedStateId || "State"} view`;
  }
  const option = electionMapDistrictOptions(election).find(
    (district) => district.districtId === selectedDistrict,
  );
  return option?.label || selectedDistrict;
}

function shouldRenderElectionMap(election = state.pages.elections) {
  const scope = normalizeElectionScope(election.selectedScope);
  if (ELECTION_AUTH_SCOPES.has(scope)) return false;
  return scope !== ELECTION_SCOPE_STATE || Boolean(selectedElectionMapChamber());
}

function formatElectionTimestamp(value) {
  const normalized = normalizeString(value);
  if (!normalized) return "";
  const numeric = Number(normalized);
  const date =
    Number.isFinite(numeric) && numeric > 0
      ? new Date(numeric)
      : new Date(normalized);
  if (Number.isNaN(date.getTime())) return normalized;
  return date.toLocaleString(undefined, {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  });
}

function electionCountyCoverageLine(snapshot = null) {
  const coverage = snapshot?.countyCoverage;
  if (!coverage) return "";
  const expected = Number(coverage.expectedCount) || coverage.counties.length;
  const reporting = Number(coverage.reportingCount) || 0;
  const parts = [
    expected
      ? `${formatElectionVotes(reporting)} of ${formatElectionVotes(expected)} counties reporting`
      : `${formatElectionVotes(reporting)} counties reporting`,
  ];
  const updatedAt = formatElectionTimestamp(coverage.updatedAt);
  if (updatedAt) parts.push(`Updated ${updatedAt}`);
  return parts.join(" · ");
}

function groupElectionRaces(snapshot = null, selectedDistrictId = "") {
  const races = snapshot?.races || [];
  if (!races.length) return [];
  const selectedDistrict = normalizeString(selectedDistrictId);
  if (selectedDistrict) {
    const districtName =
      races.find((race) => normalizeString(race.districtName))?.districtName ||
      selectedDistrict;
    return [{ title: districtName, races }];
  }
  if (
    normalizeElectionScope(snapshot?.scope) === ELECTION_SCOPE_STATE &&
    normalizeElectionRaceType(snapshot?.raceType) === "statewide"
  ) {
    return [{ title: "Statewide state races", races }];
  }
  const groups = new Map();
  for (const race of races) {
    const key = normalizeString(race.districtId) || "statewide";
    const title =
      normalizeString(race.districtName || race.districtId) || "Statewide";
    const entry = groups.get(key) || { title, races: [] };
    entry.races.push(race);
    groups.set(key, entry);
  }
  return Array.from(groups.values()).sort((left, right) =>
    left.title.localeCompare(right.title),
  );
}

function electionRaceResultScope(race = {}) {
  return normalizeElectionScope(race.scope || race.resultScope);
}

function electionCandidatePartyKey(candidate = {}) {
  return normalizeElectionPartyToken(
    candidate.partyToken || candidate.partyCode || candidate.partyLabel,
  ) || "UNK";
}

function electionRaceIsPrimary(race = {}) {
  const stage = normalizeString(race.stage).toLowerCase();
  const title = normalizeString(race.officeTitle).toLowerCase();
  return stage.includes("primary") || title.includes(" primary");
}

function electionRaceTitlePrimaryPartyToken(race = {}) {
  const title = normalizeString(race.officeTitle).toUpperCase();
  const match = title.match(
    /(?:^|[-\u2013\u2014])\s*([A-Z][A-Z .&/]+?)\s+PRIMARY(?:\b|$)/u,
  );
  return normalizeElectionPartyToken(match?.[1]) || "";
}

function electionRaceCandidatePrimaryPartyToken(race = {}) {
  const parties = Array.from(
    new Set(
      (race.candidates || [])
        .map(electionCandidatePartyKey)
        .filter((party) => party && party !== "UNK" && party !== "OTH"),
    ),
  );
  return parties.length === 1 ? parties[0] : "";
}

function electionRacePrimaryPartyToken(race = {}) {
  if (!electionRaceIsPrimary(race)) return "";
  return (
    electionRaceTitlePrimaryPartyToken(race) ||
    electionRaceCandidatePrimaryPartyToken(race)
  );
}

function electionRaceVisibleForPartyFilter(race = {}, partyFilter = "all") {
  const normalizedPartyFilter = normalizeElectionPartyFilter(partyFilter);
  if (normalizedPartyFilter === "all") return true;
  const hasSelectedPartyCandidate = (race.candidates || []).some(
    (candidate) => electionCandidatePartyKey(candidate) === normalizedPartyFilter,
  );
  if (hasSelectedPartyCandidate) return true;
  const primaryParty = electionRacePrimaryPartyToken(race);
  return !primaryParty || primaryParty === normalizedPartyFilter;
}

function filterElectionRacesForPartyView(races = [], options = {}) {
  const partyFilter = normalizeElectionPartyFilter(options.partyFilter);
  return (races || []).filter((race) =>
    electionRaceVisibleForPartyFilter(race, partyFilter),
  );
}

function electionPartyFilterOptions(snapshot = null) {
  const userParty = normalizeElectionPartyToken(
    state.pages.elections.context?.userPartyToken ||
      state.pages.elections.context?.userPartyLabel,
  );
  const options = new Map();
  if (userParty) {
    options.set(userParty, {
      value: userParty,
      label: candidatePartyLabelForKey(userParty),
    });
  }
  for (const race of snapshot?.races || []) {
    for (const candidate of race.candidates || []) {
      const value = electionCandidatePartyKey(candidate);
      if (!options.has(value)) {
        options.set(value, {
          value,
          label: candidatePartyLabelForKey(value, candidate),
        });
      }
    }
  }
  return [
    { value: "all", label: "All" },
    ...Array.from(options.values()).sort((left, right) => {
      const leftRank = candidatePartySortRank(left.value, userParty);
      const rightRank = candidatePartySortRank(right.value, userParty);
      if (leftRank !== rightRank) return leftRank - rightRank;
      return left.label.localeCompare(right.label);
    }),
  ];
}

function selectedElectionPartyFilterValue(snapshot = null) {
  const selected = normalizeElectionPartyFilter(
    state.pages.elections.selectedPartyFilter,
  );
  if (selected === "all") return "all";
  const options = electionPartyFilterOptions(snapshot);
  return options.some((option) => option.value === selected) ? selected : "all";
}

function renderElectionPartyFilterControl(election) {
  const snapshot = election.results.snapshot;
  const selected = selectedElectionPartyFilterValue(snapshot);
  const options = electionPartyFilterOptions(snapshot);
  return `<label>
    <span>Party</span>
    <select data-election-control="party-filter">
      ${options
        .map(
          (option) =>
            `<option value="${escapeHtml(option.value)}"${option.value === selected ? " selected" : ""}>${escapeHtml(option.label)}</option>`,
        )
        .join("")}
    </select>
  </label>`;
}

function renderElectionAuthPrompt(scope) {
  return `<section class="shared-election-upcoming">
    <h2>${escapeHtml(electionScopeLabel(scope))} results require sign-in</h2>
    <p>Sign in to load district-specific and saved election views for your account.</p>
    <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="auth-login-inline">Sign in</button>
  </section>`;
}

function renderElectionCustomViewSelector(election) {
  const custom = election.customViews;
  const selected = selectedElectionCustomView(election);
  const atLimit = custom.items.length >= custom.maxViews;
  return `<div class="shared-election-custom-toolbar">
    <label>
      <span>Saved slate</span>
      <select data-election-control="custom-view"${custom.items.length ? "" : " disabled"}>
        ${
          custom.items.length
            ? custom.items
                .map(
                  (view) =>
                    `<option value="${escapeHtml(view.viewId)}"${view.viewId === selected?.viewId ? " selected" : ""}>${escapeHtml(view.name)}</option>`,
                )
                .join("")
            : '<option value="">No saved slates</option>'
        }
      </select>
    </label>
    <div class="shared-election-custom-toolbar__actions">
      <button class="shared-feed-chip${custom.items.length ? "" : " shared-feed-chip--primary"}" type="button" data-action="election-custom-new"${atLimit ? " disabled" : ""}>New</button>
      <button class="shared-feed-chip" type="button" data-action="election-custom-edit"${selected ? "" : " disabled"}>Edit</button>
      <button class="shared-feed-chip" type="button" data-action="election-custom-share"${selected ? "" : " disabled"}>Copy share link</button>
      <button class="shared-feed-chip" type="button" data-action="election-custom-delete"${selected ? "" : " disabled"}>Delete</button>
    </div>
  </div>`;
}

function renderElectionCustomEditor(election) {
  const custom = election.customViews;
  const draft = custom.draft || createElectionCustomDraft(selectedElectionCustomView(election));
  normalizeElectionCustomAddSelection(election);
  const addStateId = electionCustomAddStateId(election);
  const targetOptions = electionCustomTargetTypeOptions(election);
  const targetType = normalizeString(custom.addType || targetOptions[0]?.value);
  const districtOptions = electionCustomDistrictOptionsForType(targetType, election);
  const selectedDistrict =
    normalizeString(custom.addDistrict) ||
    electionCustomDefaultDistrictForType(targetType, election);
  const stateOptions = (election.context?.states || [])
    .map(
      (option) =>
        `<option value="${escapeHtml(option.stateId)}"${normalizeString(option.stateId).toUpperCase() === addStateId ? " selected" : ""}>${escapeHtml(option.stateName || option.stateId)}</option>`,
    )
    .join("");
  return `<div class="shared-election-custom-editor">
    <label>
      <span>Name</span>
      <input data-election-custom-field="name" value="${escapeHtml(draft.name)}" maxlength="80" />
    </label>
    <div class="shared-election-custom-add">
      <label>
        <span>State</span>
        <select data-election-custom-field="target-state"${stateOptions ? "" : " disabled"}>
          ${stateOptions || '<option value="">No states available</option>'}
        </select>
      </label>
      <label>
        <span>Race</span>
        <select data-election-custom-field="target-type"${targetOptions.length ? "" : " disabled"}>
          ${
            targetOptions.length
              ? targetOptions
                  .map(
                    (option) =>
                      `<option value="${escapeHtml(option.value)}"${option.value === targetType ? " selected" : ""}>${escapeHtml(option.label)}</option>`,
                  )
                  .join("")
              : '<option value="">No supported races</option>'
          }
        </select>
      </label>
      ${
        districtOptions.length
          ? `<label>
              <span>District</span>
              <select data-election-custom-field="target-district">
                ${districtOptions
                  .map(
                    (option) =>
                      `<option value="${escapeHtml(option.value)}"${option.value === selectedDistrict ? " selected" : ""}>${escapeHtml(option.label)}</option>`,
                  )
                  .join("")}
              </select>
            </label>`
          : ""
      }
      <button class="shared-feed-chip" type="button" data-action="election-custom-add-item">Add</button>
    </div>
    ${
      custom.targetLoadingKey
        ? '<div class="shared-page__loading">Loading race options…</div>'
        : ""
    }
    ${custom.targetError ? `<div class="shared-page__error">${escapeHtml(custom.targetError)}</div>` : ""}
    <div class="shared-election-custom-items">
      ${
        draft.items.length
          ? draft.items
              .map(
                (item, index) => `<div class="shared-election-custom-item">
                  <div>
                    <strong>${escapeHtml(electionCustomItemLabel(item))}</strong>
                    <span>${escapeHtml(electionScopeLabel(item.scope))}</span>
                  </div>
                  <div class="shared-election-custom-item__actions">
                    <button class="shared-feed-icon-button" type="button" data-action="election-custom-move-item" data-index="${index}" data-direction="-1" aria-label="Move up">^</button>
                    <button class="shared-feed-icon-button" type="button" data-action="election-custom-move-item" data-index="${index}" data-direction="1" aria-label="Move down">v</button>
                    <button class="shared-feed-icon-button" type="button" data-action="election-custom-remove-item" data-index="${index}" aria-label="Remove">x</button>
                  </div>
                </div>`,
              )
              .join("")
          : '<div class="shared-page__empty">Add races to this slate.</div>'
      }
    </div>
    <div class="shared-card__actions">
      <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="election-custom-save"${custom.saving ? " disabled" : ""}>Save</button>
      <button class="shared-feed-chip" type="button" data-action="election-custom-cancel">Cancel</button>
    </div>
  </div>`;
}

function renderElectionCustomControls(election) {
  if (normalizeElectionScope(election.selectedScope) !== ELECTION_SCOPE_CUSTOM) {
    return "";
  }
  if (normalizeString(election.selectedCustomShareId)) return "";
  if (!state.auth.session) return "";
  const custom = election.customViews;
  return `<section class="shared-election-custom-panel">
    ${custom.loading ? '<div class="shared-page__loading">Loading custom views…</div>' : ""}
    ${custom.error ? `<div class="shared-page__error">${escapeHtml(custom.error)}</div>` : ""}
    ${renderElectionCustomViewSelector(election)}
    ${custom.editing ? renderElectionCustomEditor(election) : ""}
  </section>`;
}

function renderElectionControls(election, selectedOption) {
  const states = election.context?.states || [];
  const selectedScope = normalizeElectionScope(election.selectedScope);
  const stateAvailable = electionStateTrackingAvailable(selectedOption);
  const myDistrictAvailable = electionOptionSupportsScope(
    selectedOption,
    ELECTION_SCOPE_MY_DISTRICT,
  );
  const customAvailable = electionOptionSupportsScope(
    selectedOption,
    ELECTION_SCOPE_CUSTOM,
  );
  const showPartyFilter =
    selectedScope === ELECTION_SCOPE_MY_DISTRICT ||
    selectedScope === ELECTION_SCOPE_CUSTOM;
  const raceTypes = stateAvailable
    ? electionStateRaceTypesForOption(selectedOption)
    : [];
  const selectedRaceType = selectedElectionRaceType() || "statewide";
  const stateOptions = states
    .map((option) => {
      const selected =
        normalizeString(option.stateId) ===
        normalizeString(election.selectedStateId);
      return `<option value="${escapeHtml(option.stateId)}"${selected ? " selected" : ""}>${escapeHtml(electionStateOptionLabel(option))}</option>`;
    })
    .join("");
  return `<div class="shared-election-controls">
    <label>
      <span>Race level</span>
      <select data-election-control="scope">
        <option value="federal"${selectedScope === ELECTION_SCOPE_FEDERAL ? " selected" : ""}>Federal</option>
        <option value="state"${selectedScope === ELECTION_SCOPE_STATE ? " selected" : ""}${stateAvailable ? "" : " disabled"}>State</option>
        <option value="my-district"${selectedScope === ELECTION_SCOPE_MY_DISTRICT ? " selected" : ""}${myDistrictAvailable ? "" : " disabled"}>My District</option>
        <option value="custom"${selectedScope === ELECTION_SCOPE_CUSTOM ? " selected" : ""}${customAvailable ? "" : " disabled"}>Custom</option>
        <option value="local" disabled>Local</option>
      </select>
    </label>
    ${
      selectedScope === ELECTION_SCOPE_CUSTOM
        ? ""
        : `<label>
      <span>State</span>
      <select data-election-control="state"${states.length ? "" : " disabled"}>
        ${stateOptions || '<option value="">No elections available</option>'}
      </select>
    </label>`
    }
    ${showPartyFilter ? renderElectionPartyFilterControl(election) : ""}
    ${
      selectedOption?.future && selectedOption.clickable !== true
        ? `<div class="shared-election-controls__hint">Next Election Date ${escapeHtml(formatElectionDate(selectedOption.electionDate) || "unavailable")}</div>`
        : ""
    }
    ${
      selectedScope === ELECTION_SCOPE_STATE
        ? `<div class="shared-election-race-tabs" role="tablist" aria-label="State race type">
            ${raceTypes
              .map(
                (raceType) =>
                  `<button class="shared-feed-chip${raceType === selectedRaceType ? " shared-feed-chip--primary" : ""}" type="button" data-action="election-race-type" data-race-type="${escapeHtml(raceType)}" aria-pressed="${raceType === selectedRaceType ? "true" : "false"}">${escapeHtml(electionRaceTypeLabel(raceType))}</button>`,
              )
              .join("")}
          </div>`
        : ""
    }
  </div>`;
}

function renderElectionMapPanel(election) {
  const selectedDistrict = normalizeString(election.selectedDistrictId);
  const selectedDistrictLabel = selectedElectionDistrictLabel(election);
  return `<section class="shared-election-map-panel">
    <div class="shared-election-map" id="shared-election-map">
      ${
        election.map.loading && !election.map.geometry
          ? '<div class="shared-page__loading">Loading election map…</div>'
          : ""
      }
      ${
        election.map.error && !election.map.geometry
          ? `<div class="shared-page__error">${escapeHtml(election.map.error)}</div>`
          : ""
      }
    </div>
    <div class="shared-election-map-panel__chrome">
      <span>${escapeHtml(selectedDistrictLabel)}</span>
      ${
        selectedDistrict
          ? '<button class="shared-feed-chip" data-action="election-state-view">State view</button>'
          : ""
      }
    </div>
  </section>`;
}

function renderElectionDistrictFilters(election) {
  if (
    normalizeElectionScope(election.selectedScope) !== ELECTION_SCOPE_STATE ||
    !selectedElectionMapChamber()
  ) {
    return "";
  }
  const districts = electionMapDistrictOptions(election);
  if (!districts.length) {
    return election.map.loading
      ? ""
      : '<div class="shared-page__empty">District filters will appear when the map loads.</div>';
  }
  const selectedDistrict = normalizeString(election.selectedDistrictId);
  return `<div class="shared-election-districts" aria-label="District filters">
    <button class="shared-feed-chip${selectedDistrict ? "" : " shared-feed-chip--primary"}" type="button" data-action="election-district-select" data-district-id="">All districts</button>
    ${districts
      .map(
        (district) =>
          `<button class="shared-feed-chip${district.districtId === selectedDistrict ? " shared-feed-chip--primary" : ""}" type="button" data-action="election-district-select" data-district-id="${escapeHtml(district.districtId)}">${escapeHtml(district.label)}</button>`,
      )
      .join("")}
  </div>`;
}

function renderElectionCandidateRow(candidate, race, previousCandidateMap) {
  const previous = previousCandidateMap.get(`${race.raceId}:${candidate.id}`);
  const changed =
    previous &&
    (Number(previous.votes) !== Number(candidate.votes) ||
      Number(previous.votePercent) !== Number(candidate.votePercent));
  const color = electionPartyColor(
    candidate.partyToken || candidate.partyLabel,
  );
  const width = Math.max(0, Math.min(100, Number(candidate.votePercent) || 0));
  return `<div class="shared-election-candidate${candidate.isWinner ? " is-winner" : ""}${changed ? " is-updated" : ""}" style="--party-color:${escapeHtml(color)}">
    ${
      candidate.avatarUrl
        ? `<img class="shared-election-candidate__avatar" src="${escapeHtml(candidate.avatarUrl)}" alt="${escapeHtml(candidate.name)}" />`
        : `<div class="shared-election-candidate__avatar shared-election-candidate__avatar--placeholder">${escapeHtml(candidate.name.slice(0, 1).toUpperCase() || "C")}</div>`
    }
    <div class="shared-election-candidate__body">
      <div class="shared-election-candidate__topline">
        <strong>${escapeHtml(candidate.name)}</strong>
        <span>${escapeHtml(candidate.partyLabel || candidate.partyToken || "Other")}</span>
      </div>
      <div class="shared-election-candidate__bar">
        <span style="width:${width}%"></span>
      </div>
    </div>
    <div class="shared-election-candidate__numbers">
      <strong data-election-counter data-from="${escapeHtml(String(previous?.votes ?? candidate.votes))}" data-to="${escapeHtml(String(candidate.votes))}">${escapeHtml(formatElectionVotes(candidate.votes))}</strong>
      <span>${escapeHtml(formatElectionPercent(candidate.votePercent))}</span>
      ${candidate.isWinner ? "<em>Winner</em>" : ""}
    </div>
  </div>`;
}

function renderElectionCountyCandidate(candidate) {
  return `<div class="shared-election-county-candidate">
    <span>${escapeHtml(candidate.name)}</span>
    <strong>${escapeHtml(formatElectionVotes(candidate.votes))}</strong>
    <em>${escapeHtml(formatElectionPercent(candidate.votePercent))}</em>
  </div>`;
}

function renderElectionCountyResultRow(county, { partyFilter = "all" } = {}) {
  const candidates = (county.candidates || []).filter(
    (candidate) =>
      partyFilter === "all" || electionCandidatePartyKey(candidate) === partyFilter,
  );
  return `<div class="shared-election-county-row">
    <div class="shared-election-county-row__header">
      <strong>${escapeHtml(county.countyName)}</strong>
      <span>${escapeHtml(formatElectionVotes(county.totalVotes))} votes</span>
    </div>
    <div class="shared-election-county-row__candidates">
      ${
        candidates.length
          ? candidates.map(renderElectionCountyCandidate).join("")
          : '<span class="shared-election-empty-candidates">No matching county candidate rows.</span>'
      }
    </div>
  </div>`;
}

function renderElectionCountyResults(race, options = {}) {
  const counties = Array.isArray(race.countyResults)
    ? race.countyResults
    : [];
  if (!counties.length) return "";
  return `<details class="shared-election-county-results">
    <summary>County results <span>${escapeHtml(formatElectionVotes(counties.length))}</span></summary>
    <div class="shared-election-county-results__list">
      ${counties
        .map((county) => renderElectionCountyResultRow(county, options))
        .join("")}
    </div>
  </details>`;
}

function renderElectionRaceCard(race, previousCandidateMap, options = {}) {
  const partyFilter = normalizeElectionPartyFilter(options.partyFilter);
  const userPartyToken = normalizeElectionPartyToken(
    state.pages.elections.context?.userPartyToken ||
      state.pages.elections.context?.userPartyLabel,
  );
  const orderedCandidates = [...(race.candidates || [])].sort(
    (left, right) => {
      if (options.partyFirst) {
        const leftRank = candidatePartySortRank(
          electionCandidatePartyKey(left),
          userPartyToken,
        );
        const rightRank = candidatePartySortRank(
          electionCandidatePartyKey(right),
          userPartyToken,
        );
        if (leftRank !== rightRank) return leftRank - rightRank;
      }
      const votes = Number(right.votes) - Number(left.votes);
      if (votes) return votes;
      return normalizeString(left.name).localeCompare(normalizeString(right.name));
    },
  );
  const visibleCandidates = orderedCandidates.filter(
    (candidate) =>
      partyFilter === "all" || electionCandidatePartyKey(candidate) === partyFilter,
  );
  const selectedPartyLabel =
    partyFilter === "all" ? "" : candidatePartyLabelForKey(partyFilter);
  return `<article class="shared-election-race">
    <div class="shared-election-race__header">
      <div>
        <div class="shared-card__meta">
          ${race.stateName ? `<span>${escapeHtml(race.stateName)}</span>` : ""}
          ${race.districtId ? `<span>${escapeHtml(race.districtId)}</span>` : ""}
          ${race.stage ? `<span>${escapeHtml(humanizeLabel(race.stage))}</span>` : ""}
          ${race.called ? "<span>Called</span>" : ""}
        </div>
        <h3>${escapeHtml(race.officeTitle)}</h3>
      </div>
      ${
        race.called
          ? `<span class="shared-election-status shared-election-status--called">Called</span>`
          : ""
      }
    </div>
    <div class="shared-election-race__candidates">
      ${
        visibleCandidates.length
          ? visibleCandidates
              .map((candidate) =>
                renderElectionCandidateRow(candidate, race, previousCandidateMap),
              )
              .join("")
          : `<div class="shared-election-empty-candidates">No ${escapeHtml(selectedPartyLabel)} candidates in this office.</div>`
      }
    </div>
    ${renderElectionCountyResults(race, { partyFilter })}
  </article>`;
}

function renderElectionMissingDistrictNotice(snapshot = null) {
  const missing = snapshot?.missingDistricts;
  if (!missing?.stateHouse && !missing?.stateSenate) return "";
  return `<div class="shared-page__empty">Home address needed for state legislative races.</div>`;
}

function renderElectionRaceList(races, previousCandidateMap, options = {}) {
  return filterElectionRacesForPartyView(races, options)
    .map((race) => renderElectionRaceCard(race, previousCandidateMap, options))
    .join("");
}

function electionCustomRaceSortValue(race = {}) {
  return Number.isFinite(Number(race.customOrder))
    ? Number(race.customOrder)
    : Number.MAX_SAFE_INTEGER;
}

function groupElectionCustomRacesByState(races = []) {
  const groups = new Map();
  for (const race of [...races].sort((left, right) => {
    const order = electionCustomRaceSortValue(left) - electionCustomRaceSortValue(right);
    if (order) return order;
    return normalizeString(left.officeTitle).localeCompare(
      normalizeString(right.officeTitle),
    );
  })) {
    const stateId = normalizeString(race.stateId || "unknown");
    const existing =
      groups.get(stateId) || {
        stateId,
        stateName: race.stateName || electionStateNameForId(stateId),
        firstOrder: electionCustomRaceSortValue(race),
        races: [],
      };
    existing.firstOrder = Math.min(
      existing.firstOrder,
      electionCustomRaceSortValue(race),
    );
    existing.races.push(race);
    groups.set(stateId, existing);
  }
  return Array.from(groups.values()).sort((left, right) => {
    if (left.firstOrder !== right.firstOrder) return left.firstOrder - right.firstOrder;
    return normalizeString(left.stateName).localeCompare(normalizeString(right.stateName));
  });
}

function renderElectionCustomStateGroups(
  races,
  previousCandidateMap,
  options = {},
) {
  return groupElectionCustomRacesByState(races)
    .map(
      (group) => `<div class="shared-election-custom-state-group">
        <h4>${escapeHtml(group.stateName || group.stateId)}</h4>
        ${group.races
          .map((race) => renderElectionRaceCard(race, previousCandidateMap, options))
          .join("")}
      </div>`,
    )
    .join("");
}

function renderElectionCustomColumns(snapshot, previousCandidateMap, options = {}) {
  const federalRaces = (snapshot.races || []).filter(
    (race) => electionRaceResultScope(race) === ELECTION_SCOPE_FEDERAL,
  );
  const stateRaces = (snapshot.races || []).filter(
    (race) => electionRaceResultScope(race) === ELECTION_SCOPE_STATE,
  );
  const visibleFederalRaces = filterElectionRacesForPartyView(
    federalRaces,
    options,
  );
  const visibleStateRaces = filterElectionRacesForPartyView(stateRaces, options);
  return `<div class="shared-election-custom-columns">
    <section class="shared-election-custom-column">
      <h3>Federal</h3>
      ${
        visibleFederalRaces.length
          ? renderElectionCustomStateGroups(
              visibleFederalRaces,
              previousCandidateMap,
              options,
            )
          : federalRaces.length
            ? '<div class="shared-page__empty">No federal races match this party filter.</div>'
          : '<div class="shared-page__empty">No federal races in this slate.</div>'
      }
    </section>
    <section class="shared-election-custom-column">
      <h3>State level</h3>
      ${
        visibleStateRaces.length
          ? renderElectionCustomStateGroups(
              visibleStateRaces,
              previousCandidateMap,
              options,
            )
          : stateRaces.length
            ? '<div class="shared-page__empty">No state races match this party filter.</div>'
          : '<div class="shared-page__empty">No state races in this slate.</div>'
      }
    </section>
  </div>`;
}

function renderElectionResults(election, selectedOption) {
  const selectedScope = normalizeElectionScope(election.selectedScope);
  const sharedCustom =
    selectedScope === ELECTION_SCOPE_CUSTOM &&
    Boolean(normalizeString(election.selectedCustomShareId));
  if (
    electionScopeRequiresAuth(selectedScope) &&
    !state.auth.session &&
    !sharedCustom
  ) {
    return renderElectionAuthPrompt(selectedScope);
  }
  if (
    selectedScope !== ELECTION_SCOPE_CUSTOM &&
    selectedOption?.future &&
    selectedOption.clickable !== true
  ) {
    return `<section class="shared-election-upcoming">
      <h2>Next Election Date ${escapeHtml(formatElectionDate(selectedOption.electionDate) || "unavailable")}</h2>
      <p>${escapeHtml(selectedOption.electionName || "Results will appear here when vote totals are available.")}</p>
    </section>`;
  }
  const snapshot = election.results.snapshot;
  if (election.results.loading && !snapshot) {
    return '<div class="shared-page__loading">Loading election results…</div>';
  }
  if (election.results.error && !snapshot) {
    return `<div class="shared-page__error">${escapeHtml(election.results.error)}</div>`;
  }
  if (!snapshot) {
    return `<div class="shared-page__empty">No ${escapeHtml(electionScopeLabel(election.selectedScope))} race results are available for this selection.</div>`;
  }
  const previousCandidateMap = electionPreviousCandidateMap(
    election.results.previousSnapshot,
  );
  const partyFilter =
    selectedScope === ELECTION_SCOPE_MY_DISTRICT ||
    selectedScope === ELECTION_SCOPE_CUSTOM
      ? selectedElectionPartyFilterValue(snapshot)
      : "all";
  const groups = groupElectionRaces(snapshot, election.selectedDistrictId);
  const countyCoverageLine = electionCountyCoverageLine(snapshot);
  const customResults =
    selectedScope === ELECTION_SCOPE_CUSTOM
      ? renderElectionCustomColumns(snapshot, previousCandidateMap, {
          partyFilter,
          partyFirst: true,
        })
      : "";
  const myDistrictResults =
    selectedScope === ELECTION_SCOPE_MY_DISTRICT
      ? (() => {
          const visibleRaces = filterElectionRacesForPartyView(
            snapshot.races || [],
            { partyFilter },
          );
          return `<div class="shared-election-group">
            <h3>My District ballot</h3>
            ${renderElectionMissingDistrictNotice(snapshot)}
            ${
              visibleRaces.length
                ? renderElectionRaceList(visibleRaces, previousCandidateMap, {
                    partyFilter,
                    partyFirst: true,
                  })
                : (snapshot.races || []).length
                  ? '<div class="shared-page__empty">No races match this party filter.</div>'
                  : '<div class="shared-page__empty">No tracked races are available for your district.</div>'
            }
          </div>`;
        })()
      : "";
  return `<section class="shared-election-results">
    <div class="shared-election-results__header">
      <div>
        <h2>${escapeHtml(snapshot.electionName || `${electionScopeLabel(snapshot.scope)} election`)}</h2>
        <p>${escapeHtml(electionReportingLine(snapshot))}</p>
      </div>
      <span class="shared-election-status">${escapeHtml(electionStatusLabel(snapshot, selectedOption))}</span>
    </div>
    ${
      countyCoverageLine
        ? `<div class="shared-election-coverage">${escapeHtml(countyCoverageLine)}</div>`
        : ""
    }
    ${
      customResults ||
      myDistrictResults ||
      (groups.length
        ? groups
            .map(
              (group) => `<div class="shared-election-group">
                <h3>${escapeHtml(group.title)}</h3>
                ${group.races
                  .map((race) =>
                    renderElectionRaceCard(race, previousCandidateMap, {
                      partyFilter: "all",
                      partyFirst: false,
                    }),
                  )
                  .join("")}
              </div>`,
            )
            .join("")
        : `<div class="shared-page__empty">No ${escapeHtml(electionScopeLabel(snapshot.scope))} race results are available for this selection.</div>`)
    }
  </section>`;
}

function renderElectionDayPage() {
  const election = state.pages.elections;
  const selectedOption = selectedElectionStateOption();
  const snapshot = election.results.snapshot;
  const status = electionStatusLabel(snapshot, selectedOption);
  const selectedScope = normalizeElectionScope(election.selectedScope);
  const showMap = shouldRenderElectionMap(election);
  const subtitle =
    selectedOption?.future && selectedOption.clickable !== true
      ? `Next Election Date ${formatElectionDate(selectedOption.electionDate) || "unavailable"}`
      : electionReportingLine(snapshot);
  return `<section class="shared-page shared-election-page">
    ${renderTopChrome()}
    <div class="shared-page__content">
      <div class="shared-page__header shared-page__header--hero">
        <div>
          <p class="shared-page__eyebrow">Election Day</p>
          <h1>Live election results</h1>
          <p>${escapeHtml(subtitle)}</p>
          <div class="shared-card__meta">
            <span>${escapeHtml(status)}</span>
            ${election.selectedStateId ? `<span>${escapeHtml(election.selectedStateId)}</span>` : ""}
            ${selectedScope === ELECTION_SCOPE_STATE ? `<span>${escapeHtml(electionRaceTypeLabel(selectedElectionRaceType()))}</span>` : ""}
            ${election.selectedDistrictId ? `<span>${escapeHtml(election.selectedDistrictId)}</span>` : ""}
          </div>
        </div>
        <div class="shared-card__actions">
          <button class="shared-feed-chip shared-feed-chip--primary" data-action="election-refresh">Refresh</button>
          <button class="shared-feed-chip" data-action="open-app-shell">Open app</button>
        </div>
      </div>
      ${election.contextError ? `<div class="shared-page__error">${escapeHtml(election.contextError)}</div>` : ""}
      ${renderElectionControls(election, selectedOption)}
      ${renderElectionCustomControls(election)}
      ${showMap ? renderElectionMapPanel(election) : ""}
      ${renderElectionDistrictFilters(election)}
      ${renderElectionResults(election, selectedOption)}
    </div>
  </section>`;
}

function normalizedCandidatePartyToken(candidate = {}) {
  return normalizeElectionPartyToken(
    candidate.partyToken || candidate.partyCode || candidate.partyLabel,
  );
}

function candidatePartyGroupKey(candidate = {}) {
  return normalizedCandidatePartyToken(candidate) || "UNK";
}

function candidatePartyLabelForKey(key, sample = null) {
  const normalizedKey = normalizeString(key).toUpperCase();
  const sampleLabel = normalizeString(sample?.partyLabel);
  if (sampleLabel) return sampleLabel;
  switch (normalizedKey) {
    case "DEM":
      return "Democratic";
    case "REP":
      return "Republican";
    case "LIB":
      return "Libertarian";
    case "GRN":
      return "Green";
    case "IND":
      return "Independent";
    case "OTH":
      return "Other";
    default:
      return "Unknown party";
  }
}

function candidatePartyColorForKey(key) {
  return electionPartyColor(key || "OTH");
}

function selectedUserCandidatePartyToken() {
  const params = readCurrentSearchParams();
  return normalizeElectionPartyToken(
    params.get("partyToken") ||
      params.get("party") ||
      params.get("partyLabel") ||
      state.pages.elections.context?.userPartyToken ||
      state.pages.elections.context?.userPartyLabel,
  );
}

function candidatePartySortRank(key, userPartyToken = "") {
  const normalizedKey = normalizeString(key).toUpperCase();
  const normalizedUserParty = normalizeString(userPartyToken).toUpperCase();
  if (normalizedUserParty && normalizedKey === normalizedUserParty) {
    return -10;
  }
  const rank = ["DEM", "REP", "LIB", "GRN", "IND", "OTH", "UNK"].indexOf(
    normalizedKey,
  );
  return rank >= 0 ? rank : 999;
}

function compareCandidateDirectoryItems(left = {}, right = {}) {
  if (left.isFollowing !== right.isFollowing) {
    return left.isFollowing ? -1 : 1;
  }
  if (Boolean(left.activeElection?.path) !== Boolean(right.activeElection?.path)) {
    return left.activeElection?.path ? -1 : 1;
  }
  const leftOffice = normalizeString(left.officeTitle || left.levelOfOffice);
  const rightOffice = normalizeString(right.officeTitle || right.levelOfOffice);
  const officeCompare = leftOffice.localeCompare(rightOffice);
  if (officeCompare) return officeCompare;
  return normalizeString(left.displayName).localeCompare(
    normalizeString(right.displayName),
  );
}

function candidatePartyGroups(items = []) {
  const userPartyToken = selectedUserCandidatePartyToken();
  const groups = new Map();
  for (const candidate of items) {
    const key = candidatePartyGroupKey(candidate);
    const existing = groups.get(key) || {
      key,
      title: candidatePartyLabelForKey(key, candidate),
      items: [],
    };
    existing.items.push(candidate);
    if (!existing.title || existing.title === "Unknown party") {
      existing.title = candidatePartyLabelForKey(key, candidate);
    }
    groups.set(key, existing);
  }
  return Array.from(groups.values())
    .map((group) => ({
      ...group,
      items: [...group.items].sort(compareCandidateDirectoryItems),
      count: group.items.length,
      preferred: Boolean(
        userPartyToken && normalizeString(group.key).toUpperCase() === userPartyToken,
      ),
    }))
    .sort((left, right) => {
      const leftRank = candidatePartySortRank(left.key, userPartyToken);
      const rightRank = candidatePartySortRank(right.key, userPartyToken);
      if (leftRank !== rightRank) return leftRank - rightRank;
      return left.title.localeCompare(right.title);
    });
}

function ensureCandidateCollapsedPartyGroupsLoaded() {
  if (candidateCollapsedPartyGroupsLoaded) return;
  candidateCollapsedPartyGroupsLoaded = true;
  try {
    const raw = window.localStorage?.getItem(
      CANDIDATE_PARTY_COLLAPSE_STORAGE_KEY,
    );
    const parsed = raw ? JSON.parse(raw) : [];
    candidateCollapsedPartyGroups = new Set(
      Array.isArray(parsed) ? parsed.map((entry) => normalizeString(entry)) : [],
    );
  } catch {
    candidateCollapsedPartyGroups = new Set();
  }
}

function persistCandidateCollapsedPartyGroups() {
  try {
    window.localStorage?.setItem(
      CANDIDATE_PARTY_COLLAPSE_STORAGE_KEY,
      JSON.stringify(Array.from(candidateCollapsedPartyGroups).filter(Boolean)),
    );
  } catch {
    // Collapsed state is an enhancement.
  }
}

function renderCandidatePreviewCard(candidate, currentPath) {
  const followTarget = resolveCandidateFollowTarget(candidate);
  const partyToken = normalizedCandidatePartyToken(candidate);
  const partyLabel = candidatePartyLabelForKey(partyToken || "UNK", candidate);
  const partyColor = candidatePartyColorForKey(partyToken || "OTH");
  return `<article class="shared-card shared-card--candidate-preview" style="--candidate-party-color:${escapeHtml(partyColor)}">
    ${
      candidate.avatarUrl
        ? `<img class="shared-card__avatar" src="${escapeHtml(candidate.avatarUrl)}" alt="${escapeHtml(candidate.displayName)}" />`
        : `<div class="shared-card__avatar shared-card__avatar--placeholder">${escapeHtml(candidate.displayName.slice(0, 1).toUpperCase() || "C")}</div>`
    }
    <div class="shared-card__body shared-card__body--candidate-preview">
      <div class="shared-card__meta">
        <span class="shared-candidate-party-pill">${escapeHtml(partyToken || partyLabel)}</span>
        <span>${escapeHtml(candidate.officeTitle || candidate.levelOfOffice || "Candidate")}</span>
        ${
          candidate.district
            ? `<span>${escapeHtml(candidate.district)}</span>`
            : ""
        }
      </div>
      <h3>${escapeHtml(partyToken ? `${candidate.displayName} (${partyToken})` : candidate.displayName)}</h3>
      <p class="shared-card__summary">${escapeHtml(candidate.bio || (candidate.kind === "official" ? "Open the official profile to see office details and the report card." : candidate.kind === "raceCandidate" ? "Open the auto-generated profile to see election details and any linked Polis profile." : "Open the candidate page to see recent posts, events, and campaign details."))}</p>
      <div class="shared-card__meta shared-card__meta--candidate-preview">
        <span>${escapeHtml(formatCount(candidate.followersCount))} followers</span>
        ${
          candidate.tags.length
            ? `<span>${escapeHtml(candidate.tags.join(", "))}</span>`
            : ""
        }
      </div>
      <div class="shared-card__actions">
        <button class="shared-feed-chip shared-feed-chip--primary" data-action="navigate" data-route="${escapeHtml(resolveCandidateOpenRoute(candidate, currentPath))}">Open</button>
        ${
          candidate.activeElection?.path
            ? `<button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(candidate.activeElection.path)}">${renderIcon("election")} Results</button>`
            : ""
        }
        ${
          followTarget.candidateId || followTarget.officialId
            ? `<button class="shared-feed-chip" data-action="candidate-follow" data-candidate-id="${escapeHtml(followTarget.candidateId)}" data-official-id="${escapeHtml(followTarget.officialId)}">${candidate.isFollowing ? "Following" : "Follow"}</button>`
            : ""
        }
        ${
          candidate.canEdit
            ? `<button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(resolveCandidateEditRoute(candidate))}">Edit</button>`
            : ""
        }
      </div>
    </div>
  </article>`;
}

function renderCandidatePartyGroup(group, currentPath) {
  const collapsed = candidateCollapsedPartyGroups.has(group.key);
  const color = candidatePartyColorForKey(group.key);
  return `<section class="shared-candidate-party-group" style="--candidate-party-color:${escapeHtml(color)}">
    <button class="shared-candidate-party-group__header" type="button" data-action="candidate-party-toggle" data-party-key="${escapeHtml(group.key)}" aria-expanded="${collapsed ? "false" : "true"}">
      <span class="shared-candidate-party-group__chevron" aria-hidden="true">${collapsed ? "›" : "⌄"}</span>
      <span class="shared-candidate-party-group__title">${escapeHtml(group.title)}</span>
      ${group.preferred ? '<span class="shared-candidate-party-group__badge">Your party</span>' : ""}
      <span class="shared-candidate-party-group__count">${escapeHtml(formatCount(group.count))}</span>
    </button>
    ${
      collapsed
        ? ""
        : `<div class="shared-card-grid shared-card-grid--candidates">
            ${group.items
              .map((candidate) => renderCandidatePreviewCard(candidate, currentPath))
              .join("")}
          </div>`
    }
  </section>`;
}

function renderCandidateListPage() {
  const list = state.pages.candidates.list;
  const currentPath = getCurrentPathWithQuery();
  ensureCandidateCollapsedPartyGroupsLoaded();
  const groups = candidatePartyGroups(list.items);
  return `<section class="shared-page">
    ${renderTopChrome()}
    <div class="shared-page__content">
      <div class="shared-page__header">
        <div>
          <p class="shared-page__eyebrow">Candidates</p>
          <h1>Candidate pages</h1>
          <p>Browse candidates, follow campaigns, and open full candidate detail pages from the browser.</p>
        </div>
        <div class="shared-card__actions">
          <button class="shared-feed-chip shared-feed-chip--primary" data-action="navigate" data-route="/election-day">${renderIcon("election")} Election Day</button>
        </div>
      </div>
      <form class="shared-form shared-form--inline" data-route-form="candidates-filter">
        <input type="search" name="q" placeholder="Search candidates" value="${escapeHtml(list.filters.q || "")}" />
        <input type="text" name="level" placeholder="Level" value="${escapeHtml(list.filters.level || "")}" />
        <input type="text" name="district" placeholder="District" value="${escapeHtml(list.filters.district || "")}" />
        <input type="text" name="tags" placeholder="Tags" value="${escapeHtml(list.filters.tags || "")}" />
        <button type="submit" class="shared-feed-chip shared-feed-chip--primary">Apply</button>
      </form>
      ${
        list.loading
          ? '<div class="shared-page__loading">Loading candidates…</div>'
          : ""
      }
      ${list.error ? `<div class="shared-page__error">${escapeHtml(list.error)}</div>` : ""}
      <div class="shared-candidate-party-groups">
        ${
          groups.length
            ? groups
                .map((group) => renderCandidatePartyGroup(group, currentPath))
                .join("")
            : list.loaded && !list.loading
              ? '<div class="shared-page__empty">No candidates match these filters.</div>'
              : ""
        }
      </div>
      ${
        list.loadingMore
          ? '<div class="shared-page__hint">Loading more candidates…</div>'
          : ""
      }
      ${
        list.nextCursor
          ? '<div class="shared-page__pagination-sentinel" data-candidate-list-sentinel aria-hidden="true"></div>'
          : ""
      }
    </div>
  </section>`;
}

function renderCandidateEditForm(candidate, detail, socials = {}) {
  const avatarUpload = detail.avatarUpload || createCandidateAvatarUploadState();
  const avatarUrl = avatarUpload.remoteUrl || candidate.avatarUrl;
  const avatarBusy = avatarUpload.uploading === true;
  return `<form class="shared-form shared-candidate-editor" data-route-form="candidate-edit">
    <input type="hidden" name="candidateId" value="${escapeHtml(candidate.candidateId)}" />
    <input type="hidden" name="avatarUploadId" value="${escapeHtml(avatarUpload.uploadId)}" />
    <input type="hidden" name="previousAvatarUploadId" value="${escapeHtml(avatarUpload.uploadId ? avatarUpload.previousAvatarUploadId : "")}" />
    <input type="hidden" name="previousAvatarUrl" value="${escapeHtml(avatarUpload.uploadId ? avatarUpload.previousAvatarUrl : "")}" />
    <section class="shared-candidate-editor__section shared-candidate-editor__section--profile">
      <div class="shared-candidate-editor__preview">
        ${
          avatarUrl
            ? `<img src="${escapeHtml(avatarUrl)}" alt="${escapeHtml(candidate.displayName)}" />`
            : `<span>${escapeHtml(candidate.displayName.slice(0, 1).toUpperCase() || "C")}</span>`
        }
        <div>
          <strong>${escapeHtml(candidate.displayName)}</strong>
          <span>${escapeHtml(candidate.levelOfOffice || "Candidate")}</span>
          ${candidate.district ? `<span>${escapeHtml(candidate.district)}</span>` : ""}
        </div>
        <input class="shared-candidate-editor__file-input" type="file" accept="${POST_COMPOSER_IMAGE_ACCEPT}" data-candidate-avatar-file />
        <div class="shared-candidate-editor__avatar-actions">
          <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="candidate-avatar-pick"${avatarBusy ? " disabled" : ""}>${avatarBusy ? "Uploading..." : "Upload image"}</button>
          ${
            avatarUpload.uploadId
              ? `<button class="shared-feed-chip" type="button" data-action="candidate-avatar-clear"${avatarBusy ? " disabled" : ""}>Clear staged</button>`
              : ""
          }
        </div>
        ${
          avatarUpload.fileName
            ? `<small>${escapeHtml(avatarUpload.fileName)}</small>`
            : ""
        }
        ${
          avatarUpload.error
            ? `<small class="shared-candidate-editor__error">${escapeHtml(avatarUpload.error)}</small>`
            : ""
        }
      </div>
      <div class="shared-candidate-editor__grid">
        <label><span>Display name</span><input name="displayName" value="${escapeHtml(candidate.displayName)}" autocomplete="name" /></label>
        <label><span>Office level</span><input name="levelOfOffice" value="${escapeHtml(candidate.levelOfOffice)}" /></label>
        <label><span>District</span><input name="district" value="${escapeHtml(candidate.district)}" /></label>
        <label><span>Avatar URL</span><input name="avatarUrl" value="${escapeHtml(avatarUrl)}" inputmode="url" /></label>
        <label class="shared-candidate-editor__wide"><span>Priority tags</span><input name="priorityTags" value="${escapeHtml(candidate.tags.join(", "))}" /></label>
      </div>
    </section>
    <section class="shared-candidate-editor__section">
      <h2>Biography</h2>
      <label><span>Bio</span><textarea name="bio" rows="6">${escapeHtml(candidate.bio)}</textarea></label>
    </section>
    <section class="shared-candidate-editor__section">
      <h2>Connect</h2>
      <div class="shared-candidate-editor__grid">
        <label><span>Phone</span><input name="phone" value="${escapeHtml(socials.phone || "")}" autocomplete="tel" inputmode="tel" /></label>
        <label><span>Email</span><input name="email" value="${escapeHtml(socials.email || "")}" autocomplete="email" inputmode="email" /></label>
        <label><span>Website</span><input name="website" value="${escapeHtml(socials.website || "")}" inputmode="url" /></label>
        <label><span>X</span><input name="x" value="${escapeHtml(socials.x || "")}" /></label>
        <label><span>Instagram</span><input name="instagram" value="${escapeHtml(socials.instagram || "")}" /></label>
        <label><span>Facebook</span><input name="facebook" value="${escapeHtml(socials.facebook || "")}" /></label>
        <label><span>Threads</span><input name="threads" value="${escapeHtml(socials.threads || "")}" /></label>
        <label><span>Bluesky</span><input name="bluesky" value="${escapeHtml(socials.bluesky || "")}" /></label>
        <label><span>TikTok</span><input name="tiktok" value="${escapeHtml(socials.tiktok || "")}" /></label>
      </div>
    </section>
    <div class="shared-candidate-editor__actions">
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${detail.saving ? " disabled" : ""}>${detail.saving ? "Saving..." : "Save changes"}</button>
      <button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(resolveCandidateOpenRoute(candidate))}">Cancel</button>
    </div>
  </form>`;
}

function candidateDonationFlowStepLabel(step = "") {
  const labels = {
    amount: "Amount",
    profile: "Profile",
    acknowledgements: "Attest",
    review: "Review",
    submitted: "Started",
  };
  return labels[normalizeString(step)] || "Step";
}

function renderCandidateDonationFlowStatus(flow) {
  const error = normalizeString(flow.error);
  const notice = normalizeString(flow.notice);
  return `${error ? `<div class="shared-donation-flow__status shared-donation-flow__status--error">${escapeHtml(error)}</div>` : ""}${notice ? `<div class="shared-donation-flow__status shared-donation-flow__status--notice">${escapeHtml(notice)}</div>` : ""}`;
}

function renderCandidateDonationFlowProgress(flow) {
  const currentStep = normalizeString(flow.step) || "amount";
  const currentIndex =
    currentStep === "submitted"
      ? CANDIDATE_DONATION_FLOW_STEPS.length - 1
      : Math.max(0, CANDIDATE_DONATION_FLOW_STEPS.indexOf(currentStep));
  return `<div class="shared-donation-flow__progress" aria-label="Donation steps">
    ${CANDIDATE_DONATION_FLOW_STEPS.map((step, index) => {
      const active = step === currentStep || (currentStep === "submitted" && step === "review");
      const reached = index <= currentIndex;
      return `<button class="shared-donation-flow__step${active ? " is-active" : ""}${reached ? " is-reached" : ""}" type="button" data-action="candidate-donation-step" data-step="${escapeHtml(step)}"${disabledAttr(!reached || flow.submitting || flow.loading)} aria-current="${active ? "step" : "false"}">
        <span>${escapeHtml(String(index + 1))}</span>
        <strong>${escapeHtml(candidateDonationFlowStepLabel(step))}</strong>
      </button>`;
    }).join("")}
  </div>`;
}

function renderCandidateDonationFlowField(
  flow,
  name,
  label,
  { autocomplete = "", inputmode = "", wide = false } = {},
) {
  const value =
    name === "amount"
      ? normalizeString(flow.amount)
      : normalizeString(flow.fields?.[name]);
  return `<label class="shared-donation-flow__field${wide ? " shared-donation-flow__field--wide" : ""}">
    <span>${escapeHtml(label)}</span>
    <input name="${escapeHtml(name)}" data-donation-flow-field="${escapeHtml(name)}" value="${escapeHtml(value)}"${autocomplete ? ` autocomplete="${escapeHtml(autocomplete)}"` : ""}${inputmode ? ` inputmode="${escapeHtml(inputmode)}"` : ""}${disabledAttr(flow.submitting)} />
  </label>`;
}

function renderCandidateDonationFlowStatusTile({
  icon = "shield",
  title = "",
  subtitle = "",
  statusLabel = "",
  complete = false,
  action = "",
  actionLabel = "",
  pending = false,
}) {
  return `<div class="shared-donation-flow__requirement${complete ? " is-complete" : ""}">
    <span class="shared-donation-flow__requirement-icon">${renderIcon(icon)}</span>
    <div>
      <strong>${escapeHtml(title)}</strong>
      <p>${escapeHtml(subtitle)}</p>
    </div>
    <span class="shared-donation-flow__requirement-status">${escapeHtml(statusLabel)}</span>
    ${
      action && actionLabel
        ? `<button class="shared-feed-chip${complete ? "" : " shared-feed-chip--primary"}" type="button" data-action="${escapeHtml(action)}"${disabledAttr(pending)}>${escapeHtml(pending ? "Opening..." : actionLabel)}</button>`
        : ""
    }
  </div>`;
}

function renderCandidateDonationFlowReviewLine(label, value, actionStep = "") {
  return `<div class="shared-donation-flow__review-line">
    <span>${escapeHtml(label)}</span>
    <strong>${escapeHtml(normalizeString(value) || "Not provided")}</strong>
    ${
      actionStep
        ? `<button class="shared-feed-chip" type="button" data-action="candidate-donation-step" data-step="${escapeHtml(actionStep)}">Edit</button>`
        : ""
    }
  </div>`;
}

function renderCandidateDonationAmountStep(flow) {
  const amountCents = candidateDonationFlowAmountCents(flow);
  const remaining = flow.eligibility?.remainingAllowedCents;
  const remainingLabel =
    remaining !== null && remaining !== undefined
      ? formatDonationAmount(remaining)
      : "the current legal limit";
  const presets = [25, 50, 100, 250].filter((amount) => {
    return remaining === null || remaining === undefined || amount * 100 <= remaining;
  });
  const quickAmounts =
    presets.length > 0
      ? presets
      : remaining && remaining > 0
        ? [Math.max(1, Math.floor(remaining / 100))]
        : [25, 50, 100];
  return `<form class="shared-donation-flow__body" data-route-form="candidate-donation-amount">
    <section class="shared-donation-flow__card shared-donation-flow__amount-card">
      <p class="shared-donation-flow__eyebrow">Step 1</p>
      <h3>Choose how much to give</h3>
      <p>This is a one-time contribution. You can still give ${escapeHtml(remainingLabel)} this cycle.</p>
      <label class="shared-donation-flow__amount-field">
        <span>Donation amount</span>
        <div>
          <em>$</em>
          <input name="amount" data-donation-flow-field="amount" value="${escapeHtml(flow.amount)}" inputmode="decimal" placeholder="25.00"${disabledAttr(flow.submitting)} />
        </div>
      </label>
      ${
        amountCents
          ? `<div class="shared-donation-flow__pill">${renderIcon("heart")} You are giving ${escapeHtml(formatDonationAmount(amountCents))}</div>`
          : ""
      }
    </section>
    <section class="shared-donation-flow__card">
      <div class="shared-donation-flow__section-head">
        <div>
          <h3>Quick amounts</h3>
          <p>Pick once to fill the amount instantly.</p>
        </div>
      </div>
      <div class="shared-donation-flow__amount-presets">
        ${quickAmounts.map((amount) => {
          const selected = amountCents === amount * 100;
          return `<button class="shared-donation-flow__preset${selected ? " is-selected" : ""}" type="button" data-action="candidate-donation-amount-preset" data-amount="${escapeHtml(String(amount))}"${disabledAttr(flow.submitting)}>${escapeHtml(formatDonationAmount(amount * 100))}</button>`;
        }).join("")}
      </div>
    </section>
    <div class="shared-donation-flow__actions">
      <button class="shared-feed-chip" type="button" data-action="candidate-donation-close">Cancel</button>
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(flow.loading || flow.submitting)}>${flow.loading ? "Checking..." : "Continue"}</button>
    </div>
  </form>`;
}

function renderCandidateDonationProfileStep(flow) {
  const identityLocked = candidateDonationFlowIdentityLocked(flow);
  const needsIdentity = candidateDonationFlowNeedsIdentity(flow);
  const needsBankLink = candidateDonationFlowNeedsBankLink(flow);
  const pendingIdentity = flow.actionPendingKey === "identity";
  const pendingBank = flow.actionPendingKey === "bank";
  return `<form class="shared-donation-flow__body" data-route-form="candidate-donation-profile">
    <section class="shared-donation-flow__card">
      <p class="shared-donation-flow__eyebrow">Step 2</p>
      <h3>Required verification</h3>
      <p>Stripe uses these checks to confirm donor identity and eligibility before payment.</p>
      <div class="shared-donation-flow__requirements">
        ${renderCandidateDonationFlowStatusTile({
          icon: "shield",
          title: "Identity verification",
          subtitle: identityLocked
            ? "Verified and locked to your Stripe Identity result."
            : "Complete this once so name and home address can be verified.",
          statusLabel: identityLocked ? "Verified" : "Needed",
          complete: identityLocked,
          action: needsIdentity ? "candidate-donation-identity" : "",
          actionLabel: needsIdentity ? "Verify ID" : "",
          pending: pendingIdentity || flow.submitting,
        })}
        ${renderCandidateDonationFlowStatusTile({
          icon: "payments",
          title: "Bank link",
          subtitle: needsBankLink
            ? "Link a U.S. bank account to satisfy the current compliance flow."
            : "Linked and ready to use for donation checks.",
          statusLabel: needsBankLink ? "Needed" : "Linked",
          complete: !needsBankLink,
          action: needsBankLink ? "candidate-donation-bank-link" : "",
          actionLabel: needsBankLink ? "Link bank" : "",
          pending: pendingBank || flow.submitting,
        })}
      </div>
      <button class="shared-feed-chip" type="button" data-action="candidate-donation-refresh"${disabledAttr(flow.loading || flow.submitting)}>Refresh checks</button>
    </section>
    ${
      identityLocked
        ? `<section class="shared-donation-flow__card">
            <h3>Verified identity</h3>
            <p>Name and residential address now come from the verified identity result.</p>
            <div class="shared-donation-flow__review-grid">
              ${renderCandidateDonationFlowReviewLine("Full legal name", flow.fields.fullLegalName)}
              ${renderCandidateDonationFlowReviewLine("Residential address", candidateDonationFlowAddressSummary(flow))}
            </div>
          </section>`
        : `<section class="shared-donation-flow__card">
            <h3>About the donor</h3>
            <p>Use your residential address, not a P.O. Box.</p>
            <div class="shared-donation-flow__field-grid">
              ${renderCandidateDonationFlowField(flow, "fullLegalName", "Full legal name", { autocomplete: "name", wide: true })}
              ${renderCandidateDonationFlowField(flow, "addressLine1", "Residential address line 1", { autocomplete: "address-line1", wide: true })}
              ${renderCandidateDonationFlowField(flow, "addressLine2", "Address line 2 (optional)", { autocomplete: "address-line2", wide: true })}
              ${renderCandidateDonationFlowField(flow, "city", "City", { autocomplete: "address-level2" })}
              ${renderCandidateDonationFlowField(flow, "state", "State", { autocomplete: "address-level1" })}
              ${renderCandidateDonationFlowField(flow, "postalCode", "ZIP", { autocomplete: "postal-code", inputmode: "numeric" })}
            </div>
          </section>`
    }
    <section class="shared-donation-flow__card">
      <h3>Employment details</h3>
      <p>Campaign-finance rules require occupation and employer for this contribution.</p>
      <div class="shared-donation-flow__field-grid">
        ${renderCandidateDonationFlowField(flow, "occupation", "Occupation", { autocomplete: "organization-title" })}
        ${renderCandidateDonationFlowField(flow, "employer", "Employer", { autocomplete: "organization" })}
        ${renderCandidateDonationFlowField(flow, "jobTitle", "Job title (optional)")}
      </div>
    </section>
    <div class="shared-donation-flow__actions">
      <button class="shared-feed-chip" type="button" data-action="candidate-donation-step" data-step="amount"${disabledAttr(flow.submitting)}>Back</button>
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(flow.submitting)}>Continue</button>
    </div>
  </form>`;
}

function renderCandidateDonationAcknowledgementsStep(flow) {
  const missingSteps = (flow.eligibility?.missingSteps || []).filter(Boolean);
  const requirements = [
    ["usCitizenOrLpr", "I am a U.S. citizen or lawful permanent resident."],
    ["ownFunds", "This contribution is made from my own funds."],
    [
      "campaignAttribution",
      "My campaign attribution statements are true and complete.",
    ],
  ];
  return `<form class="shared-donation-flow__body" data-route-form="candidate-donation-acknowledgements">
    <section class="shared-donation-flow__card">
      <p class="shared-donation-flow__eyebrow">Step 3</p>
      <h3>Required legal attestations</h3>
      <p>These confirmations are required before you can continue to payment.</p>
      <div class="shared-donation-flow__certifications">
        ${requirements.map(([name, label]) => `<label class="shared-donation-flow__certification${flow.certifications?.[name] ? " is-checked" : ""}">
          <input type="checkbox" name="${escapeHtml(name)}" data-donation-flow-certification="${escapeHtml(name)}"${checkedAttr(flow.certifications?.[name])}${disabledAttr(flow.submitting)} />
          <span>${escapeHtml(label)}</span>
        </label>`).join("")}
      </div>
    </section>
    ${
      missingSteps.length || normalizeString(flow.unavailableReason)
        ? `<section class="shared-donation-flow__card shared-donation-flow__card--warning">
            <h3>Still required before review</h3>
            <p>The items below must be cleared before Stripe payment can start.</p>
            <div class="shared-donation-flow__missing">
              ${
                normalizeString(flow.unavailableReason)
                  ? `<span>${renderIcon("lock")} ${escapeHtml(flow.unavailableReason)}</span>`
                  : ""
              }
              ${missingSteps.map((step) => `<span>${renderIcon("check")} ${escapeHtml(candidateDonationReadableStep(step))}</span>`).join("")}
            </div>
            <div class="shared-card__actions">
              <button class="shared-feed-chip" type="button" data-action="candidate-donation-refresh"${disabledAttr(flow.loading || flow.submitting)}>Refresh</button>
              ${
                candidateDonationFlowNeedsIdentity(flow)
                  ? `<button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="candidate-donation-identity"${disabledAttr(flow.submitting || flow.actionPendingKey === "identity")}>Verify ID</button>`
                  : ""
              }
              ${
                candidateDonationFlowNeedsBankLink(flow)
                  ? `<button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="candidate-donation-bank-link"${disabledAttr(flow.submitting || flow.actionPendingKey === "bank")}>Link bank</button>`
                  : ""
              }
            </div>
          </section>`
        : ""
    }
    <div class="shared-donation-flow__actions">
      <button class="shared-feed-chip" type="button" data-action="candidate-donation-step" data-step="profile"${disabledAttr(flow.submitting)}>Back</button>
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(flow.submitting)}>${flow.submitting ? "Checking..." : "Continue to review"}</button>
    </div>
  </form>`;
}

function renderCandidateDonationReviewStep(flow) {
  const amountCents = candidateDonationFlowAmountCents(flow) || 0;
  return `<form class="shared-donation-flow__body" data-route-form="candidate-donation-review">
    <section class="shared-donation-flow__card">
      <p class="shared-donation-flow__eyebrow">Step 4</p>
      <h3>Review your donation</h3>
      <p>Confirm the summary, then move into secure hosted Stripe payment.</p>
      <div class="shared-donation-flow__review-grid">
        ${renderCandidateDonationFlowReviewLine("Candidate", flow.candidateName)}
        ${renderCandidateDonationFlowReviewLine("Amount", formatDonationAmount(amountCents), "amount")}
        ${renderCandidateDonationFlowReviewLine("Donor", flow.fields.fullLegalName, "profile")}
        ${renderCandidateDonationFlowReviewLine("Address", candidateDonationFlowAddressSummary(flow), "profile")}
        ${renderCandidateDonationFlowReviewLine("Occupation", flow.fields.occupation, "profile")}
        ${renderCandidateDonationFlowReviewLine("Employer", flow.fields.employer, "profile")}
      </div>
    </section>
    <section class="shared-donation-flow__card">
      <h3>Payment handoff</h3>
      <p>You will be sent to hosted Stripe Checkout to finish the payment.</p>
      <div class="shared-donation-flow__missing">
        <span>${renderIcon("shield")} ${candidateDonationFlowNeedsIdentity(flow) ? "Identity check still needs to complete." : "Identity check is complete."}</span>
        <span>${renderIcon("payments")} ${candidateDonationFlowNeedsBankLink(flow) ? "Bank link still needs to complete." : "Bank link is complete."}</span>
      </div>
    </section>
    <div class="shared-donation-flow__actions">
      <button class="shared-feed-chip" type="button" data-action="candidate-donation-step" data-step="acknowledgements"${disabledAttr(flow.submitting)}>Back</button>
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(flow.submitting)}>${flow.submitting ? "Opening..." : "Open Stripe Checkout"}</button>
    </div>
  </form>`;
}

function renderCandidateDonationSubmittedStep(flow) {
  const checkoutUrl = normalizeUrl(flow.checkoutSession?.checkoutUrl);
  return `<section class="shared-donation-flow__body shared-donation-flow__submitted">
    <div class="shared-donation-flow__submitted-icon">${renderIcon("check")}</div>
    <h3>Donation flow started</h3>
    <p>${escapeHtml(flow.submittedMessage || "Your donation flow has been started successfully.")}</p>
    <div class="shared-donation-flow__actions">
      ${
        checkoutUrl
          ? `<a class="shared-feed-chip shared-feed-chip--primary" href="${escapeHtml(checkoutUrl)}" target="_blank" rel="noopener noreferrer">Open Stripe Checkout</a>`
          : ""
      }
      <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="candidate-donation-close">Close</button>
    </div>
  </section>`;
}

function renderCandidateDonationFlowBody(flow) {
  if (flow.loading && !flow.eligibility) {
    return `<div class="shared-donation-flow__body"><div class="shared-page__loading">Loading donation checks...</div></div>`;
  }
  if (flow.step === "profile") {
    return renderCandidateDonationProfileStep(flow);
  }
  if (flow.step === "acknowledgements") {
    return renderCandidateDonationAcknowledgementsStep(flow);
  }
  if (flow.step === "review") {
    return renderCandidateDonationReviewStep(flow);
  }
  if (flow.step === "submitted") {
    return renderCandidateDonationSubmittedStep(flow);
  }
  return renderCandidateDonationAmountStep(flow);
}

function renderCandidateDonationFlowModal() {
  const flow = state.pages.candidates.detail.donationFlow;
  if (!flow?.open) {
    return "";
  }
  return `<div class="shared-donation-flow is-open">
    <button class="shared-donation-flow__backdrop" type="button" data-action="candidate-donation-close" aria-label="Close donation flow"></button>
    <section class="shared-donation-flow__dialog" role="dialog" aria-modal="true" aria-labelledby="candidate-donation-flow-title">
      <header class="shared-donation-flow__header">
        <div>
          <p class="shared-donation-flow__eyebrow">Secure donation</p>
          <h2 id="candidate-donation-flow-title">Donate to ${escapeHtml(flow.candidateName)}</h2>
          <p>Complete the same compliance checks and Stripe handoff used in the Polis app.</p>
        </div>
        <button class="shared-comments__close" type="button" data-action="candidate-donation-close" aria-label="Close donation flow">${renderIcon("close")}</button>
      </header>
      ${renderCandidateDonationFlowProgress(flow)}
      ${renderCandidateDonationFlowStatus(flow)}
      ${renderCandidateDonationFlowBody(flow)}
    </section>
  </div>`;
}

function renderCandidateDetailPage() {
  const detail = state.pages.candidates.detail;
  const candidate = detail.item;
  const isEditRoute = getCurrentRoute().routeKey === ROUTE_KEY_CANDIDATE_EDIT;
  const isSettingsEditRoute = isCandidateSettingsEditRoute();
  if (detail.loading && !candidate) {
    return `<section class="shared-page">${renderTopChrome()}<div class="shared-page__content"><div class="shared-page__loading">Loading candidate…</div></div></section>`;
  }
  if (!candidate) {
    return `<section class="shared-page">${renderTopChrome()}<div class="shared-page__content"><div class="shared-page__error">${escapeHtml(detail.error || "Candidate unavailable.")}</div></div></section>`;
  }
  const socials = candidate.socials || {};
  const officialId = resolveCandidateOfficialId(candidate);
  const canDonate = candidateCanReceiveDonations(candidate);
  return `<section class="shared-page shared-candidate-page${isEditRoute ? " shared-candidate-page--editing" : ""}">
    ${renderTopChrome()}
    <div class="shared-page__content">
      <div class="shared-page__back-row">
        <button class="shared-feed-chip" type="button" data-action="navigate" data-route="${isSettingsEditRoute ? "/settings" : "/candidates"}">${isSettingsEditRoute ? "Back to settings" : "Back to candidates"}</button>
      </div>
      <div class="shared-page__header shared-page__header--hero">
        <div class="shared-page__hero">
          ${
            candidate.avatarUrl
              ? `<img class="shared-page__hero-avatar" src="${escapeHtml(candidate.avatarUrl)}" alt="${escapeHtml(candidate.displayName)}" />`
              : `<div class="shared-page__hero-avatar shared-page__hero-avatar--placeholder">${escapeHtml(candidate.displayName.slice(0, 1).toUpperCase() || "C")}</div>`
          }
          <div>
            <p class="shared-page__eyebrow">${escapeHtml(candidate.levelOfOffice || "Candidate")}</p>
            <h1>${escapeHtml(candidate.displayName)}</h1>
            <p>${escapeHtml(candidate.bio || "Candidate page")}</p>
            <div class="shared-card__meta">
              ${candidate.district ? `<span>${escapeHtml(candidate.district)}</span>` : ""}
              <span>${escapeHtml(formatCount(candidate.followersCount))} followers</span>
              ${
                candidate.tags.length
                  ? `<span>${escapeHtml(candidate.tags.join(", "))}</span>`
                  : ""
              }
            </div>
          </div>
        </div>
        <div class="shared-card__actions">
          <button class="shared-feed-chip shared-feed-chip--primary" data-action="candidate-follow" data-candidate-id="${escapeHtml(candidate.candidateId)}" data-official-id="${escapeHtml(officialId)}">${candidate.isFollowing ? "Following" : "Follow"}</button>
          ${
            candidate.activeElection?.path
              ? `<button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(candidate.activeElection.path)}">${renderIcon("election")} Results</button>`
              : ""
          }
          ${
            candidate.canEdit
              ? `<button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(resolveCandidateEditRoute(candidate))}">${isEditRoute ? "Editing" : "Edit page"}</button>`
              : ""
          }
          ${
            canDonate
              ? `<button class="shared-feed-chip shared-feed-chip--primary" data-action="candidate-donation-open" data-candidate-id="${escapeHtml(candidate.candidateId)}">Donate</button>`
              : normalizeString(candidate.donationDisabledReason)
                ? `<button class="shared-feed-chip" type="button" disabled>${escapeHtml(candidate.donationDisabledReason)}</button>`
                : ""
          }
          ${
            normalizeString(socials.website)
              ? `<a class="shared-feed-chip" href="${escapeHtml(socials.website)}" target="_blank" rel="noopener noreferrer">Website</a>`
              : ""
          }
          ${
            officialId
              ? `<button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(buildOfficialReportCardRoute(officialId, { returnTo: getCurrentPathWithQuery() }))}">Official Report Card</button>`
              : ""
          }
          <button class="shared-feed-chip" data-action="navigate" data-route="/events?q=${encodeURIComponent(candidate.displayName)}">Related events</button>
        </div>
      </div>
      ${
        isEditRoute
          ? renderCandidateEditForm(candidate, detail, socials)
          : ""
      }
      ${detail.error ? `<div class="shared-page__error">${escapeHtml(detail.error)}</div>` : ""}
      <div class="shared-page__split">
        <div>
          <h2>Posts</h2>
          ${renderMediaThumbnailGrid(detail.posts, {
            emptyMessage: "No posts yet.",
            getRoute: (item) =>
              item.postId ? `/posts/${encodeURIComponent(item.postId)}` : "",
            getMediaUrl: (item) => item.posterUrl || item.imageUrl,
            getAltText: (item) =>
              item.previewTitle ||
              item.caption ||
              item.authorDisplayName ||
              "Post",
            getOverlayText: (item) =>
              `${formatCount(item.likesCount)} like${Number(item.likesCount) === 1 ? "" : "s"}`,
            getPlaceholderLabel: () => "P",
            overlayBare: true,
          })}
        </div>
        <div>
          <h2>Upcoming events</h2>
          ${renderMediaThumbnailGrid(detail.relatedEvents, {
            emptyMessage: "No upcoming events yet.",
            getRoute: (item) =>
              item.eventId ? `/events/${encodeURIComponent(item.eventId)}` : "",
            getMediaUrl: (item) => item.imageUrl,
            getAltText: (item) => item.title || "Event",
            getOverlayText: (item) =>
              `${formatCount(item.attendeeCount)} going`,
            getPlaceholderLabel: () => "E",
          })}
        </div>
      </div>
    </div>
  </section>`;
}

function renderCandidateDashboardAuthGate() {
  return `<section class="shared-page shared-campaign-dashboard">
    ${renderTopChrome()}
    <div class="shared-page__content">
      <section class="shared-campaign-auth">
        <div>
          <h1>Campaign Command Center</h1>
          <p>Manage candidate operations from the browser with the same campaign access model used in the Polis app.</p>
          <div class="shared-card__actions">
            <button class="shared-feed-chip shared-feed-chip--primary" data-action="auth-login-inline">Sign in</button>
            <button class="shared-feed-chip" data-action="auth-signup-inline">Create account</button>
            <button class="shared-feed-chip" data-action="open-app-shell">Open app</button>
          </div>
        </div>
        <div class="shared-campaign-auth__grid" aria-hidden="true">
          ${["Analytics", "Missions", "Calendar", "Staff", "Messaging", "Voters"]
            .map(
              (label) =>
                `<span class="shared-campaign-auth__tile">${escapeHtml(label)}</span>`,
            )
            .join("")}
        </div>
      </section>
    </div>
  </section>`;
}

function candidateDashboardFeatureRank(section) {
  const index = CANDIDATE_DASHBOARD_FEATURE_ORDER.indexOf(section?.key);
  return index >= 0 ? index : CANDIDATE_DASHBOARD_FEATURE_ORDER.length;
}

function candidateDashboardFeatureSections({ includeOverview = false } = {}) {
  return CANDIDATE_DASHBOARD_SECTION_CONFIG.filter(
    (section) => includeOverview || section.key !== CANDIDATE_DASHBOARD_DEFAULT_SECTION,
  ).sort((left, right) => candidateDashboardFeatureRank(left) - candidateDashboardFeatureRank(right));
}

function candidateDashboardFeatureCopy(section) {
  return (
    CANDIDATE_DASHBOARD_FEATURE_COPY[section?.key] || {
      eyebrow: "Campaign",
      description: `${section?.label || "Campaign feature"} is available from this dashboard when your access includes it.`,
      cta: `Open ${section?.label || "section"}`,
    }
  );
}

function candidateDashboardFeatureStatus(section, access) {
  const enabled = canOpenCandidateDashboardSection(section, access);
  if (enabled) {
    return {
      label: access?.isOwner ? "Owner access" : "Included in your role",
      cta: candidateDashboardFeatureCopy(section).cta,
    };
  }
  if (section?.ownerOnly) {
    return {
      label: "Owner only",
      cta: "Owner access required",
    };
  }
  return {
    label: "Permission required",
    cta: "Ask for access",
  };
}

function candidateDashboardFeatureHighlights(access, limit = 5) {
  const sections = candidateDashboardFeatureSections().filter((section) =>
    canOpenCandidateDashboardSection(section, access),
  );
  const visible = sections.slice(0, limit);
  return {
    visible,
    remaining: Math.max(0, sections.length - visible.length),
    total: sections.length,
  };
}

function renderCandidateDashboardFeaturePill(section, candidateId) {
  return `<button class="shared-campaign-feature-pill" type="button" data-action="navigate" data-route="${escapeHtml(candidateDashboardSectionPath(candidateId, section.key))}">
    <span>${renderIcon(section.icon)}</span>
    <strong>${escapeHtml(section.label)}</strong>
  </button>`;
}

function renderCandidateDashboardFeatureCard(section, candidateId, access) {
  const copy = candidateDashboardFeatureCopy(section);
  const enabled = canOpenCandidateDashboardSection(section, access);
  const status = candidateDashboardFeatureStatus(section, access);
  const route = candidateDashboardSectionPath(candidateId, section.key);
  const tag = `<span class="shared-campaign-feature-card__status${enabled ? " is-enabled" : " is-locked"}">${escapeHtml(status.label)}</span>`;
  const body = `
    <span class="shared-campaign-feature-card__icon">${renderIcon(enabled ? section.icon : "lock")}</span>
    <span class="shared-campaign-feature-card__body">
      <span class="shared-card__meta"><span>${escapeHtml(copy.eyebrow)}</span>${tag}</span>
      <strong>${escapeHtml(section.label)}</strong>
      <small>${escapeHtml(copy.description)}</small>
      <em>${escapeHtml(status.cta)}</em>
    </span>`;
  if (!enabled) {
    return `<article class="shared-campaign-feature-card is-locked" aria-disabled="true">${body}</article>`;
  }
  return `<button class="shared-campaign-feature-card" type="button" data-action="navigate" data-route="${escapeHtml(route)}">${body}</button>`;
}

function renderCandidateDashboardRootSummary(campaigns = []) {
  if (!campaigns.length) {
    return "";
  }
  const ownerCount = campaigns.filter((item) => item.isOwner).length;
  const enabledSections = candidateDashboardFeatureSections().filter((section) =>
    campaigns.some((access) => canOpenCandidateDashboardSection(section, access)),
  );
  const prioritySections = enabledSections.slice(0, 6);
  return `<section class="shared-campaign-access-map">
    <div class="shared-campaign-access-map__intro">
      <span class="shared-card__meta"><span>Web command center</span><span>${escapeHtml(formatCount(enabledSections.length))} feature areas</span></span>
      <h2>Start from the campaign, then jump straight into the work.</h2>
      <p>Each campaign card now exposes the same candidate dashboard areas used in the Polis app: missions, messaging, calendar, voter tools, staff access, donations, events, and reporting.</p>
    </div>
    <div class="shared-campaign-access-map__metrics">
      <span><strong>${escapeHtml(formatCount(campaigns.length))}</strong><small>campaign${campaigns.length === 1 ? "" : "s"}</small></span>
      <span><strong>${escapeHtml(formatCount(ownerCount))}</strong><small>owner</small></span>
      <span><strong>${escapeHtml(formatCount(Math.max(0, campaigns.length - ownerCount)))}</strong><small>staff</small></span>
    </div>
    ${
      prioritySections.length
        ? `<div class="shared-campaign-access-map__features">
            ${prioritySections
              .map((section) => {
                const count = campaigns.filter((access) =>
                  canOpenCandidateDashboardSection(section, access),
                ).length;
                return `<span>
                  <i>${renderIcon(section.icon)}</i>
                  <strong>${escapeHtml(section.label)}</strong>
                  <small>${escapeHtml(`${formatCount(count)} campaign${count === 1 ? "" : "s"}`)}</small>
                </span>`;
              })
              .join("")}
          </div>`
        : ""
    }
  </section>`;
}

function renderCandidateDashboardCampaignCard(access) {
  const profile = access.profile || {};
  const displayName = normalizeString(profile.displayName) || "Campaign";
  const dashboardPath = candidateDashboardSectionPath(access.candidateId);
  const permissionCount = access.isOwner
    ? "Owner"
    : `${formatCount(access.permissions.length)} permission${access.permissions.length === 1 ? "" : "s"}`;
  const highlights = candidateDashboardFeatureHighlights(access, 5);
  return `<article class="shared-campaign-card">
    <div class="shared-campaign-card__avatar">
      ${
        profile.avatarUrl
          ? `<img src="${escapeHtml(profile.avatarUrl)}" alt="${escapeHtml(displayName)}" />`
          : `<span>${escapeHtml(displayName.slice(0, 1).toUpperCase() || "C")}</span>`
      }
    </div>
    <div class="shared-campaign-card__body">
      <div class="shared-card__meta">
        <span>${escapeHtml(permissionCount)}</span>
        ${profile.username ? `<span>@${escapeHtml(profile.username)}</span>` : ""}
      </div>
      <h3>${escapeHtml(displayName)}</h3>
      ${
        highlights.visible.length
          ? `<div class="shared-campaign-card__features">
              ${highlights.visible
                .map((section) =>
                  renderCandidateDashboardFeaturePill(section, access.candidateId),
                )
                .join("")}
              ${highlights.remaining ? `<span class="shared-campaign-feature-more">+${escapeHtml(formatCount(highlights.remaining))} more</span>` : ""}
            </div>`
          : `<p class="shared-campaign-card__note">Open the dashboard to review campaign access and request feature permissions.</p>`
      }
      <div class="shared-card__actions">
        <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="navigate" data-route="${escapeHtml(dashboardPath)}">Command center</button>
        ${
          canManageCandidateMessaging(access)
            ? `<button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(candidateMessagingServerPath(access.candidateId))}">Messaging</button>`
            : ""
        }
      </div>
    </div>
  </article>`;
}

function renderCandidateDashboardRootEmpty() {
  const profile = state.pages.profile.me;
  const status = normalizeString(profile?.candidateAccessStatus).toLowerCase();
  const title =
    status === "pending"
      ? "Candidate access is under review."
      : "No campaign dashboard access is attached to this account.";
  const copy =
    status === "pending"
      ? "Your filing review is still pending. The dashboard will open here after approval."
      : "Apply for candidate access or ask a campaign owner to invite you to their staff dashboard.";
  return `<div class="shared-page__empty shared-campaign-empty-access">
    <strong>${escapeHtml(title)}</strong>
    <span>${escapeHtml(copy)}</span>
    <div class="shared-campaign-empty-access__paths">
      <button type="button" data-action="navigate" data-route="/settings/candidate-access">
        <strong>Candidate access</strong>
        <small>Apply for owner access and unlock the campaign command center.</small>
      </button>
      <button type="button" data-action="navigate" data-route="/coalitions">
        <strong>Coalitions</strong>
        <small>Open coalition workspaces if your organizing role lives there.</small>
      </button>
      <button type="button" data-action="navigate" data-route="/messages">
        <strong>Messages</strong>
        <small>Use direct and room messaging while campaign access is being added.</small>
      </button>
    </div>
    <div class="shared-card__actions">
      <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="navigate" data-route="/settings/candidate-access">Candidate access</button>
      <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/candidates">Candidate directory</button>
    </div>
  </div>`;
}

function renderCandidateDashboardRoot() {
  const campaigns = state.pages.candidateDashboard.campaigns;
  return `<section class="shared-page shared-campaign-dashboard">
    ${renderTopChrome()}
    <div class="shared-page__content">
      <div class="shared-page__header">
        <div>
          <h1>Campaigns</h1>
          <p>Open a candidate dashboard to manage campaign operations, rooms, staff access, missions, voters, events, and reporting.</p>
        </div>
        <div class="shared-card__actions">
          <button class="shared-feed-chip" data-action="navigate" data-route="/candidates">Candidate directory</button>
          <button class="shared-feed-chip" data-action="open-app-shell">Open app</button>
        </div>
      </div>
      ${campaigns.loading && !campaigns.items.length ? '<div class="shared-page__loading">Loading campaigns...</div>' : ""}
      ${campaigns.error ? `<div class="shared-page__error">${escapeHtml(campaigns.error)}</div>` : ""}
      ${campaigns.items.length ? renderCandidateDashboardRootSummary(campaigns.items) : ""}
      ${
        campaigns.items.length
          ? `<div class="shared-campaign-grid">${campaigns.items.map(renderCandidateDashboardCampaignCard).join("")}</div>`
          : campaigns.loaded && !campaigns.loading
            ? renderCandidateDashboardRootEmpty()
            : ""
      }
    </div>
  </section>`;
}

function renderCandidateDashboardHero(candidate, access) {
  const displayName =
    normalizeString(candidate?.displayName || access?.profile?.displayName) ||
    "Campaign";
  const avatarUrl = normalizeUrl(candidate?.avatarUrl || access?.profile?.avatarUrl);
  const officeLine = [
    candidate?.officeTitle,
    candidate?.levelOfOffice,
    candidate?.district,
  ]
    .map(normalizeString)
    .filter(Boolean)
    .join(" - ");
  return `<section class="shared-campaign-hero">
    <div class="shared-campaign-hero__identity">
      <div class="shared-campaign-hero__avatar">
        ${
          avatarUrl
            ? `<img src="${escapeHtml(avatarUrl)}" alt="${escapeHtml(displayName)}" />`
            : `<span>${escapeHtml(displayName.slice(0, 1).toUpperCase() || "C")}</span>`
        }
      </div>
      <div>
        <div class="shared-card__meta">
          <span>${access?.isOwner ? "Owner access" : "Staff access"}</span>
          ${access?.profile?.username ? `<span>@${escapeHtml(access.profile.username)}</span>` : ""}
        </div>
        <h1>${escapeHtml(displayName)}</h1>
        <p>${escapeHtml(officeLine || candidate?.bio || "Campaign operations")}</p>
      </div>
  </div>
  <div class="shared-campaign-hero__actions">
      <button class="shared-feed-chip shared-feed-chip--primary" data-action="navigate" data-route="${escapeHtml(candidateMessagingServerPath(access?.candidateId || candidate?.candidateId || ""))}">${renderIcon("messages")} Rooms</button>
      <button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(candidateDashboardSectionPath(access?.candidateId || candidate?.candidateId, "missions"))}">${renderIcon("mission")} Missions</button>
      <button class="shared-feed-chip" data-action="open-app-shell">Open app</button>
    </div>
  </section>`;
}

function renderCandidateDashboardTabs(candidateId, activeSection, access) {
  return `<nav class="shared-campaign-tabs" aria-label="Campaign dashboard sections">
    ${CANDIDATE_DASHBOARD_SECTION_CONFIG.map((section) => {
      const active = section.key === activeSection;
      const enabled = canOpenCandidateDashboardSection(section, access);
      return `<button class="shared-campaign-tab${active ? " is-active" : ""}${enabled ? "" : " is-muted"}" data-action="navigate" data-route="${escapeHtml(candidateDashboardSectionPath(candidateId, section.key))}">
        <span>${renderIcon(section.icon)}</span>
        <strong>${escapeHtml(section.label)}</strong>
      </button>`;
    }).join("")}
  </nav>`;
}

function renderCandidateDashboardMetric(label, value, tone = "") {
  return `<div class="shared-campaign-metric${tone ? ` shared-campaign-metric--${escapeHtml(tone)}` : ""}">
    <span>${escapeHtml(label)}</span>
    <strong>${escapeHtml(value)}</strong>
  </div>`;
}

function renderCandidateDashboardMiniList(items, renderItem, emptyText) {
  if (!items.length) {
    return `<div class="shared-page__empty">${escapeHtml(emptyText)}</div>`;
  }
  return `<div class="shared-stack">${items.map(renderItem).join("")}</div>`;
}

function renderCandidateDashboardOverview(detail, candidateId, access) {
  const analytics = detail.analytics || {};
  const metrics = [
    renderCandidateDashboardMetric("Reach", formatCount(analytics.reach || 0), "cyan"),
    renderCandidateDashboardMetric(
      "Impressions",
      formatCount(analytics.impressions || 0),
    ),
    renderCandidateDashboardMetric("Staff", formatCount(detail.staff.length)),
    renderCandidateDashboardMetric("Missions", formatCount(detail.missions.length)),
    renderCandidateDashboardMetric("Events", formatCount(detail.events.length)),
    renderCandidateDashboardMetric("Calendar", formatCount(detail.calendar.length)),
  ].join("");
  const featureSections = candidateDashboardFeatureSections({ includeOverview: true });
  return `<div class="shared-campaign-section">
    <div class="shared-campaign-metrics">${metrics}</div>
    <div class="shared-campaign-overview-grid">
      <article class="shared-campaign-panel">
        <div class="shared-campaign-panel__header">
          <h2>Operations</h2>
          <button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(candidateDashboardSectionPath(candidateId, "missions"))}">Missions</button>
        </div>
        ${renderCandidateDashboardMiniList(
          detail.missions.slice(0, 3),
          (mission) => `<button class="shared-list-item" data-action="navigate" data-route="/missions/${escapeHtml(encodeURIComponent(mission.missionId))}">
            <strong>${escapeHtml(mission.title)}</strong>
            <span>${escapeHtml(humanizeLabel(mission.status))}${mission.assignedCount ? ` - ${formatCount(mission.assignedCount)} assigned` : ""}</span>
          </button>`,
          "No active missions in this campaign view.",
        )}
      </article>
      <article class="shared-campaign-panel">
        <div class="shared-campaign-panel__header">
          <h2>Calendar</h2>
          <button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(candidateDashboardSectionPath(candidateId, "calendar"))}">Open</button>
        </div>
        ${renderCandidateDashboardMiniList(
          detail.calendar.slice(0, 3),
          (item) => `<div class="shared-list-item">
            <strong>${escapeHtml(item.title)}</strong>
            <span>${escapeHtml(item.startAt ? formatAbsoluteDateTime(item.startAt) : humanizeLabel(item.status))}</span>
          </div>`,
          "No upcoming calendar items.",
        )}
      </article>
      <article class="shared-campaign-panel">
        <div class="shared-campaign-panel__header">
          <h2>Access</h2>
          <button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(candidateDashboardSectionPath(candidateId, "staff"))}">Staff</button>
        </div>
        ${renderCandidateDashboardMiniList(
          detail.staff.slice(0, 4),
          (member) => `<div class="shared-list-item">
            <strong>${escapeHtml(member.displayName)}</strong>
            <span>${escapeHtml(member.role)} - ${escapeHtml(formatCount(member.permissions.length))} permissions</span>
          </div>`,
          "No staff members loaded.",
        )}
      </article>
      <article class="shared-campaign-panel shared-campaign-panel--wide">
        <div class="shared-campaign-panel__header">
          <div>
            <span class="shared-card__meta"><span>Feature map</span><span>${escapeHtml(access?.isOwner ? "Owner workspace" : "Staff workspace")}</span></span>
            <h2>Campaign command center</h2>
            <p>Open the browser surfaces that match the Polis app dashboard. Locked cards show what exists but needs owner access or a staff permission.</p>
          </div>
        </div>
        <div class="shared-campaign-feature-grid">
          ${featureSections
            .map((section) =>
              renderCandidateDashboardFeatureCard(section, candidateId, access),
            )
            .join("")}
        </div>
      </article>
    </div>
  </div>`;
}

function formatAnalyticsPercent(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) {
    return "0%";
  }
  const percent = numeric <= 1 ? numeric * 100 : numeric;
  return `${percent.toFixed(percent >= 10 ? 1 : 1)}%`;
}

function candidateAnalyticsAudienceLabels(context = {}) {
  if (context.matchMode === "state") {
    return {
      matched: "In-state",
      outside: "Out of state",
      unknown: "Unknown",
    };
  }
  return {
    matched: "Constituents",
    outside: "Outside district",
    unknown: "Unknown",
  };
}

function renderCandidateAnalyticsRangeControls(resource) {
  return `<div class="shared-campaign-analytics-range" role="group" aria-label="Analytics range">
    ${[7, 30, 90]
      .map((days) => {
        const selected = Number(resource.days) === days;
        return `<button class="shared-feed-chip${selected ? " shared-feed-chip--primary" : ""}" type="button" data-action="candidate-analytics-range" data-days="${escapeHtml(String(days))}"${disabledAttr(resource.loading)}>${escapeHtml(`${days}d`)}</button>`;
      })
      .join("")}
    <button class="shared-feed-chip" type="button" data-action="candidate-analytics-refresh"${disabledAttr(resource.loading)}>Refresh</button>
  </div>`;
}

function renderCandidateAnalyticsAudienceBar(breakdown, labels) {
  if (!breakdown) {
    return `<div class="shared-page__empty">Audience segmentation is unavailable for this range.</div>`;
  }
  const matched = Math.max(0, breakdown.matched?.percent || 0);
  const outside = Math.max(0, breakdown.outside?.percent || 0);
  const unknown = Math.max(0, breakdown.unknown?.percent || 0);
  return `<div class="shared-campaign-analytics-audience">
    <div class="shared-campaign-analytics-bar" aria-label="Audience breakdown">
      <span class="is-matched" style="width: ${escapeHtml(String(matched))}%"></span>
      <span class="is-outside" style="width: ${escapeHtml(String(outside))}%"></span>
      <span class="is-unknown" style="width: ${escapeHtml(String(unknown))}%"></span>
    </div>
    <div class="shared-campaign-analytics-legend">
      <span><em class="is-matched"></em>${escapeHtml(labels.matched)} ${escapeHtml(formatCount(breakdown.matched?.count || 0))}</span>
      <span><em class="is-outside"></em>${escapeHtml(labels.outside)} ${escapeHtml(formatCount(breakdown.outside?.count || 0))}</span>
      <span><em class="is-unknown"></em>${escapeHtml(labels.unknown)} ${escapeHtml(formatCount(breakdown.unknown?.count || 0))}</span>
    </div>
  </div>`;
}

function renderCandidateAnalyticsTrend(analytics) {
  const points = analytics.trend || [];
  if (!points.length) {
    return `<div class="shared-page__empty">No daily trend data yet.</div>`;
  }
  const maxReach = Math.max(...points.map((point) => point.reach || 0), 1);
  return `<div class="shared-campaign-analytics-trend">
    ${points
      .slice(-14)
      .map((point) => {
        const height = Math.max(8, Math.round(((point.reach || 0) / maxReach) * 100));
        return `<div class="shared-campaign-analytics-trend__day">
          <span title="${escapeHtml(`${formatCalendarDate(point.date)} - ${formatCount(point.reach || 0)} reach`)}" style="height: ${escapeHtml(String(height))}%"></span>
          <em>${escapeHtml(formatCalendarDate(point.date).replace(/,.*$/u, ""))}</em>
        </div>`;
      })
      .join("")}
  </div>`;
}

function renderCandidateAnalyticsTopPost(post, index, labels) {
  return `<article class="shared-campaign-analytics-post">
    <button class="shared-campaign-analytics-post__button" type="button" data-action="navigate" data-route="/posts/${escapeHtml(encodeURIComponent(post.postId))}">
      <span class="shared-campaign-analytics-rank">${escapeHtml(String(index + 1))}</span>
      <span class="shared-campaign-analytics-post__body">
        <strong>${escapeHtml(post.previewText || "Post")}</strong>
        <span>${escapeHtml(formatCount(post.reach || post.impressions || 0))} reach - ${escapeHtml(formatAnalyticsPercent(post.engagementRate))} engagement</span>
      </span>
    </button>
    ${post.reachBreakdown ? renderCandidateAnalyticsAudienceBar(post.reachBreakdown, labels) : ""}
  </article>`;
}

function renderCandidateAnalyticsEventConversion(event, labels) {
  return `<article class="shared-campaign-analytics-event">
    <div>
      <strong>${escapeHtml(event.title)}</strong>
      <span>${escapeHtml(event.startAt ? formatAbsoluteDateTime(event.startAt) : "Event")}</span>
    </div>
    <div class="shared-campaign-analytics-event__metrics">
      <span><strong>${escapeHtml(formatCount(event.reach))}</strong><em>Reach</em></span>
      <span><strong>${escapeHtml(formatCount(event.interestAdds))}</strong><em>Interested</em></span>
      <span><strong>${escapeHtml(formatCount(event.rsvpAdds))}</strong><em>RSVP</em></span>
      <span><strong>${escapeHtml(formatAnalyticsPercent(event.rsvpFromViewRateNet))}</strong><em>RSVP rate</em></span>
    </div>
    ${event.reachBreakdown ? renderCandidateAnalyticsAudienceBar(event.reachBreakdown, labels) : ""}
  </article>`;
}

function renderCandidateDashboardAnalytics(detail) {
  const resource = detail.analyticsWorkspace;
  const analytics = resource.snapshot || detail.analytics;
  if (resource.loading && !analytics) {
    return `<div class="shared-page__empty">Loading campaign analytics...</div>`;
  }
  if (!analytics) {
    return `<div class="shared-page__empty">Analytics are not available for this campaign session.</div>`;
  }
  const labels = candidateAnalyticsAudienceLabels(analytics.audienceContext);
  const conversions = resource.conversions?.events || [];
  const engagementRate =
    analytics.impressions > 0
      ? (analytics.likes + analytics.comments) / analytics.impressions
      : 0;
  return `<div class="shared-campaign-section shared-campaign-analytics">
    <article class="shared-campaign-panel shared-campaign-analytics-hero">
      <div class="shared-campaign-panel__header">
        <div>
          <h2>Audience analytics</h2>
          <p>${escapeHtml(analytics.audienceContext?.available ? `${analytics.audienceContext.referenceLabel || "Campaign target"} matching is active.` : "Segmentation is limited for this range.")}</p>
        </div>
        ${renderCandidateAnalyticsRangeControls(resource)}
      </div>
      ${resource.error ? `<div class="shared-page__empty">${escapeHtml(resource.error)}</div>` : ""}
    </article>
    <div class="shared-campaign-metrics">
      ${renderCandidateDashboardMetric("Reach", formatCount(analytics.reach), "cyan")}
      ${renderCandidateDashboardMetric("Engaged viewers", formatCount(analytics.engagedViewers))}
      ${renderCandidateDashboardMetric("Impressions", formatCount(analytics.impressions))}
      ${renderCandidateDashboardMetric("Engagement", formatAnalyticsPercent(engagementRate), "cyan")}
      ${renderCandidateDashboardMetric("Watches", formatCount(analytics.watches))}
      ${renderCandidateDashboardMetric("Completion", formatAnalyticsPercent(analytics.completionRate))}
      ${renderCandidateDashboardMetric("Negative", formatAnalyticsPercent(analytics.negativeRate))}
    </div>
    <div class="shared-campaign-analytics-grid">
      <article class="shared-campaign-panel">
        <div class="shared-campaign-panel__header">
          <div>
            <h2>Audience breakdown</h2>
            <p>Reached viewers grouped by campaign target geography.</p>
          </div>
        </div>
        ${renderCandidateAnalyticsAudienceBar(analytics.reachBreakdown, labels)}
      </article>
      <article class="shared-campaign-panel">
        <div class="shared-campaign-panel__header">
          <div>
            <h2>Daily reach trend</h2>
            <p>Most recent days in the selected range.</p>
          </div>
        </div>
        ${renderCandidateAnalyticsTrend(analytics)}
      </article>
    </div>
    <div class="shared-campaign-analytics-grid">
      <article class="shared-campaign-panel">
        <div class="shared-campaign-panel__header">
          <div>
            <h2>Top posts</h2>
            <p>Ranked by audience reach during this period.</p>
          </div>
        </div>
        ${
          analytics.topPosts.length
            ? `<div class="shared-campaign-analytics-list">${analytics.topPosts.slice(0, 10).map((post, index) => renderCandidateAnalyticsTopPost(post, index, labels)).join("")}</div>`
            : `<div class="shared-page__empty">No top posts in this analytics window.</div>`
        }
      </article>
      <article class="shared-campaign-panel">
        <div class="shared-campaign-panel__header">
          <div>
            <h2>Event conversions</h2>
            <p>Event reach, interest adds, and RSVP adds from campaign exposure.</p>
          </div>
        </div>
        ${
          conversions.length
            ? `<div class="shared-campaign-analytics-list">${conversions.slice(0, 10).map((event) => renderCandidateAnalyticsEventConversion(event, labels)).join("")}</div>`
            : `<div class="shared-page__empty">No event conversions yet.</div>`
        }
      </article>
    </div>
  </div>`;
}

function candidateDashboardEventAllItems(resource) {
  const byId = new Map();
  [
    ...resource.activeItems,
    ...resource.previousItems,
    ...resource.mapItems,
  ].forEach((event) => {
    if (event.eventId && !byId.has(event.eventId)) {
      byId.set(event.eventId, event);
    }
  });
  return Array.from(byId.values());
}

function candidateDashboardEventLocationLabel(event) {
  return (
    normalizeString(event.locationName) ||
    normalizeString(event.locationTown) ||
    normalizeString(event.address) ||
    "Location pending"
  );
}

function candidateDashboardEventMapReady(event) {
  return Number.isFinite(event.lat) && Number.isFinite(event.lng);
}

function formatEventCostAmount(amount) {
  const numeric = Number(amount);
  if (!Number.isFinite(numeric) || numeric <= 0) {
    return "$0";
  }
  return new Intl.NumberFormat(undefined, {
    style: "currency",
    currency: "USD",
    maximumFractionDigits: numeric % 1 === 0 ? 0 : 2,
  }).format(numeric);
}

function eventRequiresPayment(event = {}) {
  const costAmount = Number(event.costAmount);
  return event.isFree === false || (Number.isFinite(costAmount) && costAmount > 0);
}

function eventCostLabel(event = {}) {
  return eventRequiresPayment(event)
    ? formatEventCostAmount(event.costAmount || 0)
    : "Free";
}

function eventDetailRoute(eventOrId = "") {
  const eventId =
    typeof eventOrId === "string" ? eventOrId : eventOrId?.eventId || "";
  return eventId ? `/events/${encodeURIComponent(eventId)}` : "/events";
}

function eventSignupRoute(eventOrId = "") {
  const eventId =
    typeof eventOrId === "string" ? eventOrId : eventOrId?.eventId || "";
  return eventId
    ? `/events/${encodeURIComponent(eventId)}/signup`
    : "/events";
}

function eventPaymentRoute(eventOrId = "") {
  const eventId =
    typeof eventOrId === "string" ? eventOrId : eventOrId?.eventId || "";
  return eventId
    ? `/events/${encodeURIComponent(eventId)}/payment`
    : "/events";
}

function eventTransportAvailable(event = {}) {
  return (
    event.transportEnabled === true &&
    event.transportClosedEarly !== true &&
    Number(event.transportRemainingSeats) > 0
  );
}

function eventTransportLabel(event = {}) {
  if (event.transportEnabled !== true) {
    return "None";
  }
  if (event.transportClosedEarly === true) {
    return "Closed";
  }
  const remainingSeats = Math.max(0, Number(event.transportRemainingSeats) || 0);
  if (!remainingSeats) {
    return "Full";
  }
  return `${formatCount(remainingSeats)} seat${remainingSeats === 1 ? "" : "s"} available`;
}

function renderCandidateDashboardEventCard(event, resource, { map = false } = {}) {
  const pendingSave = resource.actionPendingKey === `save:${event.eventId}`;
  const pendingDelete = resource.actionPendingKey === `delete:${event.eventId}`;
  const mapReady = candidateDashboardEventMapReady(event);
  return `<article class="shared-campaign-event-card">
    ${
      event.imageUrl
        ? `<img class="shared-campaign-event-card__image" src="${escapeHtml(event.imageUrl)}" alt="${escapeHtml(event.title)}" />`
        : `<div class="shared-campaign-event-card__image shared-campaign-event-card__image--placeholder">${renderIcon("calendar")}</div>`
    }
    <div class="shared-campaign-event-card__body">
      <div class="shared-card__meta">
        <span>${escapeHtml(event.startAt ? formatAbsoluteDateTime(event.startAt) : "Date pending")}</span>
        <span>${escapeHtml(candidateDashboardEventLocationLabel(event))}</span>
        <span>${escapeHtml(mapReady ? "Map ready" : "Needs coordinates")}</span>
      </div>
      <h3>${escapeHtml(event.title)}</h3>
      <p>${escapeHtml(event.description || event.address || "Campaign event details.")}</p>
      <div class="shared-campaign-event-card__stats">
        <span><strong>${escapeHtml(formatCount(event.attendeeCount))}</strong><em>Going</em></span>
        <span><strong>${escapeHtml(formatCount(event.interestedCount))}</strong><em>Interested</em></span>
        <span><strong>${escapeHtml(event.isFree ? "Free" : formatEventCostAmount(event.costAmount || 0))}</strong><em>Cost</em></span>
      </div>
      ${
        event.tags.length
          ? `<div class="shared-card__tags">${event.tags.map((tag) => `<span>${escapeHtml(tag)}</span>`).join("")}</div>`
          : ""
      }
      ${
        map
          ? `<div class="shared-card__meta">
              <span>${escapeHtml(mapReady ? `${event.lat.toFixed(4)}, ${event.lng.toFixed(4)}` : "No coordinates")}</span>
              ${event.address ? `<span>${escapeHtml(event.address)}</span>` : ""}
            </div>`
          : ""
      }
      <div class="shared-card__actions">
        <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="navigate" data-route="/events/${escapeHtml(encodeURIComponent(event.eventId))}">Open</button>
        <button class="shared-feed-chip" type="button" data-action="candidate-events-edit" data-event-id="${escapeHtml(event.eventId)}"${disabledAttr(pendingSave || pendingDelete)}>Edit</button>
        <button class="shared-feed-chip" type="button" data-action="candidate-events-delete" data-event-id="${escapeHtml(event.eventId)}"${disabledAttr(pendingDelete)}>${pendingDelete ? "Deleting..." : "Delete"}</button>
      </div>
    </div>
  </article>`;
}

function renderCandidateDashboardEventForm(event = {}, mode = "create", resource) {
  const pending = resource.actionPendingKey === "create" ||
    (event.eventId && resource.actionPendingKey === `save:${event.eventId}`);
  const defaultStart = event.startAt || Date.now() + 24 * 60 * 60 * 1000;
  const defaultEnd = event.endAt || defaultStart + 2 * 60 * 60 * 1000;
  return `<article class="shared-campaign-panel shared-campaign-events-form-panel">
    <div class="shared-campaign-panel__header">
      <div>
        <h2>${mode === "edit" ? "Edit event" : "Create campaign event"}</h2>
        <p>Use map-ready location data so the event can appear in the app map and route planner.</p>
      </div>
      <button class="shared-feed-chip" type="button" data-action="candidate-events-cancel-edit"${disabledAttr(pending)}>Cancel</button>
    </div>
    <form class="shared-form shared-campaign-events-form" data-route-form="candidate-events-save">
      <input type="hidden" name="mode" value="${escapeHtml(mode)}" />
      <input type="hidden" name="eventId" value="${escapeHtml(event.eventId || "")}" />
      <label><span>Title</span><input name="title" value="${escapeHtml(event.title || "")}" required${disabledAttr(pending)} /></label>
      <label><span>Cover image URL</span><input name="imageUrl" value="${escapeHtml(event.imageUrl || "")}" required${disabledAttr(pending)} /></label>
      <label class="is-wide"><span>Description</span><textarea name="description" rows="4"${disabledAttr(pending)}>${escapeHtml(event.description || "")}</textarea></label>
      <label><span>Start</span><input type="datetime-local" name="startAt" value="${escapeHtml(formatDateTimeInputValue(defaultStart))}" required${disabledAttr(pending)} /></label>
      <label><span>End</span><input type="datetime-local" name="endAt" value="${escapeHtml(formatDateTimeInputValue(defaultEnd))}" required${disabledAttr(pending)} /></label>
      <label><span>Town</span><input name="locationTown" value="${escapeHtml(event.locationTown || "")}" required${disabledAttr(pending)} /></label>
      <label><span>Location name</span><input name="locationName" value="${escapeHtml(event.locationName || "")}"${disabledAttr(pending)} /></label>
      <label class="is-wide"><span>Address</span><input name="address" value="${escapeHtml(event.address || "")}" required${disabledAttr(pending)} /></label>
      <label><span>Place ID</span><input name="locationPlaceId" value="${escapeHtml(event.locationPlaceId || "")}"${disabledAttr(pending)} /></label>
      <label><span>Latitude</span><input name="locationLat" inputmode="decimal" value="${escapeHtml(Number.isFinite(event.lat) ? String(event.lat) : "")}" required${disabledAttr(pending)} /></label>
      <label><span>Longitude</span><input name="locationLng" inputmode="decimal" value="${escapeHtml(Number.isFinite(event.lng) ? String(event.lng) : "")}" required${disabledAttr(pending)} /></label>
      <label><span>Tags</span><input name="tags" value="${escapeHtml((event.tags || []).join(", "))}" placeholder="town hall, canvass"${disabledAttr(pending)} /></label>
      <label><span>Email</span><input name="email" value="${escapeHtml(event.raw?.socials?.email || "")}"${disabledAttr(pending)} /></label>
      <label><span>Website</span><input name="website" value="${escapeHtml(event.raw?.socials?.website || "")}"${disabledAttr(pending)} /></label>
      <label><span>Link</span><input name="link" value="${escapeHtml(event.raw?.socials?.link || "")}"${disabledAttr(pending)} /></label>
      <label class="shared-form__checkbox"><input type="checkbox" name="isFree"${event.isFree !== false ? " checked" : ""}${disabledAttr(pending)} /> Free event</label>
      <label><span>Price</span><input name="costAmount" inputmode="decimal" value="${escapeHtml(event.costAmount === null ? "" : String(event.costAmount || ""))}"${disabledAttr(pending)} /></label>
      <div class="shared-card__actions is-wide">
        <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pending)}>${pending ? "Saving..." : mode === "edit" ? "Save event" : "Create event"}</button>
      </div>
    </form>
  </article>`;
}

function renderCandidateDashboardEventsList(resource) {
  const items = candidateDashboardEventsVisibleItems(resource);
  return `<article class="shared-campaign-panel">
    <div class="shared-campaign-panel__header">
      <div>
        <h2>${escapeHtml(candidateDashboardEventsStatusLabel(resource.status))} events</h2>
        <p>Open, edit, or remove campaign-hosted events without leaving the dashboard.</p>
      </div>
      <div class="shared-campaign-events-tabs" role="group" aria-label="Campaign event status">
        ${["active", "previous"]
          .map(
            (status) =>
              `<button class="shared-feed-chip${resource.status === status ? " shared-feed-chip--primary" : ""}" type="button" data-action="candidate-events-status" data-status="${escapeHtml(status)}">${escapeHtml(candidateDashboardEventsStatusLabel(status))}</button>`,
          )
          .join("")}
      </div>
    </div>
    ${
      resource.loading && !resource.loaded
        ? '<div class="shared-page__loading">Loading campaign events...</div>'
        : items.length
          ? `<div class="shared-campaign-events-list">${items.map((event) => renderCandidateDashboardEventCard(event, resource)).join("")}</div>`
          : `<div class="shared-page__empty">No ${escapeHtml(resource.status)} campaign events.</div>`
    }
  </article>`;
}

function candidateDashboardRouteStops(route) {
  if (!route || typeof route !== "object") {
    return [];
  }
  return readArrayPayload(route, ["stops", "items", "events", "route"]).map(
    (entry, index) => ({
      eventId: normalizeString(entry.eventId || entry.id),
      title: normalizeString(entry.title || entry.name) || `Stop ${index + 1}`,
      address: normalizeString(entry.address || entry.locationName),
      order: Number(entry.order || index + 1) || index + 1,
    }),
  );
}

function renderCandidateDashboardEventsMap(resource) {
  const stops = candidateDashboardRouteStops(resource.route);
  return `<div class="shared-campaign-events-map-grid">
    <article class="shared-campaign-panel">
      <div class="shared-campaign-panel__header">
        <div>
          <h2>Event map</h2>
          <p>Filter mapped campaign events and build a field route from visible stops.</p>
        </div>
        <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="candidate-events-build-route"${disabledAttr(resource.actionPendingKey === "route" || !resource.mapItems.length)}>${resource.actionPendingKey === "route" ? "Building..." : "Build route"}</button>
      </div>
      <form class="shared-form shared-campaign-events-map-filter" data-route-form="candidate-events-map-filters">
        <label><span>Tags</span><input name="tags" value="${escapeHtml(resource.filters.tags)}" placeholder="town hall, canvass" /></label>
        <label class="shared-form__checkbox"><input type="checkbox" name="includePast"${resource.filters.includePast ? " checked" : ""} /> Include past events</label>
        <button class="shared-feed-chip" type="submit"${disabledAttr(resource.loading)}>Apply</button>
      </form>
      ${resource.mapError ? `<div class="shared-page__error">${escapeHtml(resource.mapError)}</div>` : ""}
      ${
        resource.mapLoading && !resource.mapItems.length
          ? '<div class="shared-page__loading">Loading event map...</div>'
          : resource.mapItems.length
            ? `<div class="shared-campaign-events-list">${resource.mapItems.map((event) => renderCandidateDashboardEventCard(event, resource, { map: true })).join("")}</div>`
            : '<div class="shared-page__empty">No mapped campaign events match these filters.</div>'
      }
    </article>
    <aside class="shared-campaign-panel shared-campaign-events-route">
      <div class="shared-campaign-panel__header">
        <div>
          <h2>Route plan</h2>
          <p>Use this to review the order returned by the campaign routing endpoint.</p>
        </div>
      </div>
      ${
        stops.length
          ? `<ol class="shared-campaign-events-route__stops">${stops
              .sort((left, right) => left.order - right.order)
              .map(
                (stop) => `<li>
                  <span>${escapeHtml(String(stop.order))}</span>
                  <div>
                    <strong>${escapeHtml(stop.title)}</strong>
                    ${stop.address ? `<em>${escapeHtml(stop.address)}</em>` : ""}
                  </div>
                </li>`,
              )
              .join("")}</ol>`
          : '<div class="shared-page__empty">Build a route to see ordered stops here.</div>'
      }
    </aside>
  </div>`;
}

function renderCandidateDashboardEvents(detail) {
  const resource = detail.eventsWorkspace;
  const editingEvent = resource.editingEventId
    ? candidateDashboardEventAllItems(resource).find(
        (event) => event.eventId === resource.editingEventId,
      )
    : null;
  return `<div class="shared-campaign-section shared-campaign-events">
    <article class="shared-campaign-panel shared-campaign-events-hero">
      <div>
        <h2>Campaign Events</h2>
        <p>Manage active and previous events, keep map data complete, and build field routes from campaign event locations.</p>
      </div>
      <div class="shared-campaign-events-controls">
        <button class="shared-feed-chip${resource.view === "list" ? " shared-feed-chip--primary" : ""}" type="button" data-action="candidate-events-view" data-view="list">List</button>
        <button class="shared-feed-chip${resource.view === "map" ? " shared-feed-chip--primary" : ""}" type="button" data-action="candidate-events-view" data-view="map">Event Map</button>
        <button class="shared-feed-chip" type="button" data-action="candidate-events-refresh"${disabledAttr(resource.loading)}>Refresh</button>
        <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="candidate-events-create-toggle"${disabledAttr(resource.actionPendingKey === "create")}>Create event</button>
      </div>
    </article>
    ${resource.error ? `<div class="shared-page__error">${escapeHtml(resource.error)}</div>` : ""}
    <div class="shared-campaign-events-metrics">
      ${renderCandidateDashboardMetric("Active", formatCount(resource.activeItems.length))}
      ${renderCandidateDashboardMetric("Previous", formatCount(resource.previousItems.length))}
      ${renderCandidateDashboardMetric("Map ready", formatCount(resource.mapItems.filter(candidateDashboardEventMapReady).length))}
      ${renderCandidateDashboardMetric("Route stops", formatCount(candidateDashboardRouteStops(resource.route).length))}
    </div>
    ${resource.createOpen ? renderCandidateDashboardEventForm({}, "create", resource) : ""}
    ${editingEvent ? renderCandidateDashboardEventForm(editingEvent, "edit", resource) : ""}
    ${
      resource.view === "map"
        ? renderCandidateDashboardEventsMap(resource)
        : renderCandidateDashboardEventsList(resource)
    }
  </div>`;
}

function candidateCalendarWriteTargetOptions(resource) {
  return resource.connections.flatMap((connection) => {
    const calendars = connection.calendars.length
      ? connection.calendars
      : [...connection.writeCalendars, ...connection.importedCalendars];
    return calendars
      .filter((calendar) => calendar.writeEnabled || calendar.defaultWrite)
      .map((calendar) => ({
        value: `${connection.provider}:${calendar.calendarId}`,
        label: `${connection.providerLabel} - ${calendar.title}`,
        defaultWrite: calendar.defaultWrite,
      }));
  });
}

function candidateCalendarCounts(resource) {
  const items = resource.items || [];
  return items.reduce(
    (counts, item) => {
      counts.total += 1;
      if (item.status === "pending_approval") counts.pending += 1;
      if (item.itemType === "scheduled_promotion") counts.promotions += 1;
      if (item.source === "provider" || item.provider) counts.synced += 1;
      if (item.startAt && item.startAt >= Date.now()) counts.upcoming += 1;
      if (
        item.startAt &&
        item.startAt >= Date.now() &&
        item.startAt - Date.now() <= 24 * 60 * 60 * 1000
      ) {
        counts.nextDay += 1;
      }
      return counts;
    },
    {
      total: 0,
      upcoming: 0,
      nextDay: 0,
      pending: 0,
      promotions: 0,
      synced: 0,
    },
  );
}

function candidateCalendarNextItem(resource) {
  return [...(resource.items || [])]
    .filter((item) => item.startAt && item.startAt >= Date.now())
    .sort((left, right) => left.startAt - right.startAt)[0] || null;
}

function candidateCalendarDayKey(item) {
  if (!item.startAt) {
    return "unscheduled";
  }
  const date = new Date(item.startAt);
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}-${String(date.getDate()).padStart(2, "0")}`;
}

function candidateCalendarDayLabel(item) {
  if (!item.startAt) {
    return "Unscheduled";
  }
  return new Date(item.startAt).toLocaleDateString(undefined, {
    weekday: "long",
    month: "short",
    day: "numeric",
  });
}

function candidateCalendarGroupedItems(items = []) {
  const groups = [];
  const byKey = new Map();
  items.forEach((item) => {
    const key = candidateCalendarDayKey(item);
    if (!byKey.has(key)) {
      const group = {
        key,
        label: candidateCalendarDayLabel(item),
        items: [],
      };
      byKey.set(key, group);
      groups.push(group);
    }
    byKey.get(key).items.push(item);
  });
  return groups.map((group) => ({
    ...group,
    items: group.items.sort((left, right) => (left.startAt || 0) - (right.startAt || 0)),
  }));
}

function renderCandidateCalendarCommandMetric(label, value, detail = "") {
  return `<div>
    <span>${escapeHtml(label)}</span>
    <strong>${escapeHtml(String(value))}</strong>
    ${detail ? `<small>${escapeHtml(detail)}</small>` : ""}
  </div>`;
}

function renderCandidateCalendarCommandCenter(resource, access) {
  const counts = candidateCalendarCounts(resource);
  const next = candidateCalendarNextItem(resource);
  const detailsLabel = canViewCandidateCalendarDetails(access) ? "Full details" : "Busy only";
  return `<section class="shared-campaign-calendar-command">
    <div class="shared-campaign-calendar-command__main">
      <div class="shared-card__meta">
        <span>${escapeHtml(detailsLabel)}</span>
        <span>${escapeHtml(resource.settings?.publicBookingEnabled ? "Public booking live" : "Booking off")}</span>
      </div>
      <h2>${escapeHtml(next?.title || "Campaign calendar")}</h2>
      <p>${escapeHtml(
        next?.startAt
          ? `${candidateCalendarItemTypeLabel(next.itemType)} - ${formatAbsoluteDateTime(next.startAt)}`
          : "Coordinate busy blocks, office hours, campaign events, volunteer shifts, reminders, travel, approvals, and calendar integrations from the website.",
      )}</p>
      <div class="shared-campaign-calendar-command__actions">
        <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="calendar-composer-focus">New item</button>
        <button class="shared-feed-chip" type="button" data-action="candidate-calendar-refresh"${disabledAttr(resource.loading)}>Refresh</button>
      </div>
    </div>
    <div class="shared-campaign-calendar-command__metrics">
      ${renderCandidateCalendarCommandMetric("Upcoming", formatCount(counts.upcoming), "loaded")}
      ${renderCandidateCalendarCommandMetric("Next 24h", formatCount(counts.nextDay), "ready")}
      ${renderCandidateCalendarCommandMetric("Approval", formatCount(counts.pending), "pending")}
      ${renderCandidateCalendarCommandMetric("Promotion", formatCount(counts.promotions), "scheduled")}
      ${renderCandidateCalendarCommandMetric("Synced", formatCount(counts.synced), "external")}
      ${renderCandidateCalendarCommandMetric("Connections", formatCount(resource.connections.length), "accounts")}
    </div>
  </section>`;
}

function renderCandidateCalendarFilters(resource) {
  const defaults = candidateCalendarDefaultRange();
  const from =
    resource.filters.from || formatDateInputValue(defaults.from);
  const to = resource.filters.to || formatDateInputValue(defaults.to);
  return `<form class="shared-campaign-calendar-filters" data-route-form="candidate-calendar-filters">
    <label>
      <span>Type</span>
      <select name="itemType"${disabledAttr(resource.loading)}>
        <option value="">All types</option>
        ${CANDIDATE_CALENDAR_ITEM_TYPES.map(
          ([key, label]) =>
            `<option value="${escapeHtml(key)}"${selectedAttr(resource.filters.itemType === key)}>${escapeHtml(label)}</option>`,
        ).join("")}
      </select>
    </label>
    <label>
      <span>Status</span>
      <select name="status"${disabledAttr(resource.loading)}>
        ${CANDIDATE_CALENDAR_STATUS_OPTIONS.map(
          ([key, label]) =>
            `<option value="${escapeHtml(key)}"${selectedAttr(resource.filters.status === key)}>${escapeHtml(label)}</option>`,
        ).join("")}
      </select>
    </label>
    <label>
      <span>From</span>
      <input type="date" name="from" value="${escapeHtml(from)}"${disabledAttr(resource.loading)} />
    </label>
    <label>
      <span>To</span>
      <input type="date" name="to" value="${escapeHtml(to)}"${disabledAttr(resource.loading)} />
    </label>
    <div class="shared-campaign-calendar-actions">
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(resource.loading)}>Apply</button>
      <button class="shared-feed-chip" type="button" data-action="candidate-calendar-refresh"${disabledAttr(resource.loading)}>Refresh</button>
    </div>
  </form>`;
}

function renderCandidateCalendarItemCard(item, resource, canApprove) {
  const pendingApprove =
    resource.actionPendingKey === `approve:${item.calendarItemId}`;
  const pendingReject =
    resource.actionPendingKey === `reject:${item.calendarItemId}`;
  const pending = pendingApprove || pendingReject;
  const dateLabel = item.startAt
    ? formatAbsoluteDateTime(item.startAt)
    : humanizeLabel(item.status);
  const endLabel = item.endAt ? formatAbsoluteDateTime(item.endAt) : "";
  const syncLabel = item.syncState?.lastSyncStatus || item.provider || item.source;
  return `<article class="shared-campaign-calendar-item">
    <div class="shared-campaign-calendar-item__time">
      <strong>${escapeHtml(item.startAt ? formatCalendarDate(item.startAt) : "Unscheduled")}</strong>
      <span>${escapeHtml(dateLabel)}</span>
    </div>
    <div class="shared-campaign-calendar-item__body">
      <div class="shared-campaign-calendar-item__title">
        <div>
          <span class="shared-campaign-staff-role-pill" style="--role-color: ${item.status === "pending_approval" ? "#f59e0b" : "#26f4ee"}">
            <strong>${escapeHtml(candidateCalendarItemTypeLabel(item.itemType))}</strong>
            <span>${escapeHtml(humanizeLabel(item.status))}</span>
          </span>
          <h3>${escapeHtml(item.title)}</h3>
        </div>
        <em>${escapeHtml(candidateCalendarPrivacyLabel(item.privacy))}</em>
      </div>
      <div class="shared-campaign-calendar-meta">
        ${endLabel ? `<span>${renderIcon("calendar")} Ends ${escapeHtml(endLabel)}</span>` : ""}
        ${item.locationName ? `<span>${renderIcon("map")} ${escapeHtml(item.locationName)}</span>` : ""}
        ${syncLabel ? `<span>${renderIcon("settings")} ${escapeHtml(humanizeLabel(syncLabel))}</span>` : ""}
      </div>
      ${item.description ? `<p>${escapeHtml(item.description)}</p>` : ""}
      ${
        item.labels.length
          ? `<div class="shared-campaign-staff-permissions">${item.labels.map((label) => `<span>${escapeHtml(label)}</span>`).join("")}</div>`
          : ""
      }
      ${
        canApprove && item.status === "pending_approval"
          ? `<div class="shared-campaign-calendar-actions">
              <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="candidate-calendar-approve" data-calendar-item-id="${escapeHtml(item.calendarItemId)}"${disabledAttr(pending)}>${pendingApprove ? "Approving..." : "Approve"}</button>
              <button class="shared-feed-chip" type="button" data-action="candidate-calendar-reject" data-calendar-item-id="${escapeHtml(item.calendarItemId)}"${disabledAttr(pending)}>${pendingReject ? "Rejecting..." : "Reject"}</button>
            </div>`
          : ""
      }
    </div>
  </article>`;
}

function renderCandidateCalendarAgenda(resource, access) {
  const canApprove = canApproveCandidateCalendarItems(access);
  const pendingItems = resource.items.filter(
    (item) => item.status === "pending_approval",
  );
  const groupedItems = candidateCalendarGroupedItems(
    resource.items.filter((item) => item.status !== "pending_approval"),
  );
  const agendaMarkup = resource.items.length
    ? `<div class="shared-campaign-calendar-agenda-stack">
        ${
          pendingItems.length
            ? `<section class="shared-campaign-calendar-day-group is-approval">
                <div class="shared-campaign-calendar-day-group__header">
                  <strong>Needs approval</strong>
                  <span>${escapeHtml(formatCount(pendingItems.length))} request${pendingItems.length === 1 ? "" : "s"}</span>
                </div>
                <div class="shared-campaign-calendar-list">${pendingItems.map((item) => renderCandidateCalendarItemCard(item, resource, canApprove)).join("")}</div>
              </section>`
            : ""
        }
        ${groupedItems
          .map(
            (group) => `<section class="shared-campaign-calendar-day-group">
              <div class="shared-campaign-calendar-day-group__header">
                <strong>${escapeHtml(group.label)}</strong>
                <span>${escapeHtml(formatCount(group.items.length))} item${group.items.length === 1 ? "" : "s"}</span>
              </div>
              <div class="shared-campaign-calendar-list">${group.items.map((item) => renderCandidateCalendarItemCard(item, resource, canApprove)).join("")}</div>
            </section>`,
          )
          .join("")}
      </div>`
    : `<div class="shared-page__empty">No calendar items match this window.</div>`;
  return `<article class="shared-campaign-panel shared-campaign-calendar-agenda">
    <div class="shared-campaign-panel__header">
      <div>
        <h2>Schedule</h2>
        <p>Review upcoming campaign holds, bookings, promotions, and synced busy blocks.</p>
      </div>
    </div>
    ${
      resource.loading && !resource.loaded
        ? `<div class="shared-page__empty">Loading campaign calendar...</div>`
        : resource.error
          ? `<div class="shared-page__empty">${escapeHtml(resource.error)}</div>`
          : agendaMarkup
    }
  </article>`;
}

function renderCandidateCalendarCreateForm(resource, access) {
  if (!canCreateCandidateCalendarItems(access)) {
    return "";
  }
  const pending = resource.actionPendingKey === "create";
  const now = new Date();
  now.setMinutes(0, 0, 0);
  const start = now.getTime() + 60 * 60 * 1000;
  const end = start + 60 * 60 * 1000;
  const writeTargets = candidateCalendarWriteTargetOptions(resource);
  return `<article class="shared-campaign-panel shared-campaign-calendar-create" id="candidate-calendar-composer">
    <div class="shared-campaign-panel__header">
      <div>
        <h2>Composer</h2>
        <p>Start from an app-style preset, then refine timing, visibility, labels, and write targets.</p>
      </div>
    </div>
    <form class="shared-campaign-calendar-form" data-route-form="candidate-calendar-create">
      <div class="shared-campaign-calendar-preset-rail" aria-label="Calendar item presets">
        ${CANDIDATE_CALENDAR_COMPOSER_PRESETS.map(
          (preset) => `<button class="shared-campaign-calendar-preset" type="button" data-action="candidate-calendar-preset"
            data-item-type="${escapeHtml(preset.itemType)}"
            data-title="${escapeHtml(preset.title)}"
            data-labels="${escapeHtml(preset.labels)}"
            data-location-name="${escapeHtml(preset.locationName)}"
            data-privacy="${escapeHtml(preset.privacy)}"
            data-description="${escapeHtml(preset.description)}">
              <strong>${escapeHtml(preset.label)}</strong>
              <span>${escapeHtml(candidateCalendarItemTypeLabel(preset.itemType))}</span>
            </button>`,
        ).join("")}
      </div>
      <div class="shared-campaign-calendar-form-grid">
        <label class="shared-campaign-calendar-title-field"><span>Title</span><input name="title" placeholder="Phone bank kickoff"${disabledAttr(pending)} required /></label>
        <label><span>Type</span><select name="itemType"${disabledAttr(pending)}>${CANDIDATE_CALENDAR_ITEM_TYPES.map(([key, label]) => `<option value="${escapeHtml(key)}">${escapeHtml(label)}</option>`).join("")}</select></label>
        <label><span>Start</span><input type="datetime-local" name="startAt" value="${escapeHtml(formatDateTimeInputValue(start))}"${disabledAttr(pending)} required /></label>
        <label><span>End</span><input type="datetime-local" name="endAt" value="${escapeHtml(formatDateTimeInputValue(end))}"${disabledAttr(pending)} required /></label>
        <label><span>Status</span><select name="status"${disabledAttr(pending)}>${CANDIDATE_CALENDAR_STATUS_OPTIONS.filter(([key]) => key).map(([key, label]) => `<option value="${escapeHtml(key)}"${selectedAttr(key === "confirmed")}>${escapeHtml(label)}</option>`).join("")}</select></label>
        <label><span>Privacy</span><select name="privacy"${disabledAttr(pending)}>${CANDIDATE_CALENDAR_PRIVACY_OPTIONS.map(([key, label]) => `<option value="${escapeHtml(key)}">${escapeHtml(label)}</option>`).join("")}</select></label>
        <label><span>Location</span><input name="locationName" placeholder="Field office"${disabledAttr(pending)} /></label>
        <label><span>Labels</span><input name="labels" placeholder="field, volunteers"${disabledAttr(pending)} /></label>
      </div>
      <div class="shared-campaign-calendar-menu-grid">
        <span><strong>Availability</strong><em>Busy unless marked private or synced externally.</em></span>
        <span><strong>Reminder</strong><em>Use Reminder preset for a short hold.</em></span>
        <span><strong>Promotion</strong><em>Scheduled promotion is metadata for queued cross-posting.</em></span>
      </div>
      <label class="shared-campaign-calendar-textarea"><span>Description</span><textarea name="description" rows="3" placeholder="Internal note or public details"${disabledAttr(pending)}></textarea></label>
      <label class="shared-campaign-calendar-check"><input type="checkbox" name="allDay"${disabledAttr(pending)} /> <span>All-day item</span></label>
      ${
        writeTargets.length
          ? `<fieldset class="shared-campaign-calendar-write-targets">
              <legend>Write to connected calendars</legend>
              ${writeTargets.map((target) => `<label><input type="checkbox" name="writeTarget" value="${escapeHtml(target.value)}"${checkedAttr(target.defaultWrite)}${disabledAttr(pending)} /> <span>${escapeHtml(target.label)}</span></label>`).join("")}
            </fieldset>`
          : ""
      }
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pending)}>${pending ? "Creating..." : "Create calendar item"}</button>
    </form>
  </article>`;
}

function renderCandidateCalendarConnection(connection, resource, canManage) {
  const pendingUpdate = resource.actionPendingKey === `connection:${connection.connectionId}`;
  const pendingDelete =
    resource.actionPendingKey === `disconnect:${connection.connectionId}`;
  const calendars = connection.calendars.length
    ? connection.calendars
    : [...connection.importedCalendars, ...connection.writeCalendars];
  return `<article class="shared-campaign-calendar-connection">
    <div class="shared-campaign-calendar-connection__top">
      <div>
        <span class="shared-campaign-staff-role-pill" style="--role-color: #26f4ee"><strong>${escapeHtml(connection.providerLabel)}</strong><span>${escapeHtml(humanizeLabel(connection.status))}</span></span>
        <h3>${escapeHtml(connection.accountLabel)}</h3>
        <p>${escapeHtml(connection.lastSyncAt ? `Last sync ${formatAbsoluteDateTime(connection.lastSyncAt)}` : connection.lastSyncStatus || "Sync pending")}</p>
      </div>
      ${connection.syncError ? `<em>${escapeHtml(connection.syncError)}</em>` : ""}
    </div>
    <form class="shared-campaign-calendar-connection-form" data-route-form="candidate-calendar-connection">
      <input type="hidden" name="connectionId" value="${escapeHtml(connection.connectionId)}" />
      <input type="hidden" name="calendarCount" value="${escapeHtml(String(calendars.length))}" />
      <label><span>Default privacy</span><select name="defaultPrivacy"${disabledAttr(!canManage || pendingUpdate || pendingDelete)}>${CANDIDATE_CALENDAR_PRIVACY_OPTIONS.map(([key, label]) => `<option value="${escapeHtml(key)}"${selectedAttr(connection.defaultPrivacy === key)}>${escapeHtml(label)}</option>`).join("")}</select></label>
      <div class="shared-campaign-calendar-external-list">
        ${
          calendars.length
            ? calendars.map((calendar, index) => `<div class="shared-campaign-calendar-external">
                <input type="hidden" name="calendarId:${index}" value="${escapeHtml(calendar.calendarId)}" />
                <input type="hidden" name="calendarTitle:${index}" value="${escapeHtml(calendar.title)}" />
                <input type="hidden" name="calendarLabel:${index}" value="${escapeHtml(calendar.label)}" />
                <strong>${escapeHtml(calendar.title)}</strong>
                <span>${escapeHtml(calendar.primary ? "Primary calendar" : humanizeLabel(calendar.label))}</span>
                <label><input type="checkbox" name="importEnabled:${index}"${checkedAttr(calendar.importEnabled)}${disabledAttr(!canManage || pendingUpdate || pendingDelete)} /> <span>Import busy time</span></label>
                <label><input type="checkbox" name="writeEnabled:${index}"${checkedAttr(calendar.writeEnabled)}${disabledAttr(!canManage || pendingUpdate || pendingDelete)} /> <span>Allow writes</span></label>
                <label><input type="checkbox" name="defaultWrite:${index}"${checkedAttr(calendar.defaultWrite)}${disabledAttr(!canManage || pendingUpdate || pendingDelete)} /> <span>Default write target</span></label>
              </div>`).join("")
            : `<div class="shared-page__empty">No calendars were discovered for this account.</div>`
        }
      </div>
      ${
        canManage
          ? `<div class="shared-campaign-calendar-actions">
              <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pendingUpdate || pendingDelete)}>${pendingUpdate ? "Saving..." : "Save connection"}</button>
              <button class="shared-feed-chip" type="button" data-action="candidate-calendar-disconnect" data-connection-id="${escapeHtml(connection.connectionId)}"${disabledAttr(pendingUpdate || pendingDelete)}>${pendingDelete ? "Disconnecting..." : "Disconnect"}</button>
            </div>`
          : ""
      }
    </form>
  </article>`;
}

function renderCandidateCalendarConnections(resource, access) {
  const canManage = canManageCandidateCalendarIntegrations(access);
  return `<article class="shared-campaign-panel shared-campaign-calendar-connections">
    <div class="shared-campaign-panel__header">
      <div>
        <h2>Integrations</h2>
        <p>Sync availability from external calendars and choose where Polis-created items are written.</p>
      </div>
    </div>
    ${
      resource.providers.length
        ? `<div class="shared-campaign-calendar-providers">
            ${resource.providers.map((provider) => {
              const pending = resource.actionPendingKey === `connect:${provider.provider}`;
              const disabled = !canManage || pending || provider.status === "disabled";
              return `<button class="shared-feed-chip${canManage ? " shared-feed-chip--primary" : ""}" type="button" data-action="candidate-calendar-connect" data-provider="${escapeHtml(provider.provider)}"${disabledAttr(disabled)}>${pending ? "Opening..." : `Connect ${escapeHtml(provider.label)}`}</button>`;
            }).join("")}
          </div>`
        : `<div class="shared-page__empty">${resource.configured ? "No calendar providers are available." : "Calendar provider credentials are not configured for this environment."}</div>`
    }
    ${
      resource.connections.length
        ? `<div class="shared-campaign-calendar-connection-list">${resource.connections.map((connection) => renderCandidateCalendarConnection(connection, resource, canManage)).join("")}</div>`
        : `<div class="shared-page__empty">No external calendar accounts connected.</div>`
    }
  </article>`;
}

function renderCandidateCalendarSettings(resource, access) {
  if (
    !canManageCandidatePublicBooking(access) &&
    !canManageCandidateCalendarIntegrations(access)
  ) {
    return "";
  }
  const settings = resource.settings || normalizeCandidateCalendarSettings({});
  const pending = resource.actionPendingKey === "settings";
  const writeTargets = candidateCalendarWriteTargetOptions(resource);
  return `<article class="shared-campaign-panel shared-campaign-calendar-settings">
    <div class="shared-campaign-panel__header">
      <div>
        <h2>Booking settings</h2>
        <p>Control public booking behavior and default write destinations.</p>
      </div>
    </div>
    <form class="shared-campaign-calendar-form" data-route-form="candidate-calendar-settings">
      <div class="shared-campaign-calendar-form-grid">
        <label><span>Booking slug</span><input name="publicBookingSlug" value="${escapeHtml(settings.publicBookingSlug)}" placeholder="casey-for-hd4"${disabledAttr(pending)} /></label>
        <label><span>Slot minutes</span><input type="number" min="5" max="240" step="5" name="slotMinutes" value="${escapeHtml(String(settings.slotMinutes))}"${disabledAttr(pending)} /></label>
        <label><span>Buffer minutes</span><input type="number" min="0" max="240" step="5" name="bufferMinutes" value="${escapeHtml(String(settings.bufferMinutes))}"${disabledAttr(pending)} /></label>
      </div>
      <label class="shared-campaign-calendar-check"><input type="checkbox" name="publicBookingEnabled"${checkedAttr(settings.publicBookingEnabled)}${disabledAttr(pending)} /> <span>Enable public booking requests</span></label>
      <label class="shared-campaign-calendar-check"><input type="checkbox" name="requiresApproval"${checkedAttr(settings.requiresApproval)}${disabledAttr(pending)} /> <span>Require approval before booked items become confirmed</span></label>
      ${
        writeTargets.length
          ? `<fieldset class="shared-campaign-calendar-write-targets">
              <legend>Default write targets</legend>
              ${writeTargets.map((target) => `<label><input type="checkbox" name="defaultWriteTargets" value="${escapeHtml(target.value)}"${checkedAttr(settings.defaultWriteTargets.includes(target.value) || target.defaultWrite)}${disabledAttr(pending)} /> <span>${escapeHtml(target.label)}</span></label>`).join("")}
            </fieldset>`
          : ""
      }
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pending)}>${pending ? "Saving..." : "Save calendar settings"}</button>
    </form>
  </article>`;
}

function renderCandidateDashboardCalendar(detail, candidateId, access) {
  const resource = detail.calendarWorkspace;
  return `<div class="shared-campaign-section shared-campaign-calendar">
    ${renderCandidateCalendarCommandCenter(resource, access)}
    <article class="shared-campaign-panel">
      <div class="shared-campaign-panel__header">
        <div>
          <h2>Calendar control</h2>
          <p>Manage the campaign schedule from the browser without falling back to the mobile app.</p>
        </div>
        <button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(candidateMessagingServerPath(candidateId))}">Open rooms</button>
      </div>
      ${renderCandidateCalendarFilters(resource)}
    </article>
    <div class="shared-campaign-calendar-grid">
      <div class="shared-campaign-calendar-main">
        ${renderCandidateCalendarAgenda(resource, access)}
      </div>
      <div class="shared-campaign-calendar-side">
        ${renderCandidateCalendarCreateForm(resource, access)}
        ${renderCandidateCalendarSettings(resource, access)}
      </div>
    </div>
    ${renderCandidateCalendarConnections(resource, access)}
  </div>`;
}

function candidateStaffDisplayName(person = {}) {
  return (
    normalizeString(person.displayName) ||
    (person.username ? `@${normalizeString(person.username).replace(/^@/u, "")}` : "") ||
    normalizeString(person.userId) ||
    "Staff member"
  );
}

function renderCandidateStaffAvatar(person = {}) {
  const label = candidateStaffDisplayName(person);
  return `<span class="shared-campaign-staff-avatar">${
    person.avatarUrl
      ? `<img src="${escapeHtml(person.avatarUrl)}" alt="${escapeHtml(label)}" />`
      : escapeHtml(label.slice(0, 1).toUpperCase() || "S")
  }</span>`;
}

function renderCandidateStaffRoleOptions(catalog, selectedRoleKey) {
  const normalizedSelected = normalizeCandidateStaffRoleKey(selectedRoleKey);
  const roles = candidateStaffAssignableRoles(catalog);
  return roles
    .map(
      (role) =>
        `<option value="${escapeHtml(role.roleKey)}"${selectedAttr(role.roleKey === normalizedSelected)}>${escapeHtml(role.label)}</option>`,
    )
    .join("");
}

function groupedCandidateStaffPermissions(catalog) {
  const grouped = new Map();
  const permissions =
    catalog?.permissions?.length > 0
      ? catalog.permissions
      : CANDIDATE_STAFF_PERMISSION_DEFINITIONS;
  permissions.forEach((permission) => {
    const category = normalizeString(permission.category) || "General";
    if (!grouped.has(category)) {
      grouped.set(category, []);
    }
    grouped.get(category).push(permission);
  });
  return Array.from(grouped.entries());
}

function renderCandidateStaffPermissionChips(permissions = []) {
  const normalized = normalizeCandidateStaffPermissionsForWrite(permissions);
  if (!normalized.length) {
    return '<span class="shared-campaign-staff-muted">No permissions</span>';
  }
  return `<span class="shared-campaign-staff-permission-chips">${normalized
    .slice(0, 6)
    .map((permission) => {
      const definition = candidateStaffPermissionDefinition(permission);
      return `<em>${escapeHtml(definition.label)}</em>`;
    })
    .join("")}${
    normalized.length > 6
      ? `<em>+${escapeHtml(formatCount(normalized.length - 6))}</em>`
      : ""
  }</span>`;
}

function renderCandidateStaffPermissionCheckboxes(
  catalog,
  selectedPermissions = [],
  { disabled = false, name = "permission" } = {},
) {
  const selected = new Set(
    normalizeCandidateStaffPermissionsForWrite(selectedPermissions),
  );
  return `<div class="shared-campaign-staff-permission-grid">
    ${groupedCandidateStaffPermissions(catalog)
      .map(
        ([category, permissions]) => `<fieldset>
          <legend>${escapeHtml(category)}</legend>
          ${permissions
            .map(
              (permission) => `<label>
                <input type="checkbox" name="${escapeHtml(name)}" value="${escapeHtml(permission.key)}"${checkedAttr(selected.has(permission.key))}${disabledAttr(disabled)} />
                <span>${escapeHtml(permission.label)}</span>
              </label>`,
            )
            .join("")}
        </fieldset>`,
      )
      .join("")}
  </div>`;
}

function renderCandidateStaffInviteSearchResult(user, detail, resource) {
  const status = candidateStaffInviteStatus(user, detail, resource);
  const disabled = status.disabled || resource.actionPendingKey === "invite";
  return `<button class="shared-campaign-staff-search-result${status.disabled ? " is-disabled" : ""}" type="button" data-action="candidate-staff-search-select"
    data-user-id="${escapeHtml(user.userId)}"
    data-username="${escapeHtml(user.username)}"
    data-display-name="${escapeHtml(user.displayName)}"
    data-avatar-url="${escapeHtml(user.avatarUrl)}"${disabledAttr(disabled)}>
    ${renderCandidateStaffAvatar(user)}
    <span>
      <strong>${escapeHtml(user.displayName)}</strong>
      <small>@${escapeHtml(user.username)}${user.subtitle ? ` - ${escapeHtml(user.subtitle.replace(/^@/u, ""))}` : ""}</small>
    </span>
    <em>${escapeHtml(status.label)}</em>
  </button>`;
}

function renderCandidateStaffInviteSelected(user, pending) {
  if (!user) {
    return "";
  }
  return `<div class="shared-campaign-staff-selected">
    ${renderCandidateStaffAvatar(user)}
    <span>
      <strong>${escapeHtml(user.displayName || "Selected staff member")}</strong>
      <small>@${escapeHtml(normalizeString(user.username).replace(/^@/u, ""))}</small>
    </span>
    <button class="shared-feed-chip" type="button" data-action="candidate-staff-search-clear"${disabledAttr(pending)}>Change</button>
  </div>`;
}

function renderCandidateStaffInviteSearch(detail, resource) {
  const search = candidateStaffInviteSearch(resource);
  const pending = resource.actionPendingKey === "invite";
  const selected = search.selected;
  const queryValue = selected
    ? `@${normalizeString(selected.username).replace(/^@/u, "")}`
    : search.query;
  const normalizedQuery = normalizeString(search.query).replace(/^@/u, "");
  const showSuggestions = !selected && (search.loading || search.loaded || normalizedQuery.length >= 2);
  return `<div class="shared-campaign-staff-search">
    <label class="shared-campaign-staff-search-field">
      <span>Search by username</span>
      <input name="username" data-candidate-staff-search-input value="${escapeHtml(queryValue)}" placeholder="Type a username to find staff" autocomplete="off"${disabledAttr(pending)} />
    </label>
    <input type="hidden" name="userId" value="${escapeHtml(selected?.userId || "")}" />
    ${renderCandidateStaffInviteSelected(selected, pending)}
    ${
      selected
        ? '<div class="shared-campaign-staff-search-hint">Selected account will receive this campaign invitation.</div>'
        : showSuggestions
        ? `<div class="shared-campaign-staff-search-results">
            ${
              search.loading
                ? '<div class="shared-campaign-staff-search-message">Searching people...</div>'
                : search.error
                  ? `<div class="shared-campaign-staff-search-message is-error">${escapeHtml(search.error)}</div>`
                  : search.items.length
                    ? search.items.map((user) => renderCandidateStaffInviteSearchResult(user, detail, resource)).join("")
                    : '<div class="shared-campaign-staff-search-message">No matching people.</div>'
            }
          </div>`
        : `<div class="shared-campaign-staff-search-hint">Type at least two characters, then choose a Polis account before sending.</div>`
    }
  </div>`;
}

function renderCandidateStaffInvitePermissionSummary(catalog, roleKey) {
  const role = candidateStaffCatalogRole(catalog, roleKey);
  const permissions = candidateStaffRoleDefaultPermissions(catalog, role.roleKey);
  return `<div class="shared-campaign-staff-invite-summary">
    <div>
      <strong>${escapeHtml(role.label)}</strong>
      <span>${escapeHtml(role.category || "Role preset")} - ${escapeHtml(formatCount(permissions.length))} default permissions</span>
    </div>
    ${renderCandidateStaffPermissionChips(permissions)}
  </div>`;
}

function renderCandidateStaffInviteForm(resource, catalog) {
  const pending = resource.actionPendingKey === "invite";
  const search = candidateStaffInviteSearch(resource);
  const defaultRole =
    normalizeCandidateStaffRoleKey(search.roleKey) ||
    candidateStaffAssignableRoles(catalog)[0]?.roleKey ||
    "staff";
  return `<article class="shared-campaign-panel shared-campaign-staff-invite">
    <div class="shared-campaign-panel__header">
      <div>
        <h2>Invite staff</h2>
        <p>Search for a Polis account, choose the role access they should receive, and send a campaign invitation.</p>
      </div>
    </div>
    <form class="shared-campaign-staff-form" data-route-form="candidate-staff-invite">
      ${renderCandidateStaffInviteSearch(state.pages.candidateDashboard.detail, resource)}
      <div class="shared-campaign-staff-form-grid shared-campaign-staff-invite-role-grid">
        <label>
          <span>Role preset</span>
          <select name="roleKey" data-candidate-staff-invite-role${disabledAttr(pending)}>
            ${renderCandidateStaffRoleOptions(catalog, defaultRole)}
          </select>
        </label>
      </div>
      ${renderCandidateStaffInvitePermissionSummary(catalog, defaultRole)}
      <label class="shared-campaign-staff-toggle">
        <input type="checkbox" name="useRoleDefaults" checked${disabledAttr(pending)} />
        <span>Use the selected role's default permissions</span>
      </label>
      <details class="shared-campaign-staff-details">
        <summary>Custom permission selection</summary>
        ${renderCandidateStaffPermissionCheckboxes(catalog, [], {
          disabled: pending,
        })}
      </details>
      <details class="shared-campaign-staff-details shared-campaign-staff-direct-id">
        <summary>Direct user id fallback</summary>
        <div class="shared-campaign-staff-direct-id__body">
          <label>
            <span>User id</span>
            <input name="directUserId" placeholder="Optional direct id"${disabledAttr(pending)} />
          </label>
        </div>
      </details>
      <div class="shared-campaign-staff-actions">
        <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pending)}>${pending ? "Sending..." : "Send invitation"}</button>
      </div>
    </form>
  </article>`;
}

function renderCandidateStaffInvitationRow(invite, resource, catalog) {
  const role = candidateStaffCatalogRole(catalog, invite.roleKey);
  const pending = resource.actionPendingKey === `invite-cancel:${invite.userId}`;
  return `<article class="shared-campaign-staff-invite-row">
    <div class="shared-campaign-staff-person">
      ${renderCandidateStaffAvatar(invite)}
      <div>
        <strong>${escapeHtml(candidateStaffDisplayName(invite))}</strong>
        <span>${escapeHtml(invite.username ? `@${invite.username.replace(/^@/u, "")}` : invite.userId)}</span>
      </div>
    </div>
    <div class="shared-campaign-staff-role-pill" style="${role.color ? `--role-color:${escapeHtml(role.color)};` : ""}">
      <strong>${escapeHtml(invite.roleLabel || role.label)}</strong>
      <span>${escapeHtml(humanizeLabel(invite.status))}${invite.invitedAt ? ` - ${escapeHtml(formatAbsoluteDateTime(invite.invitedAt))}` : ""}</span>
    </div>
    <div class="shared-campaign-staff-row-actions">
      ${renderCandidateStaffPermissionChips(invite.permissions)}
      ${
        invite.status === "pending"
          ? `<button class="shared-feed-chip" type="button" data-action="candidate-staff-invite-cancel" data-user-id="${escapeHtml(invite.userId)}"${disabledAttr(pending)}>${pending ? "Canceling..." : "Cancel invite"}</button>`
          : ""
      }
    </div>
  </article>`;
}

function renderCandidateStaffInvitations(resource, catalog) {
  const status = resource.invitationStatus || "pending";
  return `<article class="shared-campaign-panel shared-campaign-staff-invitations">
    <div class="shared-campaign-panel__header">
      <div>
        <h2>Invitations</h2>
        <p>Track pending invites and older staff invitation decisions.</p>
      </div>
      <form class="shared-campaign-staff-status" data-route-form="candidate-staff-invite-status">
        <select name="status">
          ${CANDIDATE_STAFF_INVITE_STATUS_OPTIONS.map(
            ([key, label]) =>
              `<option value="${escapeHtml(key)}"${selectedAttr(key === status)}>${escapeHtml(label)}</option>`,
          ).join("")}
        </select>
        <button class="shared-feed-chip" type="submit"${disabledAttr(resource.loading)}>View</button>
      </form>
    </div>
    ${
      resource.loading && !resource.invitations.length
        ? '<div class="shared-page__loading">Loading invitations...</div>'
        : ""
    }
    ${
      resource.invitations.length
        ? `<div class="shared-campaign-staff-list">${resource.invitations
            .map((invite) =>
              renderCandidateStaffInvitationRow(invite, resource, catalog),
            )
            .join("")}</div>`
        : '<div class="shared-page__empty">No staff invitations for this filter.</div>'
    }
  </article>`;
}

function renderCandidateStaffMemberCard(member, resource, catalog, canManage) {
  const pendingSave = resource.actionPendingKey === `staff:${member.userId}`;
  const pendingRemove = resource.actionPendingKey === `remove:${member.userId}`;
  const role = candidateStaffCatalogRole(catalog, member.roleKey);
  return `<article class="shared-campaign-staff-card">
    <form data-route-form="candidate-staff-access">
      <input type="hidden" name="userId" value="${escapeHtml(member.userId)}" />
      <div class="shared-campaign-staff-card__top">
        <div class="shared-campaign-staff-person">
          ${renderCandidateStaffAvatar(member)}
          <div>
            <strong>${escapeHtml(candidateStaffDisplayName(member))}</strong>
            <span>${escapeHtml(member.username ? `@${member.username.replace(/^@/u, "")}` : member.userId)}</span>
          </div>
        </div>
        <label class="shared-campaign-staff-role-select">
          <span>Role</span>
          <select name="roleKey"${disabledAttr(!canManage || pendingSave || pendingRemove)}>
            ${renderCandidateStaffRoleOptions(catalog, member.roleKey)}
          </select>
        </label>
      </div>
      <div class="shared-campaign-staff-card__summary">
        <span class="shared-campaign-staff-role-pill" style="${role.color ? `--role-color:${escapeHtml(role.color)};` : ""}">
          <strong>${escapeHtml(member.roleLabel || role.label)}</strong>
          <span>${escapeHtml(role.category)}${member.joinedAt ? ` - joined ${escapeHtml(formatAbsoluteDateTime(member.joinedAt))}` : ""}</span>
        </span>
        ${renderCandidateStaffPermissionChips(member.permissions)}
      </div>
      <details class="shared-campaign-staff-details">
        <summary>Edit permissions</summary>
        ${renderCandidateStaffPermissionCheckboxes(catalog, member.permissions, {
          disabled: !canManage || pendingSave || pendingRemove,
        })}
      </details>
      ${
        canManage
          ? `<div class="shared-campaign-staff-actions">
              <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pendingSave || pendingRemove)}>${pendingSave ? "Saving..." : "Save access"}</button>
              <button class="shared-feed-chip" type="button" data-action="candidate-staff-remove" data-user-id="${escapeHtml(member.userId)}"${disabledAttr(pendingSave || pendingRemove)}>${pendingRemove ? "Removing..." : "Remove"}</button>
            </div>`
          : ""
      }
    </form>
  </article>`;
}

function renderCandidateStaffRoster(detail, resource, catalog, canManage) {
  return `<article class="shared-campaign-panel shared-campaign-staff-roster">
    <div class="shared-campaign-panel__header">
      <div>
        <h2>Active staff</h2>
        <p>Manage campaign roles and feature permissions for each staff member.</p>
      </div>
      <button class="shared-feed-chip" type="button" data-action="candidate-staff-refresh"${disabledAttr(resource.loading)}>Refresh</button>
    </div>
    ${
      resource.loading && !detail.staff.length
        ? '<div class="shared-page__loading">Loading staff...</div>'
        : ""
    }
    ${
      detail.staff.length
        ? `<div class="shared-campaign-staff-card-grid">${detail.staff
            .map((member) =>
              renderCandidateStaffMemberCard(member, resource, catalog, canManage),
            )
            .join("")}</div>`
        : '<div class="shared-page__empty">No active campaign staff members yet.</div>'
    }
  </article>`;
}

function renderCandidateStaffRoleCard(role, resource, catalog) {
  const pendingUpdate = resource.actionPendingKey === `role:${role.roleKey}`;
  const pendingDelete = resource.actionPendingKey === `role-delete:${role.roleKey}`;
  const canDelete = role.custom === true && role.protectedRole !== true;
  const replacementRoles = candidateStaffAssignableRoles(catalog).filter(
    (candidate) => candidate.roleKey !== role.roleKey,
  );
  return `<details class="shared-campaign-staff-role-card">
    <summary>
      <span class="shared-campaign-staff-role-swatch" style="${role.color ? `background:${escapeHtml(role.color)};` : ""}"></span>
      <strong>${escapeHtml(role.label)}</strong>
      <span>${escapeHtml(role.system ? "Preset" : "Custom")} - ${escapeHtml(formatCount(role.defaultPermissions.length))} defaults</span>
    </summary>
    <form class="shared-campaign-staff-role-form" data-route-form="candidate-staff-role-update">
      <input type="hidden" name="roleKey" value="${escapeHtml(role.roleKey)}" />
      <div class="shared-campaign-staff-form-grid">
        <label>
          <span>Role name</span>
          <input name="label" value="${escapeHtml(role.label)}"${disabledAttr(role.system || pendingUpdate || pendingDelete)} />
        </label>
        <label>
          <span>Category</span>
          <input name="category" value="${escapeHtml(role.category)}"${disabledAttr(pendingUpdate || pendingDelete)} />
        </label>
        <label>
          <span>Color</span>
          <input name="color" value="${escapeHtml(role.color)}" placeholder="#64748b"${disabledAttr(pendingUpdate || pendingDelete)} />
        </label>
      </div>
      <label class="shared-campaign-staff-toggle">
        <input type="checkbox" name="enabled"${checkedAttr(role.enabled)}${disabledAttr(role.protectedRole || pendingUpdate || pendingDelete)} />
        <span>Assignable role</span>
      </label>
      ${renderCandidateStaffPermissionCheckboxes(catalog, role.defaultPermissions, {
        disabled: pendingUpdate || pendingDelete,
      })}
      <div class="shared-campaign-staff-actions">
        <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pendingUpdate || pendingDelete)}>${pendingUpdate ? "Saving..." : "Save defaults"}</button>
      </div>
    </form>
    ${
      canDelete
        ? `<form class="shared-campaign-staff-role-delete" data-route-form="candidate-staff-role-delete">
            <input type="hidden" name="roleKey" value="${escapeHtml(role.roleKey)}" />
            <label>
              <span>Move assigned people to</span>
              <select name="replacementRole"${disabledAttr(pendingUpdate || pendingDelete)}>
                ${replacementRoles
                  .map(
                    (replacement) =>
                      `<option value="${escapeHtml(replacement.roleKey)}">${escapeHtml(replacement.label)}</option>`,
                  )
                  .join("")}
              </select>
            </label>
            <button class="shared-feed-chip" type="submit"${disabledAttr(pendingUpdate || pendingDelete || !replacementRoles.length)}>${pendingDelete ? "Removing..." : "Remove role"}</button>
          </form>`
        : ""
    }
  </details>`;
}

function renderCandidateStaffRoles(resource, catalog) {
  const grouped = new Map();
  catalog.roles.forEach((role) => {
    const category = role.category || "Custom";
    if (!grouped.has(category)) {
      grouped.set(category, []);
    }
    grouped.get(category).push(role);
  });
  const creating = resource.actionPendingKey === "role-create";
  return `<article class="shared-campaign-panel shared-campaign-staff-roles">
    <div class="shared-campaign-panel__header">
      <div>
        <h2>Role presets</h2>
        <p>Maintain reusable permission defaults for campaign staff assignments.</p>
      </div>
    </div>
    <form class="shared-campaign-staff-create-role" data-route-form="candidate-staff-role-create">
      <div class="shared-campaign-staff-form-grid">
        <label>
          <span>Role name</span>
          <input name="label" placeholder="Regional Field Lead"${disabledAttr(creating)} />
        </label>
        <label>
          <span>Category</span>
          <input name="category" value="Custom"${disabledAttr(creating)} />
        </label>
        <label>
          <span>Color</span>
          <input name="color" placeholder="#64748b"${disabledAttr(creating)} />
        </label>
      </div>
      <details class="shared-campaign-staff-details">
        <summary>Default permissions</summary>
        ${renderCandidateStaffPermissionCheckboxes(catalog, [], {
          disabled: creating,
        })}
      </details>
      <div class="shared-campaign-staff-actions">
        <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(creating)}>${creating ? "Creating..." : "Create custom role"}</button>
      </div>
    </form>
    <div class="shared-campaign-staff-role-groups">
      ${Array.from(grouped.entries())
        .map(
          ([category, roles]) => `<section>
            <h3>${escapeHtml(category)}</h3>
            <div class="shared-campaign-staff-role-list">
              ${roles
                .map((role) => renderCandidateStaffRoleCard(role, resource, catalog))
                .join("")}
            </div>
          </section>`,
        )
        .join("")}
    </div>
  </article>`;
}

function renderCandidateDashboardStaff(detail, candidateId, access) {
  const resource = detail.staffAdmin;
  const catalog = resource.catalog || normalizeCandidateStaffAccessCatalog({});
  const canManage = canManageCandidateStaff(access);
  const pendingCount = resource.invitations.filter(
    (invite) => invite.status === "pending",
  ).length;
  return `<div class="shared-campaign-section shared-campaign-staff">
    <div class="shared-campaign-metrics">
      ${renderCandidateDashboardMetric("Active staff", formatCount(detail.staff.length), "cyan")}
      ${renderCandidateDashboardMetric("Pending invites", formatCount(pendingCount))}
      ${renderCandidateDashboardMetric("Role presets", formatCount(catalog.roles.length))}
      ${renderCandidateDashboardMetric("Access", canManage ? "Manage" : "View")}
    </div>
    ${resource.error ? `<div class="shared-page__error">${escapeHtml(resource.error)}</div>` : ""}
    <div class="shared-campaign-staff-grid">
      <div class="shared-campaign-staff-main">
        ${renderCandidateStaffRoster(detail, resource, catalog, canManage)}
        ${renderCandidateStaffInvitations(resource, catalog)}
      </div>
      <div class="shared-campaign-staff-side">
        ${canManage ? renderCandidateStaffInviteForm(resource, catalog) : ""}
        ${renderCandidateStaffRoles(resource, catalog)}
      </div>
    </div>
  </div>`;
}

function renderMissionWorkspaceClaimButton(
  missionId,
  job,
  resource,
  actionName,
) {
  if (!job?.isClaimable) {
    return "";
  }
  const pendingKey = `${missionId}:${job.jobId}:claim`;
  const pending = resource?.actionPendingKey === pendingKey;
  return `<button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="${escapeHtml(actionName)}" data-mission-id="${escapeHtml(missionId)}" data-job-id="${escapeHtml(job.jobId)}"${disabledAttr(pending)}>${pending ? "Claiming..." : "Claim"}</button>`;
}

function renderCandidateMissionCard(mission, options = {}) {
  const nextJob = missionNextJob(mission);
  const progress = missionCompletionPercent(mission);
  const compact = options.compact === true;
  const resource =
    options.resource || state.pages.candidateDashboard.detail.missionsWorkspace;
  const claimAction = options.claimAction || "candidate-mission-job-claim";
  const returnTo = encodeURIComponent(getCurrentPathWithQuery());
  const route = `/missions/${encodeURIComponent(mission.missionId)}?returnTo=${returnTo}`;
  const meta = [
    humanizeLabel(mission.priority),
    mission.dueAt ? `Due ${formatAbsoluteDateTime(mission.dueAt)}` : "",
    nextJob ? `Next: ${nextJob.title}` : "",
  ].filter(Boolean);
  return `<article class="shared-campaign-mission-card${compact ? " is-compact" : ""}">
    <div class="shared-campaign-mission-card__top">
      <button class="shared-campaign-mission-card__open" type="button" data-action="navigate" data-route="${escapeHtml(route)}">
        <span class="shared-campaign-mission-card__icon">${renderIcon("mission")}</span>
        <span class="shared-campaign-mission-card__body">
          <span class="shared-card__meta">${meta.map((item) => `<span>${escapeHtml(item)}</span>`).join("")}</span>
          <strong>${escapeHtml(mission.title)}</strong>
          <span>${escapeHtml(mission.description || (nextJob ? missionJobOwnerLabel(nextJob) : "Mission details and task progress"))}</span>
        </span>
      </button>
      <div class="shared-campaign-mission-card__actions">
        ${renderMissionBadge(humanizeLabel(mission.status), missionStatusTone(mission.status))}
        ${renderMissionWorkspaceClaimButton(
          mission.missionId,
          nextJob,
          resource,
          claimAction,
        )}
      </div>
    </div>
    <div class="shared-mission-progress" aria-label="${escapeHtml(`${progress}% complete`)}"><span style="width: ${Math.max(0, Math.min(100, progress))}%"></span></div>
    <div class="shared-campaign-mission-card__metrics">
      <span>${escapeHtml(formatCount(mission.openCount))} open</span>
      <span>${escapeHtml(formatCount(mission.attentionCount))} attention</span>
      <span>${escapeHtml(formatCount(mission.claimableCount))} claimable</span>
      <span>${escapeHtml(`${progress}% complete`)}</span>
    </div>
  </article>`;
}

function renderCandidateMissionSection(
  title,
  subtitle,
  missions,
  emptyText,
  options = {},
) {
  return `<article class="shared-campaign-panel shared-campaign-mission-section">
    <div class="shared-campaign-panel__header">
      <div>
        <h2>${escapeHtml(title)}</h2>
        ${subtitle ? `<p>${escapeHtml(subtitle)}</p>` : ""}
      </div>
      <span class="shared-mission-badge">${escapeHtml(formatCount(missions.length))}</span>
    </div>
    <div class="shared-campaign-mission-list">
      ${
        missions.length
          ? missions
              .map((mission) => renderCandidateMissionCard(mission, options))
              .join("")
          : `<div class="shared-page__empty">${escapeHtml(emptyText || "No missions in this section.")}</div>`
      }
    </div>
  </article>`;
}

function renderCandidateMissionCreateForm(resource, options = {}) {
  const draft = resource.createDraft || {};
  const presetKey = normalizeString(draft.presetKey) || "general";
  const priorityKey = normalizeString(draft.priority).toLowerCase() || "normal";
  const targetModeKey =
    normalizeString(draft.targetMode).toLowerCase() || "user";
  const deadlineModeKey =
    normalizeString(draft.deadlineMode).toLowerCase() || "indefinite";
  const timeoutPolicyKey =
    normalizeString(draft.timeoutPolicy).toLowerCase() || "escalate";
  const pending = resource.actionPendingKey === "create";
  const formKind = options.formKind || "candidate-missions-create";
  const toggleAction = options.toggleAction || "candidate-missions-create-toggle";
  const noun = options.noun || "campaign";
  const scopeType = normalizeMissionScopeType(options.scopeType);
  const scopeId = normalizeString(options.scopeId);
  return `<form class="shared-form shared-campaign-mission-create" data-route-form="${escapeHtml(formKind)}">
    <input type="hidden" name="templateId" value="${escapeHtml(draft.templateId || "")}" />
    <input type="hidden" name="templateVersion" value="${escapeHtml(draft.templateVersion || "")}" />
    ${scopeType && scopeId ? `<input type="hidden" name="scopeType" value="${escapeHtml(scopeType)}" /><input type="hidden" name="scopeId" value="${escapeHtml(scopeId)}" />` : ""}
    <div class="shared-campaign-mission-create__header">
      <div>
        <h2>${draft.templateId ? "Create from template" : "New mission"}</h2>
        <p>Publish a ${escapeHtml(noun)} mission with one lead task. Add follow-up tasks and files from the mission detail after it is created.</p>
      </div>
      <button class="shared-feed-chip" type="button" data-action="${escapeHtml(toggleAction)}"${disabledAttr(pending)}>Cancel</button>
    </div>
    <div class="shared-campaign-mission-form-grid">
      <label>
        <span>Mission objective</span>
        <input name="title" value="${escapeHtml(draft.title || "")}" placeholder="Print GOTV walk cards"${disabledAttr(pending)} required />
      </label>
      <label>
        <span>Preset</span>
        <select name="presetKey"${disabledAttr(pending)}>
          ${MISSION_PRESETS.map(
            (preset) =>
              `<option value="${escapeHtml(preset.key)}"${selectedAttr(preset.key === presetKey)}>${escapeHtml(preset.label)}</option>`,
          ).join("")}
        </select>
      </label>
      <label>
        <span>Priority</span>
        <select name="priority"${disabledAttr(pending)}>
          ${["low", "normal", "high", "urgent"]
            .map(
              (priority) =>
                `<option value="${escapeHtml(priority)}"${selectedAttr(priority === priorityKey)}>${escapeHtml(humanizeLabel(priority))}</option>`,
            )
            .join("")}
        </select>
      </label>
      <label>
        <span>Lead owner</span>
        <input name="assignee" placeholder="@username, user id, or role key"${disabledAttr(pending)} required />
      </label>
      <label>
        <span>Target mode</span>
        <select name="targetMode"${disabledAttr(pending)}>
          <option value="user"${selectedAttr(targetModeKey === "user")}>Specific user</option>
          <option value="role_claim"${selectedAttr(targetModeKey === "role_claim")}>Role can claim</option>
          <option value="role_fanout"${selectedAttr(targetModeKey === "role_fanout")}>Fan out to role</option>
        </select>
      </label>
      <label>
        <span>Deadline</span>
        <select name="deadlineMode"${disabledAttr(pending)}>
          <option value="indefinite"${selectedAttr(deadlineModeKey === "indefinite")}>No deadline</option>
          <option value="due_at"${selectedAttr(deadlineModeKey === "due_at")}>Due in hours</option>
          <option value="duration_after_activation"${selectedAttr(deadlineModeKey === "duration_after_activation")}>Hours after activation</option>
        </select>
      </label>
      <label>
        <span>Hours</span>
        <input name="dueHours" type="number" min="0" step="1" value="${escapeHtml(draft.dueHours || "")}" placeholder="48"${disabledAttr(pending)} />
      </label>
      <label>
        <span>Timeout action</span>
        <select name="timeoutPolicy"${disabledAttr(pending)}>
          <option value="escalate"${selectedAttr(timeoutPolicyKey === "escalate")}>Escalate</option>
          <option value="none"${selectedAttr(timeoutPolicyKey === "none")}>None</option>
          <option value="auto_unassign"${selectedAttr(timeoutPolicyKey === "auto_unassign")}>Auto-unassign</option>
          <option value="auto_fail"${selectedAttr(timeoutPolicyKey === "auto_fail")}>Auto-fail</option>
        </select>
      </label>
      <label>
        <span>Timeout grace hours</span>
        <input name="timeoutHours" type="number" min="0" step="1" value="${escapeHtml(draft.timeoutHours || "")}" placeholder="24"${disabledAttr(pending)} />
      </label>
      <label class="shared-campaign-mission-create__description">
        <span>Context for the team</span>
        <textarea name="description" rows="4" placeholder="What should the assignee know before starting?"${disabledAttr(pending)}>${escapeHtml(draft.description || "")}</textarea>
      </label>
    </div>
    <div class="shared-campaign-mission-create__preset">
      <strong>${escapeHtml(missionPresetForKey(presetKey).label)}</strong>
      <span>${escapeHtml(missionPresetForKey(presetKey).description)}</span>
    </div>
    <div class="shared-campaign-mission-create__actions">
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pending)}>${pending ? "Publishing..." : "Publish mission"}</button>
    </div>
  </form>`;
}

function renderCandidateMissionTabs(resource, canManage, options = {}) {
  const viewAction = options.viewAction || "candidate-missions-view";
  return `<div class="shared-campaign-mission-tabs">
    ${candidateMissionViewOptions(canManage)
      .map(
        (option) =>
          `<button class="shared-missions-tab${resource.view === option.key ? " is-active" : ""}" type="button" data-action="${escapeHtml(viewAction)}" data-view="${escapeHtml(option.key)}">${escapeHtml(option.label)}</button>`,
      )
      .join("")}
  </div>`;
}

function renderCandidateMissionAttentionView(resource, options = {}) {
  const visible = filterCandidateMissions(resource.items, resource.filter);
  const activeFilter =
    candidateMissionFilterOptions().find((option) => option.key === resource.filter) ||
    candidateMissionFilterOptions()[0];
  const filterAction = options.filterAction || "candidate-missions-filter";
  return `<div class="shared-campaign-mission-workspace">
    <article class="shared-campaign-panel shared-campaign-mission-filter-panel">
      <div class="shared-campaign-panel__header">
        <div>
          <h2>${escapeHtml(activeFilter.label)}</h2>
          <p>Fast triage for blocked, late, submitted, high priority, and deadline-driven work.</p>
        </div>
      </div>
      <div class="shared-campaign-mission-filters">
        ${candidateMissionFilterOptions()
          .map(
            (option) =>
              `<button class="shared-feed-chip${resource.filter === option.key ? " shared-feed-chip--primary" : ""}" type="button" data-action="${escapeHtml(filterAction)}" data-filter="${escapeHtml(option.key)}">${escapeHtml(option.label)}</button>`,
          )
          .join("")}
      </div>
    </article>
    ${renderCandidateMissionSection(
      activeFilter.label,
      "",
      visible,
      `No missions match ${activeFilter.label.toLowerCase()}.`,
      options,
    )}
  </div>`;
}

function renderCandidateMissionBoardView(items, options = {}) {
  return `<div class="shared-campaign-mission-board">
    ${candidateMissionBoardGroups(items)
      .map(
        (group) => `<section class="shared-campaign-panel shared-campaign-mission-board-column">
          <div class="shared-campaign-panel__header">
            <h2>${escapeHtml(group.title)}</h2>
            <span class="shared-mission-badge">${escapeHtml(formatCount(group.items.length))}</span>
          </div>
          <div class="shared-campaign-mission-list">
            ${
              group.items.length
                ? group.items
                    .map((mission) =>
                      renderCandidateMissionCard(mission, {
                        ...options,
                        compact: true,
                      }),
                    )
                    .join("")
                : `<div class="shared-page__empty">${escapeHtml(group.empty)}</div>`
            }
          </div>
        </section>`,
      )
      .join("")}
  </div>`;
}

function renderCandidateMissionWorkloadCard(workload) {
  const priorityMissions = Array.from(workload.missionsById.values()).sort(
    (left, right) => {
      const leftJob = missionNextJob(left);
      const rightJob = missionNextJob(right);
      const rank =
        candidateMissionJobRank(leftJob || {}) -
        candidateMissionJobRank(rightJob || {});
      if (rank) return rank;
      return (
        (candidateMissionEarliestDue(left) || Number.MAX_SAFE_INTEGER) -
        (candidateMissionEarliestDue(right) || Number.MAX_SAFE_INTEGER)
      );
    },
  );
  const chips = [
    workload.active ? `${workload.active} active` : "",
    workload.dueSoon ? `${workload.dueSoon} due soon` : "",
    workload.late ? `${workload.late} late` : "",
    workload.blocked ? `${workload.blocked} blocked` : "",
    workload.submitted ? `${workload.submitted} submitted` : "",
    workload.queued ? `${workload.queued} queued` : "",
    workload.highPriority ? `${workload.highPriority} high priority` : "",
  ].filter(Boolean);
  return `<article class="shared-campaign-mission-workload">
    <div class="shared-campaign-mission-workload__top">
      <span class="shared-campaign-mission-workload__avatar">${renderIcon(workload.label.startsWith("Claimable") ? "team" : "candidate")}</span>
      <div>
        <h3>${escapeHtml(workload.label)}</h3>
        <p>${escapeHtml(`${formatCount(workload.jobs.length)} open task${workload.jobs.length === 1 ? "" : "s"} across ${formatCount(workload.missionsById.size)} mission${workload.missionsById.size === 1 ? "" : "s"}`)}</p>
      </div>
    </div>
    <div class="shared-campaign-mission-workload__chips">
      ${chips.length ? chips.map((chip) => `<span>${escapeHtml(chip)}</span>`).join("") : "<span>No open work</span>"}
    </div>
    <div class="shared-campaign-mission-workload__rows">
      ${priorityMissions
        .slice(0, 3)
        .map((mission) => {
          const job = missionNextJob(mission);
          return `<button type="button" data-action="navigate" data-route="/missions/${escapeHtml(encodeURIComponent(mission.missionId))}?returnTo=${escapeHtml(encodeURIComponent(getCurrentPathWithQuery()))}">
            <strong>${escapeHtml(mission.title)}</strong>
            <span>${escapeHtml(job ? `${humanizeLabel(job.status)} - ${job.title}` : humanizeLabel(mission.status))}</span>
          </button>`;
        })
        .join("")}
    </div>
  </article>`;
}

function renderCandidateMissionPeopleView(items) {
  const workloads = candidateMissionWorkloads(items);
  return `<article class="shared-campaign-panel shared-campaign-mission-people">
    <div class="shared-campaign-panel__header">
      <div>
        <h2>Workload by person</h2>
        <p>Open work grouped by assignee, claimable role, or fan-out group.</p>
      </div>
    </div>
    <div class="shared-campaign-mission-workloads">
      ${
        workloads.length
          ? workloads.map(renderCandidateMissionWorkloadCard).join("")
          : '<div class="shared-page__empty">No open workload is visible.</div>'
      }
    </div>
  </article>`;
}

function renderMissionTemplateEditor(resource, options = {}) {
  if (!resource.templateEditorOpen) {
    return "";
  }
  const draft = resource.templateDraft || {};
  const defaults = missionTemplateDefaultsFromConfig({
    ...(draft.config || {}),
    ...draft,
  });
  const presetKey =
    normalizeString(draft.presetKey).toLowerCase() || "general";
  const pending = resource.actionPendingKey === "template-save";
  const formKind =
    options.templateFormKind || "candidate-missions-template-save";
  const toggleAction =
    options.templateToggleAction || "candidate-missions-template-toggle";
  const scopeType = normalizeMissionScopeType(options.scopeType);
  const scopeId = normalizeString(options.scopeId);
  const templateId = normalizeString(draft.templateId);
  return `<form class="shared-campaign-mission-template-editor" data-route-form="${escapeHtml(formKind)}">
    <input type="hidden" name="scopeType" value="${escapeHtml(scopeType)}" />
    <input type="hidden" name="scopeId" value="${escapeHtml(scopeId)}" />
    <input type="hidden" name="templateId" value="${escapeHtml(templateId)}" />
    <div class="shared-campaign-mission-template-editor__header">
      <div>
        <h3>${escapeHtml(templateId ? "Edit template" : "Template studio")}</h3>
        <p>Save mission defaults that can be reused by campaign and coalition operators without rebuilding the assignment each time.</p>
      </div>
      <button class="shared-feed-chip" type="button" data-action="${escapeHtml(toggleAction)}"${disabledAttr(pending)}>Close</button>
    </div>
    <div class="shared-campaign-mission-form-grid">
      <label>
        <span>Template name</span>
        <input name="title" value="${escapeHtml(draft.title || "")}" placeholder="Weekend phone bank"${disabledAttr(pending)} required />
      </label>
      <label>
        <span>Preset</span>
        <select name="presetKey"${disabledAttr(pending)}>
          ${MISSION_PRESETS.map(
            (preset) =>
              `<option value="${escapeHtml(preset.key)}"${selectedAttr(preset.key === presetKey)}>${escapeHtml(preset.label)}</option>`,
          ).join("")}
        </select>
      </label>
      <label>
        <span>Priority</span>
        <select name="priority"${disabledAttr(pending)}>
          ${["low", "normal", "high", "urgent"]
            .map(
              (priority) =>
                `<option value="${escapeHtml(priority)}"${selectedAttr(priority === defaults.priority)}>${escapeHtml(humanizeLabel(priority))}</option>`,
            )
            .join("")}
        </select>
      </label>
      <label>
        <span>Target mode</span>
        <select name="targetMode"${disabledAttr(pending)}>
          <option value="user"${selectedAttr(defaults.targetMode === "user")}>Specific user</option>
          <option value="role_claim"${selectedAttr(defaults.targetMode === "role_claim")}>Role can claim</option>
          <option value="role_fanout"${selectedAttr(defaults.targetMode === "role_fanout")}>Fan out to role</option>
        </select>
      </label>
      <label>
        <span>Deadline</span>
        <select name="deadlineMode"${disabledAttr(pending)}>
          <option value="indefinite"${selectedAttr(defaults.deadlineMode === "indefinite")}>No deadline</option>
          <option value="due_at"${selectedAttr(defaults.deadlineMode === "due_at")}>Due in hours</option>
          <option value="duration_after_activation"${selectedAttr(defaults.deadlineMode === "duration_after_activation")}>Hours after activation</option>
        </select>
      </label>
      <label>
        <span>Hours</span>
        <input name="dueHours" type="number" min="0" step="1" value="${escapeHtml(defaults.dueHours)}" placeholder="48"${disabledAttr(pending)} />
      </label>
      <label>
        <span>Timeout action</span>
        <select name="timeoutPolicy"${disabledAttr(pending)}>
          <option value="escalate"${selectedAttr(defaults.timeoutPolicy === "escalate")}>Escalate</option>
          <option value="none"${selectedAttr(defaults.timeoutPolicy === "none")}>None</option>
          <option value="auto_unassign"${selectedAttr(defaults.timeoutPolicy === "auto_unassign")}>Auto-unassign</option>
          <option value="auto_fail"${selectedAttr(defaults.timeoutPolicy === "auto_fail")}>Auto-fail</option>
        </select>
      </label>
      <label>
        <span>Timeout grace hours</span>
        <input name="timeoutHours" type="number" min="0" step="1" value="${escapeHtml(defaults.timeoutHours)}" placeholder="24"${disabledAttr(pending)} />
      </label>
      <label class="shared-campaign-mission-create__description">
        <span>Default context</span>
        <textarea name="description" rows="4" placeholder="What should the assignee know before starting?"${disabledAttr(pending)}>${escapeHtml(draft.description || "")}</textarea>
      </label>
    </div>
    <div class="shared-campaign-mission-template-editor__footer">
      <div>
        <strong>${escapeHtml(missionPresetForKey(presetKey).label)}</strong>
        <span>${escapeHtml(templateId ? `Version ${draft.templateVersion || draft.version || 1}` : "New reusable pattern")}</span>
      </div>
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pending)}>${pending ? "Saving..." : templateId ? "Update template" : "Save template"}</button>
    </div>
  </form>`;
}

