function renderCandidateDashboardCampaignQuest(detail, access) {
  const resource = detail.campaignQuest;
  const config = resource.config || normalizeCampaignQuestConfig({});
  const progress = resource.progress || normalizeCampaignQuestProgress({});
  const permissions = candidateDashboardPermissionSet(access);
  const canManage = access?.isOwner || permissions.has("voter_map_manager");
  if (resource.loading && !resource.loaded) {
    return `<div class="shared-campaign-section"><div class="shared-page__loading">Loading Campaign Quest...</div></div>`;
  }
  return `<div class="shared-campaign-section shared-campaign-quest">
    ${renderCampaignQuestCommandCenter(resource, progress, config, canManage)}
    ${resource.error ? `<div class="shared-page__error">${escapeHtml(resource.error)}</div>` : ""}
    ${
      resource.lastCompletion
        ? `<div class="shared-campaign-quest-completion">
            <strong>Last completion</strong>
            <span>+${escapeHtml(formatCount(resource.lastCompletion.xp.totalAwarded))} XP${resource.lastCompletion.badgesUnlocked.length ? ` - ${escapeHtml(formatCount(resource.lastCompletion.badgesUnlocked.length))} badge unlocked` : ""}</span>
          </div>`
        : ""
    }
    <div class="shared-campaign-quest-grid">
      <div class="shared-campaign-quest-main">
        ${renderCampaignQuestProgress(progress)}
        ${renderCampaignQuestTargets(resource, config)}
      </div>
      <div class="shared-campaign-quest-side">
        ${renderCampaignQuestQuests(progress)}
        ${renderCampaignQuestBadges(config, progress)}
        ${renderCampaignQuestConfigForm(config, resource, canManage)}
      </div>
    </div>
  </div>`;
}

function candidateVoterMapAccessLabel(voterMapAccess, dashboardAccess) {
  if (voterMapAccess?.canManageTerritories || dashboardAccess?.isOwner) {
    return "Territory admin";
  }
  if (voterMapAccess?.scope === "territories") {
    return "Territory assigned";
  }
  const permissions = candidateDashboardPermissionSet(dashboardAccess);
  if (permissions.has("voter_map_manager")) {
    return "Map manager";
  }
  if (permissions.has("voter_map_territory")) {
    return "Territory access";
  }
  return "Campaign access";
}

function renderCandidateVoterMapCampaignCard(access) {
  const profile = access.profile || {};
  const candidateId = normalizeString(access.candidateId);
  const displayName = normalizeString(profile.displayName) || "Campaign";
  const voterMapPath = candidateVoterMapPath("", candidateId);
  return `<article class="shared-candidate-voter-map-campaign">
    <div class="shared-campaign-card__avatar">
      ${
        profile.avatarUrl
          ? `<img src="${escapeHtml(profile.avatarUrl)}" alt="${escapeHtml(displayName)}" />`
          : `<span>${escapeHtml(displayName.slice(0, 1).toUpperCase() || "C")}</span>`
      }
    </div>
    <div>
      <div class="shared-card__meta">
        <span>${escapeHtml(access.isOwner ? "Owner" : `${formatCount(access.permissions.length)} permissions`)}</span>
        ${profile.username ? `<span>@${escapeHtml(profile.username)}</span>` : ""}
      </div>
      <h3>${escapeHtml(displayName)}</h3>
      <p>Open voter-map tools for this campaign.</p>
      <div class="shared-card__actions">
        <button class="shared-feed-chip shared-feed-chip--primary" data-action="navigate" data-route="${escapeHtml(candidateVoterMapPath("map", candidateId))}">Open map</button>
        <button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(candidateVoterMapPath("connected", candidateId))}">Voters</button>
        <button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(voterMapPath)}">Menu</button>
      </div>
    </div>
  </article>`;
}

