function renderCandidateDonationUnavailable(resource) {
  return `<div class="shared-campaign-section shared-campaign-donations shared-campaign-donations--setup">
    ${resource.error ? `<div class="shared-page__error">${escapeHtml(resource.error)}</div>` : ""}
    <article class="shared-campaign-panel shared-campaign-panel--accent shared-campaign-donations-setup-hero">
      <div class="shared-campaign-panel__header">
        <div>
          <span class="shared-card__meta"><span>Candidate donations</span><span>Status unavailable</span></span>
          <h2>Donation setup could not load</h2>
          <p>The website could not confirm this campaign's finance setup, payout account, or donation CTA status.</p>
        </div>
        <div class="shared-card__actions">
          <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="candidate-donations-refresh"${disabledAttr(resource.loading)}>${resource.loading ? "Retrying..." : "Retry"}</button>
        </div>
      </div>
    </article>
  </div>`;
}

function renderCandidateDashboardDonations(detail, candidateId) {
  const resource = detail.donations;
  const status = resource.status;
  if (resource.loading && !resource.loaded) {
    return `<div class="shared-campaign-section"><div class="shared-page__loading">Loading donations...</div></div>`;
  }
  if (!status) {
    return renderCandidateDonationUnavailable(resource);
  }
  const canUseDashboard = candidateDonationCanUseDashboard(status);
  const totalAmount = resource.transactions.reduce(
    (sum, item) => sum + (Number(item.amountCents) || 0),
    0,
  );
  if (!canUseDashboard) {
    return `<div class="shared-campaign-section shared-campaign-donations shared-campaign-donations--setup">
      ${resource.error ? `<div class="shared-page__error">${escapeHtml(resource.error)}</div>` : ""}
      ${renderCandidateDonationSetupHero(status, resource)}
      ${renderCandidateDonationReadinessPanel(status, resource)}
      <div class="shared-campaign-donations-grid shared-campaign-donations-grid--setup">
        <div class="shared-campaign-donations-main">
          ${renderCandidateDonationFinanceSetup(status, resource)}
          ${renderCandidateDonationReportingLocked(status, resource)}
        </div>
        <div class="shared-campaign-donations-side">
          ${renderCandidateDonationSettings(status, resource, { locked: true })}
          <article class="shared-campaign-panel shared-campaign-donations-note-panel">
            <div class="shared-campaign-panel__header"><h2>What unlocks next</h2></div>
            <p>Once setup is ready, this web dashboard will show donor search, status filters, transaction details, CSV export, and campaign analytics navigation.</p>
          </article>
        </div>
      </div>
    </div>`;
  }
  return `<div class="shared-campaign-section shared-campaign-donations">
    ${resource.error ? `<div class="shared-page__error">${escapeHtml(resource.error)}</div>` : ""}
    ${renderCandidateDonationSetupHero(status, resource)}
    <div class="shared-campaign-metrics">
      ${renderCandidateDashboardMetric("Readiness", status.readiness?.readyToEnable ? "Ready" : "Blocked", status.readiness?.readyToEnable ? "cyan" : "")}
      ${renderCandidateDashboardMetric("Enabled", status.settings?.donationsEnabled ? "On" : "Off")}
      ${renderCandidateDashboardMetric("Loaded donations", formatCount(resource.transactions.length))}
      ${renderCandidateDashboardMetric("Visible total", formatDonationAmount(totalAmount), "cyan")}
    </div>
    ${renderCandidateDonationReadinessPanel(status, resource)}
    <div class="shared-campaign-donations-grid">
      <div class="shared-campaign-donations-main">
        ${renderCandidateDonationFinanceSetup(status, resource)}
        ${renderCandidateDonationTransactions(resource)}
      </div>
      <div class="shared-campaign-donations-side">
        ${renderCandidateDonationSettings(status, resource)}
        ${renderCandidateDonationDetail(resource)}
        <article class="shared-campaign-panel shared-campaign-donations-note-panel">
          <div class="shared-campaign-panel__header"><h2>Compliance exports</h2></div>
          <p>Exports include donor name, address, occupation, employer, certification flags, routing, transfer, and net amount fields from the Polis donation ledger.</p>
          <div class="shared-card__actions">
            <button class="shared-feed-chip" type="button" data-action="candidate-donation-export"${disabledAttr(resource.actionPendingKey === "export")}>Export CSV</button>
            <button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(candidateDashboardSectionPath(candidateId, "analytics"))}">Analytics</button>
          </div>
        </article>
      </div>
    </div>
  </div>`;
}

function renderCandidateDashboardBuildoutPanel(section, candidateId) {
  const actionBySection = {
    "voter-registry": "Voter registry",
    "campaign-quest": "Campaign quest",
    donations: "Donations",
    "voter-contact-prompt": "Contact prompt",
    engagement: "Engagement queue",
  };
  return `<div class="shared-campaign-section">
    <article class="shared-campaign-panel shared-campaign-panel--accent">
      <div class="shared-campaign-panel__header">
        <h2>${escapeHtml(section.label)}</h2>
        <button class="shared-feed-chip" data-action="open-app-shell">Open app</button>
      </div>
      <p>${escapeHtml(actionBySection[section.key] || section.label)} is available from the Polis app while this browser workspace is being enabled for your campaign.</p>
      <div class="shared-card__actions">
        <button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(candidateDashboardSectionPath(candidateId))}">Dashboard overview</button>
        <button class="shared-feed-chip shared-feed-chip--primary" data-action="open-app-shell">Continue in app</button>
      </div>
    </article>
  </div>`;
}

function renderCandidateDashboardSection(detail, candidateId, access, activeSection) {
  const section =
    CANDIDATE_DASHBOARD_SECTION_CONFIG.find(
      (item) => item.key === activeSection,
    ) || CANDIDATE_DASHBOARD_SECTION_CONFIG[0];
  if (!canOpenCandidateDashboardSection(section, access)) {
    return `<div class="shared-page__empty">This campaign access does not include ${escapeHtml(section.label)}.</div>`;
  }
  if (section.key === "overview") {
    return renderCandidateDashboardOverview(detail, candidateId, access);
  }
  if (section.key === "analytics") {
    return renderCandidateDashboardAnalytics(detail);
  }
  if (section.key === "events") {
    return renderCandidateDashboardEvents(detail);
  }
  if (section.key === "calendar") {
    return renderCandidateDashboardCalendar(detail, candidateId, access);
  }
  if (section.key === "engagement") {
    return renderCandidateDashboardEngagement(detail, candidateId, access);
  }
  if (section.key === "voter-contact-prompt") {
    return renderCandidateDashboardContactPrompt(detail, candidateId, access);
  }
  if (section.key === "voter-registry") {
    return renderCandidateDashboardVoterRegistry(detail, candidateId);
  }
  if (section.key === "campaign-quest") {
    return renderCandidateDashboardCampaignQuest(detail, access);
  }
  if (section.key === "donations") {
    return renderCandidateDashboardDonations(detail, candidateId, access);
  }
  if (section.key === "staff") {
    return renderCandidateDashboardStaff(detail, candidateId, access);
  }
  if (section.key === "missions") {
    return renderCandidateDashboardMissions(detail, candidateId, access);
  }
  if (section.key === "messaging") {
    return renderCandidateDashboardMessaging(detail, candidateId, access);
  }
  return renderCandidateDashboardBuildoutPanel(section, candidateId);
}

function renderCandidateDashboardPage() {
  const route = getCurrentRoute();
  const candidateId = decodeRouteSegment(route.routeParams.candidateId);
  if (!candidateId) {
    return renderCandidateDashboardRoot();
  }
  const dashboard = state.pages.candidateDashboard;
  const detail = dashboard.detail;
  const access = detail.access || findCandidateDashboardAccess(candidateId);
  const candidate = detail.candidate;
  const activeSection = candidateDashboardSectionForRoute(route);
  if (detail.loading && !candidate && !access) {
    return `<section class="shared-page shared-campaign-dashboard">${renderTopChrome()}<div class="shared-page__content"><div class="shared-page__loading">Loading campaign dashboard...</div></div></section>`;
  }
  if (detail.error && !candidate && !access) {
    return `<section class="shared-page shared-campaign-dashboard">${renderTopChrome()}<div class="shared-page__content"><div class="shared-page__error">${escapeHtml(detail.error)}</div></div></section>`;
  }
  if (!candidate && !access) {
    return `<section class="shared-page shared-campaign-dashboard">${renderTopChrome()}<div class="shared-page__content"><div class="shared-page__error">Campaign dashboard unavailable.</div></div></section>`;
  }
  return `<section class="shared-page shared-campaign-dashboard">
    ${renderTopChrome()}
    <div class="shared-page__content">
      <div class="shared-page__back-row">
        <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/candidate-dashboard">All campaigns</button>
      </div>
      ${renderCandidateDashboardHero(candidate, access)}
      ${detail.error ? `<div class="shared-page__error">${escapeHtml(detail.error)}</div>` : ""}
      ${renderCandidateDashboardTabs(candidateId, activeSection, access)}
      ${renderCandidateDashboardSection(detail, candidateId, access, activeSection)}
    </div>
  </section>`;
}

function renderCoalitionsAuthGate() {
  return `<section class="shared-page shared-coalition-workspace">
    ${renderTopChrome()}
    <div class="shared-page__content">
      <section class="shared-coalition-auth">
        <div>
          <h1>Coalition Workspace</h1>
          <p>Open coalition rooms, member access, missions, voter map tools, governance, calendar, and amplify requests from the browser.</p>
          <div class="shared-card__actions">
            <button class="shared-feed-chip shared-feed-chip--primary" data-action="auth-login-inline">Sign in</button>
            <button class="shared-feed-chip" data-action="auth-signup-inline">Create account</button>
            <button class="shared-feed-chip" data-action="open-app-shell">Open app</button>
          </div>
        </div>
        <div class="shared-coalition-auth__grid" aria-hidden="true">
          ${["Rooms", "Members", "Missions", "Voter Map", "Governance", "Amplify"]
            .map(
              (label) =>
                `<span class="shared-coalition-auth__tile">${escapeHtml(label)}</span>`,
            )
            .join("")}
        </div>
      </section>
    </div>
  </section>`;
}

function coalitionSectionForRoute(route = state.route) {
  const section = coalitionRouteSectionPath(route).split("/")[0] || "";
  if (section === "admin") {
    return "members";
  }
  if (section === "constitution" || section === "voting") {
    return "governance";
  }
  return (
    COALITION_SECTION_CONFIG.some((item) => item.key === section)
      ? section
      : COALITION_DEFAULT_SECTION
  );
}

function coalitionSectionPath(coalitionId, sectionKey = "") {
  const encodedId = encodeURIComponent(normalizeString(coalitionId));
  if (!encodedId) {
    return "/coalitions";
  }
  const section = normalizeString(sectionKey);
  if (!section || section === COALITION_DEFAULT_SECTION) {
    return `/coalitions/${encodedId}`;
  }
  const encodedSection = section
    .split("/")
    .map((part) => encodeURIComponent(part))
    .join("/");
  return `/coalitions/${encodedId}/${encodedSection}`;
}

function coalitionEntryPath(coalition, membership) {
  const coalitionId = normalizeString(coalition?.coalitionId);
  if (!coalitionId) {
    return "/coalitions";
  }
  if (membership?.isActive && membership?.isLeader) {
    return coalitionSectionPath(coalitionId, "admin");
  }
  return coalitionSectionPath(coalitionId);
}

function coalitionEntryLabel(membership) {
  if (membership?.isPending) {
    return "Pending approval";
  }
  return membership?.isLeader ? "Admin view" : "Open coalition";
}

function coalitionRouteSectionPath(route = state.route) {
  return decodeRouteSegment(route?.routeParams?.section)
    .replace(/^\/+|\/+$/gu, "")
    .toLowerCase();
}

function coalitionRouteParts(route = state.route) {
  return coalitionRouteSectionPath(route).split("/").filter(Boolean);
}

function coalitionVoterMapSectionForRoute(route = state.route) {
  const parts = coalitionRouteParts(route);
  if (parts[0] !== "voter-map") {
    return "menu";
  }
  const section = parts.slice(1).join("/") || "menu";
  if (section === "territories" || section === "territory-admin") {
    return "territories/admin";
  }
  return (
    COALITION_VOTER_MAP_SECTION_CONFIG.some((item) => item.key === section)
      ? section
      : "menu"
  );
}

function coalitionGovernanceRouteForRoute(route = state.route) {
  const parts = coalitionRouteParts(route);
  if (parts[0] === "constitution") {
    return { key: "constitution", voteId: "" };
  }
  if (parts[0] !== "voting") {
    return { key: "governance", voteId: "" };
  }
  if (parts[1] === "speaker") {
    return { key: "speaker", voteId: "" };
  }
  if (parts[1] === "proposals" && parts[2] === "new") {
    return { key: "proposal-create", voteId: "" };
  }
  if (parts[1] === "votes" && parts[2]) {
    return {
      key: parts[3] === "results" ? "vote-results" : "vote-detail",
      voteId: decodeRouteSegment(parts[2]),
    };
  }
  return { key: "voting", voteId: "" };
}

function isCoalitionAmplifyCreateRoute(route = state.route) {
  const parts = coalitionRouteParts(route);
  return parts[0] === "amplify" && parts[1] === "create";
}

function isCoalitionAdminEditRoute(route = state.route) {
  const parts = coalitionRouteParts(route);
  return parts[0] === "admin" && parts[1] === "edit";
}

function coalitionHasAnyPermission(membership, permissions = []) {
  if (!permissions.length) {
    return true;
  }
  if (membership?.isAdmin) {
    return true;
  }
  const permissionSet = new Set(membership?.permissions || []);
  return permissions.some((permission) =>
    permissionSet.has(normalizeCoalitionPermission(permission)),
  );
}

function canOpenCoalitionSection(section, coalition, membership) {
  if (!section) {
    return false;
  }
  if (section.key === COALITION_DEFAULT_SECTION) {
    return true;
  }
  if (!membership?.isActive) {
    return false;
  }
  if (section.key === "members") {
    return true;
  }
  if (section.key === "rooms") {
    return true;
  }
  if (section.key === "missions") {
    return (
      membership.isAdmin ||
      (membership.permissions || []).some((permission) =>
        COALITION_MISSION_PERMISSIONS.has(permission),
      )
    );
  }
  if (section.key === "voter-map") {
    return coalition?.voterMapEnabled && membership.canAccessVoterMap;
  }
  if (section.key === "governance") {
    return (
      coalition?.coalitionType === "constitutional" ||
      coalition?.hasConstitution ||
      coalitionHasAnyPermission(membership, section.permissions)
    );
  }
  if (section.key === "amplify") {
    return true;
  }
  return coalitionHasAnyPermission(membership, section.permissions);
}

function coalitionFeatureRank(section) {
  const index = COALITION_FEATURE_ORDER.indexOf(section?.key);
  return index >= 0 ? index : COALITION_FEATURE_ORDER.length;
}

function coalitionFeatureSections({ includeOverview = false } = {}) {
  return COALITION_SECTION_CONFIG.filter(
    (section) => includeOverview || section.key !== COALITION_DEFAULT_SECTION,
  ).sort((left, right) => coalitionFeatureRank(left) - coalitionFeatureRank(right));
}

function coalitionFeatureCopy(section) {
  return (
    COALITION_FEATURE_COPY[section?.key] || {
      eyebrow: "Coalition",
      description: `${section?.label || "Coalition feature"} is available from this workspace when your membership includes it.`,
      cta: `Open ${section?.label || "section"}`,
    }
  );
}

function coalitionFeatureStatus(section, coalition, membership) {
  const enabled = canOpenCoalitionSection(section, coalition, membership);
  const copy = coalitionFeatureCopy(section);
  if (enabled) {
    return {
      label: membership?.isAdmin
        ? "Admin access"
        : membership?.isLeader
          ? "Leader access"
          : section?.key === "members" ||
              section?.key === "rooms" ||
              section?.key === "amplify"
            ? "Member access"
            : "Included in your role",
      cta: copy.cta,
    };
  }
  if (membership?.isPending) {
    return {
      label: "Pending approval",
      cta: "Wait for approval",
    };
  }
  if (!membership?.isActive) {
    return {
      label: "Inactive membership",
      cta: "Access unavailable",
    };
  }
  if (section?.key === "voter-map" && !coalition?.voterMapEnabled) {
    return {
      label: "Voter map disabled",
      cta: "Not enabled here",
    };
  }
  if (
    section?.key === "governance" &&
    coalition?.coalitionType !== "constitutional" &&
    !coalition?.hasConstitution
  ) {
    return {
      label: "Governance unavailable",
      cta: "Needs constitution",
    };
  }
  return {
    label: "Permission required",
    cta: "Ask for access",
  };
}

function coalitionFeatureHighlights(coalition, membership, limit = 5) {
  const sections = coalitionFeatureSections().filter((section) =>
    canOpenCoalitionSection(section, coalition, membership),
  );
  const visible = sections.slice(0, limit);
  return {
    visible,
    remaining: Math.max(0, sections.length - visible.length),
    total: sections.length,
  };
}

function renderCoalitionFeaturePill(section, coalitionId) {
  return `<button class="shared-coalition-feature-pill" type="button" data-action="navigate" data-route="${escapeHtml(coalitionSectionPath(coalitionId, section.key))}">
    <span>${renderIcon(section.icon)}</span>
    <strong>${escapeHtml(section.label)}</strong>
  </button>`;
}

function renderCoalitionFeatureCard(section, coalition, membership) {
  const copy = coalitionFeatureCopy(section);
  const enabled = canOpenCoalitionSection(section, coalition, membership);
  const status = coalitionFeatureStatus(section, coalition, membership);
  const route = coalitionSectionPath(coalition.coalitionId, section.key);
  const tag = `<span class="shared-coalition-feature-card__status${enabled ? " is-enabled" : " is-locked"}">${escapeHtml(status.label)}</span>`;
  const body = `
    <span class="shared-coalition-feature-card__icon">${renderIcon(enabled ? section.icon : "lock")}</span>
    <span class="shared-coalition-feature-card__body">
      <span class="shared-card__meta"><span>${escapeHtml(copy.eyebrow)}</span>${tag}</span>
      <strong>${escapeHtml(section.label)}</strong>
      <small>${escapeHtml(copy.description)}</small>
      <em>${escapeHtml(status.cta)}</em>
    </span>`;
  if (!enabled) {
    return `<article class="shared-coalition-feature-card is-locked" aria-disabled="true">${body}</article>`;
  }
  return `<button class="shared-coalition-feature-card" type="button" data-action="navigate" data-route="${escapeHtml(route)}">${body}</button>`;
}

function renderCoalitionAvatar(coalition, sizeClass = "") {
  const className = `shared-coalition-avatar${sizeClass ? ` ${sizeClass}` : ""}`;
  return `<div class="${className}">
    ${
      coalition?.imageUrl
        ? `<img src="${escapeHtml(coalition.imageUrl)}" alt="${escapeHtml(coalition.name)}" />`
        : `<span>${escapeHtml((coalition?.name || "C").slice(0, 1).toUpperCase())}</span>`
    }
  </div>`;
}

function renderCoalitionListCard(item) {
  const coalition = item.coalition;
  const membership = item.membership;
  const canOpen = !membership.isPending && membership.isActive;
  const entryPath = coalitionEntryPath(coalition, membership);
  const highlights = coalitionFeatureHighlights(coalition, membership, 5);
  const status = membership.isPending
    ? "Pending"
    : membership.isActive
      ? "Active"
      : humanizeLabel(membership.status);
  return `<article class="shared-coalition-card">
    ${renderCoalitionAvatar(coalition)}
    <div class="shared-coalition-card__body">
      <div class="shared-card__meta">
        <span>${escapeHtml(status)}</span>
        <span>${escapeHtml(membership.roleLabel)}</span>
        <span>${escapeHtml(humanizeLabel(coalition.coalitionType))}</span>
      </div>
      <h3>${escapeHtml(coalition.name)}</h3>
      <p>${escapeHtml(coalition.description || "Coalition workspace")}</p>
      ${
        highlights.visible.length
          ? `<div class="shared-coalition-card__features">
              ${highlights.visible
                .map((section) =>
                  renderCoalitionFeaturePill(section, coalition.coalitionId),
                )
                .join("")}
              ${highlights.remaining ? `<span class="shared-coalition-feature-more">+${escapeHtml(formatCount(highlights.remaining))} more</span>` : ""}
            </div>`
          : `<p class="shared-coalition-card__note">Open the coalition overview to review membership status and request access to workspace tools.</p>`
      }
      <div class="shared-card__actions">
        <button class="shared-feed-chip shared-feed-chip--primary" ${canOpen ? `data-action="navigate" data-route="${escapeHtml(entryPath)}"` : disabledAttr(true)}>${escapeHtml(canOpen ? "Workspace" : coalitionEntryLabel(membership))}</button>
        <button class="shared-feed-chip" ${canOpen ? `data-action="navigate" data-route="/messages/servers/coalition/${escapeHtml(encodeURIComponent(coalition.coalitionId))}"` : disabledAttr(true)}>${renderIcon("messages")} Rooms</button>
      </div>
    </div>
  </article>`;
}

function renderCoalitionImageUploadField(
  target,
  upload = createCoalitionImageUploadState(),
  currentUrl = "",
  pending = false,
) {
  const normalizedTarget = normalizeString(target) || "start";
  const imageUrl = normalizeUrl(upload.remoteUrl) || normalizeUrl(currentUrl);
  const isUploading = upload.uploading === true;
  const uploadDisabled = pending || isUploading;
  return `<section class="shared-coalition-image-picker is-full">
    <input class="shared-coalition-image-picker__file" type="file" accept="${escapeHtml(POST_COMPOSER_IMAGE_ACCEPT)}" data-coalition-image-file="${escapeHtml(normalizedTarget)}" />
    <div class="shared-coalition-image-picker__preview${imageUrl ? " has-image" : ""}">
      ${
        imageUrl
          ? `<img src="${escapeHtml(imageUrl)}" alt="Coalition image preview" />`
          : `<div>${renderIcon("upload")}<strong>Add coalition image</strong><span>Upload a logo, banner, or organizing image.</span></div>`
      }
      <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="coalition-image-pick" data-upload-target="${escapeHtml(normalizedTarget)}"${disabledAttr(uploadDisabled)}>${isUploading ? "Uploading..." : imageUrl ? "Change image" : "Upload image"}</button>
    </div>
    <label class="shared-coalition-image-picker__url">
      <span>Image URL</span>
      <input name="imageUrl" type="url" inputmode="url" placeholder="https://example.com/logo.png" value="${escapeHtml(imageUrl)}"${disabledAttr(pending || isUploading)} required />
    </label>
    <div class="shared-coalition-image-picker__meta">
      ${
        upload.fileName
          ? `<span>${escapeHtml(upload.fileName)}</span>`
          : `<span>Upload from this computer or paste a hosted image URL.</span>`
      }
      ${
        upload.remoteUrl
          ? `<button class="shared-feed-chip" type="button" data-action="coalition-image-clear" data-upload-target="${escapeHtml(normalizedTarget)}"${disabledAttr(pending || isUploading)}>Clear upload</button>`
          : ""
      }
    </div>
    ${upload.error ? `<small class="shared-coalition-image-picker__error">${escapeHtml(upload.error)}</small>` : ""}
  </section>`;
}

function renderCoalitionOnboardingAccessList() {
  const items = state.pages.coalitions.list.items.slice(0, 4);
  if (!items.length) {
    return `<div class="shared-coalition-onboarding-empty">No coalition memberships are attached to this account yet.</div>`;
  }
  return `<div class="shared-coalition-onboarding-list">
    ${items
      .filter((item) => !item.hidden)
      .map((item) => {
        const status = item.membership.isPending
          ? "Pending"
          : item.membership.isActive
            ? "Active"
            : humanizeLabel(item.membership.status);
        return `<button class="shared-coalition-onboarding-row" type="button" data-action="navigate" data-route="${escapeHtml(coalitionSectionPath(item.coalition.coalitionId))}">
          ${renderCoalitionAvatar(item.coalition, "shared-coalition-avatar--small")}
          <span>
            <strong>${escapeHtml(item.coalition.name)}</strong>
            <em>${escapeHtml(`${status} - ${item.membership.roleLabel}`)}</em>
          </span>
        </button>`;
      })
      .join("")}
  </div>`;
}

function renderCoalitionOnboardingSide(mode) {
  const onboarding = state.pages.coalitions.onboarding;
  const requestedId = normalizeString(onboarding.requestedCoalitionId);
  const createdId = normalizeString(onboarding.createdCoalitionId);
  return `<aside class="shared-coalition-onboarding-side">
    ${
      requestedId && mode === "join"
        ? `<div class="shared-coalition-onboarding-status">
            <strong>Request sent for approval</strong>
            <span>${escapeHtml(requestedId)}</span>
          </div>`
        : ""
    }
    ${
      createdId && mode === "start"
        ? `<div class="shared-coalition-onboarding-status">
            <strong>Coalition created</strong>
            <span>${escapeHtml(createdId)}</span>
          </div>`
        : ""
    }
    <section class="shared-coalition-panel">
      <div class="shared-coalition-panel__header">
        <div>
          <h2>Your coalitions</h2>
          <p>Open an existing workspace or keep building this one.</p>
        </div>
      </div>
      ${renderCoalitionOnboardingAccessList()}
      <div class="shared-card__actions">
        <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/coalitions">All coalitions</button>
        ${
          mode === "start"
            ? `<button class="shared-feed-chip" type="button" data-action="navigate" data-route="/coalitions/join">Join one</button>`
            : `<button class="shared-feed-chip" type="button" data-action="navigate" data-route="/coalitions/start">Start one</button>`
        }
      </div>
    </section>
  </aside>`;
}

function renderCoalitionTypeChoices(pending) {
  return `<fieldset class="shared-coalition-choice-grid is-full">
    <legend>Coalition type</legend>
    <label class="shared-coalition-choice">
      <input type="radio" name="coalitionType" value="simple" checked${disabledAttr(pending)} />
      <span>${renderIcon("team")}</span>
      <strong>Simple</strong>
      <em>Member workspace with roles, rooms, missions, and operations tools.</em>
    </label>
    <label class="shared-coalition-choice">
      <input type="radio" name="coalitionType" value="constitutional"${disabledAttr(pending)} />
      <span>${renderIcon("election")}</span>
      <strong>Constitutional</strong>
      <em>Add constitution setup, proposals, voting, and governance records.</em>
    </label>
  </fieldset>`;
}

function renderCoalitionSocialFields(pending) {
  return `<fieldset class="shared-coalition-social-grid is-full">
    <legend>Social links</legend>
    ${["facebook", "threads", "bluesky", "instagram", "tiktok"]
      .map(
        (key) => `<label>
          <span>${escapeHtml(humanizeLabel(key))}</span>
          <input name="social:${escapeHtml(key)}" placeholder="https://" autocomplete="url"${disabledAttr(pending)} />
        </label>`,
      )
      .join("")}
  </fieldset>`;
}

function renderCoalitionStartPage() {
  const onboarding = state.pages.coalitions.onboarding;
  const pending = onboarding.actionPendingKey === "create";
  const imageUploading = onboarding.imageUpload?.uploading === true;
  return `<section class="shared-page shared-coalition-workspace">
    ${renderTopChrome()}
    <div class="shared-page__content">
      <div class="shared-page__back-row">
        <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/coalitions">All coalitions</button>
      </div>
      <div class="shared-page__header shared-coalition-onboarding-header">
        <div>
          <h1>Start a coalition</h1>
          <p>Create the web workspace, contact profile, access model, rooms, missions, voter map, and governance foundation from one place.</p>
        </div>
        <div class="shared-card__actions">
          <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/coalitions/join">Join coalition</button>
          <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/messages">Messages</button>
        </div>
      </div>
      ${onboarding.error ? `<div class="shared-page__error">${escapeHtml(onboarding.error)}</div>` : ""}
      <div class="shared-coalition-onboarding">
        <form class="shared-coalition-onboarding-form shared-coalition-profile-form" data-route-form="coalition-start-create">
          ${renderCoalitionImageUploadField(
            "start",
            onboarding.imageUpload,
            "",
            pending,
          )}
          ${renderCoalitionTypeChoices(pending)}
          <label class="is-wide">
            <span>Name</span>
            <input name="name" autocomplete="organization" required${disabledAttr(pending)} />
          </label>
          <label class="is-full">
            <span>Description</span>
            <textarea name="description" rows="4" required${disabledAttr(pending)}></textarea>
          </label>
          <label>
            <span>Primary contact</span>
            <input name="primaryContactName" autocomplete="name" required${disabledAttr(pending)} />
          </label>
          <label>
            <span>Phone</span>
            <input name="phone" type="tel" autocomplete="tel" required${disabledAttr(pending)} />
          </label>
          <label>
            <span>Email</span>
            <input name="email" type="email" autocomplete="email" required${disabledAttr(pending)} />
          </label>
          <label>
            <span>Website</span>
            <input name="website" type="url" inputmode="url" placeholder="https://" autocomplete="url"${disabledAttr(pending)} />
          </label>
          <label class="shared-coalition-profile-form__toggle">
            <input type="checkbox" name="pacAssociated" value="true"${disabledAttr(pending)} />
            <span>PAC associated</span>
          </label>
          <label>
            <span>FEC number</span>
            <input name="fecNumber" autocomplete="off"${disabledAttr(pending)} />
          </label>
          ${renderCoalitionSocialFields(pending)}
          <div class="shared-coalition-profile-form__actions">
            <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pending || imageUploading)}>${pending ? "Creating..." : imageUploading ? "Uploading image..." : "Create coalition"}</button>
          </div>
        </form>
        ${renderCoalitionOnboardingSide("start")}
      </div>
    </div>
  </section>`;
}

function renderCoalitionJoinPage() {
  const onboarding = state.pages.coalitions.onboarding;
  const pending = onboarding.actionPendingKey === "join";
  return `<section class="shared-page shared-coalition-workspace">
    ${renderTopChrome()}
    <div class="shared-page__content">
      <div class="shared-page__back-row">
        <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/coalitions">All coalitions</button>
      </div>
      <div class="shared-page__header shared-coalition-onboarding-header">
        <div>
          <h1>Join coalition</h1>
          <p>Request access with a coalition ID and return to the full coalition workspace after approval.</p>
        </div>
        <div class="shared-card__actions">
          <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/coalitions/start">Start coalition</button>
          <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/messages">Messages</button>
        </div>
      </div>
      ${onboarding.error ? `<div class="shared-page__error">${escapeHtml(onboarding.error)}</div>` : ""}
      <div class="shared-coalition-onboarding shared-coalition-onboarding--join">
        <form class="shared-coalition-join-form shared-coalition-panel" data-route-form="coalition-join-request">
          <div class="shared-coalition-panel__header">
            <div>
              <h2>Request membership</h2>
              <p>The coalition admin will review the request before workspace access opens.</p>
            </div>
          </div>
          <label>
            <span>Coalition ID</span>
            <input name="coalitionId" placeholder="coalition-id" autocomplete="off" required${disabledAttr(pending)} />
          </label>
          <div class="shared-card__actions">
            <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pending)}>${pending ? "Sending..." : "Send request"}</button>
          </div>
        </form>
        ${renderCoalitionOnboardingSide("join")}
      </div>
    </div>
  </section>`;
}

function renderCoalitionsRootSummary(items = []) {
  const visibleItems = items.filter((item) => !item.hidden);
  if (!visibleItems.length) {
    return "";
  }
  const activeItems = visibleItems.filter((item) => item.membership.isActive);
  const pendingItems = visibleItems.filter((item) => item.membership.isPending);
  const enabledSections = coalitionFeatureSections().filter((section) =>
    visibleItems.some((item) =>
      canOpenCoalitionSection(section, item.coalition, item.membership),
    ),
  );
  const prioritySections = enabledSections.slice(0, 6);
  return `<section class="shared-coalition-access-map">
    <div class="shared-coalition-access-map__intro">
      <span class="shared-card__meta"><span>Coalition workspaces</span><span>${escapeHtml(formatCount(enabledSections.length))} feature areas</span></span>
      <h2>Open the coalition, then jump straight into the work.</h2>
      <p>Each workspace exposes the Polis app surfaces the browser can handle: rooms, member access, missions, voter tools, calendar, governance, and amplify requests.</p>
    </div>
    <div class="shared-coalition-access-map__metrics">
      <span><strong>${escapeHtml(formatCount(visibleItems.length))}</strong><small>coalition${visibleItems.length === 1 ? "" : "s"}</small></span>
      <span><strong>${escapeHtml(formatCount(activeItems.length))}</strong><small>active</small></span>
      <span><strong>${escapeHtml(formatCount(pendingItems.length))}</strong><small>pending</small></span>
    </div>
    ${
      prioritySections.length
        ? `<div class="shared-coalition-access-map__features">
            ${prioritySections
              .map((section) => {
                const count = visibleItems.filter((item) =>
                  canOpenCoalitionSection(section, item.coalition, item.membership),
                ).length;
                return `<span>
                  <i>${renderIcon(section.icon)}</i>
                  <strong>${escapeHtml(section.label)}</strong>
                  <small>${escapeHtml(`${formatCount(count)} workspace${count === 1 ? "" : "s"}`)}</small>
                </span>`;
              })
              .join("")}
          </div>`
        : ""
    }
  </section>`;
}

function renderCoalitionsRootEmpty() {
  return `<section class="shared-coalition-empty-state">
    <span>${renderIcon("team")}</span>
    <div>
      <h2>No coalition workspace yet</h2>
      <p>Start a new coalition from the browser, or request access to an existing one with its coalition ID.</p>
    </div>
    <div class="shared-card__actions">
      <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="navigate" data-route="/coalitions/start">Start coalition</button>
      <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/coalitions/join">Join coalition</button>
      <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/messages">Open messages</button>
    </div>
  </section>`;
}

function renderCoalitionsRootPage() {
  const list = state.pages.coalitions.list;
  return `<section class="shared-page shared-coalition-workspace">
    ${renderTopChrome()}
    <div class="shared-page__content">
      <div class="shared-page__header">
        <div>
          <h1>Coalitions</h1>
          <p>Open coalition rooms, member access, missions, voter map tools, governance, calendar, and amplify requests.</p>
        </div>
        <div class="shared-card__actions">
          <button class="shared-feed-chip shared-feed-chip--primary" data-action="navigate" data-route="/coalitions/start">Start coalition</button>
          <button class="shared-feed-chip" data-action="navigate" data-route="/coalitions/join">Join coalition</button>
          <button class="shared-feed-chip" data-action="navigate" data-route="/messages">Messages</button>
        </div>
      </div>
      ${list.loading && !list.items.length ? '<div class="shared-page__loading">Loading coalitions...</div>' : ""}
      ${list.error ? `<div class="shared-page__error">${escapeHtml(list.error)}</div>` : ""}
      ${
        list.items.length
          ? `${renderCoalitionsRootSummary(list.items)}
            <div class="shared-coalition-grid">${list.items.map(renderCoalitionListCard).join("")}</div>`
          : list.loaded && !list.loading
            ? renderCoalitionsRootEmpty()
            : ""
      }
    </div>
  </section>`;
}

function renderCoalitionHero(coalition, membership) {
  const statusLabel = membership.isPending
    ? "Pending approval"
    : membership.isActive
      ? "Active member"
      : humanizeLabel(membership.status);
  const actions = [];
  if (membership.isPending) {
    actions.push(
      `<button class="shared-feed-chip shared-feed-chip--primary" type="button"${disabledAttr(true)}>Pending approval</button>`,
    );
  } else if (membership.isActive && membership.isLeader) {
    actions.push(
      `<button class="shared-feed-chip shared-feed-chip--primary" data-action="navigate" data-route="${escapeHtml(coalitionSectionPath(coalition.coalitionId, "admin"))}">${renderIcon("dashboard")} Admin view</button>`,
    );
  }
  if (membership.isActive) {
    actions.push(
      `<button class="shared-feed-chip${membership.isLeader ? "" : " shared-feed-chip--primary"}" data-action="navigate" data-route="/messages/servers/coalition/${escapeHtml(encodeURIComponent(coalition.coalitionId))}">${renderIcon("messages")} Rooms</button>`,
    );
  }
  if (canViewCoalitionMissions(membership)) {
    actions.push(
      `<button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(coalitionSectionPath(coalition.coalitionId, "missions"))}">${renderIcon("mission")} Missions</button>`,
    );
  }
  actions.push(
    `<button class="shared-feed-chip" data-action="open-app-shell">Open app</button>`,
  );
  return `<section class="shared-coalition-hero">
    <div class="shared-coalition-hero__identity">
      ${renderCoalitionAvatar(coalition, "shared-coalition-avatar--large")}
      <div>
        <div class="shared-card__meta">
          <span>${escapeHtml(statusLabel)}</span>
          <span>${escapeHtml(membership.roleLabel)}</span>
          <span>${escapeHtml(humanizeLabel(coalition.coalitionType))}</span>
        </div>
        <h1>${escapeHtml(coalition.name)}</h1>
        <p>${escapeHtml(coalition.description || "Coalition operations")}</p>
      </div>
    </div>
    <div class="shared-coalition-hero__actions">
      ${actions.join("")}
    </div>
  </section>`;
}

function renderCoalitionTabs(coalition, membership, activeSection) {
  return `<nav class="shared-coalition-tabs" aria-label="Coalition sections">
    ${COALITION_SECTION_CONFIG.map((section) => {
      const active = section.key === activeSection;
      const enabled = canOpenCoalitionSection(section, coalition, membership);
      const actionAttrs = enabled
        ? `data-action="navigate" data-route="${escapeHtml(coalitionSectionPath(coalition.coalitionId, section.key))}"`
        : `${disabledAttr(true)} aria-disabled="true"`;
      return `<button class="shared-coalition-tab${active ? " is-active" : ""}${enabled ? "" : " is-muted"}" ${actionAttrs}>
        <span>${renderIcon(section.icon)}</span>
        <strong>${escapeHtml(section.label)}</strong>
      </button>`;
    }).join("")}
  </nav>`;
}

function renderCoalitionMetric(label, value, tone = "") {
  return `<div class="shared-coalition-metric${tone ? ` shared-coalition-metric--${escapeHtml(tone)}` : ""}">
    <span>${escapeHtml(label)}</span>
    <strong>${escapeHtml(value)}</strong>
  </div>`;
}

function renderCoalitionMiniList(items, renderItem, emptyText) {
  if (!items.length) {
    return `<div class="shared-page__empty">${escapeHtml(emptyText)}</div>`;
  }
  return `<div class="shared-stack">${items.map(renderItem).join("")}</div>`;
}

function renderCoalitionContactPanel(coalition) {
  const contactRows = [
    ["Primary contact", coalition.primaryContactName || "Not set"],
    ["Email", coalition.email || "Not set"],
    ["Phone", coalition.phone || "Not set"],
    ["Website", coalition.website || "Not set"],
    [
      "PAC status",
      coalition.pacAssociated
        ? `PAC associated${coalition.fecNumber ? ` - FEC ${coalition.fecNumber}` : ""}`
        : "Not a PAC",
    ],
  ];
  return `<article class="shared-coalition-panel">
    <div class="shared-coalition-panel__header"><h2>Contact</h2></div>
    <div class="shared-coalition-contact-list">
      ${contactRows
        .map(
          ([label, value]) =>
            `<div><span>${escapeHtml(label)}</span><strong>${escapeHtml(value)}</strong></div>`,
        )
        .join("")}
    </div>
  </article>`;
}

function renderCoalitionOverview(detail, coalition, membership) {
  const featureSections = coalitionFeatureSections();
  const missionSection = COALITION_SECTION_CONFIG.find(
    (section) => section.key === "missions",
  );
  const governanceSection = COALITION_SECTION_CONFIG.find(
    (section) => section.key === "governance",
  );
  const canOpenMissions = canOpenCoalitionSection(
    missionSection,
    coalition,
    membership,
  );
  const canOpenGovernance = canOpenCoalitionSection(
    governanceSection,
    coalition,
    membership,
  );
  const metrics = [
    renderCoalitionMetric("Members", formatCount(detail.members.length), "cyan"),
    renderCoalitionMetric("Roles", formatCount(detail.roles.length)),
    renderCoalitionMetric("Missions", formatCount(detail.missions.length)),
    renderCoalitionMetric("Calendar", formatCount(detail.calendar.length)),
    renderCoalitionMetric("Proposals", formatCount(detail.proposals.length)),
    renderCoalitionMetric("Votes", formatCount(detail.votes.length)),
  ].join("");
  return `<div class="shared-coalition-section">
    <div class="shared-coalition-metrics">${metrics}</div>
    ${
      membership.isPending
        ? '<div class="shared-page__hint shared-page__banner">Pending approval. Coalition tools unlock once an admin approves the membership.</div>'
        : ""
    }
    <div class="shared-coalition-overview-grid">
      ${
        canOpenMissions
          ? `<article class="shared-coalition-panel">
              <div class="shared-coalition-panel__header">
                <h2>Operations</h2>
                <button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(coalitionSectionPath(coalition.coalitionId, "missions"))}">Missions</button>
              </div>
              ${renderCoalitionMiniList(
                detail.missions.slice(0, 3),
                (mission) => `<button class="shared-list-item" data-action="navigate" data-route="/missions/${escapeHtml(encodeURIComponent(mission.missionId))}">
                  <strong>${escapeHtml(mission.title)}</strong>
                  <span>${escapeHtml(humanizeLabel(mission.status))}${mission.assignedCount ? ` - ${formatCount(mission.assignedCount)} assigned` : ""}</span>
                </button>`,
                "No coalition missions loaded.",
              )}
            </article>`
          : ""
      }
      ${
        canOpenGovernance
          ? `<article class="shared-coalition-panel">
              <div class="shared-coalition-panel__header">
                <h2>Governance</h2>
                <button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(coalitionSectionPath(coalition.coalitionId, "governance"))}">Open</button>
              </div>
              ${renderCoalitionMiniList(
                detail.proposals.slice(0, 3),
                (proposal) => `<div class="shared-list-item">
                  <strong>${escapeHtml(proposal.title)}</strong>
                  <span>${escapeHtml(humanizeLabel(proposal.status))} - ${escapeHtml(formatCount(proposal.signerCount))} signatures</span>
                </div>`,
                detail.constitution
                  ? "No active proposals loaded."
                  : "No constitution or proposals loaded.",
              )}
            </article>`
          : ""
      }
      <article class="shared-coalition-panel">
        <div class="shared-coalition-panel__header">
          <h2>Access</h2>
          <button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(coalitionSectionPath(coalition.coalitionId, "members"))}">Members</button>
        </div>
        ${renderCoalitionMiniList(
          detail.members.slice(0, 4),
          (member) => `<div class="shared-list-item">
            <strong>${escapeHtml(member.displayName)}</strong>
            <span>${escapeHtml(member.roleLabel)} - ${escapeHtml(formatCount(member.permissions.length))} permissions</span>
          </div>`,
          "No members loaded.",
        )}
      </article>
      <article class="shared-coalition-panel shared-coalition-panel--wide">
        <div class="shared-coalition-panel__header">
          <div>
            <span class="shared-card__meta"><span>Feature map</span><span>${escapeHtml(membership?.isLeader ? "Leader workspace" : "Member workspace")}</span></span>
            <h2>Coalition command center</h2>
            <p>Open the browser surfaces that match the Polis app coalition hub. Locked cards show what exists but needs approval, a permission, voter-map enablement, or governance setup.</p>
          </div>
        </div>
        <div class="shared-coalition-feature-grid">
          ${featureSections
            .map((section) =>
              renderCoalitionFeatureCard(section, coalition, membership),
            )
            .join("")}
        </div>
      </article>
      ${renderCoalitionContactPanel(coalition)}
    </div>
  </div>`;
}

function canManageCoalitionMembers(membership) {
  return (
    membership?.isAdmin ||
    (membership?.permissions || []).includes("members_manage")
  );
}

function canManageCoalitionJoinRequests(membership) {
  return (
    membership?.isAdmin ||
    (membership?.permissions || []).includes("join_requests_manage") ||
    canManageCoalitionMembers(membership)
  );
}

function canManageCoalitionRoles(membership, catalog = null) {
  return (
    membership?.isAdmin ||
    catalog?.canManage ||
    (membership?.permissions || []).includes("roles_manage")
  );
}

function canManageCoalitionMissions(membership) {
  if (membership?.isAdmin) {
    return true;
  }
  const permissions = new Set(membership?.permissions || []);
  return [
    "missions_assign",
    "missions_delegate",
    "missions_approve",
    "mission_templates_manage",
    "missions_manage",
  ].some((permission) => permissions.has(permission));
}

function canViewCoalitionMissions(membership) {
  return (
    canManageCoalitionMissions(membership) ||
    (membership?.permissions || []).includes("missions_view")
  );
}

function canViewCoalitionCalendar(membership) {
  if (membership?.isAdmin) {
    return true;
  }
  const permissions = new Set(membership?.permissions || []);
  return [...COALITION_CALENDAR_PERMISSIONS].some((permission) =>
    permissions.has(permission),
  );
}

function canManageCoalitionCalendar(membership) {
  if (membership?.isAdmin) {
    return true;
  }
  const permissions = new Set(membership?.permissions || []);
  return (
    permissions.has("calendar_manage") ||
    permissions.has("calendar_promotion_manage")
  );
}

function canManageCoalitionCta(membership, access = null) {
  if (membership?.isAdmin || access?.canManageCta) {
    return true;
  }
  return (membership?.permissions || []).includes("cta_manage");
}

function canCreateCoalitionAmplify(membership) {
  return Boolean(membership?.isActive && !membership?.isPending);
}

function canRespondCoalitionAmplify(membership) {
  return canCreateCoalitionAmplify(membership);
}

function canPrioritizeCoalitionAmplify(membership) {
  const rawRole = normalizeCoalitionRole(
    membership?.raw?.roleKey || membership?.raw?.role_key || membership?.raw?.role,
  );
  return Boolean(
    membership?.isAdmin ||
      rawRole === "admin" ||
      rawRole === "officer" ||
      membership?.roleKey === "officer" ||
      membership?.role === "officer",
  );
}

function coalitionSocialValue(coalition, key) {
  const socials = coalition?.socials && typeof coalition.socials === "object"
    ? coalition.socials
    : {};
  return normalizeString(socials[key]);
}

function renderCoalitionAdminNav(coalition, activeKey) {
  const items = [
    {
      key: "access",
      path: "admin",
      label: "Access",
      icon: "team",
      description: "Members, requests, invitations, and role defaults.",
    },
    {
      key: "profile",
      path: "admin/edit",
      label: "Profile",
      icon: "settings",
      description: "Coalition identity, contact, PAC status, and links.",
    },
    {
      key: "rooms",
      path: "rooms",
      label: "Rooms",
      icon: "messages",
      description: "Messaging room bridge for coalition operations.",
    },
  ];
  return renderCoalitionSubrouteNav(
    coalition,
    items,
    activeKey,
    "Coalition admin routes",
  );
}

function renderCoalitionProfileEditPanel(detail, coalition, membership) {
  const canManage = canManageCoalitionProfile(membership);
  const pending = detail.actionPendingKey === "profile:update";
  const imageUploading = detail.imageUpload?.uploading === true;
  if (!canManage) {
    const contactRows = [
      ["Primary contact", coalition.primaryContactName || "Not set"],
      ["Email", coalition.email || "Not set"],
      ["Phone", coalition.phone || "Not set"],
      ["Website", coalition.website || "Not set"],
    ];
    return `<article class="shared-coalition-panel shared-coalition-panel--accent">
      <div class="shared-coalition-panel__header">
        <div>
          <h2>Profile editing</h2>
          <p>This coalition role can view the profile but cannot edit coalition identity or contact settings.</p>
        </div>
      </div>
      <div class="shared-coalition-contact-list">
        ${contactRows
          .map(
            ([label, value]) =>
              `<div><span>${escapeHtml(label)}</span><strong>${escapeHtml(value)}</strong></div>`,
          )
          .join("")}
      </div>
    </article>`;
  }
  const socialKeys = [
    ["facebook", "Facebook"],
    ["threads", "Threads"],
    ["bluesky", "Bluesky"],
    ["instagram", "Instagram"],
    ["tiktok", "TikTok"],
  ];
  return `<article class="shared-coalition-panel shared-coalition-profile-edit">
    <div class="shared-coalition-panel__header">
      <div>
        <h2>Edit coalition profile</h2>
        <p>Update the website and app-facing coalition identity, contact owner, PAC status, and social links.</p>
      </div>
    </div>
    <form class="shared-coalition-profile-form" data-route-form="coalition-profile-edit">
      ${renderCoalitionImageUploadField(
        "edit",
        detail.imageUpload,
        coalition.imageUrl,
        pending,
      )}
      <label class="is-wide"><span>Name</span><input name="name" value="${escapeHtml(coalition.name)}"${disabledAttr(pending)} required /></label>
      <label><span>Type</span><select name="coalitionType"${disabledAttr(pending)}>
        <option value="simple"${selectedAttr(coalition.coalitionType !== "constitutional")}>Simple</option>
        <option value="constitutional"${selectedAttr(coalition.coalitionType === "constitutional")}>Constitutional</option>
      </select></label>
      <label class="is-full"><span>Description</span><textarea name="description" rows="4"${disabledAttr(pending)} required>${escapeHtml(coalition.description)}</textarea></label>
      <label><span>Primary contact</span><input name="primaryContactName" value="${escapeHtml(coalition.primaryContactName)}"${disabledAttr(pending)} required /></label>
      <label><span>Phone</span><input name="phone" value="${escapeHtml(coalition.phone)}"${disabledAttr(pending)} required /></label>
      <label><span>Email</span><input name="email" type="email" value="${escapeHtml(coalition.email)}"${disabledAttr(pending)} required /></label>
      <label><span>Website</span><input name="website" value="${escapeHtml(coalition.website)}" placeholder="https://"${disabledAttr(pending)} /></label>
      <label class="shared-coalition-profile-form__toggle">
        <input type="checkbox" name="pacAssociated"${checkedAttr(coalition.pacAssociated)}${disabledAttr(pending)} />
        <span>PAC associated</span>
      </label>
      <label><span>FEC number</span><input name="fecNumber" value="${escapeHtml(coalition.fecNumber)}"${disabledAttr(pending)} /></label>
      ${socialKeys
        .map(
          ([key, label]) =>
            `<label><span>${escapeHtml(label)}</span><input name="social:${escapeHtml(key)}" value="${escapeHtml(coalitionSocialValue(coalition, key))}"${disabledAttr(pending)} /></label>`,
        )
        .join("")}
      <div class="shared-coalition-profile-form__actions">
        <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pending || imageUploading)}>${pending ? "Saving..." : imageUploading ? "Uploading image..." : "Save profile"}</button>
      </div>
    </form>
  </article>`;
}

function renderCoalitionAdminOverview(detail, coalition, membership) {
  const canProfile = canManageCoalitionProfile(membership);
  const canMembers = canManageCoalitionMembers(membership);
  const canRoles = canManageCoalitionRoles(
    membership,
    detail.accessWorkspace?.catalog,
  );
  return `<article class="shared-coalition-panel shared-coalition-panel--accent">
    <div class="shared-coalition-panel__header">
      <div>
        <h2>Admin center</h2>
        <p>Manage coalition profile, member access, role defaults, rooms, and operations from one browser entry point.</p>
      </div>
    </div>
    <div class="shared-coalition-admin-grid">
      <div><span>Profile</span><strong>${escapeHtml(canProfile ? "Can edit" : "View only")}</strong></div>
      <div><span>Members</span><strong>${escapeHtml(canMembers ? "Can manage" : "View only")}</strong></div>
      <div><span>Roles</span><strong>${escapeHtml(canRoles ? "Can manage" : "View only")}</strong></div>
      <div><span>Pending requests</span><strong>${escapeHtml(formatCount(detail.accessWorkspace?.joinRequests?.length || 0))}</strong></div>
    </div>
    <div class="shared-card__actions">
      <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="navigate" data-route="${escapeHtml(coalitionSectionPath(coalition.coalitionId, "admin/edit"))}">Edit profile</button>
      <button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(coalitionSectionPath(coalition.coalitionId, "members"))}">Member access</button>
      <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/messages/servers/coalition/${escapeHtml(encodeURIComponent(coalition.coalitionId))}">Rooms</button>
    </div>
  </article>`;
}

function renderCoalitionAdminSection(detail, coalition, membership) {
  const profileRoute = isCoalitionAdminEditRoute();
  return `<div class="shared-coalition-section shared-coalition-admin">
    <div class="shared-coalition-metrics">
      ${renderCoalitionMetric("Members", formatCount(detail.members.length), "cyan")}
      ${renderCoalitionMetric("Requests", formatCount(detail.accessWorkspace?.joinRequests?.length || 0))}
      ${renderCoalitionMetric("Invitations", formatCount(detail.accessWorkspace?.invitations?.length || 0))}
      ${renderCoalitionMetric("Profile", canManageCoalitionProfile(membership) ? "Editable" : "View")}
    </div>
    ${renderCoalitionAdminNav(coalition, profileRoute ? "profile" : "access")}
    ${profileRoute
      ? renderCoalitionProfileEditPanel(detail, coalition, membership)
      : renderCoalitionAdminOverview(detail, coalition, membership)}
    ${renderCoalitionMembers(detail, coalition, membership)}
  </div>`;
}

function coalitionCatalogRole(catalog, roleKey) {
  const normalized = normalizeCoalitionRole(roleKey);
  return (
    (catalog?.roles || []).find((role) => role.roleKey === normalized) ||
    COALITION_ROLE_FALLBACKS.map(normalizeCoalitionAccessRole).find(
      (role) => role.roleKey === normalized,
    ) || {
      roleKey: normalized,
      label: coalitionRoleLabel(normalized),
      category: "Custom",
      color: "",
      enabled: true,
      system: false,
      custom: true,
      protectedRole: false,
      defaultPermissions: [],
    }
  );
}

function coalitionAssignableRoles(catalog, selectedRoleKey = "") {
  const roles = (catalog?.roles?.length
    ? catalog.roles
    : COALITION_ROLE_FALLBACKS.map(normalizeCoalitionAccessRole)
  ).filter((role) => role.enabled);
  const selected = selectedRoleKey
    ? coalitionCatalogRole(catalog, selectedRoleKey)
    : null;
  if (selected && !roles.some((role) => role.roleKey === selected.roleKey)) {
    return [...roles, selected];
  }
  return roles;
}

function coalitionRoleDefaultPermissions(catalog, roleKey) {
  return normalizeCoalitionPermissionsForWrite(
    coalitionCatalogRole(catalog, roleKey).defaultPermissions,
  );
}

function coalitionAccessDisplayName(person = {}) {
  return (
    normalizeString(person.displayName) ||
    (person.username ? `@${normalizeString(person.username).replace(/^@/u, "")}` : "") ||
    normalizeString(person.userId) ||
    "Member"
  );
}

function renderCoalitionAccessAvatar(person = {}) {
  const label = coalitionAccessDisplayName(person);
  return `<span class="shared-campaign-staff-avatar">${
    person.avatarUrl
      ? `<img src="${escapeHtml(person.avatarUrl)}" alt="${escapeHtml(label)}" />`
      : escapeHtml(label.slice(0, 1).toUpperCase() || "M")
  }</span>`;
}

function renderCoalitionRoleOptions(catalog, selectedRoleKey = "") {
  const selected = normalizeCoalitionRole(selectedRoleKey);
  return coalitionAssignableRoles(catalog, selected)
    .map(
      (role) =>
        `<option value="${escapeHtml(role.roleKey)}"${selectedAttr(role.roleKey === selected)}>${escapeHtml(role.label)}</option>`,
    )
    .join("");
}

function groupedCoalitionPermissions(catalog) {
  const grouped = new Map();
  const permissions =
    catalog?.permissions?.length > 0
      ? catalog.permissions
      : COALITION_ASSIGNABLE_PERMISSION_DEFINITIONS;
  permissions.forEach((permission) => {
    const category = normalizeString(permission.category) || "General";
    if (!grouped.has(category)) {
      grouped.set(category, []);
    }
    grouped.get(category).push(permission);
  });
  return Array.from(grouped.entries());
}

function renderCoalitionPermissionChips(permissions = []) {
  const normalized = normalizeCoalitionPermissionsForWrite(permissions);
  if (!normalized.length) {
    return '<span class="shared-campaign-staff-muted">No permissions</span>';
  }
  return `<span class="shared-campaign-staff-permission-chips">${normalized
    .slice(0, 6)
    .map((permission) => {
      const definition = coalitionPermissionDefinition(permission);
      return `<em>${escapeHtml(definition.label)}</em>`;
    })
    .join("")}${
    normalized.length > 6
      ? `<em>+${escapeHtml(formatCount(normalized.length - 6))}</em>`
      : ""
  }</span>`;
}

function renderCoalitionPermissionCheckboxes(
  catalog,
  selectedPermissions = [],
  { disabled = false, name = "permission" } = {},
) {
  const selected = new Set(
    normalizeCoalitionPermissionsForWrite(selectedPermissions),
  );
  return `<div class="shared-campaign-staff-permission-grid">
    ${groupedCoalitionPermissions(catalog)
      .map(
        ([category, permissions]) => `<fieldset>
          <legend>${escapeHtml(category)}</legend>
          ${permissions
            .map((permission) => {
              const key = normalizeCoalitionPermission(permission.key);
              return `<label>
                <input type="checkbox" name="${escapeHtml(name)}" value="${escapeHtml(key)}"${checkedAttr(selected.has(key))}${disabledAttr(disabled)} />
                <span>${escapeHtml(permission.label)}</span>
              </label>`;
            })
            .join("")}
        </fieldset>`,
      )
      .join("")}
  </div>`;
}

function renderCoalitionRolePill(role, detail = "") {
  return `<span class="shared-campaign-staff-role-pill" style="${role.color ? `--role-color:${escapeHtml(role.color)};` : ""}">
    <strong>${escapeHtml(role.label)}</strong>
    <span>${escapeHtml(detail || role.category)}</span>
  </span>`;
}

function renderCoalitionInviteSearchResult(user, detail, resource) {
  const status = coalitionInviteStatus(user, detail, resource);
  const disabled = status.disabled || resource.actionPendingKey === "invite";
  return `<button class="shared-campaign-staff-search-result${status.disabled ? " is-disabled" : ""}" type="button" data-action="coalition-invite-search-select"
    data-user-id="${escapeHtml(user.userId)}"
    data-username="${escapeHtml(user.username)}"
    data-display-name="${escapeHtml(user.displayName)}"
    data-avatar-url="${escapeHtml(user.avatarUrl)}"${disabledAttr(disabled)}>
    ${renderCoalitionAccessAvatar(user)}
    <span>
      <strong>${escapeHtml(user.displayName)}</strong>
      <small>@${escapeHtml(user.username)}${user.subtitle ? ` - ${escapeHtml(user.subtitle.replace(/^@/u, ""))}` : ""}</small>
    </span>
    <em>${escapeHtml(status.label)}</em>
  </button>`;
}

function renderCoalitionInviteSelected(user, pending) {
  if (!user) {
    return "";
  }
  return `<div class="shared-campaign-staff-selected">
    ${renderCoalitionAccessAvatar(user)}
    <span>
      <strong>${escapeHtml(user.displayName || "Selected coalition member")}</strong>
      <small>@${escapeHtml(normalizeString(user.username).replace(/^@/u, ""))}</small>
    </span>
    <button class="shared-feed-chip" type="button" data-action="coalition-invite-search-clear"${disabledAttr(pending)}>Change</button>
  </div>`;
}

function renderCoalitionInviteSearch(detail, resource, canManage) {
  const search = coalitionInviteSearch(resource);
  const pending = resource.actionPendingKey === "invite";
  const disabled = !canManage || pending;
  const selected = search.selected;
  const queryValue = selected
    ? `@${normalizeString(selected.username).replace(/^@/u, "")}`
    : search.query;
  const normalizedQuery = normalizeString(search.query).replace(/^@/u, "");
  const showSuggestions = !selected && (search.loading || search.loaded || normalizedQuery.length >= 2);
  return `<div class="shared-campaign-staff-search">
    <label class="shared-campaign-staff-search-field">
      <span>Search by username</span>
      <input name="username" data-coalition-invite-search-input value="${escapeHtml(queryValue)}" placeholder="Type a username to find members" autocomplete="off"${disabledAttr(disabled)} />
    </label>
    <input type="hidden" name="userId" value="${escapeHtml(selected?.userId || "")}" />
    ${renderCoalitionInviteSelected(selected, disabled)}
    ${
      selected
        ? '<div class="shared-campaign-staff-search-hint">Selected account will receive this coalition invitation.</div>'
        : showSuggestions
          ? `<div class="shared-campaign-staff-search-results">
              ${
                search.loading
                  ? '<div class="shared-campaign-staff-search-message">Searching people...</div>'
                  : search.error
                    ? `<div class="shared-campaign-staff-search-message is-error">${escapeHtml(search.error)}</div>`
                    : search.items.length
                      ? search.items.map((user) => renderCoalitionInviteSearchResult(user, detail, resource)).join("")
                      : '<div class="shared-campaign-staff-search-message">No matching people.</div>'
              }
            </div>`
          : `<div class="shared-campaign-staff-search-hint">Type at least two characters, then choose a Polis account before sending.</div>`
    }
  </div>`;
}

function renderCoalitionInvitePermissionSummary(catalog, roleKey) {
  const role = coalitionCatalogRole(catalog, roleKey);
  const permissions = coalitionRoleDefaultPermissions(catalog, role.roleKey);
  return `<div class="shared-campaign-staff-invite-summary">
    <div>
      <strong>${escapeHtml(role.label)}</strong>
      <span>${escapeHtml(role.category || "Role preset")} - ${escapeHtml(formatCount(permissions.length))} default permissions</span>
    </div>
    ${renderCoalitionPermissionChips(permissions)}
  </div>`;
}

function renderCoalitionInviteForm(resource, catalog, canManage) {
  const pending = resource.actionPendingKey === "invite";
  const search = coalitionInviteSearch(resource);
  const defaultRole =
    normalizeCoalitionRole(search.roleKey) ||
    coalitionAssignableRoles(catalog)[0]?.roleKey || "member";
  return `<article class="shared-campaign-panel shared-campaign-staff-invite">
    <div class="shared-campaign-panel__header">
      <div>
        <h2>Invite member</h2>
        <p>Search for a Polis account, choose their coalition role, and send an invitation with the right access defaults.</p>
      </div>
    </div>
    <form class="shared-campaign-staff-form" data-route-form="coalition-invite">
      ${renderCoalitionInviteSearch(state.pages.coalitions.detail, resource, canManage)}
      <div class="shared-campaign-staff-form-grid shared-campaign-staff-invite-role-grid">
        <label>
          <span>Role preset</span>
          <select name="roleKey" data-coalition-invite-role${disabledAttr(!canManage || pending)}>
            ${renderCoalitionRoleOptions(catalog, defaultRole)}
          </select>
        </label>
      </div>
      ${renderCoalitionInvitePermissionSummary(catalog, defaultRole)}
      <label class="shared-campaign-staff-toggle">
        <input type="checkbox" name="useRoleDefaults" checked${disabledAttr(!canManage || pending)} />
        <span>Use the selected role's default permissions</span>
      </label>
      <details class="shared-campaign-staff-details">
        <summary>Custom permission selection</summary>
        ${renderCoalitionPermissionCheckboxes(catalog, [], {
          disabled: !canManage || pending,
        })}
      </details>
      <details class="shared-campaign-staff-details shared-campaign-staff-direct-id">
        <summary>Direct user id fallback</summary>
        <div class="shared-campaign-staff-direct-id__body">
          <label>
            <span>User id</span>
            <input name="directUserId" placeholder="Optional direct id"${disabledAttr(!canManage || pending)} />
          </label>
        </div>
      </details>
      <div class="shared-campaign-staff-actions">
        <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(!canManage || pending)}>${pending ? "Sending..." : "Send invitation"}</button>
      </div>
    </form>
  </article>`;
}

function renderCoalitionAccessRequestRow(request, resource, catalog, canManage) {
  const role = coalitionCatalogRole(catalog, request.roleKey);
  const pendingApprove =
    resource.actionPendingKey === `request-approve:${request.userId}`;
  const pendingReject =
    resource.actionPendingKey === `request-reject:${request.userId}`;
  return `<article class="shared-campaign-staff-invite-row shared-coalition-access-request-row">
    <div class="shared-campaign-staff-person">
      ${renderCoalitionAccessAvatar(request)}
      <div>
        <strong>${escapeHtml(coalitionAccessDisplayName(request))}</strong>
        <span>${escapeHtml(request.username ? `@${request.username.replace(/^@/u, "")}` : request.userId)}</span>
      </div>
    </div>
    ${renderCoalitionRolePill(
      role,
      `${humanizeLabel(request.status)}${request.requestedAt ? ` - ${formatAbsoluteDateTime(request.requestedAt)}` : ""}`,
    )}
    <div class="shared-campaign-staff-row-actions">
      ${renderCoalitionPermissionChips(request.permissions)}
      ${
        request.isPending && canManage
          ? `<button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="coalition-request-approve" data-user-id="${escapeHtml(request.userId)}"${disabledAttr(pendingApprove || pendingReject)}>${pendingApprove ? "Approving..." : "Approve"}</button>
             <button class="shared-feed-chip" type="button" data-action="coalition-request-reject" data-user-id="${escapeHtml(request.userId)}"${disabledAttr(pendingApprove || pendingReject)}>${pendingReject ? "Rejecting..." : "Reject"}</button>`
          : ""
      }
    </div>
  </article>`;
}

