function renderCoalitionAccessRoleCard(role, resource, catalog, canManage) {
  const pendingUpdate = resource.actionPendingKey === `role:${role.roleKey}`;
  const pendingDelete =
    resource.actionPendingKey === `role-delete:${role.roleKey}`;
  const canDelete = role.custom === true && role.protectedRole !== true;
  const replacementRoles = coalitionAssignableRoles(catalog).filter(
    (candidate) => candidate.roleKey !== role.roleKey,
  );
  return `<details class="shared-campaign-staff-role-card">
    <summary>
      <span class="shared-campaign-staff-role-swatch" style="${role.color ? `background:${escapeHtml(role.color)};` : ""}"></span>
      <strong>${escapeHtml(role.label)}</strong>
      <span>${escapeHtml(role.system ? "Preset" : "Custom")} - ${escapeHtml(formatCount(role.defaultPermissions.length))} defaults</span>
    </summary>
    <form class="shared-campaign-staff-role-form" data-route-form="coalition-role-update">
      <input type="hidden" name="roleKey" value="${escapeHtml(role.roleKey)}" />
      <div class="shared-campaign-staff-form-grid">
        <label>
          <span>Role name</span>
          <input name="label" value="${escapeHtml(role.label)}"${disabledAttr(!canManage || role.system || pendingUpdate || pendingDelete)} />
        </label>
        <label>
          <span>Category</span>
          <input name="category" value="${escapeHtml(role.category)}"${disabledAttr(!canManage || pendingUpdate || pendingDelete)} />
        </label>
        <label>
          <span>Color</span>
          <input name="color" value="${escapeHtml(role.color)}" placeholder="#64748b"${disabledAttr(!canManage || pendingUpdate || pendingDelete)} />
        </label>
      </div>
      <label class="shared-campaign-staff-toggle">
        <input type="checkbox" name="enabled"${checkedAttr(role.enabled)}${disabledAttr(!canManage || role.protectedRole || pendingUpdate || pendingDelete)} />
        <span>Assignable role${role.messagingSynced ? " and synced to rooms" : ""}</span>
      </label>
      ${renderCoalitionPermissionCheckboxes(catalog, role.defaultPermissions, {
        disabled: !canManage || pendingUpdate || pendingDelete,
      })}
      ${
        canManage
          ? `<div class="shared-campaign-staff-actions">
              <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pendingUpdate || pendingDelete)}>${pendingUpdate ? "Saving..." : "Save defaults"}</button>
            </div>`
          : ""
      }
    </form>
    ${
      canManage && canDelete
        ? `<form class="shared-campaign-staff-role-delete" data-route-form="coalition-role-delete">
            <input type="hidden" name="roleKey" value="${escapeHtml(role.roleKey)}" />
            <label>
              <span>Move assigned people to</span>
              <select name="replacementRole"${disabledAttr(pendingUpdate || pendingDelete)}>
                ${replacementRoles
                  .map(
                    (replacement) =>
                      `<option value="${escapeHtml(replacement.roleKey)}">${escapeHtml(replacement.label)}</option>`,
                  )
                  .join("")}
              </select>
            </label>
            <button class="shared-feed-chip" type="submit"${disabledAttr(pendingUpdate || pendingDelete || !replacementRoles.length)}>${pendingDelete ? "Removing..." : "Remove role"}</button>
          </form>`
        : ""
    }
  </details>`;
}

function renderCoalitionAccessRoles(resource, catalog, canManage) {
  const grouped = new Map();
  catalog.roles.forEach((role) => {
    const category = role.category || "Custom";
    if (!grouped.has(category)) {
      grouped.set(category, []);
    }
    grouped.get(category).push(role);
  });
  const creating = resource.actionPendingKey === "role-create";
  return `<article class="shared-campaign-panel shared-campaign-staff-roles">
    <div class="shared-campaign-panel__header">
      <div>
        <h2>Role presets</h2>
        <p>Maintain reusable permission defaults and room-synced coalition roles.</p>
      </div>
    </div>
    ${
      canManage
        ? `<form class="shared-campaign-staff-create-role" data-route-form="coalition-role-create">
            <div class="shared-campaign-staff-form-grid">
              <label>
                <span>Role name</span>
                <input name="label" placeholder="Regional Field Lead"${disabledAttr(creating)} />
              </label>
              <label>
                <span>Category</span>
                <input name="category" value="Custom"${disabledAttr(creating)} />
              </label>
              <label>
                <span>Color</span>
                <input name="color" placeholder="#64748b"${disabledAttr(creating)} />
              </label>
            </div>
            <details class="shared-campaign-staff-details">
              <summary>Default permissions</summary>
              ${renderCoalitionPermissionCheckboxes(catalog, [], {
                disabled: creating,
              })}
            </details>
            <div class="shared-campaign-staff-actions">
              <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(creating)}>${creating ? "Creating..." : "Create custom role"}</button>
            </div>
          </form>`
        : ""
    }
    <div class="shared-campaign-staff-role-groups">
      ${Array.from(grouped.entries())
        .map(
          ([category, roles]) => `<section>
            <h3>${escapeHtml(category)}</h3>
            <div class="shared-campaign-staff-role-list">
              ${roles
                .map((role) =>
                  renderCoalitionAccessRoleCard(
                    role,
                    resource,
                    catalog,
                    canManage,
                  ),
                )
                .join("")}
            </div>
          </section>`,
        )
        .join("")}
    </div>
  </article>`;
}

