function renderCoalitionVoterMapMapPanel(coalition, access, workspace) {
  const map = coalitionVoterMapEnsureViewport(access);
  const members = map.members || [];
  const linkedCount = members.filter((member) => member.linkStatus === "linked")
    .length;
  const categories = new Set(
    members.map((member) => member.roleCategory).filter(Boolean),
  ).size;
  const selectedMember =
    members.find((member) => member.memberId === map.selectedMemberId) ||
    members[0] ||
    null;
  return `<div class="shared-coalition-voter-map-map">
    <div class="shared-campaign-metrics">
      ${renderCoalitionMetric("Visible badges", formatCount(members.length), "cyan")}
      ${renderCoalitionMetric("Linked users", formatCount(linkedCount))}
      ${renderCoalitionMetric("Categories", formatCount(categories))}
      ${renderCoalitionMetric("Scope", access.territories.length ? `${formatCount(access.territories.length)} territories` : humanizeLabel(access.scope))}
    </div>
    <article class="shared-coalition-panel shared-coalition-voter-map-live">
      <div class="shared-coalition-panel__header">
        <div>
          <h2>Coalition map</h2>
          <p>Load the same geocoded coalition directory badges the app overlays on the voter map, then select a member to inspect assignment context.</p>
        </div>
        <div class="shared-card__actions">
          <button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(coalitionSectionPath(coalition.coalitionId, "missions"))}">Missions</button>
          <button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(coalitionSectionPath(coalition.coalitionId, "voter-map/members"))}">Directory</button>
        </div>
      </div>
      ${renderCoalitionVoterMapViewportForm(map)}
      ${map.error ? `<div class="shared-page__error">${escapeHtml(map.error)}</div>` : ""}
      ${renderCoalitionVoterMapCanvas(map, access)}
    </article>
    <div class="shared-coalition-voter-map-grid">
      <div class="shared-coalition-map-side-stack">
        ${renderCoalitionVoterMapMemberSummary(selectedMember)}
        ${renderCoalitionVoterMapMemberList(map)}
      </div>
      ${renderCoalitionVoterMapTerritoryPanel(workspace, access)}
    </div>
  </div>`;
}

function coalitionVoterRecordsSourceCounts(resource = {}) {
  return (resource.items || []).reduce(
    (counts, item) => {
      const source = candidateVoterSourceLabel(item).toLowerCase();
      if (source.includes("polis")) {
        counts.polis += 1;
      } else if (source.includes("manual")) {
        counts.manual += 1;
      } else if (source.includes("import")) {
        counts.imported += 1;
      } else {
        counts.other += 1;
      }
      return counts;
    },
    { polis: 0, manual: 0, imported: 0, other: 0 },
  );
}

function renderCoalitionVoterRecordsWorkflow(coalition, resource, activeSection) {
  const filterCount = candidateVoterRegistryActiveFilterCount(resource.filters);
  const importStatus = resource.import.status
    ? humanizeLabel(resource.import.status.status)
    : "Ready";
  const connectedRoute = coalitionSectionPath(
    coalition.coalitionId,
    "voter-map/connected",
  );
  const addRoute = coalitionSectionPath(coalition.coalitionId, "voter-map/add");
  return `<div class="shared-campaign-registry-workflow shared-coalition-voter-records-workflow" aria-label="Coalition voter records workflow">
    <button class="${activeSection === "connected" ? "is-active" : ""}" type="button" data-action="navigate" data-route="${escapeHtml(connectedRoute)}">
      ${renderIcon("registry")}
      <span>
        <strong>Connected voters</strong>
        <small>${escapeHtml(filterCount ? `${formatCount(filterCount)} filters active` : "Review scoped records")}</small>
      </span>
    </button>
    <button class="${activeSection === "add" ? "is-active" : ""}" type="button" data-action="navigate" data-route="${escapeHtml(addRoute)}">
      ${renderIcon("create")}
      <span>
        <strong>Add voter</strong>
        <small>Manual entry and duplicate review</small>
      </span>
    </button>
    <button class="${activeSection === "add" ? "is-active" : ""}" type="button" data-action="navigate" data-route="${escapeHtml(addRoute)}">
      ${renderIcon("upload")}
      <span>
        <strong>Bulk CSV</strong>
        <small>${escapeHtml(importStatus)}</small>
      </span>
    </button>
  </div>`;
}

