function renderCoalitionVoterDuplicate(resource) {
  const duplicate = resource.duplicate;
  if (!duplicate) {
    return "";
  }
  const existing = duplicate.existing || {};
  const pending = normalizeString(resource.actionPendingKey).startsWith("duplicate:");
  return `<div class="shared-campaign-registry-duplicate">
    <span class="shared-campaign-registry-duplicate__icon">${renderIcon("registry")}</span>
    <div>
      <strong>Duplicate coalition voter found</strong>
      <span>${escapeHtml(existing.displayName || "Existing voter")}${existing.city ? ` in ${escapeHtml(existing.city)}` : ""}. Keep the existing record or replace it with this submission.</span>
    </div>
    <div class="shared-card__actions">
      <button class="shared-feed-chip" type="button" data-action="coalition-voter-duplicate-resolve" data-mode="skip"${disabledAttr(pending)}>Keep existing</button>
      <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="coalition-voter-duplicate-resolve" data-mode="replace"${disabledAttr(pending)}>Replace existing</button>
      <button class="shared-feed-chip" type="button" data-action="coalition-voter-duplicate-cancel"${disabledAttr(pending)}>Cancel</button>
    </div>
  </div>`;
}

