function renderCoalitionDirectoryImportPreview(directoryImport) {
  const preview = directoryImport.preview;
  if (!preview) {
    return "";
  }
  const summary = preview.summary || {};
  return `<div class="shared-campaign-registry-import-preview shared-coalition-directory-preview">
    <div class="shared-campaign-registry-summary">
      ${renderCandidateDashboardMetric("Total", formatCount(summary.totalRows || 0), "cyan")}
      ${renderCandidateDashboardMetric("Valid", formatCount(summary.validRows || 0))}
      ${renderCandidateDashboardMetric("Invalid", formatCount(summary.invalidRows || 0))}
      ${renderCandidateDashboardMetric("Duplicates", formatCount(summary.duplicateRows || 0))}
    </div>
    ${
      preview.items?.length
        ? `<div class="shared-campaign-registry-preview-list">
            ${preview.items
              .slice(0, 10)
              .map(
                (item) => `<div class="shared-list-item">
                  <strong>${escapeHtml(item.fullName || `Row ${item.rowNumber}`)}</strong>
                  <span>${escapeHtml([item.email, item.roleTitle, item.roleCategory, item.organizationName, item.duplicate ? "Duplicate" : "", item.error].map(normalizeString).filter(Boolean).join(" - ") || "Preview row")}</span>
                </div>`,
              )
              .join("")}
          </div>`
        : ""
    }
  </div>`;
}

function renderCoalitionDirectoryImportStatus(directoryImport) {
  const status = directoryImport.status;
  if (!status) {
    return "";
  }
  const pending = directoryImport.actionPendingKey === "status";
  return `<div class="shared-campaign-registry-import-status">
    <span class="shared-campaign-registry-import-status__icon">${renderIcon("upload")}</span>
    <div>
      <strong>${escapeHtml(humanizeLabel(status.status || "queued"))}</strong>
      <span>Processed ${escapeHtml(formatCount(status.processedRows))}; imported ${escapeHtml(formatCount(status.importedCount))}; skipped ${escapeHtml(formatCount(status.skippedCount))}; failed ${escapeHtml(formatCount(status.failedCount))}</span>
      ${status.errorMessage ? `<em>${escapeHtml(status.errorMessage)}</em>` : ""}
    </div>
    <button class="shared-feed-chip" type="button" data-action="coalition-directory-import-status"${disabledAttr(pending)}>${pending ? "Refreshing..." : "Refresh status"}</button>
  </div>`;
}

function renderCoalitionDirectoryImportPanel(directory, canManage) {
  const directoryImport = directory.import;
  const previewing = directoryImport.actionPendingKey === "preview";
  const starting = directoryImport.actionPendingKey === "start";
  const canStart =
    canManage && directoryImport.uploadId && directoryImport.preview && !starting;
  const previewReady = Boolean(directoryImport.preview);
  const importStarted = Boolean(directoryImport.status);
  if (!canManage) {
    return `<article id="coalition-directory-import" class="shared-coalition-panel shared-campaign-registry-import">
      <div class="shared-coalition-panel__header">
        <div>
          <h2>Bulk CSV import</h2>
          <p>CSV directory import is limited to coalition admins because it can create and replace scoped member records.</p>
        </div>
      </div>
      <div class="shared-page__empty">Ask a coalition admin to import directory members.</div>
    </article>`;
  }
  return `<article id="coalition-directory-import" class="shared-coalition-panel shared-campaign-registry-import">
    <div class="shared-coalition-panel__header">
      <div>
        <h2>Bulk CSV import</h2>
        <p>Preview a coalition member CSV, choose duplicate handling, then run the same directory import the app uses.</p>
      </div>
    </div>
    <div class="shared-campaign-registry-import-steps">
      <span class="${previewReady ? "is-complete" : "is-active"}"><em>1</em>Preview</span>
      <span class="${previewReady ? importStarted ? "is-complete" : "is-active" : ""}"><em>2</em>Duplicates</span>
      <span class="${importStarted ? "is-active" : ""}"><em>3</em>Import</span>
    </div>
    <form class="shared-campaign-registry-import-form" data-route-form="coalition-directory-import-preview">
      <label>
        <span>CSV file</span>
        <input name="csvFile" type="file" accept=".csv,text/csv"${disabledAttr(previewing || starting)} />
      </label>
      <button class="shared-feed-chip shared-feed-chip--primary shared-campaign-registry-icon-chip" type="submit"${disabledAttr(previewing || starting)}>${renderIcon("upload")} <span>${escapeHtml(previewing ? "Previewing..." : "Preview CSV")}</span></button>
    </form>
    ${directoryImport.error ? `<div class="shared-page__error">${escapeHtml(directoryImport.error)}</div>` : ""}
    ${directoryImport.fileName ? `<p class="shared-campaign-registry-import-file">Selected: ${escapeHtml(directoryImport.fileName)}</p>` : ""}
    ${renderCoalitionDirectoryImportPreview(directoryImport)}
    ${
      directoryImport.preview
        ? `<div class="shared-campaign-registry-import-start">
            <label>
              <span>Duplicates</span>
              <select data-coalition-directory-import-duplicate-mode>
                <option value="replace"${selectedAttr(directoryImport.duplicateMode === "replace")}>Replace existing</option>
                <option value="skip"${selectedAttr(directoryImport.duplicateMode === "skip")}>Keep existing</option>
              </select>
            </label>
            <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="coalition-directory-import-start"${disabledAttr(!canStart)}>${starting ? "Starting..." : "Start import"}</button>
          </div>`
        : ""
    }
    ${renderCoalitionDirectoryImportStatus(directoryImport)}
  </article>`;
}

