function renderMessagingServerSettingsGroups(subroute, serverSettings, sectionId) {
  const groups = messagingServerSettingsGroups(serverSettings);
  if (!groups.length) {
    return renderMessagingServerSettingsSection({
      title: "Settings areas",
      subtitle: "This server has not exposed website-manageable settings yet.",
      badge: "None",
      body: '<div class="shared-messaging-empty">No server settings sections are available from the app API.</div>',
    });
  }
  const selectedSection = normalizeString(sectionId);
  return `<div class="shared-messaging-server-settings-groups">${groups
    .map(
      (group) => `<section class="shared-messaging-server-settings-group">
        <div class="shared-messaging-server-settings-group__header">
          <div>
            <h3>${escapeHtml(group.title)}</h3>
            <p>${escapeHtml(group.subtitle)}</p>
          </div>
          <span>${escapeHtml(formatCount(group.items.length))}</span>
        </div>
        <div class="shared-messaging-server-settings-list">${group.items
          .map((item) => {
            const active = selectedSection === normalizeString(item.id);
            const route = buildMessagingServerRoute(
              subroute.scopeType,
              subroute.scopeId,
              `/settings/${encodeURIComponent(item.id)}`,
            );
            return `<button class="shared-messaging-server-settings-item${active ? " is-active" : ""}${item.available ? "" : " is-disabled"}" type="button"${item.available ? ` data-action="navigate" data-route="${escapeHtml(route)}"` : " disabled"}>
              <span>
                <strong>${escapeHtml(item.title || humanizeLabel(item.id) || "Section")}</strong>
                <small>${escapeHtml(item.description || (item.available ? "Open this settings area." : "Not available for this server."))}</small>
              </span>
              <em>${escapeHtml(item.available ? messagingServerSettingsValue(item.status, active ? "Open" : "Ready") : "Unavailable")}</em>
            </button>`;
          })
          .join("")}</div>
      </section>`,
    )
    .join("")}</div>`;
}

function messagingServerSettingsSectionActionRoute(subroute, sectionId) {
  const normalized = normalizeString(sectionId).toLowerCase();
  if (normalized === "channels") {
    return buildMessagingServerRoute(subroute.scopeType, subroute.scopeId);
  }
  if (normalized === "integrations") {
    return buildMessagingServerRoute(
      subroute.scopeType,
      subroute.scopeId,
      "/workflows",
    );
  }
  if (normalized === "invites") {
    return buildMessagingServerRoute(subroute.scopeType, subroute.scopeId, "/members");
  }
  if (normalized.includes("role") || normalized.includes("permission")) {
    return buildMessagingServerRoute(subroute.scopeType, subroute.scopeId, "/roles");
  }
  if (
    normalized.includes("member") ||
    normalized.includes("user") ||
    normalized.includes("roster")
  ) {
    return buildMessagingServerRoute(subroute.scopeType, subroute.scopeId, "/members");
  }
  if (
    normalized.includes("moderation") ||
    normalized.includes("report") ||
    normalized.includes("automod")
  ) {
    return buildMessagingServerRoute(
      subroute.scopeType,
      subroute.scopeId,
      "/moderation",
    );
  }
  if (normalized.includes("workflow") || normalized.includes("automation")) {
    return buildMessagingServerRoute(
      subroute.scopeType,
      subroute.scopeId,
      "/workflows",
    );
  }
  return "";
}

