function renderAddressChangeAttachmentList(resource) {
  const pending = Boolean(resource.actionPendingKey);
  if (!resource.attachments.length) {
    return '<div class="shared-address-change-empty">Attach proof only when the direct save path cannot verify the correction.</div>';
  }
  return `<div class="shared-address-change-attachments">
    ${resource.attachments
      .map((attachment) => {
        const id = attachment.attachmentId || attachment.fileName;
        const meta = [
          attachment.type ? humanizeLabel(attachment.type) : "",
          formatComposerFileSize(attachment.sizeBytes),
        ]
          .filter(Boolean)
          .join(" - ");
        return `<article class="shared-address-change-attachment">
          <div>
            <strong>${escapeHtml(attachment.fileName || attachment.key || "Evidence file")}</strong>
            <span>${escapeHtml(meta || attachment.contentType || "Attached")}</span>
          </div>
          <button class="shared-feed-chip" type="button" data-action="settings-address-change-attachment-remove" data-attachment-id="${escapeHtml(id)}"${disabledAttr(pending)}>Remove</button>
        </article>`;
      })
      .join("")}
  </div>`;
}

function renderAddressChangeRequestCard(request) {
  const address = formatAddressChangeAddress(request.requestedAddress);
  const created = request.createdAt
    ? formatAbsoluteDateTime(request.createdAt)
    : request.updatedAt
      ? formatAbsoluteDateTime(request.updatedAt)
      : "";
  const secondary = [
    request.resolutionStatus ? `Resolution: ${humanizeLabel(request.resolutionStatus)}` : "",
    request.attachments.length
      ? `${formatCount(request.attachments.length)} evidence file${request.attachments.length === 1 ? "" : "s"}`
      : "",
  ]
    .filter(Boolean)
    .join(" - ");
  return `<article class="shared-address-change-request">
    <div class="shared-address-change-request__top">
      ${renderSettingsStatusPill(humanizeLabel(request.status), addressChangeStatusTone(request.status))}
      <span>${escapeHtml(created || "Submitted")}</span>
    </div>
    <h3>${escapeHtml(address || "Requested address")}</h3>
    ${request.message ? `<p>${escapeHtml(request.message)}</p>` : ""}
    ${secondary ? `<small>${escapeHtml(secondary)}</small>` : ""}
    ${request.decisionReason ? `<small>${escapeHtml(`Decision: ${request.decisionReason}`)}</small>` : ""}
  </article>`;
}

function renderAddressChangeHistory(resource) {
  if (resource.loading && !resource.loaded) {
    return '<div class="shared-settings-empty">Loading request history...</div>';
  }
  if (resource.error) {
    return `<div class="shared-settings-empty">${escapeHtml(resource.error)}</div>`;
  }
  if (!resource.items.length) {
    return '<div class="shared-settings-empty">No home-location review requests have been submitted from this account yet.</div>';
  }
  return `<div class="shared-address-change-history">
    ${resource.items.map(renderAddressChangeRequestCard).join("")}
    ${
      resource.nextCursor
        ? `<button class="shared-feed-chip" type="button" data-action="settings-address-change-load-more"${disabledAttr(resource.loadingMore)}>${resource.loadingMore ? "Loading..." : "Load more"}</button>`
        : ""
    }
  </div>`;
}

function renderVoterProfileHomeLocationRequest(profile) {
  const resource = settingsAddressChangeRequestState();
  const pending = Boolean(resource.actionPendingKey);
  return `<section class="shared-settings-panel shared-address-change-request-panel">
    <div class="shared-settings-panel__header">
      <div>
        <h2>Request home location review</h2>
        <p>Use this when the direct save path cannot verify the correction or a previous district assignment needs staff approval.</p>
      </div>
      <div class="shared-settings-form-actions">
        <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/settings/voter-profile/home-location">Direct save</button>
        <button class="shared-feed-chip" type="button" data-action="settings-address-change-refresh"${disabledAttr(resource.loading)}>Refresh</button>
      </div>
    </div>
    ${
      resource.submittedRequest
        ? `<div class="shared-settings-inline-note">Latest request submitted. Status: ${escapeHtml(humanizeLabel(resource.submittedRequest.status))}.</div>`
        : ""
    }
    ${resource.error ? `<div class="shared-page__error">${escapeHtml(resource.error)}</div>` : ""}
    <div class="shared-address-change-layout">
      <form class="shared-settings-form shared-address-change-form" data-route-form="settings-home-location-request">
        <div class="shared-settings-form-grid">
          <label>
            <span>Address</span>
            <input name="addressLine1" value="${escapeHtml(profile?.addressLine1 || "")}" autocomplete="address-line1" required${disabledAttr(pending)} />
          </label>
          <label>
            <span>Apartment, suite, unit</span>
            <input name="addressLine2" value="${escapeHtml(profile?.addressLine2 || "")}" autocomplete="address-line2"${disabledAttr(pending)} />
          </label>
          <label>
            <span>City</span>
            <input name="city" value="${escapeHtml(profile?.city || "")}" autocomplete="address-level2" required${disabledAttr(pending)} />
          </label>
          <label>
            <span>State</span>
            <input name="state" value="${escapeHtml(profile?.locationStateId || "")}" autocomplete="address-level1" maxlength="2" required${disabledAttr(pending)} />
          </label>
          <label>
            <span>ZIP</span>
            <input name="postalCode" value="${escapeHtml(profile?.postalCode || "")}" autocomplete="postal-code" required${disabledAttr(pending)} />
          </label>
          <label>
            <span>County optional</span>
            <input name="county" value="${escapeHtml(profile?.locationCounty || "")}"${disabledAttr(pending)} />
          </label>
          <label>
            <span>District optional</span>
            <input name="district" value="${escapeHtml(profile?.locationDistrictId || profile?.manualCongressionalDistrictId || "")}"${disabledAttr(pending)} />
          </label>
          <label class="is-wide">
            <span>Why should this change be approved?</span>
            <textarea name="message" rows="4" maxlength="1000" required${disabledAttr(pending)} placeholder="Example: address correction after account issue"></textarea>
          </label>
        </div>
        <div class="shared-address-change-upload">
          <div>
            <strong>Evidence files</strong>
            <span>${escapeHtml(`${formatCount(resource.attachments.length)}/3 attached`)}</span>
          </div>
          <label>
            <span>Image</span>
            <input type="file" accept="image/png,image/jpeg,image/webp" data-address-change-file${disabledAttr(pending || resource.attachments.length >= 3)} />
          </label>
          <label>
            <span>PDF</span>
            <input type="file" accept="application/pdf,.pdf" data-address-change-file${disabledAttr(pending || resource.attachments.length >= 3)} />
          </label>
        </div>
        ${resource.attachmentError ? `<div class="shared-settings-inline-note">${escapeHtml(resource.attachmentError)}</div>` : ""}
        ${renderAddressChangeAttachmentList(resource)}
        <div class="shared-settings-form-actions">
          <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pending)}>${resource.actionPendingKey === "submit" ? "Submitting..." : "Submit request"}</button>
          <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/settings/voter-profile">Profile card</button>
        </div>
      </form>
      <aside class="shared-address-change-review">
        <div>
          <span class="shared-settings-eyebrow">Review path</span>
          <h3>What happens next</h3>
          <p>Polis stores the requested address, note, and evidence for admin review. If approved, the new location is applied to your voter profile and district context can be refreshed.</p>
        </div>
        <div class="shared-address-change-review__steps">
          <span>1. Submit request</span>
          <span>2. Admin reviews evidence</span>
          <span>3. Profile location updates if approved</span>
        </div>
      </aside>
    </div>
    <section class="shared-address-change-history-panel">
      <div class="shared-settings-panel__header">
        <div>
          <h2>Your requests</h2>
          <p>Pending and reviewed home-location corrections for this account.</p>
        </div>
      </div>
      ${renderAddressChangeHistory(resource)}
    </section>
  </section>`;
}

function renderVoterProfileDistricts(profile, resource) {
  const districts = resource.item;
  const federal = districts?.jurisdictions?.federal || {};
  const state = districts?.jurisdictions?.state || {};
  const county = districts?.jurisdictions?.county || {};
  const city = districts?.jurisdictions?.city || {};
  const hasAddress = Boolean(voterProfileAddress(profile));
  const districtId =
    federal.congressionalDistrictId ||
    normalizeString(profile?.locationDistrictId) ||
    normalizeString(profile?.manualCongressionalDistrictId);
  return `<section class="shared-settings-panel shared-voter-profile-districts">
    <div class="shared-settings-panel__header">
      <div>
        <h2>District context</h2>
        <p>These fields power candidate matching, local election filters, and voter-intelligence coverage.</p>
      </div>
      <button class="shared-feed-chip" data-action="settings-voter-profile-refresh-districts"${disabledAttr(resource.loading)}>Refresh districts</button>
    </div>
    ${renderSettingsResourceStatus(resource, "district context")}
    ${
      hasAddress || districtId
        ? `<div class="shared-voter-profile-district-grid">
            ${renderVoterProfileMetric("Federal", districtId || "Pending", federal.congressionalDistrictName || "Congressional district")}
            ${renderVoterProfileMetric("State", state.stateId || profile?.locationStateId || "Missing", [state.senateDistrictName, state.houseDistrictName].filter(Boolean).join(" / ") || "State legislative context")}
            ${renderVoterProfileMetric("County", county.countyName || profile?.locationCounty || "Pending", city.cityName || "County and city context")}
          </div>`
        : `<div class="shared-settings-empty">Add a home location to resolve district context for Polis web.</div>`
    }
    <div class="shared-voter-profile-district-foot">
      <span>${escapeHtml(districts?.homeLocation?.source ? `Source: ${humanizeLabel(districts.homeLocation.source)}` : profile?.locationSource ? `Source: ${humanizeLabel(profile.locationSource)}` : "No source yet")}</span>
      <span>${escapeHtml(districts?.refreshedAt ? `Refreshed ${formatCalendarDate(districts.refreshedAt)}` : profile?.updatedAtIso ? `Profile updated ${formatCalendarDate(profile.updatedAtIso)}` : "Awaiting refresh")}</span>
    </div>
  </section>`;
}

function renderSettingsPreferenceCard({
  icon,
  title,
  copy,
  route,
  status = "Open",
  primary = false,
}) {
  return `<button class="shared-settings-preference-card${primary ? " is-primary" : ""}" type="button" data-action="navigate" data-route="${escapeHtml(route)}">
    <span class="shared-settings-preference-card__icon">${renderIcon(icon || "settings")}</span>
    <span>
      <strong>${escapeHtml(title)}</strong>
      <small>${escapeHtml(copy)}</small>
    </span>
    <em>${escapeHtml(status)}</em>
  </button>`;
}

